def _safe_excerpt(value: str, max_len: int = 120) -> str:
    return value[:max_len].replace("\n", " ")


def _assistant_share_draft_type(channel: str) -> str:
    mapping = {
        "whatsapp": "send_whatsapp_message",
        "telegram": "send_telegram_message",
        "instagram": "send_instagram_message",
        "email": "send_email",
        "x": "post_x_update",
        "linkedin": "post_linkedin_update",
    }
    return mapping.get(str(channel or "").strip().lower(), "send_email")


def _assistant_share_subject(content: str) -> str:
    normalized_lines = [" ".join(str(line).split()).strip() for line in str(content or "").splitlines()]
    first_line = next((line for line in normalized_lines if line), "")
    if not first_line:
        return "Asistan paylaşımı"
    if len(first_line) > 72:
        return f"{first_line[:69].rstrip()}..."
    return first_line


def _assistant_share_contact_value(profile: dict[str, Any], *, channel: str) -> str:
    normalized_channel = str(channel or "").strip().lower()
    if normalized_channel == "email":
        return _compact_inline_text(str((profile.get("emails") or [""])[0] or profile.get("display_name") or ""))
    if normalized_channel == "telegram":
        return _compact_inline_text(
            str((profile.get("handles") or [""])[0] or (profile.get("phone_numbers") or [""])[0] or profile.get("display_name") or "")
        )
    if normalized_channel == "instagram":
        return _compact_inline_text(str((profile.get("handles") or [""])[0] or profile.get("display_name") or ""))
    return _compact_inline_text(str(profile.get("display_name") or ""))


def _assistant_share_channel_label(channel: str) -> str:
    mapping = {
        "whatsapp": "WhatsApp",
        "telegram": "Telegram",
        "instagram": "Instagram",
        "email": "E-posta",
        "x": "X",
        "linkedin": "LinkedIn",
    }
    return mapping.get(str(channel or "").strip().lower(), "Paylaşım")


def _map_route_mode_for_profile(profile: dict[str, Any] | None) -> str:
    normalized = _normalize_tr_text(
        " ".join(
            part
            for part in [
                str((profile or {}).get("transport_preference") or "").strip(),
                str((profile or {}).get("travel_preferences") or "").strip(),
                str((profile or {}).get("maps_preference") or "").strip(),
            ]
            if part
        )
    )
    if any(token in normalized for token in ("yuru", "yürü", "walk")):
        return "walking"
    if any(token in normalized for token in ("bisiklet", "bicycle", "bike")):
        return "bicycling"
    if any(token in normalized for token in ("metro", "tramvay", "tren", "train", "otobus", "otobüs", "toplu", "transit")):
        return "transit"
    return "driving"


def _build_map_directions_url(
    profile: dict[str, Any] | None,
    *,
    destination_query: str,
    origin_query: str = "",
    route_mode: str = "",
) -> str:
    destination = str(destination_query or "").strip()
    if not destination:
        return ""
    origin = str(origin_query or "").strip()
    provider = _maps_provider_key(profile or {})
    if provider == "apple":
        params = [f"daddr={quote(destination)}"]
        if origin:
            params.append(f"saddr={quote(origin)}")
        if route_mode == "walking":
            params.append("dirflg=w")
        elif route_mode == "transit":
            params.append("dirflg=r")
        else:
            params.append("dirflg=d")
        return f"https://maps.apple.com/?{'&'.join(params)}"
    if provider == "yandex":
        params = [f"rtext={quote(origin)}~{quote(destination)}" if origin else f"text={quote(destination)}"]
        if origin:
            params.append("rtt=auto")
        return f"https://yandex.com/maps/?{'&'.join(params)}"
    params = [f"destination={quote(destination)}"]
    if origin:
        params.append(f"origin={quote(origin)}")
    if route_mode:
        params.append(f"travelmode={quote(route_mode)}")
    return f"https://www.google.com/maps/dir/?api=1&{'&'.join(params)}"


def _build_map_embed_url(
    settings,
    *,
    destination_query: str,
    origin_query: str = "",
    route_mode: str = "",
) -> str:
    destination = str(destination_query or "").strip()
    if not destination:
        return ""
    origin = str(origin_query or "").strip()
    api_key = str(getattr(settings, "google_maps_embed_api_key", "") or "").strip()
    if api_key:
        if origin:
            mode = route_mode or "driving"
            return (
                "https://www.google.com/maps/embed/v1/directions"
                f"?key={quote(api_key)}&origin={quote(origin)}&destination={quote(destination)}&mode={quote(mode)}"
            )
        return f"https://www.google.com/maps/embed/v1/place?key={quote(api_key)}&q={quote(destination)}"
    return f"https://www.google.com/maps?q={quote(destination)}&z=15&output=embed"


def _normalize_map_preview(
    *,
    title: str,
    subtitle: str = "",
    destination_label: str,
    destination_query: str,
    maps_url: str,
    directions_url: str,
    embed_url: str,
    source_kind: str,
    starts_at: str = "",
    origin_label: str = "",
    route_mode: str = "",
) -> dict[str, Any] | None:
    normalized_title = _compact_inline_text(title)
    normalized_destination = _compact_inline_text(destination_label)
    normalized_query = _compact_inline_text(destination_query)
    if not normalized_destination or not normalized_query:
        return None
    return {
        "title": normalized_title or normalized_destination,
        "subtitle": _compact_inline_text(subtitle),
        "destination_label": normalized_destination,
        "destination_query": normalized_query,
        "origin_label": _compact_inline_text(origin_label),
        "route_mode": route_mode,
        "maps_url": maps_url,
        "directions_url": directions_url,
        "embed_url": embed_url,
        "source_kind": source_kind,
        "starts_at": starts_at or None,
    }


def _build_assistant_map_preview(
    *,
    reply: dict[str, Any],
    settings,
    store: Persistence,
) -> dict[str, Any] | None:
    source_context = reply.get("source_context") if isinstance(reply.get("source_context"), dict) else {}
    profile = store.get_user_profile(settings.office_id)
    origin_label = _profile_location_label(profile)
    route_mode = _map_route_mode_for_profile(profile)

    event_candidates = [
        source_context.get("created_calendar_event"),
        source_context.get("pending_calendar_event"),
        source_context.get("calendar_map_event"),
    ]
    for candidate in event_candidates:
        if not isinstance(candidate, dict):
            continue
        location = _compact_inline_text(str(candidate.get("location") or ""))
        if not location:
            continue
        title = _compact_inline_text(str(candidate.get("title") or "Toplantı konumu"))
        starts_at = str(candidate.get("starts_at") or "")
        subtitle_parts = [_format_turkish_datetime(starts_at) if starts_at else "", location]
        destination_query = location
        maps_url = _build_map_search_url(profile, destination_query)
        directions_url = _build_map_directions_url(
            profile,
            destination_query=destination_query,
            origin_query=origin_label,
            route_mode=route_mode,
        )
        embed_url = _build_map_embed_url(
            settings,
            destination_query=destination_query,
            origin_query=origin_label,
            route_mode=route_mode,
        )
        return _normalize_map_preview(
            title=title,
            subtitle=" · ".join(part for part in subtitle_parts if part),
            destination_label=location,
            destination_query=destination_query,
            maps_url=maps_url,
            directions_url=directions_url or maps_url,
            embed_url=embed_url,
            source_kind="calendar_event",
            starts_at=starts_at,
            origin_label=origin_label,
            route_mode=route_mode,
        )

    place_results = source_context.get("place_results") if isinstance(source_context.get("place_results"), list) else []
    if place_results:
        first_place = next((item for item in place_results if isinstance(item, dict)), None)
        if first_place:
            title = _compact_inline_text(str(first_place.get("title") or "Önerilen mekan"))
            snippet = _compact_inline_text(str(first_place.get("snippet") or ""))
            destination_query = title or _compact_inline_text(str(source_context.get("original_query") or ""))
            maps_url = _compact_inline_text(str(source_context.get("map_url") or first_place.get("url") or ""))
            directions_url = _build_map_directions_url(
                profile,
                destination_query=destination_query,
                origin_query=origin_label,
                route_mode=route_mode,
            )
            embed_url = _build_map_embed_url(
                settings,
                destination_query=destination_query,
                origin_query=origin_label,
                route_mode=route_mode,
            )
            return _normalize_map_preview(
                title=title,
                subtitle=snippet,
                destination_label=title or destination_query,
                destination_query=destination_query,
                maps_url=maps_url or _build_map_search_url(profile, destination_query),
                directions_url=directions_url or maps_url,
                embed_url=embed_url,
                source_kind="place_result",
                origin_label=origin_label,
                route_mode=route_mode,
            )
    return None


def _attach_map_preview_to_reply(
    *,
    reply: dict[str, Any],
    settings,
    store: Persistence,
) -> None:
    source_context = reply.get("source_context") if isinstance(reply.get("source_context"), dict) else {}
    if source_context.get("map_preview"):
        return
    map_preview = _build_assistant_map_preview(reply=reply, settings=settings, store=store)
    if not map_preview:
        return
    reply["source_context"] = {
        **source_context,
        "map_preview": map_preview,
    }


def _extract_attachment_analysis(
    *,
    filename: str,
    content: bytes,
    content_type: str | None,
    runtime,
    events: StructuredLogger | None = None,
    subject: str | None = None,
) -> dict[str, Any]:
    analysis = analyze_attachment_content(
        filename=filename,
        content=content,
        content_type=content_type,
        runtime=runtime,
        events=events,
        subject=subject,
    )
    attachment_text = str(analysis.get("text") or "").strip()
    if not attachment_text and analysis.get("analysis_available"):
        attachment_text = str(analysis.get("attachment_context") or "").strip()
    if not attachment_text:
        raise ValueError(str(analysis.get("analysis_error") or "Dosya içeriği çözümlenemedi."))
    return {
        **analysis,
        "text": attachment_text,
    }


def _support_level(citations: list[dict]) -> str:
    if not citations:
        return "none"
    top = max(float(item.get("relevance_score", 0.0)) for item in citations)
    if top >= 0.26 and len(citations) >= 2:
        return "high"
    if top >= 0.16:
        return "medium"
    return "low"


def _citation_view(citation: dict, index: int | None = None) -> dict:
    payload = {
        "document_id": citation.get("document_id"),
        "document_name": citation.get("document_name"),
        "matter_id": citation.get("matter_id"),
        "chunk_id": citation.get("chunk_id"),
        "chunk_index": citation.get("chunk_index"),
        "excerpt": citation.get("excerpt"),
        "relevance_score": citation.get("relevance_score"),
        "source_type": citation.get("source_type"),
        "support_type": citation.get("support_type"),
        "confidence": citation.get("confidence"),
        "line_anchor": citation.get("line_anchor"),
        "page": citation.get("page"),
        "line_start": citation.get("line_start"),
        "line_end": citation.get("line_end"),
    }
    if index is not None:
        payload["index"] = index
        payload["label"] = f"[{index}]"
    return payload


def _truncate_for_prompt(value: str, max_len: int = 260) -> str:
    return " ".join(str(value or "").strip().split())[:max_len]


def _legacy_source_prompt_lines(sources: list[dict]) -> list[str]:
    lines: list[str] = []
    for index, source in enumerate(sources[:4], start=1):
        lines.append(
            f"[{index}] Belge: {source.get('document')} | Sayfa: {source.get('page')} | "
            f"Satırlar: {source.get('line_start')}-{source.get('line_end')} | "
            f"Pasaj: {_truncate_for_prompt(source.get('snippet') or '')}"
        )
    return lines


def _citation_prompt_lines(citations: list[dict]) -> list[str]:
    lines: list[str] = []
    for index, citation in enumerate(citations[:5], start=1):
        lines.append(
            f"[{index}] Belge: {citation.get('document_name')} | Tür: {citation.get('source_type')} | "
            f"Güven: {citation.get('confidence')} | "
            f"Pasaj: {_truncate_for_prompt(citation.get('excerpt') or '')}"
        )
    return lines


def _runtime_generated_from(runtime_completion: dict | None, *, direct_label: str, advanced_label: str, fallback_label: str) -> str:
    if not runtime_completion:
        return fallback_label
    if str(runtime_completion.get("runtime_mode") or "") == "advanced-openclaw":
        return advanced_label
    return direct_label


def _iter_text_deltas(value: str, *, chunk_size: int = 32):
    text = str(value or "")
    if not text.strip():
        return
    index = 0
    total_len = len(text)
    while index < total_len:
        next_index = min(total_len, index + chunk_size)
        if next_index < total_len:
            whitespace_match = re.search(r"\s", text[next_index : min(total_len, next_index + 24)])
            if whitespace_match:
                next_index += whitespace_match.start() + 1
        yield text[index:next_index]
        index = next_index


def _ndjson_line(payload: dict[str, Any]) -> bytes:
    return (json.dumps(payload, ensure_ascii=False) + "\n").encode("utf-8")


def _maybe_runtime_completion(runtime, prompt: str, events: StructuredLogger | None = None, *, task: str, **meta) -> dict | None:
    if not runtime:
        return None
    try:
        completion = runtime.complete(prompt, events, task=task, **meta)
    except TypeError:
        result = runtime.complete(prompt)
        if result.ok and result.text:
            if events:
                events.log("openclaw_runtime_used", task=task, provider=result.provider, model=result.model, **meta)
            return {
                "text": result.text,
                "provider": result.provider,
                "model": result.model,
            }
        if events:
            events.log("openclaw_runtime_fallback", level="warning", task=task, error=result.error, **meta)
        return None
    return completion


def _maybe_runtime_stream(runtime, prompt: str, events: StructuredLogger | None = None, *, task: str, **meta):
    if not runtime or not hasattr(runtime, "stream_complete"):
        return None, None
    try:
        return runtime.stream_complete(prompt, events, task=task, **meta)
    except TypeError:
        return None, None
    except Exception as exc:
        if events:
            events.log("assistant_thread_stream_fallback", level="warning", task=task, error=str(exc), **meta)
        return None, None


def _runtime_semantic_available(runtime) -> bool:
    if not runtime:
        return False
    enabled = getattr(runtime, "enabled", None)
    if enabled is not None:
        return bool(enabled)
    return True


def _profile_summary_lines(profile: dict | None) -> list[str]:
    if not profile:
        return []
    lines: list[str] = []
    if profile.get("display_name"):
        lines.append(f"- Kullanıcı adı / hitap: {_truncate_for_prompt(profile['display_name'], 120)}")
    if profile.get("favorite_color"):
        lines.append(f"- Sevdiği renk: {_truncate_for_prompt(profile['favorite_color'], 120)}")
    if profile.get("assistant_notes"):
        lines.append(f"- Kullanıcı profil notu: {_truncate_for_prompt(profile['assistant_notes'], 260)}")
    if profile.get("food_preferences"):
        lines.append(f"- Yeme içme tercihleri: {_truncate_for_prompt(profile['food_preferences'], 220)}")
    if profile.get("transport_preference"):
        lines.append(f"- Ulaşım tercihi: {_truncate_for_prompt(profile['transport_preference'], 180)}")
    if profile.get("weather_preference"):
        lines.append(f"- Hava tercihi: {_truncate_for_prompt(profile['weather_preference'], 180)}")
    if profile.get("travel_preferences"):
        lines.append(f"- Seyahat notları: {_truncate_for_prompt(profile['travel_preferences'], 220)}")
    if profile.get("home_base"):
        lines.append(f"- Ana yaşam / dönüş noktası: {_truncate_for_prompt(profile['home_base'], 160)}")
    if profile.get("current_location"):
        lines.append(f"- Güncel konum: {_truncate_for_prompt(profile['current_location'], 180)}")
    if profile.get("location_preferences"):
        lines.append(f"- Yakın çevre tercihleri: {_truncate_for_prompt(profile['location_preferences'], 220)}")
    if profile.get("maps_preference"):
        lines.append(f"- Harita tercihi: {_truncate_for_prompt(profile['maps_preference'], 120)}")
    if profile.get("prayer_notifications_enabled"):
        prayer_notes = _truncate_for_prompt(profile.get("prayer_habit_notes") or "", 180)
        lines.append("- Özel rutin / mekan desteği açık." + (f" {prayer_notes}" if prayer_notes else ""))
    if profile.get("communication_style"):
        lines.append(f"- İletişim stili: {_truncate_for_prompt(profile['communication_style'], 180)}")
    source_preference_rules = summarize_source_preference_rules(profile.get("source_preference_rules") or [], limit=3)
    if source_preference_rules:
        lines.append(f"- Kaynak tercihleri: {'; '.join(_truncate_for_prompt(item, 220) for item in source_preference_rules)}")
    important_dates = profile.get("important_dates") or []
    if important_dates:
        compact: list[str] = []
        for item in important_dates[:4]:
            label = _truncate_for_prompt(item.get("label") or "Önemli tarih", 80)
            date_value = item.get("date") or "Tarih yok"
            notes = _truncate_for_prompt(item.get("notes") or "", 100)
            compact.append(f"{label} ({date_value})" + (f": {notes}" if notes else ""))
        lines.append(f"- Önemli tarihler: {'; '.join(compact)}")
    related_profiles = profile.get("related_profiles") or []
    if related_profiles:
        compact_related: list[str] = []
        for item in related_profiles[:4]:
            name = _truncate_for_prompt(item.get("name") or "Yakın çevre", 80)
            relationship = _truncate_for_prompt(item.get("relationship") or "", 40)
            notes = _truncate_for_prompt(item.get("notes") or item.get("preferences") or "", 100)
            label = f"{name} ({relationship})" if relationship else name
            compact_related.append(label + (f": {notes}" if notes else ""))
        lines.append(f"- Yakın çevre profilleri: {'; '.join(compact_related)}")
    return lines


def _assistant_runtime_profile_lines(runtime_profile: dict | None) -> list[str]:
    if not runtime_profile:
        return []
    lines: list[str] = []
    if runtime_profile.get("assistant_name"):
        lines.append(f"- Asistan adı: {_truncate_for_prompt(runtime_profile['assistant_name'], 80)}")
    if runtime_profile.get("role_summary"):
        lines.append(f"- Asistan rolü: {_truncate_for_prompt(runtime_profile['role_summary'], 180)}")
    if runtime_profile.get("tone"):
        lines.append(f"- Konuşma tonu: {_truncate_for_prompt(runtime_profile['tone'], 180)}")
    if runtime_profile.get("soul_notes"):
        lines.append(f"- Davranış sınırları: {_truncate_for_prompt(runtime_profile['soul_notes'], 220)}")
    lines.extend(assistant_core_prompt_lines(runtime_profile))
    return lines


