def _assistant_home_payload(settings, store: Persistence) -> dict[str, Any]:
    home = build_assistant_home(store, settings.office_id, settings=settings)
    onboarding = _assistant_onboarding_state(settings, store)
    merged_requires_setup = list(onboarding.get("setup_items") or []) + list(home.get("requires_setup") or [])
    deduped: list[dict[str, Any]] = []
    seen_ids: set[str] = set()
    for item in merged_requires_setup:
        key = str(item.get("id") or "")
        if key in seen_ids:
            continue
        seen_ids.add(key)
        deduped.append(item)
    home["requires_setup"] = deduped
    home["onboarding"] = onboarding
    return home


def _knowledge_recommendations_as_home_cards(payload: dict[str, Any]) -> list[dict[str, Any]]:
    cards: list[dict[str, Any]] = []
    for item in payload.get("items") or []:
        next_actions = [str(action).strip() for action in item.get("next_actions") or [] if str(action).strip()]
        priority = "high" if float(item.get("confidence") or 0.0) >= 0.8 else "medium"
        tool = "drafts" if "draft" in str(item.get("kind") or "") else "today"
        cards.append(
            {
                "id": str(item.get("id") or ""),
                "kind": str(item.get("kind") or "knowledge_recommendation"),
                "title": str(item.get("suggestion") or "Öneri").strip(),
                "details": str(item.get("why_this") or "").strip(),
                "action_label": next_actions[0] if next_actions else "İncele",
                "prompt": str(item.get("suggestion") or "").strip(),
                "tool": tool,
                "priority": priority,
                "confidence": item.get("confidence"),
                "requires_confirmation": bool(item.get("requires_confirmation")),
                "source_basis": item.get("source_basis") or [],
                "memory_scope": item.get("memory_scope") or [],
                "supporting_pages_or_records": item.get("supporting_pages_or_records") or [],
                "recent_related_feedback": item.get("recent_related_feedback") or [],
                "explainability": item.get("explainability") or {},
                "decision_record": item.get("decision_record"),
                "action_ladder": {
                    "current_stage": "suggest",
                    "available_next_stages": ["draft", "preview", "one_click_approve"],
                    "risk_level": item.get("risk_level"),
                },
            }
        )
    return cards


