            "belleğe ne ekledin",
            "bellege ne yazdin",
            "belleğe ne yazdın",
            "bellek guncellemesi neydi",
            "bellek güncellemesi neydi",
            "profil notuna ne yazdin",
            "profil notuna ne yazdın",
            "destek notuna ne yazdin",
