def _recent_thread_memory_updates(prior_messages: list[dict]) -> list[dict[str, Any]]:
    for message in reversed(prior_messages):
        if str(message.get("role") or "") != "assistant":
            continue
        source_context = message.get("source_context") or {}
        updates = source_context.get("memory_updates")
        if isinstance(updates, list) and updates:
            return list(updates)
    return []


def _build_onboarding_question_copy(
    question: dict[str, Any],
    *,
    first_question: bool,
    acknowledgement: str | None = None,
) -> str:
    prompt = str(question.get("question") or "").strip()
    if not prompt:
        return ""

    lines: list[str] = []
    if acknowledgement:
        lines.append(acknowledgement)
    elif first_question:
        lines.append("Bunu kısa tutacağım. Önce çalışma tarzını netleştireceğim; ardından hangi hesapları ve servisleri bağlamak istediğini sohbetten birlikte kuracağız.")

    prompt_lead = "İlk sorum:" if first_question and not acknowledgement else "Sıradaki sorum:"
    lines.append(f"{prompt_lead} {prompt}")

    reason = str(question.get("reason") or "").strip()
    if reason:
        lines.append(f"Bunu şöyle kullanacağım: {reason}")

    help_text = str(question.get("help_text") or "").strip()
    if help_text:
        lines.append(f"Nasıl cevap verebilirsin: {help_text}")

    examples = _assistant_onboarding_examples(question)
    if examples:
        lines.append("")
        lines.append("Örnek yanıtlar:")
        lines.extend(f"- {item}" for item in examples[:4])

    return "\n".join(lines).strip()


def _maybe_compose_onboarding_meta_reply(
    query: str,
    *,
    home: dict[str, Any],
    onboarding_state: dict[str, object],
    settings,
    store: Persistence,
) -> dict[str, Any] | None:
    if bool(onboarding_state.get("complete")) or bool(onboarding_state.get("blocked_by_setup")):
        return None

    normalized = _normalize_tr_text(query)
    runtime_profile = store.get_assistant_runtime_profile(settings.office_id) or _empty_assistant_runtime_profile_payload(settings.office_id)
    profile = store.get_user_profile(settings.office_id) or _empty_profile_payload(settings.office_id)
    assistant_name = str(runtime_profile.get("assistant_name") or "LawCopilot").strip() or "LawCopilot"
    user_name = str(profile.get("display_name") or "").strip()
    tone = str(runtime_profile.get("tone") or "net ve profesyonel").strip().lower()

    lead: str | None = None
    if any(token in normalized for token in ("ismin ne", "adin ne", "adın ne", "sen kimsin", "kimsin")):
        lead = f"Ben {assistant_name}."
        if user_name:
            lead += f" Sana {user_name} diye hitap edeceğim."
    elif any(token in normalized for token in ("nasilsin", "nasılsın", "hazir misin", "hazır mısın", "orada misin", "orada mısın", "ne durumdasin", "ne durumdasın")):
        lead = f"İyiyim, hazırım. Şu an {assistant_name} olarak {tone} bir çizgide yanında olacağım."

    if not lead:
        return None

    content = _append_onboarding_followup(lead, onboarding_state, memory_updates=[])
    return {
        "content": content.strip(),
        "assistant_summary": home.get("today_summary") or "",
        "tool_suggestions": [],
        "linked_entities": [],
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_onboarding_guide",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "priority_items": home.get("priority_items") or [],
            "requires_setup": home.get("requires_setup") or [],
            "onboarding": onboarding_state,
        },
    }


def _compose_assistant_onboarding_reply(
    query: str,
    *,
    home: dict[str, Any],
    onboarding_state: dict[str, object],
    memory_updates: list[dict[str, Any]],
    settings,
    store: Persistence,
) -> dict[str, Any]:
    setup_items = list(onboarding_state.get("setup_items") or [])
    current_question = _assistant_onboarding_current_question(onboarding_state)
    acknowledgement = _memory_update_acknowledgement(memory_updates, settings=settings, store=store) if memory_updates else None
    if bool(onboarding_state.get("blocked_by_setup")) and setup_items:
        checklist = " ".join(
            f"{item.get('title')}: {item.get('details')}"
            for item in setup_items[:2]
            if str(item.get("title") or "").strip()
        ).strip()
        next_steps = [
            "İstersen doğrudan \"Gemini bağla\", \"OpenAI hesabımı bağla\" ya da \"Ollama kullan\" diye yazabilirsin.",
        ]
        if any(str(item.get("id") or "").strip() == "setup-workspace" for item in setup_items):
            next_steps.append("Çalışma klasörü eksikse bunu ayarlardan bir kez seçmen yeterli.")
        content = (
            ((acknowledgement + " ") if acknowledgement else "")
            + "Tanışma kısmına geçmeden önce asistanın kullanacağı modeli seçelim. "
            + (f"Gerekli adımlar: {checklist} " if checklist else "")
            + "Model hazır olunca kısa tanışma sorularını sohbetten birlikte tamamlarız. "
            + " ".join(next_steps)
        ).strip()
    elif current_question:
        content = _build_onboarding_question_copy(
            current_question,
            first_question=not bool(acknowledgement),
            acknowledgement=acknowledgement,
        )
    elif setup_items:
        checklist = " ".join(
            f"{item.get('title')}: {item.get('details')}"
            for item in setup_items[:2]
            if str(item.get("title") or "").strip()
        ).strip()
        next_steps = [
            "İstersen doğrudan \"Google hesabımı bağla\", \"WhatsApp kur\" veya \"Outlook hesabımı bağla\" diye yazabilirsin.",
        ]
        if not bool(onboarding_state.get("provider_ready")) or not bool(onboarding_state.get("model_ready")):
            next_steps.insert(0, "Model tarafı için de \"Gemini bağla\", \"OpenAI hesabımı bağla\" ya da \"Ollama kullan\" diye yazman yeterli.")
        content = (
            ((acknowledgement + " ") if acknowledgement else "")
            + "Tanışma kısmını tamamladık. "
            + (f"Eksik temel adımlar: {checklist} " if checklist else "")
            + "Şimdi ilk bağlantıları ve kalan kurulumu sohbetten birlikte ilerletebiliriz. "
            + " ".join(next_steps)
        ).strip()
    else:
        content = acknowledgement or "Tanışma tamam. Artık normal şekilde devam edebiliriz."
    return {
        "content": content.strip(),
        "assistant_summary": home.get("today_summary") or "",
        "tool_suggestions": [],
        "linked_entities": [],
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_onboarding_guide",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "priority_items": home.get("priority_items") or [],
            "requires_setup": home.get("requires_setup") or [],
            "onboarding": onboarding_state,
        },
    }


def _normalize_tr_text(value: str) -> str:
    return (
        str(value or "")
        .lower()
        .replace("i̇", "i")
        .replace("\u0307", "")
        .replace("ı", "i")
        .replace("ğ", "g")
        .replace("ü", "u")
        .replace("ş", "s")
        .replace("ö", "o")
        .replace("ç", "c")
    )


def _clean_onboarding_answer(value: str, *, limit: int = 240) -> str:
    return clean_persona_text(value, limit=limit)


def _append_profile_note(existing: str | None, note: str) -> str:
    return append_unique_note(existing, note)


def _append_user_profile_note(existing: str | None, note: str) -> str:
    return merge_profile_memory_note(existing, note)


def _extract_json_object_from_text(text: str) -> dict[str, Any] | None:
    cleaned = str(text or "").strip()
    if not cleaned:
        return None
    fenced = re.search(r"```(?:json)?\s*(\{.*\})\s*```", cleaned, flags=re.DOTALL | re.IGNORECASE)
    if fenced:
        cleaned = fenced.group(1).strip()
    try:
        payload = json.loads(cleaned)
    except json.JSONDecodeError:
        payload = None
    if isinstance(payload, dict):
        return payload
    start = cleaned.find("{")
    end = cleaned.rfind("}")
    if start == -1 or end <= start:
        return None
    candidate = cleaned[start : end + 1]
    try:
        payload = json.loads(candidate)
    except json.JSONDecodeError:
        return None
    return payload if isinstance(payload, dict) else None


def _clean_semantic_freeform(value: Any, *, limit: int) -> str:
    return clean_persona_text(str(value or ""), limit=limit).strip(" ,;")


def _clean_semantic_descriptors(value: Any) -> list[str]:
    if not isinstance(value, list):
        return []
    cleaned: list[str] = []
    seen: set[str] = set()
    for item in value:
        descriptor = _clean_semantic_freeform(item, limit=40)
        normalized = _normalize_tr_text(descriptor)
        if not descriptor or not normalized or normalized in seen:
            continue
        seen.add(normalized)
        cleaned.append(descriptor)
    return cleaned[:6]


def _build_onboarding_semantic_prompt(
    *,
    field: str,
    answer: str,
    next_question: dict[str, Any],
    profile: dict[str, Any],
    runtime_profile: dict[str, Any],
) -> str:
    current_communication_style = _truncate_for_prompt(str(profile.get("communication_style") or ""), 180) or "-"
    current_tone = _truncate_for_prompt(str(runtime_profile.get("tone") or ""), 120) or "-"
    current_role = _truncate_for_prompt(str(runtime_profile.get("role_summary") or ""), 160) or "-"
    current_soul_notes = _truncate_for_prompt(str(runtime_profile.get("soul_notes") or ""), 180) or "-"
    current_assistant_notes = _truncate_for_prompt(str(profile.get("assistant_notes") or ""), 180) or "-"
    question_text = str(next_question.get("question") or "").strip()
    help_text = str(next_question.get("help_text") or "").strip()
    return (
        "Türkçe çalışan bir kişisel asistan onboarding çözücüsüsün.\n"
        "Kullanıcının cevabını ön tanımlı etiket havuzuna zorlama. Gerekirse yeni Türkçe tanımlar üret.\n"
        "Yanıtı teknik sınıflandırma yerine doğal, kısa ve saklanabilir Türkçe ifadeye çevir.\n"
        "Yalnız JSON döndür. Açıklama, markdown veya kod bloğu ekleme.\n\n"
        f"Hedef alan: {field}\n"
        f"Soru: {question_text or '-'}\n"
        f"Yardım metni: {help_text or '-'}\n"
        f"Kullanıcı cevabı: {answer}\n\n"
        "Mevcut bağlam:\n"
        f"- İletişim tercihi: {current_communication_style}\n"
        f"- Konuşma tonu: {current_tone}\n"
        f"- Rol özeti: {current_role}\n"
        f"- Davranış notları: {current_soul_notes}\n"
        f"- Destek notları: {current_assistant_notes}\n\n"
        "JSON şeması:\n"
        "{\n"
        '  "assistant_name": "",\n'
        '  "tone": "",\n'
        '  "communication_style": "",\n'
        '  "assistant_notes": "",\n'
        '  "role_summary": "",\n'
        '  "soul_notes": "",\n'
        '  "new_descriptors": [],\n'
        '  "reason": ""\n'
        "}\n\n"
        "Kurallar:\n"
        "- assistant_name: Hedef alan assistant_name ise kullanıcının asistan için seçtiği kısa ve temiz adı yaz. Komut fiillerini, ekleri ve yönlendirme parçalarını dahil etme.\n"
        "- tone: Serbest Türkçe descriptor dizisi ya da kısa ifade olsun. Ön tanımlı bir listeye bağlı olma.\n"
        "- communication_style: Kullanıcının nasıl cevap istediğini anlatan doğal ve kısa bir Türkçe cümle olsun.\n"
        "- assistant_notes / role_summary / soul_notes: Yalnız cevaptan açıkça çıkıyorsa doldur, yoksa boş bırak.\n"
        "- new_descriptors: Cevaptan türetilen yeni veya önemli kavramları kısa Türkçe ifadeler halinde yaz.\n"
        "- reason: Bir kısa Türkçe açıklama yaz.\n"
        "- Hedef alanla ilgisiz alanları boş bırak.\n"
    )


def _extract_semantic_onboarding_values(
    *,
    field: str,
    answer: str,
    next_question: dict[str, Any],
    profile: dict[str, Any],
    runtime_profile: dict[str, Any],
    llm_service: LLMService | None,
) -> dict[str, Any] | None:
    if not llm_service or not getattr(llm_service, "enabled", False):
        return None
    completion = llm_service.complete(
        _build_onboarding_semantic_prompt(
            field=field,
            answer=answer,
            next_question=next_question,
            profile=profile,
            runtime_profile=runtime_profile,
        ),
        task="assistant_onboarding_semantic_extract",
        field=field,
    )
    if not completion:
        return None
    payload = _extract_json_object_from_text(str(completion.get("text") or ""))
    if not payload:
        return None
    descriptors = _clean_semantic_descriptors(payload.get("new_descriptors"))
    tone = _clean_semantic_freeform(payload.get("tone"), limit=120)
    if not tone and descriptors:
        tone = ", ".join(descriptors)[:120]
    result = {
        "assistant_name": _clean_semantic_freeform(payload.get("assistant_name"), limit=40),
        "tone": tone,
        "communication_style": _clean_semantic_freeform(payload.get("communication_style"), limit=220),
        "assistant_notes": normalize_profile_memory_notes(
            _clean_semantic_freeform(payload.get("assistant_notes"), limit=260)
        ),
        "role_summary": _clean_semantic_freeform(payload.get("role_summary"), limit=180),
        "soul_notes": _clean_semantic_freeform(payload.get("soul_notes"), limit=260),
        "new_descriptors": descriptors,
        "reason": _clean_semantic_freeform(payload.get("reason"), limit=180),
    }
    if not any(result.get(key) for key in ("assistant_name", "tone", "communication_style", "assistant_notes", "role_summary", "soul_notes")):
        return None
    return result


def _looks_like_semantic_memory_update_query(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    if not normalized:
        return False
    if "?" in query and not any(
        contains_normalized_phrase(normalized, marker)
        for marker in ("guncelle", "degistir", "kaydet", "olsun", "bundan sonra", "artik")
    ):
        return False
    identity_markers = (
        "adim",
        "ismim",
        "hitap",
        "bana",
        "benim",
        "ben",
    )
    preference_markers = (
        "tercih ederim",
        "tercih ediyorum",
        "severim",
        "seviyorum",
        "sevmem",
        "hoslanirim",
        "hoşlanırım",
        "istemem",
        "genelde",
    )
    assistant_markers = (
        "sen ",
        "asistan",
        "tonun",
        "rolun",
        "rolün",
        "davran",
        "komik ol",
        "net ol",
        "sicak ol",
        "sıcak ol",
    )
    mutation_markers = (
        "guncelle",
        "degistir",
        "kaydet",
        "olsun",
        "kalsin",
        "bundan sonra",
        "artik",
        "diye seslen",
        "diye hitap et",
        "diye hitap",
    )
    return bool(
        (
            any(contains_normalized_phrase(normalized, marker) for marker in identity_markers + assistant_markers)
            and any(contains_normalized_phrase(normalized, marker) for marker in mutation_markers)
        )
        or (
            any(contains_normalized_phrase(normalized, marker) for marker in preference_markers)
            and any(contains_normalized_phrase(normalized, marker) for marker in identity_markers + ("ulasim", "hava", "seyahat", "yemek", "renk", "harita", "konum"))
        )
    )


def _semantic_profile_field_supported_by_query(field: str, query: str) -> bool:
    normalized = _normalize_tr_text(query)
    if not normalized:
        return False

    identity_markers = ("ben", "bana", "benim", "adim", "ismim", "hitap")
    mutation_markers = (
        "guncelle",
        "degistir",
        "kaydet",
        "olsun",
        "kalsin",
        "bundan sonra",
        "artik",
        "diye seslen",
        "diye hitap",
    )
    preference_markers = (
        "tercih ederim",
        "tercih ediyorum",
        "severim",
        "seviyorum",
        "sevmem",
        "hoslanirim",
        "hoşlanırım",
        "istemem",
        "genelde",
    )

    has_identity = any(contains_normalized_phrase(normalized, marker) for marker in identity_markers)
    has_mutation = any(contains_normalized_phrase(normalized, marker) for marker in mutation_markers)
    has_preference = any(contains_normalized_phrase(normalized, marker) for marker in preference_markers)

    if field == "display_name":
        return bool(extract_explicit_user_name_update(query)) or (has_identity and has_mutation)

    if field == "favorite_color":
        return has_identity and has_preference and any(
            contains_normalized_phrase(normalized, marker)
            for marker in ("renk", "favori renk", "sevdigim renk", "sevdigim")
        )

    if field == "food_preferences":
        return has_identity and has_preference and any(
            contains_normalized_phrase(normalized, marker)
            for marker in ("yemek", "kahve", "cay", "çay", "pizza", "burger", "tatli", "tatlı", "vegan", "vejetaryen")
        )

    if field == "transport_preference":
        return has_identity and has_preference and any(
            contains_normalized_phrase(normalized, marker)
            for marker in ("ulasim", "ulaşım", "ucak", "uçak", "otobus", "otobüs", "tren", "metro", "araba", "taksi", "vapur", "bisiklet")
        )

    if field == "weather_preference":
        return has_identity and has_preference and any(
            contains_normalized_phrase(normalized, marker)
            for marker in ("hava", "iklim", "gunesli", "güneşli", "serin", "soguk", "soğuk", "yagmurlu", "yağmurlu")
        )

    if field == "travel_preferences":
        return has_identity and has_preference and any(
            contains_normalized_phrase(normalized, marker)
            for marker in ("seyahat", "yolculuk", "bilet", "ucus", "uçuş", "otel", "konaklama", "cam kenari", "cam kenarı")
        )

    if field == "communication_style":
        return has_identity and (
            has_preference
            or has_mutation
            or any(
                contains_normalized_phrase(normalized, marker)
                for marker in ("iletisim", "iletişim", "uslup", "üslup", "cevap", "yanit", "yanıt")
            )
        )

    if field == "assistant_notes":
        return has_identity and any(
            contains_normalized_phrase(normalized, marker)
            for marker in ("profil notu", "not et", "aklinda tut", "yardim notu", "destek notu")
        )

    if field in {"home_base", "current_location", "location_preferences"}:
        location_markers = (
            "konumum",
            "konum",
            "bulundugum",
            "bulunduğum",
            "yasiyorum",
            "yaşıyorum",
            "yasadigim",
            "yaşadığım",
            "ikamet",
            "evim",
            "ana us",
            "ana üs",
            "yasam noktam",
            "yaşam noktam",
            "yakin cevrem",
            "yakın çevrem",
            "mahallem",
            "civarim",
            "civarım",
        )
        extra_location_updates = ("su an", "şu an", "buradayim", "buradayım", "burada yasiyorum", "burada yaşıyorum")
        return has_identity and any(
            contains_normalized_phrase(normalized, marker) for marker in location_markers
        ) and (
            has_mutation
            or field == "current_location"
            and any(contains_normalized_phrase(normalized, marker) for marker in extra_location_updates)
        )

    if field == "maps_preference":
        return has_identity and (
            has_mutation or has_preference
        ) and any(
            contains_normalized_phrase(normalized, marker)
            for marker in ("harita", "maps", "google maps", "apple maps", "yandex", "waze")
        )

    return True


def _build_chat_memory_semantic_prompt(
    *,
    query: str,
    profile: dict[str, Any],
    runtime_profile: dict[str, Any],
) -> str:
    current_name = _truncate_for_prompt(str(profile.get("display_name") or ""), 80) or "-"
    current_communication_style = _truncate_for_prompt(str(profile.get("communication_style") or ""), 180) or "-"
    current_transport = _truncate_for_prompt(str(profile.get("transport_preference") or ""), 140) or "-"
    current_food = _truncate_for_prompt(str(profile.get("food_preferences") or ""), 140) or "-"
    current_weather = _truncate_for_prompt(str(profile.get("weather_preference") or ""), 140) or "-"
    current_travel = _truncate_for_prompt(str(profile.get("travel_preferences") or ""), 140) or "-"
    current_location = _truncate_for_prompt(str(profile.get("current_location") or profile.get("home_base") or ""), 140) or "-"
    current_assistant_name = _truncate_for_prompt(str(runtime_profile.get("assistant_name") or ""), 80) or "-"
    current_tone = _truncate_for_prompt(str(runtime_profile.get("tone") or ""), 120) or "-"
    current_role = _truncate_for_prompt(str(runtime_profile.get("role_summary") or ""), 160) or "-"
    return (
        "Türkçe çalışan bir kişisel asistan hafıza güncelleme çözücüsüsün.\n"
        "Kullanıcının mesajından yalnız gerçekten saklanması gereken profil veya asistan ayarı değişikliklerini çıkar.\n"
        "Yalnız JSON döndür. Açıklama, markdown veya kod bloğu ekleme.\n\n"
        f"Kullanıcı mesajı: {query}\n\n"
        "Mevcut kullanıcı profili:\n"
        f"- hitap adı: {current_name}\n"
        f"- sana karşı üslup tercihi: {current_communication_style}\n"
        f"- ulaşım tercihi: {current_transport}\n"
        f"- yemek tercihi: {current_food}\n"
        f"- hava tercihi: {current_weather}\n"
        f"- seyahat tercihi: {current_travel}\n"
        f"- konum bilgisi: {current_location}\n\n"
        "Mevcut asistan ayarları:\n"
        f"- asistan adı: {current_assistant_name}\n"
        f"- konuşma tonu: {current_tone}\n"
        f"- rol özeti: {current_role}\n\n"
        "JSON şeması:\n"
        "{\n"
        '  "user_profile": {\n'
        '    "display_name": "",\n'
        '    "favorite_color": "",\n'
        '    "food_preferences": "",\n'
        '    "transport_preference": "",\n'
        '    "weather_preference": "",\n'
        '    "travel_preferences": "",\n'
        '    "communication_style": "",\n'
        '    "assistant_notes": "",\n'
        '    "home_base": "",\n'
        '    "current_location": "",\n'
        '    "location_preferences": "",\n'
        '    "maps_preference": ""\n'
        "  },\n"
        '  "assistant_profile": {\n'
        '    "assistant_name": "",\n'
        '    "tone": "",\n'
        '    "role_summary": "",\n'
        '    "soul_notes": "",\n'
        '    "tools_notes": ""\n'
        "  },\n"
        '  "reason": ""\n'
        "}\n\n"
        "Kurallar:\n"
        "- Kullanıcı kendisiyle ilgili bir tercih söylüyorsa user_profile alanlarını doldur.\n"
        "- Kullanıcı asistanın nasıl davranmasını istediğini söylüyorsa assistant_profile alanlarını doldur.\n"
        "- 'Bana Kenan diye seslen', 'Artık bana Kenan de' gibi ifadelerde user_profile.display_name alanını doldur.\n"
        "- 'İsmimi Sami olarak değiştir, yanlış girmişsin' gibi cümlelerde yalnız seçilen adı yaz: Sami. Yakınma veya yorum parçalarını isim diye yazma.\n"
        "- 'Komik ol, net ol, daha sıcak davran' gibi ifadeleri user_profile.communication_style alanına yazma; assistant_profile.tone veya soul_notes alanına yaz.\n"
        "- Soru, genel sohbet veya operasyonel bir komutsa alanları boş bırak.\n"
        "- Açık olmayan çıkarım yapma. Emin değilsen boş bırak.\n"
        "- Alan değerleri kısa, doğal ve kayda uygun Türkçe olsun.\n"
    )


def _extract_semantic_chat_memory_values(
    *,
    query: str,
    profile: dict[str, Any],
    runtime_profile: dict[str, Any],
    llm_service: LLMService | None,
) -> dict[str, Any] | None:
    if not _looks_like_semantic_memory_update_query(query):
        return None
    if not llm_service or not getattr(llm_service, "enabled", False):
        return None
    completion = llm_service.complete(
        _build_chat_memory_semantic_prompt(
            query=query,
            profile=profile,
            runtime_profile=runtime_profile,
        ),
        task="assistant_chat_memory_semantic_extract",
    )
    if not completion:
        return None
    payload = _extract_json_object_from_text(str(completion.get("text") or ""))
    if not payload:
        return None

    raw_profile = payload.get("user_profile") if isinstance(payload.get("user_profile"), dict) else {}
    raw_runtime = payload.get("assistant_profile") if isinstance(payload.get("assistant_profile"), dict) else {}

    profile_limits = {
        "display_name": 40,
        "favorite_color": 40,
        "food_preferences": 180,
        "transport_preference": 180,
        "weather_preference": 180,
        "travel_preferences": 180,
        "communication_style": 220,
        "assistant_notes": 260,
        "home_base": 120,
        "current_location": 120,
        "location_preferences": 180,
        "maps_preference": 80,
    }
    runtime_limits = {
        "assistant_name": 40,
        "tone": 120,
        "role_summary": 180,
        "soul_notes": 260,
        "tools_notes": 260,
    }

    cleaned_profile: dict[str, str] = {}
    for field, limit in profile_limits.items():
        value = _clean_semantic_freeform(raw_profile.get(field), limit=limit)
        if not value:
            continue
        if not _semantic_profile_field_supported_by_query(field, query):
            continue
        if field == "assistant_notes":
            value = normalize_profile_memory_notes(value)
        else:
            value = compact_user_profile_value(field, value)
        if value:
            cleaned_profile[field] = value

    cleaned_runtime: dict[str, str] = {}
    for field, limit in runtime_limits.items():
        value = _clean_semantic_freeform(raw_runtime.get(field), limit=limit)
        if not value:
            continue
        if field in {"soul_notes", "tools_notes"}:
            value = clean_persona_text(value, limit=limit)
        else:
            value = compact_assistant_profile_value(field, value)
        if value:
            cleaned_runtime[field] = value

    explicit_display_name = extract_explicit_user_name_update(query)
    if explicit_display_name:
        cleaned_profile["display_name"] = explicit_display_name

    explicit_assistant_name = extract_explicit_assistant_name_update(query)
    if explicit_assistant_name:
        cleaned_runtime["assistant_name"] = explicit_assistant_name

    if not cleaned_profile and not cleaned_runtime:
        return None
    return {
        "profile_patch": cleaned_profile,
        "runtime_patch": cleaned_runtime,
        "reason": _clean_semantic_freeform(payload.get("reason"), limit=180),
    }


def _merge_memory_updates(*update_groups: list[dict[str, Any]]) -> list[dict[str, Any]]:
    merged: list[dict[str, Any]] = []
    seen: set[tuple[str, tuple[str, ...], str]] = set()
    for group in update_groups:
        for item in group or []:
            kind = str(item.get("kind") or "").strip()
            fields = tuple(sorted(str(field).strip() for field in list(item.get("fields") or []) if str(field).strip()))
            summary = str(item.get("summary") or "").strip()
            key = (kind, fields, summary)
            if key in seen:
                continue
            seen.add(key)
            merged.append(item)
    return merged


def _capture_semantic_chat_memory_update(
    query: str,
    *,
    settings,
    store: Persistence,
    llm_service: LLMService | None,
    memory_service: MemoryService,
) -> list[dict[str, Any]]:
    profile = store.get_user_profile(settings.office_id) or _empty_profile_payload(settings.office_id)
    runtime_profile = store.get_assistant_runtime_profile(settings.office_id) or _empty_assistant_runtime_profile_payload(settings.office_id)
    semantic_values = _extract_semantic_chat_memory_values(
        query=query,
        profile=profile,
        runtime_profile=runtime_profile,
        llm_service=llm_service,
    )
    if not semantic_values:
        return []

    updates: list[dict[str, Any]] = []

    profile_patch = {
        "display_name": profile.get("display_name"),
        "favorite_color": profile.get("favorite_color"),
        "food_preferences": profile.get("food_preferences"),
        "transport_preference": profile.get("transport_preference"),
        "weather_preference": profile.get("weather_preference"),
        "travel_preferences": profile.get("travel_preferences"),
        "home_base": profile.get("home_base"),
        "current_location": profile.get("current_location"),
        "location_preferences": profile.get("location_preferences"),
        "maps_preference": profile.get("maps_preference"),
        "prayer_notifications_enabled": profile.get("prayer_notifications_enabled"),
        "prayer_habit_notes": profile.get("prayer_habit_notes"),
        "communication_style": profile.get("communication_style"),
        "assistant_notes": profile.get("assistant_notes"),
        "important_dates": profile.get("important_dates") or [],
        "related_profiles": profile.get("related_profiles") or [],
        "inbox_watch_rules": profile.get("inbox_watch_rules") or [],
        "inbox_keyword_rules": profile.get("inbox_keyword_rules") or [],
        "inbox_block_rules": profile.get("inbox_block_rules") or [],
        "source_preference_rules": profile.get("source_preference_rules") or [],
    }
    profile_changes: dict[str, Any] = {}
    for field, value in dict(semantic_values.get("profile_patch") or {}).items():
        next_value = value
        if field == "assistant_notes":
            next_value = merge_profile_memory_note(profile_patch.get("assistant_notes"), value)
            next_value = normalize_profile_memory_notes(next_value)
        if next_value == profile_patch.get(field):
            continue
        profile_patch[field] = next_value
        profile_changes[field] = next_value
    if profile_changes:
        saved_profile = store.upsert_user_profile(settings.office_id, **profile_patch)
        changed_fields = memory_service._changed_fields(profile_changes, profile)
        if changed_fields:
            updates.append(
                {
                    "kind": "profile_signal",
                    "status": "stored",
                    "summary": memory_service._memory_update_summary("profile_signal", changed_fields),
                    "fields": changed_fields,
                    "route": memory_service._settings_route_for_update("profile_signal", changed_fields),
                    "action": "open_settings",
                    "action_label": "Ayarı aç",
                    "updated_at": saved_profile.get("updated_at"),
                    "profile_reconciliation": memory_service._reconcile_profile(saved_profile, reason="semantic_chat_profile_signal"),
                }
            )
        profile = saved_profile

    runtime_patch = {
        "assistant_name": runtime_profile.get("assistant_name"),
        "role_summary": runtime_profile.get("role_summary"),
        "tone": runtime_profile.get("tone"),
        "avatar_path": runtime_profile.get("avatar_path"),
        "soul_notes": runtime_profile.get("soul_notes"),
        "tools_notes": runtime_profile.get("tools_notes"),
        "assistant_forms": runtime_profile.get("assistant_forms") or [],
        "behavior_contract": runtime_profile.get("behavior_contract") or {},
        "evolution_history": runtime_profile.get("evolution_history") or [],
        "heartbeat_extra_checks": runtime_profile.get("heartbeat_extra_checks") or [],
    }
    runtime_changes: dict[str, Any] = {}
    for field, value in dict(semantic_values.get("runtime_patch") or {}).items():
        next_value = value
        if field == "tone":
            next_value = merge_assistant_tone(runtime_patch.get("tone"), value)
        elif field in {"soul_notes", "tools_notes"}:
            next_value = append_unique_note(str(runtime_patch.get(field) or ""), value)
        if next_value == runtime_patch.get(field):
            continue
        runtime_patch[field] = next_value
        runtime_changes[field] = next_value
    if runtime_changes:
        saved_runtime = store.upsert_assistant_runtime_profile(settings.office_id, **runtime_patch)
        changed_fields = memory_service._changed_fields(runtime_changes, runtime_profile)
        if changed_fields:
            updates.append(
                {
                    "kind": "assistant_persona_signal",
                    "status": "stored",
                    "summary": memory_service._memory_update_summary("assistant_persona_signal", changed_fields),
                    "fields": changed_fields,
                    "route": memory_service._settings_route_for_update("assistant_persona_signal", changed_fields),
                    "action": "open_settings",
                    "action_label": "Ayarı aç",
                    "updated_at": saved_runtime.get("updated_at"),
                }
            )

    return updates


def _identity_snapshot_kind(query: str) -> str | None:
    normalized = _normalize_tr_text(query)
    if not normalized:
        return None
    asks_user_name = any(
        re.search(pattern, normalized)
        for pattern in (
            r"\b(?:adim|adım|ismim|hitabim|hitabım)\s+ne(?:dir|ydi)?\b",
            r"\bbana\s+ne\s+diye\s+hitap\b",
            r"\bbana\s+nasil\s+hitap\b",
        )
    )
    asks_assistant_name = any(
        re.search(pattern, normalized)
        for pattern in (
            r"\b(?:senin\s+)?(?:adin|adın|ismin)\s+ne(?:dir|ydi)?\b",
            r"\basistan(?:in|ın)?\s+adi\s+ne(?:dir|ydi)?\b",
        )
    )
    if asks_user_name and asks_assistant_name:
        return "both"
    if asks_user_name:
        return "user"
    if asks_assistant_name:
        return "assistant"
    return None


def _should_bypass_fast_assistant_reply(query: str) -> bool:
    if _identity_snapshot_kind(query):
        return True
    if _is_profile_correction_query(query):
        return True
    return _looks_like_semantic_memory_update_query(query)


def _compose_identity_snapshot_reply(
    query: str,
    *,
    settings,
    store: Persistence,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict[str, Any]] | None,
) -> dict[str, Any] | None:
    kind = _identity_snapshot_kind(query)
    if not kind:
        return None
    profile = store.get_user_profile(settings.office_id) or _empty_profile_payload(settings.office_id)
    runtime_profile = store.get_assistant_runtime_profile(settings.office_id) or _empty_assistant_runtime_profile_payload(settings.office_id)
    display_name = str(profile.get("display_name") or "").strip()
    assistant_name = str(runtime_profile.get("assistant_name") or "LawCopilot").strip() or "LawCopilot"
    lines: list[str] = []
    if kind in {"user", "both"}:
        if display_name:
            lines.append(f"Sana şu an {display_name} diye hitap edecek şekilde kayıtlıyım.")
        else:
            lines.append("Sana hitap adı için henüz net bir kayıt yok.")
    if kind in {"assistant", "both"}:
        lines.append(f"Benim adım şu an {assistant_name}.")
    return {
        "content": " ".join(lines).strip(),
        "assistant_summary": "",
        "tool_suggestions": [],
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_identity_snapshot",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "source_refs": source_refs or [],
            "identity_snapshot": {
                "display_name": display_name,
                "assistant_name": assistant_name,
            },
        },
    }


def _memory_update_details(memory_updates: list[dict[str, Any]], *, settings, store: Persistence) -> list[str]:
    if not memory_updates:
        return []

    profile = store.get_user_profile(settings.office_id) or _empty_profile_payload(settings.office_id)
    runtime_profile = store.get_assistant_runtime_profile(settings.office_id) or _empty_assistant_runtime_profile_payload(settings.office_id)

    def quoted(value: str | None, max_len: int = 140) -> str:
        text = _truncate_for_prompt(str(value or "").replace('"', "'"), max_len).strip()
        return f'"{text}"' if text else ""

    def detail_for_field(field: str) -> str:
        if field == "assistant_name":
            value = quoted(runtime_profile.get("assistant_name"), 80)
            return f"asistan adım {value}" if value else ""
        if field == "role_summary":
            value = quoted(runtime_profile.get("role_summary"), 120)
            return f"asistan rolü {value}" if value else ""
        if field == "tone":
            value = quoted(runtime_profile.get("tone"), 120)
            return f"konuşma tonum {value}" if value else ""
        if field == "soul_notes":
            value = quoted(runtime_profile.get("soul_notes"), 160)
            return f"davranış sınırlarım {value}" if value else ""
        if field == "avatar_path":
            value = quoted(runtime_profile.get("avatar_path"), 200)
            return f"avatar yolu {value}" if value else ""
        if field == "tools_notes":
            value = quoted(runtime_profile.get("tools_notes"), 180)
            return f"rutin notlarım {value}" if value else ""
        if field == "assistant_forms":
            active_forms = [
                str(item.get("title") or item.get("slug") or "").strip()
                for item in list(runtime_profile.get("assistant_forms") or [])
                if isinstance(item, dict) and item.get("active")
            ]
            if active_forms:
                return f"aktif asistan formlarim \"{'; '.join(active_forms[:4])}\""
            return "aktif asistan formum"
        if field == "behavior_contract":
            contract = dict(runtime_profile.get("behavior_contract") or {})
            contract_bits = [
                f"proaktiflik={contract.get('initiative_level')}",
                f"takip={contract.get('follow_up_style')}",
                f"plan={contract.get('planning_depth')}",
            ]
            return f"çalışma kontratım \"{', '.join(contract_bits)}\""
        if field == "heartbeat_extra_checks":
            checks = [str(item).strip() for item in list(runtime_profile.get("heartbeat_extra_checks") or []) if str(item).strip()]
            if checks:
                return f"heartbeat kontrollerim \"{'; '.join(checks[:4])}\""
            return ""
        if field == "display_name":
            value = quoted(profile.get("display_name"), 80)
            return f"bundan sonra sana {value} diye hitap edeceğim" if value else ""
        if field == "favorite_color":
            value = quoted(profile.get("favorite_color"), 60)
            return f"sevdiğin renk {value}" if value else ""
        if field == "communication_style":
            value = quoted(profile.get("communication_style"), 160)
            return f"iletişim tercihin {value}" if value else ""
        if field == "assistant_notes":
            value = quoted(profile.get("assistant_notes"), 180)
            return f"destek önceliğin {value}" if value else ""
        if field == "transport_preference":
            value = quoted(profile.get("transport_preference"), 140)
            return f"ulaşım tercihin {value}" if value else ""
        if field == "weather_preference":
            value = quoted(profile.get("weather_preference"), 140)
            return f"hava tercihin {value}" if value else ""
        if field == "food_preferences":
            value = quoted(profile.get("food_preferences"), 140)
            return f"yeme içme tercihin {value}" if value else ""
        if field == "travel_preferences":
            value = quoted(profile.get("travel_preferences"), 140)
            return f"seyahat tercihin {value}" if value else ""
        return ""

    details: list[str] = []
    seen: set[str] = set()
    for update in memory_updates:
        kind = str(update.get("kind") or "").strip()
        if kind == "automation_signal":
            summary = str(update.get("summary") or "").strip().rstrip(".")
            if summary and summary not in seen:
                seen.add(summary)
                details.append(summary)
        for field in update.get("fields") or []:
            detail = detail_for_field(str(field or ""))
            if not detail or detail in seen:
                continue
            seen.add(detail)
            details.append(detail)
    return details


def _memory_update_acknowledgement(memory_updates: list[dict[str, Any]], *, settings, store: Persistence) -> str:
    details = _memory_update_details(memory_updates, settings=settings, store=store)
    if not details:
        return "Kaydettim."
    if len(details) == 1:
        return f"Şunu kaydettim: {details[0]}."
    return "Şunları kaydettim: " + "; ".join(details) + "."


def _summarize_recent_user_intent(message: str) -> str:
    text = str(message or "").strip()
    if not text:
        return ""
    normalized = _normalize_tr_text(text)

    if any(token in normalized for token in ("adın", "adin", "ismin")):
        assistant_name = compact_assistant_profile_value("assistant_name", text)
        if assistant_name:
            return f"asistanın adının sadece {assistant_name} olmasını"

    if any(token in normalized for token in ("adım", "adim", "ismim")):
        display_name = compact_user_profile_value("display_name", text)
        if display_name:
            return f"sana {display_name} diye hitap edilmesini"

    return f'şunu netleştirmeye çalışıyordun: "{_truncate_for_prompt(text, 160)}"'


def _maybe_compose_context_audit_reply(
    query: str,
    *,
    prior_messages: list[dict],
    home: dict[str, Any],
    settings,
    store: Persistence,
) -> dict[str, Any] | None:
    if not _is_context_audit_query(query):
        return None

    normalized = _normalize_tr_text(query)
    last_assistant = _last_message_by_role(prior_messages, "assistant")
    last_user = _last_message_by_role(prior_messages, "user")
    source_context = dict((last_assistant or {}).get("source_context") or {})
    recent_updates = _recent_thread_memory_updates(prior_messages)
    specific_memory_audit = any(
        token in normalized
        for token in (
            "neyi kaydettin",
            "ne kaydettin",
            "neleri kaydettin",
            "neyi guncelledin",
            "neyi güncelledin",
            "neleri guncelledin",
            "neleri güncelledin",
            "neyi degistirdin",
            "neyi değiştirdin",
            "neleri degistirdin",
            "neleri değiştirdin",
            "bellege ne ekledin",
            "belleğe ne ekledin",
            "bellege ne yazdin",
            "belleğe ne yazdın",
            "bellek guncellemesi neydi",
            "bellek güncellemesi neydi",
            "profil notuna ne yazdin",
            "profil notuna ne yazdın",
            "destek notuna ne yazdin",
            "destek notuna ne yazdın",
        )
    )

    if specific_memory_audit:
        details = _memory_update_details(recent_updates, settings=settings, store=store)
        if details:
            content = "Bir önceki adımda şunu kaydettim: " + "; ".join(details) + "."
        elif recent_updates:
            content = "Bir önceki adımda bir bellek güncellemesi tetiklendi ama çözümlenen alanı net çıkaramadım."
        elif last_assistant and str(last_assistant.get("generated_from") or "") == "assistant_thread_memory":
            content = "Bir önceki mesajımda bellek güncellemesi yaptığımı söyledim ama arkasında saklanan alan bilgisi yoktu."
        else:
            content = "Bir önceki adımda belleğe yeni bir bilgi yazmadım."
    else:
        previous_user_text = str((last_user or {}).get("content") or "").strip()
        if not previous_user_text:
            return None
        summary = _summarize_recent_user_intent(previous_user_text)
        if summary.startswith("şunu netleştirmeye çalışıyordun:"):
            content = f"Bir önceki mesajında {summary}."
        else:
            content = f"Bir önceki mesajında {summary} netleştirmeye çalışıyordun."

    return {
        "content": content.strip(),
        "assistant_summary": home.get("today_summary") or "",
        "tool_suggestions": [],
        "linked_entities": [],
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_context_repair",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "priority_items": home.get("priority_items") or [],
            "requires_setup": home.get("requires_setup") or [],
            "memory_updates": recent_updates,
        },
    }


def _capture_direct_onboarding_answer(
    query: str,
    *,
    onboarding_state: dict[str, object],
    prior_messages: list[dict[str, object]],
    settings,
    store: Persistence,
    llm_service: LLMService | None = None,
) -> list[dict[str, Any]]:
    if bool(onboarding_state.get("complete")) or bool(onboarding_state.get("blocked_by_setup")):
        return []

    next_questions = list(onboarding_state.get("next_questions") or [])
    if not next_questions:
        return []
    next_question = next_questions[0]
    field = str(next_question.get("field") or "").strip()
    if not field:
        return []

    last_assistant = next(
        (
            message
            for message in reversed(prior_messages)
            if str(message.get("role") or "") == "assistant"
        ),
        None,
    )
    if not last_assistant or str(last_assistant.get("generated_from") or "") != "assistant_onboarding_guide":
        return []

    normalized = _normalize_tr_text(query)
    if _is_operational_task_request(query):
        if field == "assistant_notes" and _looks_like_support_preference_answer(query):
            pass
        elif _looks_like_profile_preference_answer(field, query):
            pass
        else:
            return []

    if field == "assistant_notes" and not _looks_like_support_preference_answer(query):
        return []

    answer = _clean_onboarding_answer(query)
    if not answer:
        return []

    if "?" in answer and len(answer.split()) > 3:
        return []

    runtime_profile = store.get_assistant_runtime_profile(settings.office_id) or _empty_assistant_runtime_profile_payload(settings.office_id)
    profile = store.get_user_profile(settings.office_id) or _empty_profile_payload(settings.office_id)
    semantic_values = _extract_semantic_onboarding_values(
        field=field,
        answer=answer,
        next_question=next_question,
        profile=profile,
        runtime_profile=runtime_profile,
        llm_service=llm_service,
    )

    if field == "assistant_name":
        compacted_name = str((semantic_values or {}).get("assistant_name") or "").strip()
        if not compacted_name:
            compacted_name = compact_assistant_profile_value(field, answer)
        if not compacted_name:
            return []
        saved = store.upsert_assistant_runtime_profile(
            settings.office_id,
            assistant_name=compacted_name,
            role_summary=runtime_profile.get("role_summary"),
            tone=runtime_profile.get("tone"),
            avatar_path=runtime_profile.get("avatar_path"),
            soul_notes=runtime_profile.get("soul_notes"),
            tools_notes=runtime_profile.get("tools_notes"),
            assistant_forms=runtime_profile.get("assistant_forms") or [],
            behavior_contract=runtime_profile.get("behavior_contract") or {},
            evolution_history=runtime_profile.get("evolution_history") or [],
            heartbeat_extra_checks=runtime_profile.get("heartbeat_extra_checks") or [],
        )
        return [
            {
                "kind": "assistant_persona_signal",
                "status": "stored",
                "summary": "Asistan adı kaydedildi.",
                "fields": ["assistant_name"],
                "updated_at": saved.get("updated_at"),
            }
        ]

    if field == "interaction_style":
        communication_style = str((semantic_values or {}).get("communication_style") or "").strip()
        tone = str((semantic_values or {}).get("tone") or "").strip()
        if not tone:
            tone = compact_assistant_profile_value("tone", answer) or merge_assistant_tone(runtime_profile.get("tone"), answer)
        semantic_behavior_note = str((semantic_values or {}).get("soul_notes") or "").strip()
        if not semantic_behavior_note:
            semantic_behavior_note = str((semantic_values or {}).get("assistant_notes") or "").strip()
        if not tone and not semantic_behavior_note and not communication_style:
            return []
        runtime_patch = {
            "assistant_name": runtime_profile.get("assistant_name"),
            "role_summary": runtime_profile.get("role_summary"),
            "tone": tone or runtime_profile.get("tone"),
            "avatar_path": runtime_profile.get("avatar_path"),
            "soul_notes": runtime_profile.get("soul_notes"),
            "tools_notes": runtime_profile.get("tools_notes"),
            "assistant_forms": runtime_profile.get("assistant_forms") or [],
            "behavior_contract": runtime_profile.get("behavior_contract") or {},
            "evolution_history": runtime_profile.get("evolution_history") or [],
            "heartbeat_extra_checks": runtime_profile.get("heartbeat_extra_checks") or [],
        }
        if semantic_behavior_note:
            runtime_patch["soul_notes"] = _append_profile_note(runtime_profile.get("soul_notes"), semantic_behavior_note)
        saved_runtime = store.upsert_assistant_runtime_profile(settings.office_id, **runtime_patch)
        stored_fields = ["tone"]
        if semantic_behavior_note:
            stored_fields.append("soul_notes")
        return [
            {
                "kind": "interaction_style_signal",
                "status": "stored",
                "summary": "Asistan davranışı ve üslup tercihi kaydedildi.",
                "fields": stored_fields,
                "updated_at": saved_runtime.get("updated_at"),
            }
        ]

    if field in {"tone", "soul_notes", "role_summary"}:
        patch = {
            "assistant_name": runtime_profile.get("assistant_name"),
            "role_summary": runtime_profile.get("role_summary"),
            "tone": runtime_profile.get("tone"),
            "avatar_path": runtime_profile.get("avatar_path"),
            "soul_notes": runtime_profile.get("soul_notes"),
            "tools_notes": runtime_profile.get("tools_notes"),
            "assistant_forms": runtime_profile.get("assistant_forms") or [],
            "behavior_contract": runtime_profile.get("behavior_contract") or {},
            "evolution_history": runtime_profile.get("evolution_history") or [],
            "heartbeat_extra_checks": runtime_profile.get("heartbeat_extra_checks") or [],
        }
        compacted_value = str((semantic_values or {}).get(field) or "").strip()
        if not compacted_value:
            compacted_value = compact_assistant_profile_value(field, answer)
        if not compacted_value:
            return []
        if field == "soul_notes":
            patch[field] = _append_profile_note(runtime_profile.get(field), compacted_value)
        elif field == "tone":
            patch[field] = compacted_value
        else:
            patch[field] = compacted_value
        saved = store.upsert_assistant_runtime_profile(settings.office_id, **patch)
        return [
            {
                "kind": "assistant_persona_signal",
                "status": "stored",
                "summary": "Asistan kimliği güncellendi.",
                "fields": [field],
                "updated_at": saved.get("updated_at"),
            }
        ]

    if field in {
        "display_name",
        "favorite_color",
        "food_preferences",
        "transport_preference",
        "weather_preference",
        "travel_preferences",
        "home_base",
        "current_location",
        "location_preferences",
        "maps_preference",
        "prayer_habit_notes",
        "communication_style",
        "assistant_notes",
    }:
        patch = {
            "display_name": profile.get("display_name"),
            "favorite_color": profile.get("favorite_color"),
            "food_preferences": profile.get("food_preferences"),
            "transport_preference": profile.get("transport_preference"),
            "weather_preference": profile.get("weather_preference"),
            "travel_preferences": profile.get("travel_preferences"),
            "home_base": profile.get("home_base"),
            "current_location": profile.get("current_location"),
            "location_preferences": profile.get("location_preferences"),
            "maps_preference": profile.get("maps_preference"),
            "prayer_notifications_enabled": bool(profile.get("prayer_notifications_enabled")),
            "prayer_habit_notes": profile.get("prayer_habit_notes"),
            "communication_style": profile.get("communication_style"),
            "assistant_notes": profile.get("assistant_notes"),
            "important_dates": profile.get("important_dates") or [],
            "related_profiles": profile.get("related_profiles") or [],
        }
        compacted_value = str((semantic_values or {}).get(field) or "").strip()
        if not compacted_value:
            compacted_value = compact_user_profile_value(field, answer)
        if not compacted_value:
            return []
        if field == "assistant_notes":
            patch[field] = _append_user_profile_note(profile.get(field), compacted_value)
        else:
            patch[field] = compacted_value
        patch["assistant_notes"] = normalize_profile_memory_notes(patch["assistant_notes"])
        saved = store.upsert_user_profile(settings.office_id, **patch)
        profile_reconciliation = None
        memory_mutations = getattr(store, "_memory_mutations", None)
        if memory_mutations is not None:
            try:
                profile_reconciliation = memory_mutations.reconcile_user_profile(
                    profile=saved,
                    authority="profile",
                    reason=f"assistant_onboarding_field:{field}",
                )
            except Exception:  # noqa: BLE001
                profile_reconciliation = None
        return [
            {
                "kind": "profile_signal",
                "status": "stored",
                "summary": "Kullanıcı profiline yeni bilgi işlendi.",
                "fields": [field],
                "updated_at": saved.get("updated_at"),
                "profile_reconciliation": profile_reconciliation,
            }
        ]

    return []


def _safe_local_timezone():
    return datetime.now().astimezone().tzinfo or timezone.utc


def _month_number(value: str) -> int | None:
    months = {
        "ocak": 1,
        "subat": 2,
        "mart": 3,
        "nisan": 4,
        "mayis": 5,
        "haziran": 6,
        "temmuz": 7,
        "agustos": 8,
        "eylul": 9,
        "ekim": 10,
        "kasim": 11,
        "aralik": 12,
    }
    return months.get(_normalize_tr_text(value))


def _calendar_event_cues(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    cues = [
        "takvime ekle",
        "ajandaya ekle",
        "isim var",
        "toplantim",
        "toplanti var",
        "toplanti",
        "gorusmem",
        "gorusme var",
        "gorusme",
        "durusmam",
        "durusma",
        "randevum",
        "randevu",
        "seyahatim",
        "seyahat",
        "ucusum",
        "ucus",
        "dogum gunu",
        "donum",
        "planim var",
        "etkinlik",
        "gidecegim",
        "orada olacagim",
        "hatirlat",
    ]
    return any(token in normalized for token in cues)


def _extract_calendar_candidate(query: str, *, now: datetime | None = None) -> dict | None:
    if not _calendar_event_cues(query):
        return None

    local_now = (now or datetime.now(_safe_local_timezone())).astimezone(_safe_local_timezone())
    normalized = _normalize_tr_text(query)
    matched_fragments: list[str] = []
    target_date: date | None = None

    iso_match = re.search(r"\b(20\d{2})-(\d{2})-(\d{2})\b", query)
    if iso_match:
        try:
            target_date = date(int(iso_match.group(1)), int(iso_match.group(2)), int(iso_match.group(3)))
            matched_fragments.append(iso_match.group(0))
        except ValueError:
            target_date = None

    if target_date is None:
        dotted_match = re.search(r"\b(\d{1,2})[./](\d{1,2})[./](\d{2,4})\b", query)
        if dotted_match:
            year = int(dotted_match.group(3))
            if year < 100:
                year += 2000
            try:
                target_date = date(year, int(dotted_match.group(2)), int(dotted_match.group(1)))
                matched_fragments.append(dotted_match.group(0))
            except ValueError:
                target_date = None

    if target_date is None:
        month_match = re.search(
            r"\b(\d{1,2})\s+(ocak|subat|mart|nisan|mayis|haziran|temmuz|agustos|eylul|ekim|kasim|aralik)(?:['’]?[dt][ae])?(?:\s+(20\d{2}))?\b",
            normalized,
        )
        if month_match:
            year = int(month_match.group(3)) if month_match.group(3) else local_now.year
            month_number = _month_number(month_match.group(2))
            if month_number:
                try:
                    target_date = date(year, month_number, int(month_match.group(1)))
                    matched_fragments.append(month_match.group(0))
                except ValueError:
                    target_date = None

    if target_date is None:
        if "obur gun" in normalized:
            target_date = (local_now + timedelta(days=2)).date()
            matched_fragments.append("öbür gün")
        elif "yarin" in normalized:
            target_date = (local_now + timedelta(days=1)).date()
            matched_fragments.append("yarın")
        elif "bugun" in normalized:
            target_date = local_now.date()
            matched_fragments.append("bugün")

    if target_date is None:
        return None

    time_match = re.search(r"\bsaat\s*(\d{1,2})[:.](\d{2})\b", normalized)
    if not time_match:
        time_match = re.search(r"\b(\d{1,2}):(\d{2})\b", normalized)
    meridiem_match = re.search(r"\b(sabah|ogle|oglen|ogleden sonra|aksam|gece)\s+(\d{1,2})(?:[:.](\d{2}))?\b", normalized)
    defaulted_time = False
    hour = 9
    minute = 0
    if time_match:
        hour = int(time_match.group(1))
        minute = int(time_match.group(2))
        matched_fragments.append(time_match.group(0))
    elif meridiem_match:
        label = meridiem_match.group(1)
        hour = int(meridiem_match.group(2))
        minute = int(meridiem_match.group(3) or 0)
        if label in {"ogleden sonra", "aksam", "gece"} and hour < 12:
            hour += 12
        matched_fragments.append(meridiem_match.group(0))
    else:
        defaulted_time = True

    starts_at = datetime.combine(target_date, clock_time(hour=hour, minute=minute), tzinfo=_safe_local_timezone())
    ends_at = starts_at + timedelta(hours=1)

    title = query.strip()
    for fragment in matched_fragments:
        title = re.sub(re.escape(fragment), " ", title, flags=re.IGNORECASE)
    title = re.sub(r"\b(takvime|ajandaya|ekle|ekler misin|ekleyeyim mi|benim|var|olacak|saat)\b", " ", title, flags=re.IGNORECASE)
    title = re.sub(r"\s+", " ", title).strip(" ,.-")
    if len(title) < 4:
        title = "Takvim planı"

    needs_preparation = any(
        token in normalized
        for token in ["toplanti", "gorusme", "durusma", "randevu", "sunum", "teslim", "seyahat", "ucus"]
    )
    return {
        "title": title,
        "starts_at": starts_at.isoformat(),
        "ends_at": ends_at.isoformat(),
        "defaulted_time": defaulted_time,
        "needs_preparation": needs_preparation,
        "source_query": query.strip(),
    }


def _is_calendar_confirmation(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    return normalized in {
        "ekle",
        "evet",
        "evet ekle",
        "tamam",
        "tamam ekle",
        "olur",
        "takvime ekle",
        "ajandaya ekle",
    }


def _is_calendar_rejection(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    return normalized in {"hayir", "hayır", "vazgec", "vazgeç", "ekleme", "gerek yok", "bosver"}


def _format_turkish_datetime(value: str) -> str:
    month_labels = [
        "Ocak",
        "Şubat",
        "Mart",
        "Nisan",
        "Mayıs",
        "Haziran",
        "Temmuz",
        "Ağustos",
        "Eylül",
        "Ekim",
        "Kasım",
        "Aralık",
    ]
    dt = datetime.fromisoformat(value).astimezone(_safe_local_timezone())
    return f"{dt.day} {month_labels[dt.month - 1]} {dt.year} {dt:%H:%M}"


def _pending_calendar_event(messages: list[dict]) -> dict | None:
    for item in reversed(messages):
        if item.get("role") != "assistant":
            continue
        context = item.get("source_context") or {}
        candidate = context.get("pending_calendar_event")
        if isinstance(candidate, dict):
            return candidate
    return None


def _extract_task_candidate(query: str) -> dict[str, Any] | None:
    normalized = _normalize_tr_text(query)
    task_cues = (
        "gorev",
        "görev",
        "task",
        "todo",
        "yapilacak",
        "yapılacak",
        "hatirlat",
        "hatırlat",
        "takip et",
        "listeye koy",
        "listeme koy",
        "not et",
    )
    if not _contains_any_phrase(normalized, task_cues):
        return None

    due_candidate = _extract_calendar_candidate(query)
    due_at = str(due_candidate.get("starts_at") or "") if due_candidate else ""
    priority = "medium"
    if _contains_any_phrase(normalized, ("acil", "öncelikli", "oncelikli", "hemen", "bugun", "bugün")):
        priority = "high"
    elif _contains_any_phrase(normalized, ("dusuk", "düşük", "sonra", "vakit olursa")):
        priority = "low"

    title = re.sub(
        r"\b(gorev|görev|task|todo|yapilacak|yapılacak|olarak|ekle|olustur|oluştur|listeye koy|listeme koy|hatirlat|hatırlat|takip et|not et)\b",
        " ",
        str(query or ""),
        flags=re.IGNORECASE,
    )
    title = re.sub(r"\s+", " ", title).strip(" ,.-")
    if len(title) < 4:
        return None
    return {
        "title": title[:200],
        "due_at": due_at or None,
        "priority": priority,
        "source_query": str(query or "").strip(),
        "explanation": str(query or "").strip()[:1200],
    }


def _is_task_confirmation(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    return normalized in {
        "gorev olarak ekle",
        "görev olarak ekle",
        "gorevi ekle",
        "görevi ekle",
        "gorev olustur",
        "görev oluştur",
        "gorevi olustur",
        "görevi oluştur",
        "listeye ekle",
        "todo yap",
    }


def _is_task_rejection(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    return normalized in {"gorev ekleme", "görev ekleme", "gorev olmasin", "görev olmasın", "vazgec", "vazgeç"}


def _pending_task_candidate(messages: list[dict]) -> dict[str, Any] | None:
    for item in reversed(messages):
        if item.get("role") != "assistant":
            continue
        context = item.get("source_context") or {}
        candidate = context.get("pending_task")
        if isinstance(candidate, dict):
            return candidate
    return None


def _build_summary_prompt(*, matter: dict, chronology: dict, risk_notes: dict, tasks: list[dict], documents: list[dict], fallback_summary: str) -> str:
    chronology_lines = [f"- {item['date']}: {item['event']}" for item in chronology.get("items", [])[:4]]
    risk_lines = [f"- {item['title']}: {_truncate_for_prompt(item['details'], 180)}" for item in risk_notes.get("items", [])[:4]]
    task_lines = [f"- {task['title']}" for task in tasks if task.get("status") != "completed"][:4]
    document_lines = [f"- {doc.get('display_name') or doc.get('relative_path') or doc.get('filename')}" for doc in documents[:5]]
    return "\n".join(
        [
            "LawCopilot için kısa bir dosya özeti yaz.",
            "Kurallar:",
            "- Türkçe yaz.",
            "- Yalnız verilen bağlamı kullan.",
            "- Belirsiz kısımları kesinleştirme.",
            "- En fazla iki kısa paragraf yaz.",
            "",
            f"Dosya başlığı: {matter.get('title')}",
            f"Müvekkil: {matter.get('client_name') or 'Belirtilmedi'}",
            f"Durum: {matter.get('status') or 'active'}",
            f"Mevcut kayıtlı özet: {fallback_summary}",
            "",
            "Kronoloji:",
            *(chronology_lines or ["- Açık kronoloji kaydı yok."]),
            "",
            "Risk notları:",
            *(risk_lines or ["- Belirgin risk notu yok."]),
            "",
            "Açık görevler:",
            *(task_lines or ["- Açık görev yok."]),
            "",
            "Dayanak belgeler:",
            *(document_lines or ["- İndekslenmiş belge yok."]),
        ]
    )


def _build_risk_overview_prompt(*, matter: dict, chronology: dict, risk_notes: dict) -> str:
    chronology_issues = [f"- {issue['title']}: {_truncate_for_prompt(issue['details'], 180)}" for issue in chronology.get("issues", [])[:4]]
    risk_lines = [f"- {item['title']}: {_truncate_for_prompt(item['details'], 180)}" for item in risk_notes.get("items", [])[:5]]
    return "\n".join(
        [
            "LawCopilot için kısa bir risk değerlendirme üst özeti yaz.",
            "Kurallar:",
            "- Türkçe yaz.",
            "- Hukuki görüş verme; çalışma notu tonu koru.",
            "- En fazla dört cümle yaz.",
            "- Önce en kritik doğrulama ihtiyacını söyle.",
            "",
            f"Dosya: {matter.get('title')}",
            "Kronoloji sorunları:",
            *(chronology_issues or ["- Belirgin kronoloji sorunu yok."]),
            "",
            "Risk notları:",
            *(risk_lines or ["- Belirgin risk notu yok."]),
        ]
    )


