def _sanitize_project_repo_kb_context(kb_context: dict[str, Any] | None) -> dict[str, Any]:
    payload = dict(kb_context or {})

    def _record_scope(item: dict[str, Any]) -> str:
        metadata = item.get("metadata") or {}
        return str(item.get("scope") or metadata.get("scope") or "").strip().lower()

    def _is_assistant_file_back(item: dict[str, Any]) -> bool:
        metadata = item.get("metadata") or {}
        nested = metadata.get("metadata") or {}
        source_type = str(metadata.get("source_type") or nested.get("source_type") or "").strip().lower()
        file_back_kind = str(metadata.get("file_back_kind") or nested.get("file_back_kind") or "").strip().lower()
        return source_type == "assistant_file_back" or file_back_kind == "assistant_reply"

    allowed_pages = {"projects", "legal", "decisions", "reflections"}
    supporting_records = [
        item
        for item in list(payload.get("supporting_records") or [])
        if str(item.get("page_key") or "").strip() in allowed_pages
        and _record_scope(item) != "personal"
        and not _is_assistant_file_back(item)
    ]
    decision_records = [
        item
        for item in list(payload.get("decision_records") or [])
        if _record_scope(item) != "personal"
    ]
    reflections = [
        item
        for item in list(payload.get("reflections") or [])
        if _record_scope(item) != "personal"
    ]
    payload["supporting_records"] = supporting_records
    payload["supporting_pages"] = [
        item for item in list(payload.get("supporting_pages") or []) if str(item.get("page_key") or "").strip() in allowed_pages
    ]
    payload["decision_records"] = decision_records
    payload["reflections"] = reflections
    payload["supporting_concepts"] = []
    payload["knowledge_articles"] = []
    allowed_record_refs = {
        (
            str(item.get("page_key") or "").strip(),
            str(item.get("record_id") or "").strip(),
            str(item.get("title") or "").strip(),
        )
        for item in supporting_records
    }
    resolved_claims = [
        item
        for item in list(payload.get("resolved_claims") or [])
        if isinstance(item, dict)
        and str(item.get("page_key") or "").strip() in allowed_pages
        and (
            not allowed_record_refs
            or (
                str(item.get("page_key") or "").strip(),
                str(item.get("record_id") or "").strip(),
                str(item.get("display_label") or item.get("title") or "").strip(),
            )
            in allowed_record_refs
            or (
                str(item.get("page_key") or "").strip(),
                str(item.get("record_id") or "").strip(),
                "",
            )
            in {(page_key, record_id, "") for page_key, record_id, _ in allowed_record_refs}
        )
    ]
    payload["resolved_claims"] = resolved_claims
    payload["claim_summary_lines"] = [
        str(item.get("summary_line") or "").strip()
        for item in resolved_claims
        if str(item.get("summary_line") or "").strip()
    ]
    summary_lines: list[str] = []
    for item in supporting_records[:4]:
        title = str(item.get("title") or "").strip()
        summary = str(item.get("summary") or "").strip()
        page_key = str(item.get("page_key") or "").strip() or "projects"
        if title and summary:
            summary_lines.append(f"- [{page_key}] {title}: {summary}")
        elif title:
            summary_lines.append(f"- [{page_key}] {title}")
    for item in decision_records[:2]:
        title = str(item.get("title") or "").strip()
        summary = str(item.get("summary") or "").strip()
        if title and summary:
            summary_lines.append(f"- [decisions] {title}: {summary}")
    payload["summary_lines"] = summary_lines
    payload["scopes"] = [scope for scope in list(payload.get("scopes") or []) if str(scope).strip().lower() != "personal"]
    payload["context_selection_reasons"] = [
        reason
        for reason in list(payload.get("context_selection_reasons") or [])
        if str(reason).strip().lower() not in {"concept_kind_match", "semantic_article_match"}
    ]
    payload["record_type_counts"] = {
        key: value
        for key, value in dict(payload.get("record_type_counts") or {}).items()
        if str(key).strip().lower() != "knowledge_article"
    }
    return payload


def _knowledge_context_prompt_lines(
    knowledge_context: dict[str, Any] | None,
    *,
    fallback_line: str = "- İlgili wiki kaydı bulunamadı.",
    claim_limit: int = 4,
    summary_limit: int = 4,
) -> list[str]:
    payload = dict(knowledge_context or {})
    lines: list[str] = []
    seen: set[str] = set()
    verification_line = _verification_gate_prompt_line(payload.get("verification_gate"))
    if verification_line:
        seen.add(verification_line)
        lines.append(verification_line)
    for line in _assistant_context_pack_prompt_lines(payload, limit=claim_limit):
        if line in seen:
            continue
        seen.add(line)
        lines.append(line)
    for item in list(payload.get("claim_summary_lines") or [])[: max(0, claim_limit)]:
        line = str(item or "").strip()
        if not line or line in seen:
            continue
        seen.add(line)
        lines.append(line)
    for item in list(payload.get("summary_lines") or [])[: max(0, summary_limit)]:
        line = str(item or "").strip()
        if not line or line in seen:
            continue
        seen.add(line)
        lines.append(line)
    return lines or [fallback_line]


def _personal_model_context_prompt_lines(
    personal_model_context: dict[str, Any] | None,
    *,
    fallback_line: str = "- İlgili kişisel model bilgisi seçilmedi.",
    claim_limit: int = 4,
    summary_limit: int = 4,
) -> list[str]:
    payload = dict(personal_model_context or {})
    lines: list[str] = []
    seen: set[str] = set()
    verification_line = _verification_gate_prompt_line(payload.get("verification_gate"))
    if verification_line:
        seen.add(verification_line)
        lines.append(verification_line)
    for line in _assistant_context_pack_prompt_lines(payload, limit=claim_limit):
        if line in seen:
            continue
        seen.add(line)
        lines.append(line)
    for item in list(payload.get("claim_summary_lines") or [])[: max(0, claim_limit)]:
        line = str(item or "").strip()
        if not line or line in seen:
            continue
        seen.add(line)
        lines.append(line)
    for item in list(payload.get("summary_lines") or [])[: max(0, summary_limit)]:
        line = str(item or "").strip()
        if not line or line in seen:
            continue
        seen.add(line)
        lines.append(line)
    return lines or [fallback_line]


def _assistant_context_pack_prompt_lines(
    payload: dict[str, Any] | None,
    *,
    limit: int = 4,
) -> list[str]:
    lines: list[str] = []
    seen: set[str] = set()
    for item in list((payload or {}).get("assistant_context_pack") or [])[: max(0, limit)]:
        line = str((item or {}).get("prompt_line") or "").strip()
        if not line or line in seen:
            continue
        seen.add(line)
        lines.append(line)
    return lines


def _verification_gate_prompt_line(gate: Any) -> str:
    payload = dict(gate or {}) if isinstance(gate, dict) else {}
    mode = str(payload.get("mode") or "").strip().lower()
    reason = str(payload.get("reason") or "").strip()
    if mode == "verified":
        return f"- [doğrulama] Güçlü claim dayanağı var. {reason}".strip()
    if mode == "cautious":
        return f"- [doğrulama] Destek sınırlı; yalnız desteklenen kısımları kesin ifade et. {reason}".strip()
    if mode == "strict":
        return f"- [doğrulama] Kesin ifade kullanma; belirsizlik ve doğrulama ihtiyacını açıkça belirt. {reason}".strip()
    return ""


