def _integration_access_provider_capabilities(provider: str, status: dict[str, Any]) -> list[str]:
    if provider == "google":
        caps: list[str] = []
        if status.get("gmail_connected"):
            caps.append("Gmail")
        if status.get("calendar_connected"):
            caps.append("Takvim")
        if status.get("drive_connected"):
            caps.append("Drive")
        return caps
    if provider == "outlook":
        caps: list[str] = []
        if status.get("mail_connected"):
            caps.append("Outlook Mail")
        if status.get("calendar_connected"):
            caps.append("Outlook Takvim")
        return caps
    if provider == "telegram":
        return ["Telegram mesajları"] if status.get("configured") else []
    if provider == "whatsapp":
        return ["WhatsApp mesajları"] if status.get("configured") else []
    if provider == "x":
        caps: list[str] = []
        if status.get("post_count") or status.get("configured"):
            caps.append("Gönderiler")
        if status.get("dm_count"):
            caps.append("Direkt mesajlar")
        if status.get("mention_count"):
            caps.append("Mention'lar")
        return caps
    if provider == "instagram":
        return ["Instagram mesajları"] if status.get("configured") else []
    if provider == "linkedin":
        return ["LinkedIn gönderileri", "LinkedIn yorumları", "LinkedIn paylaşımı"] if status.get("configured") else []
    return []


def _integration_access_provider_title(provider: str) -> str:
    titles = {
        "google": "Google",
        "outlook": "Outlook",
        "telegram": "Telegram",
        "whatsapp": "WhatsApp",
        "x": "X",
        "instagram": "Instagram",
        "linkedin": "LinkedIn",
    }
    return titles.get(provider, provider.capitalize())


def _compose_provider_specific_integration_access_reply(
    *,
    query: str,
    provider: str,
    status: dict[str, Any],
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
) -> dict[str, Any]:
    wants_account_label = _integration_access_wants_account_label(query)
    title = _integration_access_provider_title(provider)
    configured = bool(status.get("configured"))
    account_label = str(status.get("account_label") or "").strip()
    caps = _integration_access_provider_capabilities(provider, status)

    if wants_account_label:
        if configured and account_label:
            content = f"{title} tarafında bağlı hesap: {account_label}."
        elif configured:
            content = f"{title} tarafı bağlı görünüyor ama hesap etiketi henüz okunamıyor."
        else:
            content = f"{title} tarafında şu an bağlı bir hesap görünmüyor."
    else:
        if configured:
            content = f"{title} hesabı şu an bağlı görünüyor."
            if account_label:
                content += f" Bağlı hesap: {account_label}."
            if caps:
                content += f" Erişimler: {', '.join(caps)}."
        else:
            content = f"{title} tarafında şu an etkin bir bağlantı görünmüyor."

    return {
        "content": content,
        "assistant_summary": "",
        "tool_suggestions": [
            {
                "tool": "settings",
                "label": "Ayarlar",
                "reason": "Bağlı hesabı ve izinleri buradan doğrulayabiliriz.",
            }
        ],
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_integration_status",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "source_refs": source_refs or [],
            f"{provider}_status": status,
        },
    }


def _wants_recent_email_snapshot_explicit(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    email_markers = (
        "mail",
        "e posta",
        "eposta",
        "gmail",
        "google",
        "outlook",
        "hotmail",
        "gelen kutu",
        "inbox",
    )
    recent_markers = (
        "en son gelen",
        "son gelen",
        "son 10",
        "son 5",
        "son mail",
        "son e posta",
        "son eposta",
        "gelen kutusu",
        "gelen kutumdaki",
        "recent",
        "latest",
    )
    listing_markers = (
        "baslik",
        "başlık",
        "konu",
        "listele",
        "yaz",
        "goster",
        "göster",
        "nedir",
        "neler",
    )
    numeric_recent_marker = re.search(r"\b(?:en\s+)?son\s+\d{1,2}(?:\s*['’]?(?:er|ar|ser))?\b", normalized)
    if not any(marker in normalized for marker in email_markers):
        return False
    if not numeric_recent_marker and not any(marker in normalized for marker in recent_markers):
        return False
    return any(marker in normalized for marker in listing_markers)


def _recent_email_snapshot_follow_up_limit(query: str) -> int | None:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not normalized:
        return None

    shorthand_patterns = (
        r"(?:en\s+)?son\s+(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mail(?:i|ler|leri)?|e\s+posta(?:yi|lar|lari)?|eposta(?:yi|lar|lari)?|baslik(?:i|lar|lari)?|konu(?:yu|lar|lari)?))?(?:\s+(?:goster|yaz|listele))?",
        r"(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mail(?:i|ler|leri)?|e\s+posta(?:yi|lar|lari)?|eposta(?:yi|lar|lari)?|baslik(?:i|lar|lari)?|konu(?:yu|lar|lari)?))?(?:\s+(?:goster|yaz|listele))?",
    )
    for pattern in shorthand_patterns:
        match = re.fullmatch(pattern, normalized)
        if match:
            return int(match.group(1))
    return None


def _recent_email_snapshot_context(recent_messages: list[dict] | None) -> dict[str, bool] | None:
    history = [
        item
        for item in (recent_messages or [])
        if str(item.get("role") or "") in {"user", "assistant"}
    ][-6:]
    for item in reversed(history):
        role = str(item.get("role") or "")
        generated_from = str(item.get("generated_from") or "")
        source_context = item.get("source_context") if isinstance(item.get("source_context"), dict) else {}
        if role == "assistant" and generated_from == "assistant_email_snapshot":
            snapshot_items = source_context.get("email_snapshot") if isinstance(source_context.get("email_snapshot"), list) else []
            providers = {
                str(snapshot.get("provider") or "").strip().lower()
                for snapshot in snapshot_items
                if isinstance(snapshot, dict)
            }
            google_focus = "google" in providers
            outlook_focus = "outlook" in providers
            return {
                "active": True,
                "google_focus": google_focus,
                "outlook_focus": outlook_focus,
            }

        content = _compact_inline_text(str(item.get("content") or ""))
        if role == "user" and content and _wants_recent_email_snapshot_explicit(content):
            google_focus, outlook_focus = _recent_email_provider_focus_from_query(content)
            return {
                "active": True,
                "google_focus": google_focus,
                "outlook_focus": outlook_focus,
            }
    return None


def _wants_recent_email_snapshot(query: str, recent_messages: list[dict] | None = None) -> bool:
    if _wants_recent_email_snapshot_explicit(query):
        return True
    if _recent_email_snapshot_follow_up_limit(query) is None:
        return False
    context = _recent_email_snapshot_context(recent_messages)
    return bool(context and context.get("active"))


def _recent_email_provider_focus_from_query(query: str) -> tuple[bool, bool]:
    normalized = " ".join(_normalize_tr_text(query).split())
    google_focus = any(token in normalized for token in ("google", "gmail"))
    outlook_focus = any(token in normalized for token in ("outlook", "hotmail"))
    return google_focus, outlook_focus


def _recent_email_provider_focus(query: str, recent_messages: list[dict] | None = None) -> tuple[bool, bool]:
    google_focus, outlook_focus = _recent_email_provider_focus_from_query(query)
    if google_focus or outlook_focus:
        return google_focus, outlook_focus
    context = _recent_email_snapshot_context(recent_messages)
    if not context:
        return False, False
    return bool(context.get("google_focus")), bool(context.get("outlook_focus"))


def _recent_email_limit(query: str) -> int:
    normalized = " ".join(_normalize_tr_text(query).split())
    match = re.search(r"\b(\d{1,2})\b", normalized)
    if match:
        return max(1, min(int(match.group(1)), 50))
    plural_markers = ("mailler", "e postalar", "epostalar", "basliklar", "başlıklar", "konular")
    if any(marker in normalized for marker in plural_markers):
        return 10
    singular_markers = (
        "en son gelen mail",
        "son gelen mail",
        "son gelen e posta",
        "son gelen eposta",
        "son e posta",
        "son eposta",
        "son mail",
    )
    if any(marker in normalized for marker in singular_markers):
        return 1
    return 10


def _wants_recent_x_snapshot_explicit(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    has_standalone_x = bool(re.search(r"(?<!\w)x(?!\w)", normalized))
    x_markers = (
        "x hesab",
        "x sosyal",
        "twitter",
        "tweet",
        "mention",
        "dm",
        "direkt mesaj",
        "gelen kutu",
        "inbox",
        "sosyal medya",
    )
    recent_markers = (
        "en son",
        " son ",
        "son gelen",
        "son 10",
        "son 5",
        "recent",
        "latest",
        "incele",
        "bak",
        "kontrol et",
    )
    listing_markers = (
        "mesaj",
        "mesajlar",
        "dm",
        "direkt mesaj",
        "ne varsa",
        "veri cek",
        "veri çek",
        "mention",
        "mentionlar",
        "bildirim",
        "bildirimler",
        "listele",
        "yaz",
        "goster",
        "göster",
        "hangi",
        "neler",
        "kim",
        "kimler",
        "geldi",
        "geldiler",
    )
    if not has_standalone_x and not any(marker in normalized for marker in x_markers):
        return False
    return any(marker in normalized for marker in recent_markers) and any(
        marker in normalized for marker in listing_markers
    )


def _recent_x_snapshot_follow_up_limit(query: str) -> int | None:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not normalized:
        return None
    shorthand_patterns = (
        r"(?:en\s+)?son\s+(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mesaj|mesajlar|dm|mention|bildirim))?(?:\s+(?:goster|göster|yaz|listele))?",
        r"(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mesaj|mesajlar|dm|mention|bildirim))?(?:\s+(?:goster|göster|yaz|listele))?",
    )
    for pattern in shorthand_patterns:
        match = re.fullmatch(pattern, normalized)
        if match:
            return int(match.group(1))
    return None


def _recent_x_snapshot_context(recent_messages: list[dict] | None) -> dict[str, Any] | None:
    history = [
        item
        for item in (recent_messages or [])
        if str(item.get("role") or "") in {"user", "assistant"}
    ][-6:]
    for item in reversed(history):
        role = str(item.get("role") or "")
        generated_from = str(item.get("generated_from") or "")
        source_context = item.get("source_context") if isinstance(item.get("source_context"), dict) else {}
        if role == "assistant" and generated_from == "assistant_x_snapshot":
            return {
                "active": True,
                "messages_only": bool(source_context.get("messages_only")),
                "mentions_only": bool(source_context.get("mentions_only")),
            }
        content = _compact_inline_text(str(item.get("content") or ""))
        if role == "user" and content and _wants_recent_x_snapshot_explicit(content):
            return {
                "active": True,
                "messages_only": _recent_x_messages_requested(content),
                "mentions_only": _recent_x_mentions_requested(content),
            }
    return None


def _wants_recent_x_snapshot(query: str, recent_messages: list[dict] | None = None) -> bool:
    if _wants_recent_x_snapshot_explicit(query):
        return True
    if _recent_x_snapshot_follow_up_limit(query) is None:
        return False
    context = _recent_x_snapshot_context(recent_messages)
    return bool(context and context.get("active"))


def _recent_x_messages_requested(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    return any(
        marker in normalized
        for marker in (
            "mesaj",
            "mesajlar",
            "dm",
            "direkt mesaj",
            "gelen kutu",
            "inbox",
        )
    )


def _recent_x_mentions_requested(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    return any(
        marker in normalized
        for marker in (
            "mention",
            "bahset",
            "bildirim",
            "yorum",
            "yanit",
            "yanıt",
        )
    )


def _recent_x_limit(query: str) -> int:
    normalized = " ".join(_normalize_tr_text(query).split())
    explicit_limit = _recent_x_snapshot_follow_up_limit(query)
    if explicit_limit is not None:
        return max(1, min(explicit_limit, 50))
    match = re.search(r"\b(\d{1,2})\b", normalized)
    if match:
        return max(1, min(int(match.group(1)), 50))
    if any(marker in normalized for marker in ("mesajlar", "mentionlar", "bildirimler", "neler", "kimler")):
        return 10
    return 1


def _list_email_threads_for_provider(
    store: Persistence,
    office_id: str,
    provider: str,
    *,
    monitored_only: bool = False,
) -> list[dict[str, Any]]:
    profile = store.get_user_profile(office_id)
    aliases = {
        "google": ("google", "gmail"),
        "outlook": ("outlook",),
    }.get(provider, (provider,))
    merged: list[dict[str, Any]] = []
    seen_refs: set[str] = set()
    for alias in aliases:
        for thread in store.list_email_threads(office_id, provider=alias):
            if monitored_only:
                decision = _email_thread_monitoring_decision(profile, thread)
                if not decision.get("include"):
                    continue
            dedupe_key = f"{provider}:{thread.get('thread_ref') or thread.get('id')}"
            if dedupe_key in seen_refs:
                continue
            seen_refs.add(dedupe_key)
            merged.append(thread)
    merged.sort(
        key=lambda item: (
            str(item.get("received_at") or item.get("updated_at") or ""),
            int(item.get("id") or 0),
        ),
        reverse=True,
    )
    return merged


def _recent_email_provider_statuses(
    query: str,
    *,
    google_status: dict[str, Any],
    outlook_status: dict[str, Any],
    recent_messages: list[dict] | None = None,
) -> list[tuple[str, dict[str, Any]]]:
    google_focus, outlook_focus = _recent_email_provider_focus(query, recent_messages)
    if google_focus and not outlook_focus:
        return [("google", google_status)]
    if outlook_focus and not google_focus:
        return [("outlook", outlook_status)]
    providers: list[tuple[str, dict[str, Any]]] = []
    if google_status.get("configured") or google_status.get("gmail_connected") or google_status.get("email_thread_count"):
        providers.append(("google", google_status))
    if outlook_status.get("configured") or outlook_status.get("mail_connected") or outlook_status.get("email_thread_count"):
        providers.append(("outlook", outlook_status))
    return providers or [("google", google_status), ("outlook", outlook_status)]


def _recent_email_provider_label(provider: str, status: dict[str, Any]) -> str:
    account_label = _compact_inline_text(
        str(status.get("account_label") or ("Google hesabı" if provider == "google" else "Outlook hesabı"))
    )
    provider_label = "Gmail" if provider == "google" else "Outlook"
    return f"{provider_label} ({account_label})" if account_label else provider_label


def _format_recent_email_entry(thread: dict[str, Any], index: int) -> str:
    metadata = dict(thread.get("metadata") or {})
    participants = [str(item).strip() for item in thread.get("participants") or [] if str(item).strip()]
    subject = _compact_inline_text(str(thread.get("subject") or "Konu yok"))
    sender = _compact_inline_text(str(metadata.get("sender") or (participants[0] if participants else "")))
    received_at = str(thread.get("received_at") or "").strip()
    details: list[str] = []
    if sender:
        details.append(sender)
    if received_at:
        try:
            details.append(_format_turkish_datetime(received_at))
        except Exception:
            pass
    if details:
        return f"{index}. {subject} ({' | '.join(details)})"
    return f"{index}. {subject}"


