def _recent_telegram_snapshot_follow_up_limit(query: str) -> int | None:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not normalized:
        return None
    shorthand_patterns = (
        r"(?:en\s+)?son\s+(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mesaj|mesajlar|sohbet|dm))?(?:\s+(?:goster|göster|yaz|listele))?",
        r"(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mesaj|mesajlar|sohbet|dm))?(?:\s+(?:goster|göster|yaz|listele))?",
    )
    for pattern in shorthand_patterns:
        match = re.fullmatch(pattern, normalized)
        if match:
            return int(match.group(1))
    return None


def _recent_telegram_actor_filter(query: str) -> str | None:
    compact = _compact_inline_text(query)
    normalized_compact = " ".join(_normalize_tr_text(compact).split())
    if "whatsapp" in normalized_compact or "wp " in f"{normalized_compact} " or normalized_compact.endswith(" wp"):
        return None
    clauses = [compact]
    clauses.extend(
        _compact_inline_text(item)
        for item in re.split(r"\b(?:ya da|veya|ama|fakat|peki|bir de)\b", compact, flags=re.IGNORECASE)
        if _compact_inline_text(item)
    )

    def _clean_candidate(value: str) -> str:
        candidate = _compact_inline_text(value).strip(" \"'“”‘’")
        candidate = re.sub(r"^(?:telegram(?:['’]?(?:da|dan|de|den))?)\s+", "", candidate, flags=re.IGNORECASE)
        candidate = re.sub(
            r"^(?:telegram(?:[ıiuü']?n?[dt]?a?n?)?\s+)?(?:[ıiuü]?\s*)?(?:incele|bak|kontrol et|goster|göster|listele|ozetle|özetle)\s+",
            "",
            candidate,
            flags=re.IGNORECASE,
        )
        candidate = re.sub(r"^(?:en\s+son|son|bana|bir)\s+", "", candidate, flags=re.IGNORECASE)
        candidate = _compact_inline_text(candidate).strip(" \"'“”‘’")
        normalized_candidate = _normalize_tr_text(candidate)
        if normalized_candidate in {"kim", "kimler", "hangi kisi", "hangi kisiler", "hangi kisilerden"}:
            return ""
        if any(
            marker in normalized_candidate
            for marker in ("dikkatli bak", "zaten", "onu bul", "baksana", "goruyor musun", "görüyor musun")
        ):
            return ""
        return candidate

    message_token = r"(?:mesaj(?:i|ı|lari|ları)?(?:n[ıi])?|sohbet(?:i|ler[ıi])?|emsaj(?:i|lar[ıi])?)"
    patterns = (
        r"(?P<actor>.+?)\s+diye\s+kayitli\s+biri",
        r"(?:telegram(?:['’]?(?:da|dan|de|den))?\s+)?(?P<actor>.+?)\s+(?:ile|la|le)\s+olan\b",
        r"(?P<actor>.+?)\s+(?:ile|la|le)\s+olan\s+(?:telegram\s+)?(?:mesaj|sohbet)",
        r"(?P<actor>.+?)\s+(?:ile|la|le)\s+son\s+(?:konusma|konuşma|sohbet)",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+telegram(?:da|dan)?\s+(?:ne\s+)?{message_token}\s+gelm(?:is|iş)(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+telegram(?:da|dan)?\s+(?:hangi|hangi\s+bir)\s+{message_token}\s+geldi(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+{message_token}\s+geldi(?:\s+mi)?",
        r"(?P<actor>.+?)\s+yazm(?:is|ış)\s+mi",
        r"(?P<actor>.+?)\s+en\s+son\s+ne\s+yazm(?:is|ış)(?:ti|tı)?",
        r"(?P<actor>.+?)\s+son\s+ne\s+yazm(?:is|ış)(?:ti|tı)?",
        rf"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+en\s+son\s+{message_token}",
        rf"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+son\s+{message_token}",
        rf"(?P<actor>.+?)\s+en\s+son\s+{message_token}",
    )
    for clause in clauses:
        if not clause:
            continue
        for pattern in patterns:
            match = re.search(pattern, clause, re.IGNORECASE)
            if not match:
                continue
            actor = _clean_candidate(str(match.group("actor") or ""))
            if actor:
                return actor
    return None


def _recent_telegram_sender_rollup_requested(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not any(marker in normalized for marker in ("kimler", "kimlerden", "kim yazmis", "kim yazmış", "kim")):
        return False
    return not any(
        marker in normalized
        for marker in ("ne mesaj", "mesajlar", "hangi mesaj", "ne yazmis", "ne yazmış")
    )


def _recent_telegram_snapshot_context(recent_messages: list[dict] | None) -> dict[str, Any] | None:
    history = [
        item
        for item in (recent_messages or [])
        if str(item.get("role") or "") in {"user", "assistant"}
    ][-6:]
    for item in reversed(history):
        role = str(item.get("role") or "")
        generated_from = str(item.get("generated_from") or "")
        source_context = item.get("source_context") if isinstance(item.get("source_context"), dict) else {}
        if role == "assistant" and generated_from == "assistant_telegram_snapshot":
            return {
                "active": True,
                "inbound_only": bool(source_context.get("inbound_only", True)),
                "direct_only": bool(source_context.get("direct_only")),
                "actor_filter": _compact_inline_text(str(source_context.get("actor_filter") or "")),
            }
        content = _compact_inline_text(str(item.get("content") or ""))
        if role == "user" and content and _wants_recent_telegram_snapshot_explicit(content):
            return {
                "active": True,
                "inbound_only": True,
                "direct_only": False,
                "actor_filter": _recent_telegram_actor_filter(content) or "",
            }
    return None


def _wants_recent_telegram_snapshot(query: str, recent_messages: list[dict] | None = None) -> bool:
    if _wants_recent_telegram_snapshot_explicit(query):
        return True
    context = _recent_telegram_snapshot_context(recent_messages)
    if not context or not context.get("active"):
        return False
    normalized = _normalize_tr_text(query)
    return bool(
        _recent_telegram_snapshot_follow_up_limit(query) is not None
        or _recent_telegram_actor_filter(query)
        or _recent_telegram_sender_rollup_requested(query)
        or any(
            marker in normalized
            for marker in ("bak", "incele", "özetle", "ozetle", "goster", "göster", "listele", "görüyor musun", "goruyor musun")
        )
    )


def _recent_telegram_limit(query: str) -> int:
    normalized = " ".join(_normalize_tr_text(query).split())
    explicit_limit = _recent_telegram_snapshot_follow_up_limit(query)
    if explicit_limit is not None:
        return max(1, min(explicit_limit, 50))
    actor_multi_markers = (
        "mesajlar",
        "listele",
        "goster",
        "göster",
        "hangi mesaj",
        "son gelen",
        "kimler",
        "neler",
        "mesajlasma",
        "mesajlaşma",
        "mesajlasmalar",
        "mesajlaşmalar",
        "sohbet",
        "konusma",
        "konuşma",
        "ozetle",
        "özetle",
        "incele",
    )
    if _recent_telegram_actor_filter(query) and not any(marker in normalized for marker in actor_multi_markers):
        return 1
    if any(marker in normalized for marker in ("mesajlar", "neler", "kimler", "listele", "goster", "göster")):
        return 10
    if _recent_telegram_conversation_requested(query):
        return 10
    return 1


def _recent_telegram_conversation_requested(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not _recent_telegram_actor_filter(query):
        return False
    return any(
        marker in normalized
        for marker in (
            "mesajlasma",
            "mesajlaşma",
            "mesajlasmalar",
            "mesajlaşmalar",
            "sohbet",
            "konusma",
            "konuşma",
            "incele",
            "ozetle",
            "özetle",
            "akis",
            "akış",
        )
    )


def _recent_telegram_group_label(message: dict[str, Any]) -> str:
    metadata = dict(message.get("metadata") or {})
    conversation_ref = str(message.get("conversation_ref") or "").strip()
    is_group = bool(metadata.get("is_group")) or conversation_ref.startswith("chat:")
    group_name = _compact_inline_text(
        str(
            metadata.get("chat_title")
            or metadata.get("group_name")
            or metadata.get("chat_name")
            or metadata.get("display_name")
            or ""
        )
    )
    return group_name if is_group and group_name else ""


def _recent_telegram_actor_label(message: dict[str, Any]) -> str:
    metadata = dict(message.get("metadata") or {})
    conversation_ref = str(message.get("conversation_ref") or "").strip()
    direction = str(message.get("direction") or "").strip().lower()
    sender = _compact_inline_text(str(message.get("sender") or ""))
    recipient = _compact_inline_text(str(message.get("recipient") or ""))
    preferred_contact = _compact_inline_text(
        str(
            metadata.get("contact_name")
            or metadata.get("display_name")
            or metadata.get("chat_name")
            or metadata.get("chat_title")
            or metadata.get("profile_name")
            or metadata.get("author_name")
            or ""
        )
    )
    if preferred_contact and preferred_contact.lower() not in {"telegram web", "siz"}:
        return preferred_contact
    if direction == "outbound":
        return recipient or sender or conversation_ref or "Telegram"
    return sender or recipient or conversation_ref or "Telegram"


def _recent_telegram_target_matches(filter_text: str, candidate: str) -> bool:
    left = _normalize_contact_lookup_text(filter_text)
    right = _normalize_contact_lookup_text(candidate)
    if not left or not right:
        return False
    if left in right or right in left:
        return True
    left_tokens = {token for token in left.split() if token}
    right_tokens = {token for token in right.split() if token}
    if not left_tokens or not right_tokens:
        return False
    common_tokens = left_tokens & right_tokens
    return len(common_tokens) >= min(len(left_tokens), len(right_tokens), 2)


def _recent_telegram_message_matches_actor_aliases(message: dict[str, Any], aliases: list[str]) -> bool:
    metadata = dict(message.get("metadata") or {})
    candidates = [
        _recent_telegram_actor_label(message),
        _recent_telegram_group_label(message),
        _compact_inline_text(str(message.get("sender") or "")),
        _compact_inline_text(str(message.get("recipient") or "")),
        _compact_inline_text(str(message.get("conversation_ref") or "")),
        _compact_inline_text(str(metadata.get("chat_name") or "")),
        _compact_inline_text(str(metadata.get("contact_name") or "")),
        _compact_inline_text(str(metadata.get("profile_name") or "")),
        _compact_inline_text(str(metadata.get("display_name") or "")),
        _compact_inline_text(str(metadata.get("author_name") or "")),
        _compact_inline_text(str(metadata.get("chat_title") or "")),
    ]
    expanded_aliases = _expand_recent_whatsapp_aliases([str(alias or "") for alias in aliases])
    for alias in expanded_aliases:
        for candidate in candidates:
            if candidate and _recent_telegram_target_matches(alias, candidate):
                return True
    return False


def _list_recent_telegram_messages(
    store: Persistence,
    office_id: str,
    *,
    limit: int,
    inbound_only: bool,
    direct_only: bool = False,
    actor_filter: str | None = None,
) -> list[dict[str, Any]]:
    pool_size = max(limit * 4, 20)
    messages = store.list_telegram_messages(office_id, limit=min(pool_size, 200))
    if inbound_only:
        messages = [
            item
            for item in messages
            if str(item.get("direction") or "").strip().lower() != "outbound"
        ]
    if direct_only:
        messages = [
            item
            for item in messages
            if not _recent_telegram_group_label(item)
        ]
    if actor_filter:
        messages = [
            item
            for item in messages
            if _recent_telegram_message_matches_actor_aliases(item, [actor_filter])
        ]
    return messages[:limit]


def _format_recent_telegram_entry(message: dict[str, Any], index: int) -> str:
    direction = str(message.get("direction") or "").strip().lower()
    sender = _compact_inline_text(str(message.get("sender") or ""))
    recipient = _compact_inline_text(str(message.get("recipient") or ""))
    lead = sender if direction == "outbound" else (_recent_telegram_actor_label(message) or sender or recipient or "Telegram")
    group_label = _recent_telegram_group_label(message)
    if group_label and group_label != lead:
        lead = f"{group_label} > {lead}"
    body = _compact_inline_text(str(message.get("body") or ""))
    sent_at = str(message.get("sent_at") or "").strip()
    timestamp = ""
    if sent_at:
        try:
            timestamp = _format_turkish_datetime(sent_at)
        except Exception:
            timestamp = ""
    if body and timestamp:
        return f"{index}. {lead}: {body} ({timestamp})"
    if body:
        return f"{index}. {lead}: {body}"
    if timestamp:
        return f"{index}. {lead} ({timestamp})"
    return f"{index}. {lead}"


def _compose_recent_telegram_snapshot_reply(
    *,
    query: str,
    settings,
    store: Persistence,
    recent_messages: list[dict] | None = None,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
    home: dict[str, Any] | None = None,
    review_plan: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    if not review_plan and not _wants_recent_telegram_snapshot(query, recent_messages):
        return None
    if review_plan and str(review_plan.get("channel") or "").strip().lower() != "telegram":
        return None

    snapshot_context = _recent_telegram_snapshot_context(recent_messages) or {}
    plan_target_kind = str((review_plan or {}).get("target_kind") or "").strip().lower()
    plan_target = _compact_inline_text(str((review_plan or {}).get("target") or ""))
    answer_mode = str((review_plan or {}).get("answer_mode") or "").strip().lower() or "list"
    limit = int((review_plan or {}).get("limit") or _recent_telegram_limit(query) or 0) or 1
    inbound_only = bool((review_plan or {}).get("inbound_only", True)) if review_plan else True
    direct_only = bool((review_plan or {}).get("direct_only")) if review_plan else False
    actor_filter = (
        plan_target
        if plan_target_kind == "contact"
        else _recent_telegram_actor_filter(query) or _compact_inline_text(str(snapshot_context.get("actor_filter") or "")) or None
    )
    sender_rollup = answer_mode == "sender_rollup" or _recent_telegram_sender_rollup_requested(query)
    conversation_requested = answer_mode == "timeline" or _recent_telegram_conversation_requested(query)

    telegram_status = _telegram_status_payload(settings, store)
    home_payload = home or build_assistant_home(store, settings.office_id, settings=settings)
    snapshot_items = _list_recent_telegram_messages(
        store,
        settings.office_id,
        limit=limit,
        inbound_only=inbound_only,
        direct_only=direct_only,
        actor_filter=actor_filter,
    )
    resolved_actor_label = actor_filter or ""
    if actor_filter and snapshot_items:
        resolved_actor_label = _recent_telegram_actor_label(snapshot_items[0]) or actor_filter

    lines: list[str] = []
    if sender_rollup:
        lines.append("Telegram'da son yazan kişiler şöyle:")
    elif resolved_actor_label and conversation_requested:
        lines.append(f"{resolved_actor_label} ile son Telegram konuşma akışı şöyle:")
    elif resolved_actor_label:
        lines.append(f"{resolved_actor_label} için son {limit} Telegram mesajı şöyle:")
    elif inbound_only:
        lines.append(f"Yerel aynadaki son gelen {limit} Telegram mesajı şöyle:")
    else:
        lines.append(f"Yerel aynadaki son {limit} Telegram mesajı şöyle:")

    if snapshot_items:
        if sender_rollup:
            grouped: dict[str, dict[str, Any]] = {}
            for item in snapshot_items:
                lead = _recent_telegram_actor_label(item) or "Telegram"
                if group_label := _recent_telegram_group_label(item):
                    if group_label != lead:
                        lead = f"{group_label} > {lead}"
                bucket = grouped.setdefault(lead, {"count": 0, "last_sent_at": item.get("sent_at")})
                bucket["count"] += 1
            for index, (lead, info) in enumerate(grouped.items(), start=1):
                last_sent_at = str(info.get("last_sent_at") or "").strip()
                if last_sent_at:
                    try:
                        lines.append(f"{index}. {lead} — {int(info.get('count') or 0)} mesaj ({_format_turkish_datetime(last_sent_at)})")
                    except Exception:
                        lines.append(f"{index}. {lead} — {int(info.get('count') or 0)} mesaj")
                else:
                    lines.append(f"{index}. {lead} — {int(info.get('count') or 0)} mesaj")
        else:
            for index, item in enumerate(snapshot_items, start=1):
                lines.append(_format_recent_telegram_entry(item, index))
        if len(snapshot_items) < limit:
            lines.append(f"Şu an yerel aynada {len(snapshot_items)} Telegram kaydı var; daha fazlası henüz görünmüyor.")
    elif not telegram_status.get("configured"):
        lines.append("Telegram hesabı bağlı görünmüyor. Önce kişisel web oturumu veya bot bağlantısını tamamla.")
    elif resolved_actor_label:
        lines.append(f"Telegram'da {resolved_actor_label} ile eşleşen uygun mesaj görünmüyor.")
    else:
        lines.append("Yerel aynada henüz uygun Telegram mesajı görünmüyor.")

    lines.append("")
    if resolved_actor_label:
        lines.append(f"İstersen {resolved_actor_label} için kısa bir yanıt taslağı hazırlayabilirim.")
    else:
        lines.append("İstersen bu konuşmalardan biri için kısa bir yanıt taslağı hazırlayabilirim.")

    return {
        "content": "\n".join(lines),
        "assistant_summary": home_payload.get("today_summary") or "",
        "tool_suggestions": _assistant_tool_suggestions("telegram", requires_setup=home_payload.get("requires_setup") or []),
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_telegram_snapshot",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "source_refs": source_refs or [],
            "telegram_snapshot": snapshot_items,
            "telegram_status": telegram_status,
            "requested_limit": limit,
            "inbound_only": inbound_only,
            "direct_only": direct_only,
            "actor_filter": actor_filter,
            "resolved_actor_label": resolved_actor_label,
            "assistant_communication_plan": review_plan,
        },
    }


_ASSISTANT_COMMUNICATION_CHANNELS = {"whatsapp", "telegram", "email", "x"}
_ASSISTANT_COMMUNICATION_INTENTS = {
    "inspect_recent",
    "inspect_thread",
    "sender_rollup",
    "status_check",
}
_ASSISTANT_COMMUNICATION_ANSWER_MODES = {
    "list",
    "last_message",
    "timeline",
    "sender_rollup",
    "summary",
}


def _assistant_communication_plan_prompt(
    *,
    query: str,
    recent_messages: list[dict] | None,
) -> str:
    recent_lines: list[str] = []
    if recent_messages:
        for item in recent_messages[-6:]:
            role = str(item.get("role") or "unknown")
            content = _compact_inline_text(str(item.get("content") or ""))
            if content:
                recent_lines.append(f"- {role}: {content[:220]}")
    whatsapp_context = _recent_whatsapp_snapshot_context(recent_messages) or {}
    telegram_context = _recent_telegram_snapshot_context(recent_messages) or {}
    email_context = _recent_email_snapshot_context(recent_messages) or {}
    return "\n".join(
        [
            "LawCopilot için iletişim inceleme planı üret.",
            "Amaç: Kullanıcının WhatsApp/Telegram/e-posta/X mesaj inceleme isteğini önce yapılandırılmış plana çevir, cevap üretme.",
            "Yalnız JSON döndür.",
            "Şema:",
            "{",
            '  "channel": "whatsapp|telegram|email|x|none",',
            '  "intent": "inspect_recent|inspect_thread|sender_rollup|status_check|none",',
            '  "target_kind": "contact|group|provider|self|none",',
            '  "target": "string",',
            '  "answer_mode": "list|last_message|timeline|sender_rollup|summary",',
            '  "limit": 0,',
            '  "time_window_minutes": 0,',
            '  "direct_only": false,',
            '  "inbound_only": true,',
            '  "confidence": "low|medium|high",',
            '  "reason": "string"',
            "}",
            "Kurallar:",
            "- Bu planner yalnız iletişim inceleme istekleri içindir; gönderim/cevap atma aksiyonu istemiyorsa plan üret.",
            "- Kullanıcı belirli bir kişi veya grup için son mesajı soruyorsa target alanını doldur.",
            "- Kullanıcı kendi notlarına / kendine mesaj sohbetine bakmak istiyorsa target_kind=self seç.",
            "- 'Kimler yazmış' gibi bir istekte intent=sender_rollup ve answer_mode=sender_rollup seç.",
            "- 'En son ne yazmış', 'mesajı vardı bi baksana', 'incele' gibi isteklerde kişi odaklıysa intent=inspect_thread seç.",
            "- Belirli kişi odaklı son mesaj sorularında answer_mode=last_message veya timeline seç.",
            "- X/Twitter hesabındaki son DM, mention veya son gelen sosyal mesajlar soruluyorsa channel=x seç.",
            "- Emin değilsen none seç.",
            "",
            f"Kullanıcı sorgusu: {query}",
            "Yakın WhatsApp bağlamı:",
            json.dumps(whatsapp_context, ensure_ascii=False),
            "Yakın Telegram bağlamı:",
            json.dumps(telegram_context, ensure_ascii=False),
            "Yakın e-posta bağlamı:",
            json.dumps(email_context, ensure_ascii=False),
            "Yakın X bağlamı:",
            json.dumps(_recent_x_snapshot_context(recent_messages) or {}, ensure_ascii=False),
            "Yakın konuşma özeti:",
            *(recent_lines or ["- Yakın konuşma yok."]),
        ]
    )


def _assistant_runtime_communication_plan(
    *,
    query: str,
    recent_messages: list[dict] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    if not runtime:
        return None
    runtime_completion = _maybe_runtime_completion(
        runtime,
        _assistant_communication_plan_prompt(query=query, recent_messages=recent_messages),
        events,
        task="assistant_communication_plan",
        subject=subject,
    )
    if not runtime_completion:
        return None
    payload = _parse_json_object_from_text(str(runtime_completion.get("text") or ""))
    if not payload:
        return None
    channel = str(payload.get("channel") or "").strip().lower()
    intent = str(payload.get("intent") or "").strip().lower()
    target_kind = str(payload.get("target_kind") or "").strip().lower()
    answer_mode = str(payload.get("answer_mode") or "").strip().lower()
    confidence = str(payload.get("confidence") or "").strip().lower()
    if (
        channel not in _ASSISTANT_COMMUNICATION_CHANNELS
        or intent not in _ASSISTANT_COMMUNICATION_INTENTS
        or target_kind not in {"contact", "group", "provider", "self", "none"}
        or answer_mode not in _ASSISTANT_COMMUNICATION_ANSWER_MODES
        or confidence not in {"medium", "high"}
    ):
        return None
    limit = max(0, min(int(payload.get("limit") or 0), 50))
    time_window_minutes = max(0, min(int(payload.get("time_window_minutes") or 0), 60 * 24 * 14))
    target = _compact_inline_text(str(payload.get("target") or ""))
    if channel == "whatsapp":
        normalized_target = " ".join(_normalize_tr_text(target).split())
        compact_target = re.sub(r"[^a-z]+", "", normalized_target)
        if (
            target_kind in {"contact", "group", "self"}
            and (
                not target
                or normalized_target in {
                    "whatsapp",
                    "whatsappta",
                    "whatsapptan",
                    "whatsappdan",
                    "whatsapp icin",
                    "whatsapp için",
                    "gelen mesajlar",
                    "son mesajlar",
                    "son mesajlasmalar",
                    "son mesajlaşmalar",
                    "son konusmalar",
                    "son konuşmalar",
                }
                or compact_target in {"whatsapp", "whatsappta", "whatsapptan", "whatsappdan", "whatsappicin"}
            )
        ):
            target_kind = "none"
            target = ""
    return {
        "channel": channel,
        "intent": intent,
        "target_kind": target_kind,
        "target": target,
        "answer_mode": answer_mode,
        "limit": limit or None,
        "time_window_minutes": time_window_minutes or None,
        "direct_only": bool(payload.get("direct_only")),
        "inbound_only": bool(payload.get("inbound_only", True)),
        "confidence": confidence,
        "reason": _compact_inline_text(str(payload.get("reason") or "")),
        "source": "semantic_runtime",
    }


def _assistant_fallback_communication_plan(
    *,
    query: str,
    recent_messages: list[dict] | None,
) -> dict[str, Any] | None:
    normalized = _normalize_tr_text(query)
    if _wants_recent_telegram_snapshot(query, recent_messages):
        actor_filter = _recent_telegram_actor_filter(query) or (
            str((_recent_telegram_snapshot_context(recent_messages) or {}).get("actor_filter") or "").strip() or None
        )
        limit = _recent_telegram_limit(query)
        sender_rollup = _recent_telegram_sender_rollup_requested(query)
        conversation_requested = _recent_telegram_conversation_requested(query)
        return {
            "channel": "telegram",
            "intent": "sender_rollup" if sender_rollup else ("inspect_thread" if actor_filter else "inspect_recent"),
            "target_kind": "contact" if actor_filter else "none",
            "target": actor_filter or "",
            "answer_mode": "sender_rollup" if sender_rollup else ("timeline" if actor_filter and conversation_requested else ("last_message" if actor_filter and limit <= 1 else "list")),
            "limit": limit,
            "time_window_minutes": None,
            "direct_only": False,
            "inbound_only": False if actor_filter and conversation_requested else True,
            "confidence": "high",
            "reason": "",
            "source": "heuristic",
        }
    if _wants_recent_whatsapp_snapshot(query, recent_messages):
        snapshot_context = _recent_whatsapp_snapshot_context(recent_messages) or {}
        generic_overview = _recent_whatsapp_contextual_overview_requested(query, recent_messages)
        context_enabled = _recent_whatsapp_query_allows_context_carryover(query) and not generic_overview
        sender_rollup = _recent_whatsapp_sender_rollup_requested(query)
        self_requested = _recent_whatsapp_self_requested(query)
        self_aliases = _recent_whatsapp_self_alias_hints(query)
        actor_filter = _recent_whatsapp_actor_filter(query) or (
            str(snapshot_context.get("actor_filter") or "").strip() or None
            if context_enabled
            else None
        )
        group_filter = _recent_whatsapp_group_filter(query) or (
            str(snapshot_context.get("group_filter") or "").strip() or None
            if context_enabled
            else None
        )
        limit = _recent_whatsapp_limit(query, recent_messages, allow_context=context_enabled)
        time_window_minutes = _recent_whatsapp_time_window_minutes(
            query,
            recent_messages,
            allow_context=context_enabled,
        )
        if time_window_minutes is None and generic_overview:
            time_window_minutes = 60 * 24
        answer_mode = "list"
        intent = "inspect_recent"
        target_kind = "none"
        target = ""
        if sender_rollup:
            answer_mode = "sender_rollup"
            intent = "sender_rollup"
        elif generic_overview and _recent_whatsapp_summary_requested(query):
            answer_mode = "summary"
        elif self_requested:
            target_kind = "self"
            target = _compact_inline_text(self_aliases[0]) if self_aliases else ""
            if _recent_whatsapp_summary_requested(query):
                answer_mode = "summary"
            elif any(
                marker in normalized
                for marker in (
                    "baksana",
                    "bak",
                    "incele",
                    "yorumla",
                    "notlar",
                    "notlarim",
                    "notlarım",
                    "akis",
                    "akış",
                )
            ):
                answer_mode = "timeline"
            elif limit <= 1 or any(marker in normalized for marker in ("en son", "hangi mesaj", "son mesaj", "not")):
                answer_mode = "last_message"
            else:
                answer_mode = "timeline"
            intent = "inspect_thread"
        elif group_filter:
            target_kind = "group"
            target = group_filter
            answer_mode = "list" if limit > 1 else "summary"
            intent = "inspect_thread"
        elif actor_filter:
            target_kind = "contact"
            target = actor_filter
            if _recent_whatsapp_summary_requested(query):
                answer_mode = "summary"
            elif any(
                marker in normalized
                for marker in (
                    "baksana",
                    "bak",
                    "incele",
                    "yorumla",
                    "zaten cevap",
                    "akis",
                    "akış",
                )
            ):
                answer_mode = "timeline"
            elif limit <= 1 or any(
                marker in normalized
                for marker in ("en son ne yaz", "hangi mesaj", "son mesaj", "mesaj geldi", "gordun mu", "gördün mü")
            ):
                answer_mode = "last_message"
            else:
                answer_mode = "timeline"
            intent = "inspect_thread"
        return {
            "channel": "whatsapp",
            "intent": intent,
            "target_kind": target_kind,
            "target": target,
            "answer_mode": answer_mode,
            "limit": limit,
            "time_window_minutes": time_window_minutes,
            "direct_only": _recent_whatsapp_direct_only(query) or (bool(snapshot_context.get("direct_only")) if context_enabled else False),
            "inbound_only": False
            if self_requested
            else _recent_whatsapp_inbound_only(query, recent_messages, allow_context=context_enabled),
            "confidence": "high",
            "reason": "",
            "source": "heuristic",
        }
    if _wants_recent_email_snapshot(query, recent_messages):
        google_focus, outlook_focus = _recent_email_provider_focus(query, recent_messages)
        target = "google" if google_focus and not outlook_focus else "outlook" if outlook_focus and not google_focus else ""
        limit = _recent_email_limit(query)
        return {
            "channel": "email",
            "intent": "inspect_recent",
            "target_kind": "provider" if target else "none",
            "target": target,
            "answer_mode": "last_message" if limit == 1 else "list",
            "limit": limit,
            "time_window_minutes": None,
            "direct_only": False,
            "inbound_only": True,
            "confidence": "high",
            "reason": "",
            "source": "heuristic",
        }
    if _wants_recent_x_snapshot(query, recent_messages):
        limit = _recent_x_limit(query)
        messages_only = _recent_x_messages_requested(query)
        mentions_only = _recent_x_mentions_requested(query) and not messages_only
        return {
            "channel": "x",
            "intent": "inspect_recent",
            "target_kind": "provider",
            "target": "x",
            "answer_mode": "last_message" if limit == 1 else "list",
            "limit": limit,
            "time_window_minutes": None,
            "direct_only": messages_only,
            "inbound_only": True,
            "confidence": "high",
            "reason": "",
            "source": "heuristic",
            "messages_only": messages_only,
            "mentions_only": mentions_only,
        }
    return None


def _merge_semantic_and_deterministic_communication_plan(
    *,
    query: str,
    runtime_plan: dict[str, Any] | None,
    heuristic_plan: dict[str, Any] | None,
) -> dict[str, Any] | None:
    if not runtime_plan:
        return heuristic_plan
    merged = dict(runtime_plan)
    merged["source"] = "semantic_runtime"
    channel = str(runtime_plan.get("channel") or "").strip().lower()
    if channel not in {"whatsapp", "telegram", "x"}:
        return merged
    if heuristic_plan and str(heuristic_plan.get("channel") or "").strip().lower() == channel:
        heuristic_target_kind = str(heuristic_plan.get("target_kind") or "").strip().lower()
        heuristic_target = _compact_inline_text(str(heuristic_plan.get("target") or ""))
        if heuristic_target_kind in {"contact", "group", "self"} and heuristic_target:
            merged["target_kind"] = heuristic_target_kind
            merged["target"] = heuristic_target
        elif heuristic_target_kind == "none":
            merged["target_kind"] = "none"
            merged["target"] = ""
        if str(heuristic_plan.get("intent") or "").strip():
            merged["intent"] = heuristic_plan.get("intent")
        if str(heuristic_plan.get("answer_mode") or "").strip():
            merged["answer_mode"] = heuristic_plan.get("answer_mode")
        if heuristic_plan.get("limit") is not None:
            merged["limit"] = heuristic_plan.get("limit")
        if heuristic_plan.get("time_window_minutes") is not None:
            merged["time_window_minutes"] = heuristic_plan.get("time_window_minutes")
        merged["direct_only"] = bool(heuristic_plan.get("direct_only"))
        merged["inbound_only"] = bool(heuristic_plan.get("inbound_only", True))
        if "messages_only" in heuristic_plan:
            merged["messages_only"] = bool(heuristic_plan.get("messages_only"))
        if "mentions_only" in heuristic_plan:
            merged["mentions_only"] = bool(heuristic_plan.get("mentions_only"))
        merged["source"] = "semantic_runtime+deterministic_guard"
    return merged


def _resolve_assistant_communication_plan(
    *,
    query: str,
    recent_messages: list[dict] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    normalized = _normalize_tr_text(query)
    should_attempt = bool(
        _recent_whatsapp_follow_up_request(query)
        or _recent_whatsapp_actor_filter(query)
        or _recent_whatsapp_group_filter(query)
        or _wants_recent_whatsapp_snapshot_explicit(query)
        or _recent_telegram_actor_filter(query)
        or _wants_recent_telegram_snapshot_explicit(query)
        or _wants_recent_email_snapshot_explicit(query)
        or _recent_email_snapshot_follow_up_limit(query) is not None
        or any(
            marker in normalized
            for marker in (
                "whatsapp",
                "telegram",
                "mesaj",
                "mesajlar",
                "e posta",
                "eposta",
                "mail",
                "gmail",
                "outlook",
                "gelen kutu",
                "inbox",
                "twitter",
                "tweet",
                "mention",
                "sosyal medya",
                "x hesab",
            )
        )
    )
    if not should_attempt:
        return None
    heuristic_plan = _assistant_fallback_communication_plan(query=query, recent_messages=recent_messages)
    runtime_plan = _assistant_runtime_communication_plan(
        query=query,
        recent_messages=recent_messages,
        runtime=runtime,
        events=events,
        subject=subject,
    )
    if runtime_plan:
        return _merge_semantic_and_deterministic_communication_plan(
            query=query,
            runtime_plan=runtime_plan,
            heuristic_plan=heuristic_plan,
        )
    if _runtime_semantic_available(runtime) and heuristic_plan is None:
        return None
    return heuristic_plan


def _compose_recent_email_snapshot_reply(
    *,
    query: str,
    settings,
    store: Persistence,
    recent_messages: list[dict] | None = None,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
    home: dict[str, Any] | None = None,
    review_plan: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    if not review_plan and not _wants_recent_email_snapshot(query, recent_messages):
        return None
    if review_plan and str(review_plan.get("channel") or "").strip().lower() != "email":
        return None

    profile = store.get_user_profile(settings.office_id)
    monitored_only = _profile_has_inbox_positive_filters(profile)
    google_status = _google_status_payload(settings, store)
    outlook_status = _outlook_status_payload(settings, store)
    provider_statuses = _recent_email_provider_statuses(
        query,
        google_status=google_status,
        outlook_status=outlook_status,
        recent_messages=recent_messages,
    )
    limit = int((review_plan or {}).get("limit") or _recent_email_limit(query))
    google_focus, outlook_focus = _recent_email_provider_focus(query, recent_messages)
    if str((review_plan or {}).get("target") or "").strip().lower() == "google":
        google_focus, outlook_focus = True, False
    elif str((review_plan or {}).get("target") or "").strip().lower() == "outlook":
        google_focus, outlook_focus = False, True
    overall_mode = limit == 1 and not google_focus and not outlook_focus
    home_payload = home or build_assistant_home(store, settings.office_id, settings=settings)
    snapshot_items: list[dict[str, Any]] = []
    lines: list[str] = []

    if overall_mode:
        latest_candidates: list[tuple[str, dict[str, Any], dict[str, Any]]] = []
        for provider, status in provider_statuses:
            threads = _list_email_threads_for_provider(store, settings.office_id, provider, monitored_only=monitored_only)
            if threads:
                latest_candidates.append((provider, status, threads[0]))
        latest_candidates.sort(
            key=lambda item: (
                str(item[2].get("received_at") or item[2].get("updated_at") or ""),
                int(item[2].get("id") or 0),
            ),
            reverse=True,
        )
        if latest_candidates:
            provider, status, thread = latest_candidates[0]
            lines.append("Yerel aynadaki en son e-posta şöyle:")
            lines.append(f"{_recent_email_provider_label(provider, status)}")
            lines.append(_format_recent_email_entry(thread, 1))
            snapshot_items.append(
                {
                    "provider": provider,
                    "label": _recent_email_provider_label(provider, status),
                    "items": [thread],
                    "last_sync_at": status.get("last_sync_at"),
                    "connected": bool(status.get("gmail_connected") if provider == "google" else status.get("mail_connected")),
                }
            )
        else:
            lines.append("Bağlı hesaplarda henüz aynalanmış son e-posta başlığı görünmüyor.")
    else:
        lines.append("Yerel aynadaki son e-posta başlıkları şöyle:")
        for provider, status in provider_statuses:
            label = _recent_email_provider_label(provider, status)
            available_threads = _list_email_threads_for_provider(store, settings.office_id, provider, monitored_only=monitored_only)
            available_count = len(available_threads)
            threads = available_threads[:limit]
            lines.append("")
            lines.append(label)
            if threads:
                for index, thread in enumerate(threads, start=1):
                    lines.append(_format_recent_email_entry(thread, index))
                if available_count < limit:
                    lines.append(f"Şu an yerel aynada {available_count} başlık var; daha fazlası henüz senkronlanmadı.")
            else:
                last_sync_at = str(status.get("last_sync_at") or "").strip()
                if monitored_only:
                    lines.append("İzleme kurallarına uyan e-posta başlığı görünmüyor.")
                elif last_sync_at:
                    try:
                        sync_label = _format_turkish_datetime(last_sync_at)
                    except Exception:
                        sync_label = last_sync_at
                    lines.append(f"Henüz başlık görünmüyor. Son başarılı senkron: {sync_label}.")
                elif status.get("gmail_connected") if provider == "google" else status.get("mail_connected"):
                    lines.append("Bağlı ama henüz yerel aynada e-posta başlığı yok.")
                elif status.get("configured"):
                    lines.append("Kurulum bilgisi var ama hesap şu an bağlı görünmüyor.")
                else:
                    lines.append("Bağlı görünmüyor.")
            snapshot_items.append(
                {
                    "provider": provider,
                    "label": label,
                    "items": threads,
                    "last_sync_at": status.get("last_sync_at"),
                    "connected": bool(status.get("gmail_connected") if provider == "google" else status.get("mail_connected")),
                }
            )
    lines.append("")
    lines.append("İstersen bunlardan birinin içeriğini özetleyebilir veya yanıt taslağı hazırlayabilirim.")

    return {
        "content": "\n".join(lines),
        "assistant_summary": home_payload.get("today_summary") or "",
        "tool_suggestions": _assistant_tool_suggestions("mail", requires_setup=home_payload.get("requires_setup") or []),
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_email_snapshot",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "source_refs": source_refs or [],
            "email_snapshot": snapshot_items,
            "google_status": google_status,
            "outlook_status": outlook_status,
            "requested_limit": limit,
            "assistant_communication_plan": review_plan,
        },
    }


def _wants_recent_whatsapp_snapshot_explicit(query: str) -> bool:
    if _is_assistant_integration_setup_request(query):
        return False
    normalized = " ".join(_normalize_tr_text(query).split())
    whatsapp_markers = (
        "whatsapp",
        "whatsapptan",
        "whatsapp tan",
        "whatsappta",
        "whatsapp'ta",
        "whatsapp'tan",
        "wp",
        "wp den",
        "wp dan",
        "wp ten",
        "wp tan",
    )
    recent_markers = (
        "en son",
        "en son gelen",
        "son gelen",
        "son 10",
        "son 5",
        "son mesaj",
        "son mesajlar",
        "son konusma",
        "son konuşma",
        "recent",
        "latest",
    )
    listing_markers = (
        "mesaj",
        "mesajlar",
        "konusma",
        "konuşma",
        "akis",
        "akış",
        "listele",
        "yaz",
        "yazdi",
        "yazdı",
        "goster",
        "göster",
        "nedir",
        "neler",
        "hangi",
        "kim",
        "kimler",
        "atmis",
        "atmış",
        "geldi",
        "geldiler",
    )
    generic_message_overview_markers = (
        "son 10 mesaj",
        "son 5 mesaj",
        "son mesajlar",
        "son mesaj",
        "kimlerden ne mesaj gelmis",
        "kimlerden ne mesaj gelmiş",
        "en son kimlerden ne mesaj",
    )
    incoming_overview_markers = (
        "gelen mesaj",
        "gelen mesajlar",
        "bana gelen mesaj",
        "bana gelen mesajlar",
        "whatsapptan gelen mesaj",
        "whatsapptan gelen mesajlar",
        "whatsapp tan gelen mesaj",
        "whatsapp tan gelen mesajlar",
        "whatsapp mesajlarini soyle",
        "whatsapp mesajlarını söyle",
    )
    conversation_overview_markers = (
        "mesajlasma",
        "mesajlaşma",
        "mesajlasmalar",
        "mesajlaşmalar",
        "mesajlasmalari",
        "mesajlaşmaları",
        "sohbetler",
        "son yazismalar",
        "son yazışmalar",
        "son konusmalar",
        "son konuşmalar",
    )
    non_whatsapp_channel_markers = (
        "mail",
        "e-posta",
        "eposta",
        "gmail",
        "outlook",
        "telegram",
        "instagram",
        "x ",
        "x'te",
        "linkedin",
    )
    numeric_recent_marker = re.search(r"\b(?:en\s+)?son\s+\d{1,2}(?:\s*['’]?(?:er|ar|ser))?\b", normalized)
    inferred_target = bool(
        _recent_whatsapp_group_filter(query)
        or _recent_whatsapp_actor_filter(query)
        or _recent_whatsapp_direct_only(query)
        or _recent_whatsapp_self_requested(query)
    )
    has_whatsapp_marker = any(marker in normalized for marker in whatsapp_markers)
    generic_overview = _recent_whatsapp_generic_overview_requested(query)
    if not has_whatsapp_marker and not inferred_target and not generic_overview:
        return False
    if has_whatsapp_marker and inferred_target and _recent_whatsapp_follow_up_request(query):
        return True
    if has_whatsapp_marker and any(marker in normalized for marker in incoming_overview_markers):
        return True
    if has_whatsapp_marker and any(marker in normalized for marker in conversation_overview_markers):
        return True
    if generic_overview and not any(marker in normalized for marker in non_whatsapp_channel_markers):
        return True
    actor_received_markers = (
        "mesaj gelmis",
        "mesaj gelmiş",
        "mesaj geldi",
        "yazmis mi",
        "yazmış mı",
        "mesaji var",
        "mesajı var",
        "mesajlari var",
        "mesajları var",
        "baksana",
        "incele",
        "bul",
        "son konusma",
        "son konuşma",
        "konusma akisi",
        "konuşma akışı",
    )
    if (
        not numeric_recent_marker
        and not any(marker in normalized for marker in recent_markers)
        and not (inferred_target and any(marker in normalized for marker in actor_received_markers))
        and _recent_whatsapp_time_window_minutes(query) is None
    ):
        return False
    return any(marker in normalized for marker in listing_markers)


