def _recent_whatsapp_contextual_overview_requested(
    query: str,
    recent_messages: list[dict] | None = None,
) -> bool:
    if _recent_whatsapp_generic_overview_requested(query):
        return True
    normalized = " ".join(_normalize_tr_text(query).split())
    if not normalized:
        return False
    if not (_recent_whatsapp_snapshot_context(recent_messages) or {}).get("active"):
        return False
    if any(
        marker in normalized
        for marker in (
            "telegram",
            "mail",
            "e posta",
            "eposta",
            "gmail",
            "outlook",
            "linkedin",
            "instagram",
            "twitter",
            "x hesab",
        )
    ):
        return False
    if _recent_whatsapp_actor_filter(query) or _recent_whatsapp_group_filter(query) or _recent_whatsapp_self_requested(query):
        return False
    return (
        "mesaj" in normalized
        and any(marker in normalized for marker in ("en son", "son", "gelen", "neler", "hangi", "kimler", "soyle", "söyle", "at"))
    )


