def _default_recent_message_review_plan(
    *,
    query: str,
    store: Persistence,
    office_id: str,
) -> dict[str, Any] | None:
    candidates: list[tuple[str, datetime | None]] = []
    whatsapp_items = store.list_whatsapp_messages(office_id, limit=1)
    if whatsapp_items:
        candidates.append(("whatsapp", _parse_recent_whatsapp_sent_at(whatsapp_items[0].get("sent_at"))))
    telegram_items = store.list_telegram_messages(office_id, limit=1)
    if telegram_items:
        candidates.append(("telegram", _parse_recent_whatsapp_sent_at(telegram_items[0].get("sent_at"))))
    x_items = store.list_x_messages(office_id, limit=1)
    if x_items:
        candidates.append(("x", _parse_recent_whatsapp_sent_at(x_items[0].get("sent_at"))))
    email_candidates: list[datetime | None] = []
    for provider in ("google", "outlook"):
        threads = store.list_email_threads(office_id, provider=provider, limit=1)
        if threads:
            email_candidates.append(_parse_recent_whatsapp_sent_at(threads[0].get("received_at") or threads[0].get("updated_at")))
    if email_candidates:
        candidates.append(("email", max((item for item in email_candidates if item is not None), default=None)))
    if not candidates:
        return None
    candidates.sort(key=lambda item: item[1] or datetime.min.replace(tzinfo=timezone.utc), reverse=True)
    channel = candidates[0][0]
    time_window_minutes = _recent_whatsapp_time_window_minutes(query, None, allow_context=False)
    if time_window_minutes is None:
        time_window_minutes = 60 * 24
    return {
        "channel": channel,
        "intent": "inspect_recent",
        "target_kind": "none",
        "target": "",
        "answer_mode": "summary" if _recent_whatsapp_summary_requested(query) else "list",
        "limit": 10,
        "time_window_minutes": time_window_minutes if channel == "whatsapp" else None,
        "direct_only": False,
        "inbound_only": True,
        "confidence": "medium",
        "reason": "generic_recent_message_overview_without_channel",
        "source": "deterministic_fallback",
    }


def _recent_whatsapp_snapshot_follow_up_limit(query: str) -> int | None:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not normalized:
        return None
    shorthand_patterns = (
        r"\b(?:en\s+)?son\s+(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mesaj(?:i|lar|lari)?))(?:\s+(?:goster|yaz|listele))?\b",
        r"\b(\d{1,2})(?:\s*['’]?(?:er|ar|ser))?(?:\s+(?:tane|adet|mesaj(?:i|lar|lari)?))(?:\s+(?:goster|yaz|listele))?\b",
        r"\b(?:en\s+)?son\s+(\d{1,2})(?:\s+(?:goster|yaz|listele))\b",
        r"\b(\d{1,2})(?:\s+(?:goster|yaz|listele))\b",
    )
    for pattern in shorthand_patterns:
        match = re.search(pattern, normalized)
        if match:
            return int(match.group(1))
    return None


def _recent_whatsapp_time_window_minutes(
    query: str,
    recent_messages: list[dict] | None = None,
    *,
    allow_context: bool = True,
) -> int | None:
    normalized = " ".join(_normalize_tr_text(query).split())
    if normalized:
        if "bugun" in normalized:
            now = datetime.now(_safe_local_timezone())
            start_of_day = now.replace(hour=0, minute=0, second=0, microsecond=0)
            return max(1, int((now - start_of_day).total_seconds() // 60))
        match = re.search(
            r"\b(?:(?:en\s+)?son|gecen)?\s*(\d{1,3})\s*(dakika|saat|gun|hafta)(?:(?:da|de|ta|te)(?:ki)?)?(?:\s*(?:icinde|icerisinde|boyunca|icindeki|icerisindeki))?\b",
            normalized,
        ) or re.search(
            r"\b(\d{1,3})\s*(dakika|saat|gun|hafta)(?:(?:da|de|ta|te)(?:ki)?)?(?:\s*(?:icinde|icerisinde|boyunca|icindeki|icerisindeki))\b",
            normalized,
        )
        if match:
            amount = max(1, min(int(match.group(1)), 10080))
            unit = str(match.group(2) or "")
            multipliers = {
                "dakika": 1,
                "saat": 60,
                "gun": 60 * 24,
                "hafta": 60 * 24 * 7,
            }
            multiplier = multipliers.get(unit)
            if multiplier:
                return amount * multiplier
    if not allow_context:
        return None
    context = _recent_whatsapp_snapshot_context(recent_messages)
    candidate = context.get("time_window_minutes") if context else None
    if isinstance(candidate, int) and candidate > 0:
        return candidate
    return None


def _recent_whatsapp_direct_only(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    return any(
        marker in normalized
        for marker in (
            "ozelden",
            "ozelden",
            "ozel mesaj",
            "ozel mesajlar",
            "ozel sohbet",
            "direkt mesaj",
            "dm",
            "bana ozelden",
            "bana ozel mesaj",
        )
    )


def _recent_whatsapp_group_filter(query: str) -> str | None:
    compact = _compact_inline_text(query)
    patterns = (
        r"(?P<group>.+?)\s+grubunda",
        r"(?P<group>.+?)\s+grubundan",
        r"(?P<group>.+?)\s+grubundaki",
        r"(?P<group>.+?)\s+grubu(?:nda|ndan)?",
    )
    for pattern in patterns:
        match = re.search(pattern, compact, re.IGNORECASE)
        if not match:
            continue
        group = _compact_inline_text(str(match.group("group") or "").strip(" \"'“”‘’"))
        if group:
            return group
    return None


