def _recent_whatsapp_self_requested(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    return any(marker in normalized for marker in _RECENT_WHATSAPP_SELF_MARKERS)


def _recent_whatsapp_self_alias_hints(query: str) -> list[str]:
    compact = _compact_inline_text(query)
    if not compact:
        return []
    hints: list[str] = []
    seen: set[str] = set()

    def _push(alias: str) -> None:
        candidate = _compact_inline_text(alias).strip(" \"'“”‘’")
        normalized_candidate = _normalize_contact_lookup_text(candidate)
        if len(normalized_candidate) < 2:
            return
        if normalized_candidate in {"diye", "kayitli", "kayıtlı", "olabilir", "de"}:
            return
        if normalized_candidate not in seen:
            seen.add(normalized_candidate)
            hints.append(candidate)

    for match in re.finditer(
        r"\b(?P<alias>[A-Za-zÇĞİÖŞÜçğıöşü0-9_-]{2,32})\s+diye(?:de)?(?:\s+de)?(?:\s+kayitli|\s+kayıtlı|\s+olabilir)?\b",
        compact,
        re.IGNORECASE,
    ):
        _push(str(match.group("alias") or ""))
    return hints


def _recent_whatsapp_self_aliases(*, store: Persistence, office_id: str, query: str) -> list[str]:
    aliases: list[str] = []
    explicit_aliases = _recent_whatsapp_self_alias_hints(query)
    specific_aliases = [
        alias for alias in explicit_aliases if _normalize_contact_lookup_text(alias) not in _RECENT_WHATSAPP_GENERIC_SELF_ALIASES
    ]
    aliases.extend(specific_aliases or explicit_aliases)

    account = store.get_connected_account(office_id, "whatsapp") or {}
    account_label = _compact_inline_text(str(account.get("account_label") or ""))
    if account_label:
        aliases.append(account_label)
    profile = store.get_user_profile(office_id)
    display_name = _compact_inline_text(str(profile.get("display_name") or ""))
    if display_name:
        aliases.append(display_name)

    aliases.extend(
        [
            "Kendime Mesaj Gönder",
            "Kendime Mesaj",
            "Kendime Not",
            "Notlarım",
            "Notlarim",
            "Notes to self",
            "Saved Messages",
        ]
    )
    if not specific_aliases:
        aliases.append("Siz")
    return _expand_recent_whatsapp_aliases(aliases)


def _recent_whatsapp_query_allows_context_carryover(query: str) -> bool:
    return not _wants_recent_whatsapp_snapshot_explicit(query)


def _recent_whatsapp_target_is_self(
    *,
    store: Persistence,
    office_id: str,
    query: str,
    target: str | None,
) -> bool:
    candidate = _compact_inline_text(str(target or ""))
    if not candidate:
        return False
    aliases = _recent_whatsapp_self_aliases(store=store, office_id=office_id, query=query)
    if any(
        _recent_whatsapp_target_matches(candidate, alias) or _recent_whatsapp_target_matches(alias, candidate)
        for alias in aliases
        if alias
    ):
        return True

    account = store.get_connected_account(office_id, "whatsapp") or {}
    account_label = _compact_inline_text(str(account.get("account_label") or ""))
    profile = store.get_user_profile(office_id)
    display_name = _compact_inline_text(str(profile.get("display_name") or ""))
    self_identity_aliases = _expand_recent_whatsapp_aliases([account_label, display_name])
    if not self_identity_aliases:
        return False

    saw_outbound_self_like = False
    saw_inbound_from_target = False
    for message in _enrich_recent_whatsapp_messages(
        store,
        office_id,
        store.list_whatsapp_messages(office_id, limit=200),
    ):
        if _recent_whatsapp_group_label(message):
            continue
        metadata = dict(message.get("metadata") or {})
        labels = [
            _recent_whatsapp_actor_label(message),
            _compact_inline_text(str(metadata.get("chat_name") or "")),
            _compact_inline_text(str(metadata.get("contact_name") or "")),
            _compact_inline_text(str(message.get("sender") or "")),
            _compact_inline_text(str(message.get("recipient") or "")),
        ]
        if not any(_recent_whatsapp_target_matches(candidate, label) for label in labels if label):
            continue
        direction = str(message.get("direction") or "").strip().lower()
        sender = _compact_inline_text(str(message.get("sender") or ""))
        recipient = _compact_inline_text(str(message.get("recipient") or ""))
        sender_is_self = any(_recent_whatsapp_target_matches(sender, alias) for alias in self_identity_aliases)
        recipient_is_target = _recent_whatsapp_target_matches(candidate, recipient)
        sender_is_target = _recent_whatsapp_target_matches(candidate, sender)
        if direction == "outbound" and sender_is_self and recipient_is_target:
            saw_outbound_self_like = True
        elif direction == "inbound" and sender_is_target:
            saw_inbound_from_target = True

    return saw_outbound_self_like and not saw_inbound_from_target


def _recent_whatsapp_actor_filter(query: str) -> str | None:
    compact = _compact_inline_text(query)
    normalized_compact = " ".join(_normalize_tr_text(compact).split())
    has_whatsapp_marker = any(
        marker in normalized_compact
        for marker in (
            "whatsapp",
            "whatsappta",
            "whatsapptan",
            "whatsappdan",
            "wp",
            "wp den",
            "wp dan",
            "wp ten",
            "wp tan",
        )
    )
    if not has_whatsapp_marker and any(
        marker in normalized_compact
        for marker in ("telegram", "mail", "e posta", "eposta", "gmail", "outlook", "linkedin", "instagram", "twitter", "x hesab")
    ):
        return None
    clauses = [compact]
    clauses.extend(
        _compact_inline_text(item)
        for item in re.split(r"\b(?:ya da|veya|ama|fakat|peki|bir de)\b", compact, flags=re.IGNORECASE)
        if _compact_inline_text(item)
    )

    def _clean_candidate(value: str) -> str:
        candidate = _compact_inline_text(value).strip(" \"'“”‘’")
        candidate = re.sub(
            r"^(?:(?:whatsapp|wp)(?:['’]?(?:ta|tan|dan|te|ten|taki))?|whatsappta|whatsapptan|whatsappdan|whatsapptaki|wpden|wpdan|wpten|wptan)\s+",
            "",
            candidate,
            flags=re.IGNORECASE,
        )
        candidate = re.sub(
            r"^(?:(?:whatsapp|wp)(?:[ıiuü']?n?[dt]?a?n?)?\s+)?(?:[ıiuü]?\s*)?(?:incele|bak|kontrol et|goster|göster|listele)\s+",
            "",
            candidate,
            flags=re.IGNORECASE,
        )
        candidate = re.sub(r"^(?:en\s+son|son|bana|bir)\s+", "", candidate, flags=re.IGNORECASE)
        candidate = re.sub(
            r"\b((?:abi|abla|baba|anne|dayi|dayı|amca|teyze|hala|dede|anneanne|babaanne))n\b",
            r"\1",
            candidate,
            flags=re.IGNORECASE,
        )
        candidate = _compact_inline_text(candidate).strip(" \"'“”‘’")
        normalized_candidate = _normalize_tr_text(candidate)
        compact_platform_token = re.sub(r"[^a-z]+", "", normalized_candidate)
        if normalized_candidate in {
            "whatsapp",
            "whatsappta",
            "whatsapptan",
            "whatsappdan",
            "whatsapptaki",
            "whatsapp icin",
            "whatsapp için",
            "wp",
            "wpden",
            "wpdan",
            "wpten",
            "wptan",
            "icin",
            "için",
            "bana",
            "bana whatsapp",
        } or compact_platform_token in {
            "whatsapp",
            "whatsappta",
            "whatsapptan",
            "whatsappdan",
            "whatsappicin",
            "wp",
            "wpden",
            "wpdan",
            "wpten",
            "wptan",
        }:
            return ""
        if _normalize_tr_text(candidate) in {
            "kim",
            "kimler",
            "kimler",
            "hangi kisi",
            "hangi kisiler",
            "hangi kisilerden",
        }:
            return ""
        noisy_follow_up_markers = (
            "dikkatli bak",
            "zaten",
            "cevapvermistim",
            "cevap vermistim",
            "cevapvermiştim",
            "cevap vermiştim",
            "onu bul",
            "baksana",
        )
        if any(marker in normalized_candidate for marker in noisy_follow_up_markers):
            return ""
        return candidate

    message_token = r"mesaj(?:i|ı|lari|ları)?(?:n[ıi])?"
    patterns = (
        rf"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+{message_token}\s+var(?:di|dı|mis|mış|miş|mus|muş)?",
        r"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+mesajlar[ıi]na?\s+bak",
        r"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+mesajlar[ıi]n[ıi]?\s+incele",
        rf"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+{message_token}\s+(?:incele|bul|gordun(?:\s+mu)?|gördün(?:\s+mü)?)",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+whatsapp(?:ta|tan)?\s+(?:ne\s+)?{message_token}\s+gelm(?:is|iş)(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+(?:hangi|hangi\s+bir)\s+{message_token}\s+geldi(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+(?:hangi|hangi\s+bir)\s+{message_token}\s+gelm(?:is|iş)(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+(?:ne\s+)?{message_token}\s+gelm(?:is|iş)(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+{message_token}\s+geldi(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+{message_token}\s+en\s+son\s+ne\s+geldi(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+{message_token}\s+en\s+son\s+ne\s+gelm(?:is|iş)(?:\s+mi)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+(?:ne\s+)?{message_token}\s+geldi(?:\s+mi)?(?:\s+en\s+son)?",
        r"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+ne\s+gelm(?:is|iş)(?:\s+mi)?",
        r"(?P<actor>.+?)\s+yazm(?:is|ış)\s+mi",
        r"(?P<actor>.+?)\s+en\s+son\s+ne\s+yazm(?:is|ış)(?:ti|tı)?",
        r"(?P<actor>.+?)\s+son\s+ne\s+yazm(?:is|ış)(?:ti|tı)?",
        rf"(?P<actor>.+?)['’]?\s*(?:dan|den)\s+son\s+{message_token}(?:\s+neydi|\s+gordun(?:\s+mu)?|\s+gördün(?:\s+mü)?)?",
        rf"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+son\s+{message_token}(?:\s+neydi|\s+gordun(?:\s+mu)?|\s+gördün(?:\s+mü)?)?",
        rf"(?P<actor>.+?)['’]?(?:in|ın|un|ün)\s+en\s+son\s+{message_token}(?:\s+neydi|\s+gordun(?:\s+mu)?|\s+gördün(?:\s+mü)?)?",
        rf"(?P<actor>.+?)\s+en\s+son\s+{message_token}",
        rf"(?P<actor>.+?)\s+son\s+{message_token}",
        r"(?P<actor>.+?)\s+ile\s+son\s+(?:konusma|konuşma)(?:\s+(?:akisi|akışı))?",
        rf"(?P<actor>.+?)\s+ile\s+son\s+{message_token}",
    )
    for clause in clauses:
        if not clause:
            continue
        for pattern in patterns:
            match = re.search(pattern, clause, re.IGNORECASE)
            if not match:
                continue
            actor = _clean_candidate(str(match.group("actor") or ""))
            if actor:
                return actor
    return None


def _recent_whatsapp_summary_requested(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    return any(
        marker in normalized
        for marker in (
            "ne ile alakali",
            "ne ile alakalı",
            "neden bahsediyor",
            "ne anlatiyor",
            "ne anlatıyor",
            "ne demek istiyor",
            "ne diyor",
            "yorumla",
            "yorumlarsan",
            "ozetle",
            "özetle",
        )
    )


def _recent_whatsapp_target_matches(filter_text: str, candidate: str) -> bool:
    left = _normalize_tr_text(filter_text)
    right = _normalize_tr_text(candidate)
    if not left or not right:
        return False
    if left in right or right in left:
        return True
    left_tokens = {token for token in _normalize_contact_lookup_text(left).split() if token}
    right_tokens = {token for token in _normalize_contact_lookup_text(right).split() if token}
    if not left_tokens or not right_tokens:
        return False
    common_tokens = left_tokens & right_tokens
    return len(common_tokens) >= min(len(left_tokens), len(right_tokens), 2)


_RECENT_WHATSAPP_RELATION_ALIASES: dict[str, tuple[str, ...]] = {
    "anne": ("anne", "annem", "anneden", "anneme", "mother", "mom"),
    "baba": ("baba", "babam", "babadan", "babama", "father", "dad"),
    "abi": ("abi", "abim", "abiden", "abime", "brother"),
    "abla": ("abla", "ablam", "abladan", "ablama", "sister"),
    "es": ("es", "eş", "eşim", "karim", "karım", "kocam", "wife", "husband", "spouse"),
    "ogul": ("ogul", "oğul", "ogluma", "oğluma", "son"),
    "kiz": ("kiz", "kız", "kizim", "kızım", "daughter"),
}


def _expand_recent_whatsapp_aliases(values: list[str] | tuple[str, ...]) -> list[str]:
    aliases: list[str] = []
    seen: set[str] = set()

    def _push(alias: str) -> None:
        compact_alias = _compact_inline_text(alias)
        alias_normalized = _normalize_contact_lookup_text(compact_alias)
        if alias_normalized and alias_normalized not in seen:
            seen.add(alias_normalized)
            aliases.append(compact_alias)

    for value in values:
        compact = _compact_inline_text(str(value or ""))
        if not compact:
            continue
        normalized = _normalize_contact_lookup_text(compact)
        _push(compact)
        tokens = [token for token in normalized.split() if token]
        if len(tokens) >= 3:
            _push(f"{tokens[0]} {tokens[-1]}")
            _push(" ".join(tokens[:2]))
        elif len(tokens) == 2:
            _push(tokens[0])
        for relation_key, relation_aliases in _RECENT_WHATSAPP_RELATION_ALIASES.items():
            if normalized == relation_key or normalized in relation_aliases:
                for alias in relation_aliases:
                    _push(alias)
    return aliases


def _recent_whatsapp_target_score(search_text: str, alias: str) -> int:
    left = _normalize_contact_lookup_text(search_text)
    right = _normalize_contact_lookup_text(alias)
    if not left or not right or len(right) < 2:
        return 0
    if left == right:
        return 120
    if re.search(rf"(?:^| ){re.escape(right)}(?: |$)", left):
        return 105
    if right in left:
        return 88
    if left in right:
        return 72
    left_tokens = set(left.split())
    right_tokens = set(right.split())
    if right_tokens and right_tokens.issubset(left_tokens):
        return 70
    common_tokens = left_tokens & right_tokens
    if len(common_tokens) >= 2:
        return 64
    if common_tokens and len(left_tokens) == 1 and len(right_tokens) <= 2:
        return 52
    return 0


def _recent_whatsapp_self_note_label_score(value: str) -> int:
    normalized = _normalize_contact_lookup_text(value)
    if not normalized:
        return 0
    if any(marker in normalized for marker in _RECENT_WHATSAPP_SELF_NOTE_LABELS):
        return 120
    if "not" in normalized and ("kendi" in normalized or "mesaj" in normalized):
        return 84
    return 0


def _resolve_recent_whatsapp_actor_target(
    *,
    query: str,
    actor_filter: str | None,
    store: Persistence,
    office_id: str,
) -> dict[str, Any] | None:
    search_text = _compact_inline_text(actor_filter or "")
    if not search_text:
        return None

    candidate_pool: list[dict[str, Any]] = []
    profile = store.get_user_profile(office_id)
    whatsapp_snapshot_ref_by_phone: dict[str, str] = {}
    for item in store.list_whatsapp_contact_snapshots(office_id, limit=240):
        conversation_ref = _compact_inline_text(str(item.get("conversation_ref") or ""))
        if not conversation_ref or conversation_ref == "status@broadcast":
            continue
        is_group = bool(item.get("is_group")) or conversation_ref.endswith("@g.us")
        if is_group:
            continue
        for source in (item.get("phone_number"), conversation_ref):
            digits = _extract_recent_whatsapp_digits(source)
            if digits and digits not in whatsapp_snapshot_ref_by_phone:
                whatsapp_snapshot_ref_by_phone[digits] = conversation_ref
    for item in list(profile.get("related_profiles") or []):
        if not isinstance(item, dict):
            continue
        name = _compact_inline_text(str(item.get("name") or ""))
        relationship = _compact_inline_text(str(item.get("relationship") or ""))
        aliases = _expand_recent_whatsapp_aliases([name, relationship])
        if not aliases:
            continue
        candidate_pool.append(
            {
                "display_name": name or relationship or "Kişi",
                "relationship_hint": relationship,
                "aliases": aliases,
                "source": "related_profile",
            }
        )
    for item in build_assistant_relationship_profiles(store, office_id, limit=18):
        aliases = _expand_recent_whatsapp_aliases(
            [
                str(item.get("display_name") or ""),
                str(item.get("relationship_hint") or ""),
                *[str(value) for value in item.get("handles") or []],
                *[str(value) for value in item.get("phone_numbers") or []],
            ]
        )
        if not aliases:
            continue
        candidate_pool.append(
            {
                "display_name": _compact_inline_text(str(item.get("display_name") or "")) or "Kişi",
                "relationship_hint": _compact_inline_text(str(item.get("relationship_hint") or "")),
                "aliases": aliases,
                "source": "relationship_profile",
            }
        )
    for item in build_assistant_contact_profiles(store, office_id, limit=80):
        phone_numbers = [str(value) for value in item.get("phone_numbers") or []]
        handles = [str(value) for value in item.get("handles") or []]
        conversation_ref = ""
        for source in [*phone_numbers, *handles]:
            digits = _extract_recent_whatsapp_digits(source)
            if digits and whatsapp_snapshot_ref_by_phone.get(digits):
                conversation_ref = whatsapp_snapshot_ref_by_phone[digits]
                break
        aliases = _expand_recent_whatsapp_aliases(
            [
                str(item.get("display_name") or ""),
                str(item.get("relationship_hint") or ""),
                *handles,
                *phone_numbers,
            ]
        )
        if not aliases:
            continue
        candidate_pool.append(
            {
                "display_name": _compact_inline_text(str(item.get("display_name") or "")) or "Kişi",
                "relationship_hint": _compact_inline_text(str(item.get("relationship_hint") or "")),
                "aliases": aliases,
                "conversation_ref": conversation_ref,
                "source": "contact_profile",
                "kind": str(item.get("kind") or ""),
                "has_phone_identity": bool(phone_numbers),
            }
        )
    for item in store.list_whatsapp_contact_snapshots(office_id, limit=200):
        conversation_ref = _compact_inline_text(str(item.get("conversation_ref") or ""))
        if not conversation_ref or conversation_ref == "status@broadcast":
            continue
        is_group = bool(item.get("is_group")) or conversation_ref.endswith("@g.us")
        if is_group:
            continue
        metadata = dict(item.get("metadata") or {})
        aliases = _expand_recent_whatsapp_aliases(
            [
                str(item.get("display_name") or ""),
                str(item.get("profile_name") or ""),
                str(item.get("phone_number") or ""),
                str(metadata.get("contact_name") or ""),
                str(metadata.get("chat_name") or ""),
                conversation_ref,
            ]
        )
        if not aliases:
            continue
        candidate_pool.append(
            {
                "display_name": _compact_inline_text(str(item.get("display_name") or item.get("profile_name") or "")) or "Kişi",
                "relationship_hint": "",
                "aliases": aliases,
                "conversation_ref": conversation_ref,
                "source": "whatsapp_snapshot",
                "has_phone_identity": bool(str(item.get("phone_number") or "").strip()),
            }
        )
    for item in _enrich_recent_whatsapp_messages(
        store,
        office_id,
        store.list_whatsapp_messages(office_id, limit=200),
    ):
        metadata = dict(item.get("metadata") or {})
        aliases = _expand_recent_whatsapp_aliases(
            [
                _recent_whatsapp_actor_label(item),
                str(metadata.get("chat_name") or ""),
                str(metadata.get("contact_name") or ""),
                str(metadata.get("profile_name") or ""),
                str(item.get("sender") or ""),
                str(item.get("recipient") or ""),
                str(item.get("conversation_ref") or ""),
            ]
        )
        if not aliases:
            continue
        candidate_pool.append(
            {
                "display_name": _compact_inline_text(_recent_whatsapp_actor_label(item)) or "Kişi",
                "relationship_hint": "",
                "aliases": aliases,
                "conversation_ref": _compact_inline_text(str(item.get("conversation_ref") or "")),
                "source": "whatsapp_message",
                "is_group": bool(metadata.get("is_group")) or str(item.get("conversation_ref") or "").strip().endswith("@g.us"),
            }
        )

    best: dict[str, Any] | None = None
    best_score = 0
    for candidate in candidate_pool:
        aliases = list(candidate.get("aliases") or [])
        alias_scores = [(alias, _recent_whatsapp_target_score(search_text, alias)) for alias in aliases]
        base_score = max((score for _, score in alias_scores), default=0)
        if base_score <= 0:
            continue
        score = base_score
        source = str(candidate.get("source") or "")
        if source == "related_profile":
            score += 22
        elif source == "contact_profile":
            score += 18
        elif source == "whatsapp_snapshot":
            score += 15
        elif source == "relationship_profile":
            score += 10
        if candidate.get("has_phone_identity"):
            score += 8
        if candidate.get("kind") == "group" or candidate.get("is_group"):
            score -= 18
        if score > best_score:
            matched_alias = next((alias for alias, alias_score in alias_scores if alias_score == base_score), aliases[0])
            best_score = score
            best = {
                **candidate,
                "matched_alias": _compact_inline_text(matched_alias),
                "score": score,
            }
    return best


def _recent_whatsapp_self_conversation_context(
    *,
    store: Persistence,
    office_id: str,
    profile: dict[str, Any] | None,
    query: str,
    time_window_minutes: int | None,
    preferred_aliases: list[str] | None = None,
) -> dict[str, Any] | None:
    aliases = _recent_whatsapp_self_aliases(store=store, office_id=office_id, query=query)
    if preferred_aliases:
        aliases = _expand_recent_whatsapp_aliases([*aliases, *[str(alias or "") for alias in preferred_aliases]])
    explicit_aliases = _recent_whatsapp_self_alias_hints(query)
    specific_aliases = [
        alias for alias in explicit_aliases if _normalize_contact_lookup_text(alias) not in _RECENT_WHATSAPP_GENERIC_SELF_ALIASES
    ]
    preferred_specific_aliases = [
        _compact_inline_text(str(alias or ""))
        for alias in (preferred_aliases or [])
        if _normalize_contact_lookup_text(str(alias or "")) not in _RECENT_WHATSAPP_GENERIC_SELF_ALIASES
    ]
    score_aliases = list(specific_aliases or preferred_specific_aliases)
    candidate_messages = _enrich_recent_whatsapp_messages(
        store,
        office_id,
        store.list_whatsapp_messages(office_id, limit=400),
    )
    if profile is not None:
        candidate_messages = [
            item
            for item in candidate_messages
            if not _whatsapp_message_monitoring_decision(profile, item).get("blocked")
        ]
    candidate_messages = [
        item
        for item in candidate_messages
        if not _recent_whatsapp_group_label(item)
    ]
    if time_window_minutes:
        cutoff = datetime.now(_safe_local_timezone()) - timedelta(minutes=time_window_minutes)
        candidate_messages = [
            item
            for item in candidate_messages
            if (parsed_sent_at := _parse_recent_whatsapp_sent_at(item.get("sent_at"))) is not None and parsed_sent_at >= cutoff
        ]
    if not candidate_messages:
        return None

    conversations: dict[str, list[dict[str, Any]]] = {}
    for item in candidate_messages:
        conversation_ref = _compact_inline_text(str(item.get("conversation_ref") or "")) or str(item.get("id") or "")
        if conversation_ref:
            conversations.setdefault(conversation_ref, []).append(item)

    best_ref = ""
    best_label = ""
    best_rank: tuple[int, int, float] | None = None
    for conversation_ref, items in conversations.items():
        labels: set[str] = set()
        outbound_count = 0
        for item in items:
            metadata = dict(item.get("metadata") or {})
            if str(item.get("direction") or "").strip().lower() == "outbound":
                outbound_count += 1
            labels.update(
                {
                    _compact_inline_text(_recent_whatsapp_actor_label(item)),
                    _compact_inline_text(str(metadata.get("chat_name") or "")),
                    _compact_inline_text(str(metadata.get("contact_name") or "")),
                    _compact_inline_text(str(item.get("sender") or "")),
                    _compact_inline_text(str(item.get("recipient") or "")),
                    _compact_inline_text(str(item.get("conversation_ref") or "")),
                }
            )
        labels = {label for label in labels if label}
        explicit_score = max((_recent_whatsapp_target_score(alias, label) for alias in score_aliases for label in labels), default=0)
        note_score = max((_recent_whatsapp_self_note_label_score(label) for label in labels), default=0)
        latest_dt = max(
            (_parse_recent_whatsapp_sent_at(item.get("sent_at")) or datetime.min.replace(tzinfo=timezone.utc))
            for item in items
        )
        if specific_aliases:
            if explicit_score <= 0:
                continue
            rank = (explicit_score, note_score + outbound_count, latest_dt.timestamp())
        else:
            combined_score = max(explicit_score, note_score)
            if combined_score <= 0:
                continue
            rank = (combined_score, outbound_count, latest_dt.timestamp())
        if best_rank is None or rank > best_rank:
            best_rank = rank
            best_ref = conversation_ref
            if specific_aliases:
                best_label = next(
                    (
                        label
                        for label in labels
                        if any(_recent_whatsapp_target_score(alias, label) > 0 for alias in aliases)
                    ),
                    "",
                )
            if not best_label:
                best_label = next((label for label in labels if _recent_whatsapp_self_note_label_score(label) > 0), "")
            if not best_label:
                best_label = next(iter(labels), "")

    if not best_ref:
        return None

    conversation_items = [
        item
        for item in candidate_messages
        if _compact_inline_text(str(item.get("conversation_ref") or "")) == best_ref
    ]
    if not conversation_items:
        return None
    conversation_items.sort(
        key=lambda item: (
            _parse_recent_whatsapp_sent_at(item.get("sent_at")) or datetime.min.replace(tzinfo=timezone.utc),
            int(item.get("id") or 0),
        )
    )
    latest_message = conversation_items[-1] if conversation_items else None
    if not latest_message:
        return None
    return {
        "conversation_ref": best_ref,
        "self_label": best_label or "Kendine not sohbeti",
        "latest_message": latest_message,
        "recent_window": conversation_items[-4:],
        "conversation_items": conversation_items,
        "matched_aliases": aliases,
    }


def _recent_whatsapp_message_matches_actor_aliases(message: dict[str, Any], aliases: list[str]) -> bool:
    normalized_aliases = [alias for alias in (_compact_inline_text(item) for item in aliases or []) if alias]
    if not normalized_aliases:
        return False
    metadata = dict(message.get("metadata") or {})
    is_group = bool(_recent_whatsapp_group_label(message))
    candidates = [
        _recent_whatsapp_actor_label(message),
        _recent_whatsapp_group_label(message),
        _compact_inline_text(str(message.get("sender") or "")),
        _compact_inline_text(str(message.get("recipient") or "")),
        _compact_inline_text(str(message.get("conversation_ref") or "")),
        _compact_inline_text(str(metadata.get("contact_name") or "")),
        _compact_inline_text(str(metadata.get("chat_name") or "")),
        _compact_inline_text(str(metadata.get("author") or "")),
        _compact_inline_text(str(metadata.get("participant") or "")),
    ]
    if not is_group:
        candidates.append(_compact_inline_text(str(metadata.get("profile_name") or "")))
    return any(
        _recent_whatsapp_target_matches(alias, candidate)
        for alias in normalized_aliases
        for candidate in candidates
        if candidate
    )


def _recent_whatsapp_follow_up_request(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    if _recent_whatsapp_generic_overview_requested(query):
        return True
    if _recent_whatsapp_snapshot_follow_up_limit(query) is not None:
        return True
    if _recent_whatsapp_time_window_minutes(query) is not None:
        return True
    if (
        _recent_whatsapp_group_filter(query)
        or _recent_whatsapp_actor_filter(query)
        or _recent_whatsapp_direct_only(query)
        or _recent_whatsapp_self_requested(query)
    ):
        return True
    return any(
        marker in normalized
        for marker in (
            "en son",
            "son mesaj",
            "mesajlar",
            "kim",
            "kimler",
            "hangi mesaj",
            "ne yazmis",
            "ne yazmış",
            "atmis",
            "atmış",
            "yazdi",
            "yazdı",
            "goster",
            "göster",
            "listele",
            "geldi",
            "geldiler",
            "mesajlasma",
            "mesajlaşma",
            "mesajlasmalar",
            "mesajlaşmalar",
            "sohbet",
            "sohbetler",
            "bak",
            "baksana",
            "incele",
            "bul",
            "yorumla",
            "cevapvermistim",
            "cevap vermistim",
            "cevapvermiştim",
            "cevap vermiştim",
        )
    )


def _recent_whatsapp_conversation_context(
    *,
    store: Persistence,
    office_id: str,
    profile: dict[str, Any] | None,
    actor_filter: str | None,
    actor_aliases: list[str] | None,
    time_window_minutes: int | None,
) -> dict[str, Any] | None:
    aliases = [alias for alias in (_compact_inline_text(item) for item in list(actor_aliases or [])) if alias]
    if actor_filter:
        aliases.append(_compact_inline_text(actor_filter))
    aliases = _expand_recent_whatsapp_aliases(aliases)
    if not aliases:
        return None

    candidate_messages = _enrich_recent_whatsapp_messages(
        store,
        office_id,
        store.list_whatsapp_messages(office_id, limit=400),
    )
    if profile is not None:
        candidate_messages = [
            item
            for item in candidate_messages
            if not _whatsapp_message_monitoring_decision(profile, item).get("blocked")
        ]
    if time_window_minutes:
        cutoff = datetime.now(_safe_local_timezone()) - timedelta(minutes=time_window_minutes)
        candidate_messages = [
            item
            for item in candidate_messages
            if (parsed_sent_at := _parse_recent_whatsapp_sent_at(item.get("sent_at"))) is not None and parsed_sent_at >= cutoff
        ]
    matched_messages = [
        item
        for item in candidate_messages
        if _recent_whatsapp_message_matches_actor_aliases(item, aliases)
    ]
    if not matched_messages:
        return None

    def _message_target_score(message: dict[str, Any]) -> int:
        metadata = dict(message.get("metadata") or {})
        is_group = bool(_recent_whatsapp_group_label(message))
        candidates = [
            _recent_whatsapp_actor_label(message),
            _recent_whatsapp_group_label(message),
            _compact_inline_text(str(metadata.get("contact_name") or "")),
            _compact_inline_text(str(metadata.get("chat_name") or "")),
            _compact_inline_text(str(message.get("sender") or "")),
            _compact_inline_text(str(message.get("recipient") or "")),
        ]
        if not is_group:
            candidates.append(_compact_inline_text(str(metadata.get("profile_name") or "")))
        best_score = 0
        for alias in aliases:
            for candidate in candidates:
                if not candidate:
                    continue
                best_score = max(
                    best_score,
                    _recent_whatsapp_target_score(candidate, alias),
                    _recent_whatsapp_target_score(alias, candidate),
                )
        return best_score

    conversations: dict[str, list[dict[str, Any]]] = {}
    for item in matched_messages:
        conversation_ref = _compact_inline_text(str(item.get("conversation_ref") or "")) or str(item.get("id") or "")
        conversations.setdefault(conversation_ref, []).append(item)

    best_ref = ""
    best_rank: tuple[int, int, float] | None = None
    for conversation_ref, items in conversations.items():
        latest_dt = max(
            (_parse_recent_whatsapp_sent_at(item.get("sent_at")) or datetime.min.replace(tzinfo=timezone.utc))
            for item in items
        )
        direct_bonus = 1 if any(not _recent_whatsapp_group_label(item) for item in items) else 0
        match_score = max((_message_target_score(item) for item in items), default=0)
        rank = (direct_bonus, match_score, latest_dt.timestamp())
        if best_rank is None or rank > best_rank:
            best_rank = rank
            best_ref = conversation_ref

    if not best_ref:
        return None

    conversation_items = [
        item
        for item in candidate_messages
        if _compact_inline_text(str(item.get("conversation_ref") or "")) == best_ref
    ]
    if not conversation_items:
        conversation_items = list(conversations.get(best_ref) or [])
    if not conversation_items:
        return None

    conversation_items.sort(
        key=lambda item: (
            _parse_recent_whatsapp_sent_at(item.get("sent_at")) or datetime.min.replace(tzinfo=timezone.utc),
            int(item.get("id") or 0),
        )
    )
    latest_inbound = next(
        (item for item in reversed(conversation_items) if str(item.get("direction") or "").strip().lower() == "inbound"),
        None,
    )
    latest_outbound = next(
        (item for item in reversed(conversation_items) if str(item.get("direction") or "").strip().lower() == "outbound"),
        None,
    )
    actor_label = ""
    for item in reversed(conversation_items):
        if str(item.get("direction") or "").strip().lower() == "inbound":
            actor_label = _recent_whatsapp_actor_label(item)
            if actor_label:
                break
    if not actor_label:
        actor_label = aliases[0]

    return {
        "conversation_ref": best_ref,
        "actor_label": actor_label,
        "latest_inbound": latest_inbound,
        "latest_outbound": latest_outbound,
        "recent_window": conversation_items[-4:],
        "conversation_items": conversation_items,
    }


def _compose_recent_whatsapp_actor_conversation_lines(context: dict[str, Any]) -> list[str]:
    actor_label = _compact_inline_text(str(context.get("actor_label") or "")) or "Karşı taraf"
    recent_window = list(context.get("recent_window") or [])
    latest_inbound = context.get("latest_inbound") if isinstance(context.get("latest_inbound"), dict) else None
    latest_outbound = context.get("latest_outbound") if isinstance(context.get("latest_outbound"), dict) else None

    lines: list[str] = []
    if recent_window:
        lines.append("")
        lines.append(f"{actor_label} ile son konuşma akışı:")
        for item in recent_window:
            body = _compact_inline_text(str(item.get("body") or ""))
            if not body:
                continue
            direction = str(item.get("direction") or "").strip().lower()
            speaker = "Sen" if direction == "outbound" else actor_label
            timestamp = ""
            sent_at = str(item.get("sent_at") or "").strip()
            if sent_at:
                try:
                    timestamp = _format_turkish_datetime(sent_at)
                except Exception:
                    timestamp = ""
            if timestamp:
                lines.append(f"• {speaker}: {body} ({timestamp})")
            else:
                lines.append(f"• {speaker}: {body}")
    if latest_inbound:
        latest_inbound_body = _compact_inline_text(str(latest_inbound.get("body") or ""))
        if latest_inbound_body:
            lines.append(f'En son ondan gelen mesaj: "{latest_inbound_body}".')
    elif latest_outbound:
        latest_outbound_body = _compact_inline_text(str(latest_outbound.get("body") or ""))
        if latest_outbound_body:
            lines.append(f'Bu konuşmada en son yazan sendin: "{latest_outbound_body}".')
    return lines


def _compose_recent_whatsapp_actor_last_message_lines(context: dict[str, Any]) -> list[str]:
    actor_label = _compact_inline_text(str(context.get("actor_label") or "")) or "Karşı taraf"
    recent_window = list(context.get("recent_window") or [])[-3:]
    latest_inbound = context.get("latest_inbound") if isinstance(context.get("latest_inbound"), dict) else None

    lines: list[str] = []
    if recent_window:
        lines.append("")
        lines.append(f"{actor_label} ile son konuşma akışı:")
        for item in recent_window:
            body = _compact_inline_text(str(item.get("body") or ""))
            if not body:
                continue
            direction = str(item.get("direction") or "").strip().lower()
            speaker = "Sen" if direction == "outbound" else actor_label
            lines.append(f"• {speaker}: {body}")
    if latest_inbound:
        latest_inbound_body = _compact_inline_text(str(latest_inbound.get("body") or ""))
        if latest_inbound_body:
            lines.append(f'En son ondan gelen mesaj: "{latest_inbound_body}".')
    return lines


def _recent_whatsapp_message_identity(message: dict[str, Any] | None) -> tuple[str, str, str, str, str]:
    if not isinstance(message, dict):
        return ("", "", "", "", "")
    return (
        str(message.get("id") or "").strip(),
        str(message.get("message_ref") or "").strip(),
        str(message.get("sent_at") or "").strip(),
        str(message.get("direction") or "").strip().lower(),
        _compact_inline_text(str(message.get("body") or "")),
    )


def _recent_whatsapp_previous_outbound_before_inbound(context: dict[str, Any]) -> dict[str, Any] | None:
    latest_inbound = context.get("latest_inbound") if isinstance(context.get("latest_inbound"), dict) else None
    conversation_items = list(context.get("conversation_items") or [])
    if not latest_inbound or not conversation_items:
        return None

    inbound_identity = _recent_whatsapp_message_identity(latest_inbound)
    seen_inbound = False
    for item in reversed(conversation_items):
        if not isinstance(item, dict):
            continue
        if not seen_inbound:
            if _recent_whatsapp_message_identity(item) == inbound_identity:
                seen_inbound = True
            continue
        if str(item.get("direction") or "").strip().lower() == "outbound":
            return item
    return None


def _compose_recent_whatsapp_actor_summary_lines(context: dict[str, Any]) -> list[str]:
    lines = _compose_recent_whatsapp_actor_last_message_lines(context)
    latest_inbound = context.get("latest_inbound") if isinstance(context.get("latest_inbound"), dict) else None
    latest_outbound = context.get("latest_outbound") if isinstance(context.get("latest_outbound"), dict) else None
    previous_outbound = _recent_whatsapp_previous_outbound_before_inbound(context)

    latest_inbound_body = _compact_inline_text(str((latest_inbound or {}).get("body") or ""))
    previous_outbound_body = _compact_inline_text(str((previous_outbound or {}).get("body") or ""))
    latest_outbound_body = _compact_inline_text(str((latest_outbound or {}).get("body") or ""))

    if latest_inbound_body and previous_outbound_body:
        lines.append(
            f'Bu mesajdan hemen önce sen "{previous_outbound_body}" yazmışsın; '
            "yani en son gelen mesaj buna yanıt gibi görünüyor."
        )
    elif latest_outbound_body and not latest_inbound_body:
        lines.append(f'Bu konuşmada en son yazan sendin: "{latest_outbound_body}".')
    return lines


