def _compose_recent_whatsapp_self_last_message_lines(context: dict[str, Any]) -> list[str]:
    label = _compact_inline_text(str(context.get("self_label") or "")) or "Kendine not sohbeti"
    recent_window = list(context.get("recent_window") or [])[-3:]
