def _compose_recent_whatsapp_self_summary_lines(context: dict[str, Any]) -> list[str]:
    lines = _compose_recent_whatsapp_self_last_message_lines(context)
    conversation_items = list(context.get("conversation_items") or [])
    if len(conversation_items) >= 2:
        previous_body = _compact_inline_text(str(conversation_items[-2].get("body") or ""))
        if previous_body:
            lines.append(f'Bir önceki notun da şu şekilde: "{previous_body}".')
    return lines


def _recent_whatsapp_snapshot_context(recent_messages: list[dict] | None) -> dict[str, Any] | None:
    history = [
        item
        for item in (recent_messages or [])
        if str(item.get("role") or "") in {"user", "assistant"}
    ][-6:]
    for item in reversed(history):
        role = str(item.get("role") or "")
        generated_from = str(item.get("generated_from") or "")
        source_context = item.get("source_context") if isinstance(item.get("source_context"), dict) else {}
        if role == "assistant" and generated_from == "assistant_whatsapp_snapshot":
            return {
                "active": True,
                "inbound_only": bool(source_context.get("inbound_only")),
                "direct_only": bool(source_context.get("direct_only")),
                "time_window_minutes": int(source_context.get("time_window_minutes") or 0) or None,
                "group_filter": source_context.get("group_filter"),
                "actor_filter": source_context.get("actor_filter"),
            }
        content = _compact_inline_text(str(item.get("content") or ""))
        if role == "user" and content and _wants_recent_whatsapp_snapshot_explicit(content):
            return {
                "active": True,
                "inbound_only": _recent_whatsapp_inbound_only(content),
                "direct_only": _recent_whatsapp_direct_only(content),
                "time_window_minutes": _recent_whatsapp_time_window_minutes(content),
                "group_filter": _recent_whatsapp_group_filter(content),
                "actor_filter": _recent_whatsapp_actor_filter(content),
            }
    return None


def _wants_recent_whatsapp_snapshot(query: str, recent_messages: list[dict] | None = None) -> bool:
    if _wants_recent_whatsapp_snapshot_explicit(query):
        return True
    if not _recent_whatsapp_follow_up_request(query):
        return False
    context = _recent_whatsapp_snapshot_context(recent_messages)
    return bool(context and context.get("active"))


def _recent_whatsapp_limit(
    query: str,
    recent_messages: list[dict] | None = None,
    *,
    allow_context: bool = True,
) -> int:
    normalized = " ".join(_normalize_tr_text(query).split())
    explicit_limit = _recent_whatsapp_snapshot_follow_up_limit(query)
    if explicit_limit is not None:
        return max(1, min(explicit_limit, 50))
    time_window_minutes = _recent_whatsapp_time_window_minutes(
        query,
        recent_messages,
        allow_context=allow_context,
    )
    actor_multi_markers = ("mesajlar", "listele", "goster", "göster", "hangi mesaj", "son gelen", "kimler")
    plural_markers = ("mesajlar", "son mesaj", "son gelen", "listele", "goster", "göster", "kimler")
    if _recent_whatsapp_self_requested(query) and time_window_minutes is None and not any(
        marker in normalized for marker in actor_multi_markers
    ):
        return 1
    if _recent_whatsapp_actor_filter(query) and time_window_minutes is None and not any(marker in normalized for marker in actor_multi_markers):
        return 1
    if time_window_minutes is not None:
        return 50
    if any(marker in normalized for marker in plural_markers):
        return 10
    return 1


def _recent_whatsapp_inbound_only(
    query: str,
    recent_messages: list[dict] | None = None,
    *,
    allow_context: bool = True,
) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    if _recent_whatsapp_self_requested(query):
        return False
    outbound_markers = (
        "benim yazdigim",
        "benim yazdigim",
        "yazdigim",
        "yazdigim",
        "gonderdigim",
        "gönderdiğim",
        "gonderdiğim",
        "gonderdiklerim",
        "gönderdiklerim",
        "yolladigim",
        "yolladıklarım",
        "tum sohbet",
        "tüm sohbet",
        "konusma gecmisi",
        "konuşma geçmişi",
    )
    if any(marker in normalized for marker in outbound_markers):
        return False
    if any(marker in normalized for marker in ("gelen", "bana gelen", "gelenler", "geldi", "geldiler", "gelmis", "gelmiş")):
        return True
    if not allow_context:
        return True
    context = _recent_whatsapp_snapshot_context(recent_messages)
    if context is not None:
        return bool(context.get("inbound_only"))
    return True


def _recent_whatsapp_group_label(message: dict[str, Any]) -> str:
    metadata = dict(message.get("metadata") or {})
    conversation_ref = str(message.get("conversation_ref") or "").strip()
    group_name = _compact_inline_text(str(metadata.get("group_name") or metadata.get("chat_name") or ""))
    is_group = bool(metadata.get("is_group")) or conversation_ref.endswith("@g.us")
    return group_name if is_group and group_name else ""


def _recent_whatsapp_actor_label(message: dict[str, Any]) -> str:
    metadata = dict(message.get("metadata") or {})
    conversation_ref = str(message.get("conversation_ref") or "").strip()
    is_group = bool(metadata.get("is_group")) or conversation_ref.endswith("@g.us")
    direction = str(message.get("direction") or "").strip().lower()
    sender = _compact_inline_text(str(message.get("sender") or ""))
    recipient = _compact_inline_text(str(message.get("recipient") or ""))
    conversation_label = _compact_inline_text(str(message.get("conversation_ref") or "WhatsApp"))
    preferred_contact = _compact_inline_text(
        str(
            (metadata.get("chat_name") if not is_group else "")
            or metadata.get("contact_name")
            or metadata.get("profile_name")
            or ""
        )
    )
    if preferred_contact:
        return preferred_contact
    if direction == "outbound":
        return recipient or conversation_label or "WhatsApp"
    return sender or conversation_label or "WhatsApp"


def _recent_whatsapp_lead_label(message: dict[str, Any]) -> str:
    group_label = _recent_whatsapp_group_label(message)
    actor_label = _recent_whatsapp_actor_label(message)
    lead = actor_label or "WhatsApp"
    if group_label and group_label != actor_label:
        lead = f"{group_label} > {actor_label}"
    return lead


def _recent_whatsapp_sender_rollup_requested(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not any(marker in normalized for marker in ("kimler", "hangi kisiler", "hangi kisiler", "kimlerden")):
        return False
    detailed_message_markers = (
        "ne mesaj",
        "mesaj atmis",
        "mesaj atmış",
        "ne yazmis",
        "ne yazmış",
        "mesajlar",
        "hangi mesaj",
    )
    return not any(marker in normalized for marker in detailed_message_markers)


def _recent_whatsapp_time_window_label(minutes: int | None) -> str | None:
    if not minutes or minutes <= 0:
        return None
    if minutes % (60 * 24 * 7) == 0:
        value = minutes // (60 * 24 * 7)
        return f"son {value} hafta"
    if minutes % (60 * 24) == 0:
        value = minutes // (60 * 24)
        return f"son {value} gün"
    if minutes % 60 == 0:
        value = minutes // 60
        return f"son {value} saat"
    return f"son {minutes} dakika"


def _parse_recent_whatsapp_sent_at(value: object) -> datetime | None:
    text = str(value or "").strip()
    if not text:
        return None
    normalized = text.replace("Z", "+00:00")
    try:
        parsed = datetime.fromisoformat(normalized)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=_safe_local_timezone())
    return parsed.astimezone(_safe_local_timezone())


def _extract_recent_whatsapp_digits(value: object) -> str:
    text = _compact_inline_text(str(value or ""))
    if not text:
        return ""
    if "@" in text:
        text = text.split("@", 1)[0]
    digits = re.sub(r"\D+", "", text)
    return digits if len(digits) >= 8 else ""


def _recent_whatsapp_label_needs_resolution(value: object) -> bool:
    text = _compact_inline_text(str(value or ""))
    if not text:
        return True
    normalized = _normalize_contact_lookup_text(text)
    if not normalized:
        return True
    if "@g.us" in text or "@c.us" in text:
        return True
    digits = _extract_recent_whatsapp_digits(text)
    if digits and normalized.replace(" ", "") == digits:
        return True
    if re.fullmatch(r"[0-9\-_\s]+", text):
        return True
    return False


def _recent_whatsapp_saved_label_indexes(
    store: Persistence,
    office_id: str,
) -> tuple[dict[str, str], dict[str, str]]:
    conversation_labels: dict[str, str] = {}
    digits_labels: dict[str, str] = {}
    for item in store.list_whatsapp_contact_snapshots(office_id, limit=400):
        conversation_ref = _compact_inline_text(str(item.get("conversation_ref") or ""))
        metadata = dict(item.get("metadata") or {})
        is_group = bool(item.get("is_group")) or conversation_ref.endswith("@g.us")
        label = _compact_inline_text(
            str(
                item.get("display_name")
                or (item.get("group_name") if is_group else "")
                or metadata.get("chat_name")
                or metadata.get("contact_name")
                or item.get("profile_name")
                or metadata.get("profile_name")
                or ""
            )
        )
        if not label:
            continue
        if conversation_ref and conversation_ref not in conversation_labels:
            conversation_labels[conversation_ref] = label
        if is_group:
            continue
        for source in (
            item.get("phone_number"),
            conversation_ref,
            metadata.get("contact_name"),
            metadata.get("chat_name"),
        ):
            digits = _extract_recent_whatsapp_digits(source)
            if digits and digits not in digits_labels:
                digits_labels[digits] = label
    return conversation_labels, digits_labels


def _enrich_recent_whatsapp_messages(
    store: Persistence,
    office_id: str,
    messages: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    if not messages:
        return []

    conversation_labels, digits_labels = _recent_whatsapp_saved_label_indexes(store, office_id)
    enriched: list[dict[str, Any]] = []
    for item in messages:
        clone = dict(item)
        metadata = dict(item.get("metadata") or {})
        conversation_ref = _compact_inline_text(str(item.get("conversation_ref") or ""))
        is_group = bool(metadata.get("is_group")) or conversation_ref.endswith("@g.us")
        direction = str(item.get("direction") or "").strip().lower()

        if is_group:
            group_label = conversation_labels.get(conversation_ref, "")
            if group_label:
                if _recent_whatsapp_label_needs_resolution(metadata.get("chat_name")):
                    metadata["chat_name"] = group_label
                if _recent_whatsapp_label_needs_resolution(metadata.get("group_name")):
                    metadata["group_name"] = group_label
            resolved_actor = ""
            for source in (
                metadata.get("author"),
                metadata.get("participant"),
                item.get("sender"),
            ):
                source_ref = _compact_inline_text(str(source or ""))
                if not source_ref:
                    continue
                resolved_actor = conversation_labels.get(source_ref, "")
                if resolved_actor:
                    break
                digits = _extract_recent_whatsapp_digits(source_ref)
                if digits:
                    resolved_actor = digits_labels.get(digits, "")
                    if resolved_actor:
                        break
            if resolved_actor:
                if _recent_whatsapp_label_needs_resolution(metadata.get("contact_name")):
                    metadata["contact_name"] = resolved_actor
                if _recent_whatsapp_label_needs_resolution(metadata.get("profile_name")):
                    metadata["profile_name"] = resolved_actor
                if direction != "outbound" and _recent_whatsapp_label_needs_resolution(clone.get("sender")):
                    clone["sender"] = resolved_actor
        else:
            resolved_direct = conversation_labels.get(conversation_ref, "")
            if not resolved_direct:
                digits = _extract_recent_whatsapp_digits(conversation_ref)
                if digits:
                    resolved_direct = digits_labels.get(digits, "")
            if resolved_direct:
                if _recent_whatsapp_label_needs_resolution(metadata.get("chat_name")):
                    metadata["chat_name"] = resolved_direct
                if _recent_whatsapp_label_needs_resolution(metadata.get("contact_name")):
                    metadata["contact_name"] = resolved_direct
                if _recent_whatsapp_label_needs_resolution(metadata.get("profile_name")):
                    metadata["profile_name"] = resolved_direct
                if direction == "outbound":
                    if _recent_whatsapp_label_needs_resolution(clone.get("recipient")):
                        clone["recipient"] = resolved_direct
                elif _recent_whatsapp_label_needs_resolution(clone.get("sender")):
                    clone["sender"] = resolved_direct

        clone["metadata"] = metadata
        enriched.append(clone)
    return enriched


def _list_recent_whatsapp_messages(
    store: Persistence,
    office_id: str,
    *,
    limit: int,
    inbound_only: bool,
    direct_only: bool = False,
    group_filter: str | None = None,
    actor_filter: str | None = None,
    actor_aliases: list[str] | None = None,
    conversation_ref_filter: str | None = None,
    time_window_minutes: int | None = None,
    respect_positive_filters: bool = True,
) -> list[dict[str, Any]]:
    profile = store.get_user_profile(office_id)
    targeted_lookup = bool(group_filter or actor_filter or actor_aliases or conversation_ref_filter)
    pool_size = max(limit * 4, 20)
    if targeted_lookup:
        pool_size = max(limit * 20, 400)
    messages = _enrich_recent_whatsapp_messages(
        store,
        office_id,
        store.list_whatsapp_messages(office_id, limit=min(pool_size, 1200)),
    )
    filtered_messages: list[dict[str, Any]] = []
    for item in messages:
        decision = _whatsapp_message_monitoring_decision(profile, item)
        if decision.get("blocked"):
            continue
        if respect_positive_filters and not decision.get("include"):
            continue
        filtered_messages.append(item)
    messages = filtered_messages
    if time_window_minutes:
        cutoff = datetime.now(_safe_local_timezone()) - timedelta(minutes=time_window_minutes)
        messages = [
            item
            for item in messages
            if (parsed_sent_at := _parse_recent_whatsapp_sent_at(item.get("sent_at"))) is not None and parsed_sent_at >= cutoff
        ]
    if inbound_only:
        messages = [
            item
            for item in messages
            if str(item.get("direction") or "").strip().lower() != "outbound"
        ]
    if direct_only:
        messages = [
            item
            for item in messages
            if not _recent_whatsapp_group_label(item)
        ]
    if group_filter:
        messages = [
            item
            for item in messages
            if _recent_whatsapp_target_matches(group_filter, _recent_whatsapp_group_label(item))
        ]
    if conversation_ref_filter:
        target_digits = _extract_recent_whatsapp_digits(conversation_ref_filter)
        messages = [
            item
            for item in messages
            if (
                _compact_inline_text(str(item.get("conversation_ref") or "")) == conversation_ref_filter
                or (
                    target_digits
                    and _extract_recent_whatsapp_digits(item.get("conversation_ref")) == target_digits
                )
            )
        ]
    if actor_filter or actor_aliases:
        aliases = list(actor_aliases or [])
        if actor_filter:
            aliases.append(actor_filter)
        messages = [
            item
            for item in messages
            if _recent_whatsapp_message_matches_actor_aliases(item, aliases)
        ]
    return messages[:limit]


def _format_recent_whatsapp_entry(message: dict[str, Any], index: int) -> str:
    lead = _recent_whatsapp_lead_label(message)
    body = _compact_inline_text(str(message.get("body") or ""))
    sent_at = str(message.get("sent_at") or "").strip()
    timestamp = ""
    if sent_at:
        try:
            timestamp = _format_turkish_datetime(sent_at)
        except Exception:
            timestamp = ""
    if body and timestamp:
        return f"{index}. {lead}: {body} ({timestamp})"
    if body:
        return f"{index}. {lead}: {body}"
    if timestamp:
        return f"{index}. {lead} ({timestamp})"
    return f"{index}. {lead}"


def _compose_recent_whatsapp_overview_summary_lines(snapshot_items: list[dict[str, Any]]) -> list[str]:
    if not snapshot_items:
        return []
    sender_counts: Counter[str] = Counter()
    latest_by_sender: dict[str, dict[str, Any]] = {}
    for item in snapshot_items:
        lead = _recent_whatsapp_lead_label(item)
        if not lead:
            continue
        sender_counts[lead] += 1
        latest_by_sender.setdefault(lead, item)

    lines: list[str] = []
    if sender_counts:
        top_senders = sender_counts.most_common(3)
        parts = [f"{lead} ({count})" for lead, count in top_senders]
        lines.append(f"En çok yazanlar: {', '.join(parts)}.")
    lines.append("Öne çıkan son mesajlar:")
    for index, item in enumerate(snapshot_items[:5], start=1):
        lines.append(_format_recent_whatsapp_entry(item, index))
    return lines


def _compose_recent_whatsapp_snapshot_reply(
    *,
    query: str,
    settings,
    store: Persistence,
    recent_messages: list[dict] | None = None,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
    home: dict[str, Any] | None = None,
    review_plan: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    if not review_plan and not _wants_recent_whatsapp_snapshot(query, recent_messages):
        return None
    if review_plan and str(review_plan.get("channel") or "").strip().lower() != "whatsapp":
        return None

    snapshot_context = _recent_whatsapp_snapshot_context(recent_messages) or {}
    generic_overview = _recent_whatsapp_contextual_overview_requested(query, recent_messages)
    context_enabled = _recent_whatsapp_query_allows_context_carryover(query) and not generic_overview
    profile = store.get_user_profile(settings.office_id)
    monitored_only = _profile_has_inbox_positive_filters(profile)
    plan_target_kind = str((review_plan or {}).get("target_kind") or "").strip().lower()
    plan_target = _compact_inline_text(str((review_plan or {}).get("target") or ""))
    answer_mode = str((review_plan or {}).get("answer_mode") or "").strip().lower() or "list"
    time_window_minutes = int(
        (review_plan or {}).get("time_window_minutes")
        or _recent_whatsapp_time_window_minutes(query, recent_messages, allow_context=context_enabled)
        or 0
    ) or None
    if (
        time_window_minutes is None
        and generic_overview
        and str((review_plan or {}).get("target_kind") or "").strip().lower() in {"", "none"}
    ):
        time_window_minutes = 60 * 24
    limit = int(
        (review_plan or {}).get("limit")
        or _recent_whatsapp_limit(query, recent_messages, allow_context=context_enabled)
        or 0
    ) or 1
    self_requested = plan_target_kind == "self" or _recent_whatsapp_self_requested(query)
    inbound_only = (
        bool((review_plan or {}).get("inbound_only"))
        if review_plan and "inbound_only" in review_plan
        else _recent_whatsapp_inbound_only(query, recent_messages, allow_context=context_enabled)
    )
    direct_only = bool((review_plan or {}).get("direct_only")) if review_plan and "direct_only" in review_plan else (
        _recent_whatsapp_direct_only(query) or (bool(snapshot_context.get("direct_only")) if context_enabled else False)
    )
    self_target_hint = plan_target if plan_target_kind == "self" and plan_target else ""
    if self_requested:
        inbound_only = False
        direct_only = True
    group_filter = (
        plan_target
        if plan_target_kind == "group"
        else _recent_whatsapp_group_filter(query) or (
        str(snapshot_context.get("group_filter") or "").strip() or None
        if context_enabled
        else None
        )
    )
    actor_filter = (
        None
        if group_filter or (direct_only and not self_requested)
        else (
            plan_target
            if plan_target_kind == "contact"
            else _recent_whatsapp_actor_filter(query) or (
                str(snapshot_context.get("actor_filter") or "").strip() or None
                if context_enabled
                else None
            )
        )
    )
    if not self_requested and actor_filter and _recent_whatsapp_target_is_self(
        store=store,
        office_id=settings.office_id,
        query=query,
        target=actor_filter,
    ):
        self_requested = True
        self_target_hint = actor_filter
        inbound_only = False
        direct_only = True
        actor_filter = None
    resolved_actor_target = (
        _resolve_recent_whatsapp_actor_target(
            query=query,
            actor_filter=actor_filter,
            store=store,
            office_id=settings.office_id,
        )
        if not group_filter and not direct_only
        else None
    )
    sender_rollup = answer_mode == "sender_rollup" or _recent_whatsapp_sender_rollup_requested(query)
    self_conversation = (
        _recent_whatsapp_self_conversation_context(
            store=store,
            office_id=settings.office_id,
            profile=profile,
            query=query if not plan_target else f"{query} {plan_target}",
            time_window_minutes=time_window_minutes,
            preferred_aliases=[self_target_hint] if self_target_hint else None,
        )
        if self_requested and not group_filter and not sender_rollup
        else None
    )
    actor_aliases = _expand_recent_whatsapp_aliases(
        [
            str((resolved_actor_target or {}).get("matched_alias") or ""),
            str((resolved_actor_target or {}).get("display_name") or ""),
            str((resolved_actor_target or {}).get("relationship_hint") or ""),
        ]
    )
    if actor_filter:
        actor_aliases.append(actor_filter)
    resolved_actor_conversation_ref = (
        None
        if self_requested
        else _compact_inline_text(str((resolved_actor_target or {}).get("conversation_ref") or "")) or None
    )
    resolved_actor_label = None if self_requested else actor_filter
    if not resolved_actor_label and resolved_actor_target:
        resolved_actor_label = (
            _compact_inline_text(str(resolved_actor_target.get("matched_alias") or ""))
            or _compact_inline_text(str(resolved_actor_target.get("display_name") or ""))
            or _compact_inline_text(str(resolved_actor_target.get("relationship_hint") or ""))
        )
    resolved_self_label = _compact_inline_text(str((self_conversation or {}).get("self_label") or "")) or None
    whatsapp_status = _whatsapp_status_payload(settings, store)
    home_payload = home or build_assistant_home(store, settings.office_id, settings=settings)
    manual_snapshot_query = bool(
        review_plan
        or _wants_recent_whatsapp_snapshot_explicit(query)
        or _recent_whatsapp_follow_up_request(query)
    )
    effective_monitored_only = monitored_only and not manual_snapshot_query
    snapshot_items = [] if self_requested else _list_recent_whatsapp_messages(
        store,
        settings.office_id,
        limit=limit,
        inbound_only=inbound_only,
        direct_only=direct_only,
        group_filter=group_filter,
        actor_filter=actor_filter,
        actor_aliases=actor_aliases,
        conversation_ref_filter=resolved_actor_conversation_ref,
        time_window_minutes=time_window_minutes,
        respect_positive_filters=not manual_snapshot_query,
    )
    if resolved_actor_label and not direct_only and not group_filter:
        direct_snapshot_items = _list_recent_whatsapp_messages(
            store,
            settings.office_id,
            limit=limit,
            inbound_only=inbound_only,
            direct_only=True,
            actor_filter=actor_filter,
            actor_aliases=actor_aliases,
            conversation_ref_filter=resolved_actor_conversation_ref,
            time_window_minutes=time_window_minutes,
            respect_positive_filters=not manual_snapshot_query,
        )
        if direct_snapshot_items:
            snapshot_items = direct_snapshot_items
    if actor_filter and snapshot_items:
        matched_actor_label = _recent_whatsapp_actor_label(snapshot_items[0])
        if matched_actor_label:
            resolved_actor_label = matched_actor_label
    elif resolved_actor_target and snapshot_items:
        resolved_actor_label = (
            _compact_inline_text(str(resolved_actor_target.get("matched_alias") or ""))
            or _compact_inline_text(str(resolved_actor_target.get("display_name") or ""))
            or _compact_inline_text(str(resolved_actor_target.get("relationship_hint") or ""))
            or resolved_actor_label
        )
    actor_conversation = (
        _recent_whatsapp_conversation_context(
            store=store,
            office_id=settings.office_id,
            profile=profile,
            actor_filter=actor_filter,
            actor_aliases=actor_aliases,
            time_window_minutes=time_window_minutes,
        )
        if resolved_actor_label and not group_filter and not sender_rollup
        else None
    )
    if actor_conversation and actor_conversation.get("actor_label"):
        resolved_actor_label = _compact_inline_text(str(actor_conversation.get("actor_label") or "")) or resolved_actor_label
    if actor_conversation and answer_mode == "list" and limit <= 1:
        answer_mode = "summary" if _recent_whatsapp_summary_requested(query) else "last_message"
    lines: list[str] = []
    time_window_label = _recent_whatsapp_time_window_label(time_window_minutes)
    actor_conversation_overview = bool(actor_conversation and answer_mode in {"timeline", "last_message", "summary"})
    self_conversation_overview = bool(self_conversation and answer_mode in {"timeline", "last_message", "summary"})
    if sender_rollup:
        if time_window_label:
            lines.append(f"{time_window_label.title()} içinde WhatsApp'ta yazan kişiler şöyle:")
        elif direct_only and inbound_only:
            lines.append("Yerel aynadaki özel sohbetlerden en son yazan kişiler şöyle:")
        elif direct_only:
            lines.append("Yerel aynadaki özel sohbetlerde en son yazan kişiler şöyle:")
        elif inbound_only:
            lines.append("Yerel aynadaki en son yazan WhatsApp kişiler şöyle:")
        else:
            lines.append("Yerel aynadaki en son yazan WhatsApp kişiler şöyle:")
    elif group_filter and time_window_label:
        lines.append(f"{group_filter} için {time_window_label} içindeki WhatsApp mesajları şöyle:")
    elif group_filter:
        lines.append(f"{group_filter} için son {limit} WhatsApp mesajı şöyle:")
    elif resolved_self_label and time_window_label:
        if not self_conversation_overview:
            lines.append(f"{resolved_self_label} sohbetinde {time_window_label} içindeki notlar şöyle:")
    elif resolved_self_label:
        if not self_conversation_overview:
            lines.append(f"{resolved_self_label} sohbetindeki son not şöyle:")
    elif resolved_actor_label and time_window_label:
        if not actor_conversation_overview:
            lines.append(f"{resolved_actor_label} için {time_window_label} içindeki WhatsApp mesajları şöyle:")
    elif resolved_actor_label:
        if not actor_conversation_overview:
            lines.append(f"{resolved_actor_label} için son {limit} WhatsApp mesajı şöyle:")
    elif direct_only and inbound_only and time_window_label:
        lines.append(f"Yerel aynadaki özel sohbetlerden {time_window_label} içinde gelen WhatsApp mesajları şöyle:")
    elif direct_only and inbound_only:
        lines.append(f"Yerel aynadaki özel sohbetlerden en son gelen {limit} WhatsApp mesajı şöyle:")
    elif direct_only and time_window_label:
        lines.append(f"Yerel aynadaki özel sohbetlerden {time_window_label} içindeki WhatsApp mesajları şöyle:")
    elif direct_only:
        lines.append(f"Yerel aynadaki özel sohbetlerden son {limit} WhatsApp mesajı şöyle:")
    elif inbound_only and time_window_label:
        lines.append(f"Yerel aynadaki {time_window_label} içinde gelen WhatsApp mesajları şöyle:")
    elif inbound_only:
        lines.append(f"Yerel aynadaki en son gelen {limit} WhatsApp mesajı şöyle:")
    elif time_window_label:
        lines.append(f"Yerel aynadaki {time_window_label} içindeki WhatsApp mesajları şöyle:")
    else:
        lines.append(f"Yerel aynadaki son {limit} WhatsApp mesajı şöyle:")
    if self_conversation_overview:
        if answer_mode == "timeline":
            lines.extend(_compose_recent_whatsapp_self_conversation_lines(self_conversation))
        elif answer_mode == "summary":
            lines.extend(_compose_recent_whatsapp_self_summary_lines(self_conversation))
        else:
            lines.extend(_compose_recent_whatsapp_self_last_message_lines(self_conversation))
    elif actor_conversation_overview:
        if answer_mode == "timeline":
            lines.extend(_compose_recent_whatsapp_actor_conversation_lines(actor_conversation))
        elif answer_mode == "summary":
            lines.extend(_compose_recent_whatsapp_actor_summary_lines(actor_conversation))
        else:
            lines.extend(_compose_recent_whatsapp_actor_last_message_lines(actor_conversation))
    elif snapshot_items:
        if sender_rollup:
            grouped: dict[str, dict[str, Any]] = {}
            for item in snapshot_items:
                lead = _recent_whatsapp_lead_label(item)
                bucket = grouped.setdefault(lead, {"count": 0, "last_sent_at": item.get("sent_at")})
                bucket["count"] += 1
            for index, (lead, info) in enumerate(grouped.items(), start=1):
                count = int(info.get("count") or 0)
                message_label = "mesaj" if count == 1 else "mesaj"
                last_sent_at = str(info.get("last_sent_at") or "").strip()
                if last_sent_at:
                    try:
                        lines.append(f"{index}. {lead} — {count} {message_label} ({_format_turkish_datetime(last_sent_at)})")
                    except Exception:
                        lines.append(f"{index}. {lead} — {count} {message_label}")
                else:
                    lines.append(f"{index}. {lead} — {count} {message_label}")
        elif answer_mode == "summary":
            lines.extend(_compose_recent_whatsapp_overview_summary_lines(snapshot_items))
        else:
            for index, item in enumerate(snapshot_items, start=1):
                lines.append(_format_recent_whatsapp_entry(item, index))
            if actor_conversation:
                lines.extend(_compose_recent_whatsapp_actor_conversation_lines(actor_conversation))
        if len(snapshot_items) < limit and not time_window_minutes:
            lines.append(f"Şu an yerel aynada {len(snapshot_items)} kayıt var; daha fazlası henüz görünmüyor.")
    elif self_conversation:
        lines.extend(_compose_recent_whatsapp_self_conversation_lines(self_conversation))
    elif actor_conversation:
        lines.extend(_compose_recent_whatsapp_actor_conversation_lines(actor_conversation))
    else:
        if self_requested:
            hinted_aliases = _recent_whatsapp_self_alias_hints(query)
            if hinted_aliases:
                lines.append(
                    f"WhatsApp'ta kendine ait not sohbetini ({', '.join(hinted_aliases)}) adıyla bulamadım."
                )
            else:
                lines.append("WhatsApp'ta kendine ait not sohbetini bulamadım.")
        elif effective_monitored_only:
            if time_window_label:
                lines.append(f"İzleme kurallarına uyan {time_window_label} içindeki WhatsApp mesajı görünmüyor.")
            else:
                lines.append("İzleme kurallarına uyan WhatsApp mesajı görünmüyor.")
        else:
            if time_window_label:
                lines.append(f"Yerel aynada {time_window_label} içinde uygun WhatsApp mesajı görünmüyor.")
            else:
                lines.append("Yerel aynada henüz uygun WhatsApp mesajı görünmüyor.")
    lines.append("")
    if resolved_self_label:
        lines.append(f"İstersen {resolved_self_label} sohbetindeki son notlar için kısa bir özet daha çıkarabilirim.")
    elif self_requested:
        lines.append("İstersen bu not sohbetinin kayıt adını da yaz; ona göre tekrar bakayım.")
    elif resolved_actor_label:
        lines.append(f"İstersen {resolved_actor_label} için buna uygun kısa bir yanıt taslağı hazırlayabilirim.")
    else:
        lines.append("İstersen bu mesajlardan biri için hemen yanıt taslağı hazırlayabilirim.")

    return {
        "content": "\n".join(lines),
        "assistant_summary": home_payload.get("today_summary") or "",
        "tool_suggestions": _assistant_tool_suggestions("whatsapp", requires_setup=home_payload.get("requires_setup") or []),
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_whatsapp_snapshot",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "source_refs": source_refs or [],
            "whatsapp_snapshot": snapshot_items,
            "whatsapp_status": whatsapp_status,
            "requested_limit": limit,
            "inbound_only": inbound_only,
            "direct_only": direct_only,
            "group_filter": group_filter,
            "actor_filter": actor_filter,
            "resolved_actor_target": resolved_actor_target,
            "resolved_actor_label": resolved_actor_label,
            "actor_conversation": actor_conversation,
            "self_requested": self_requested,
            "self_conversation": self_conversation,
            "resolved_self_label": resolved_self_label,
            "time_window_minutes": time_window_minutes,
            "sender_rollup": sender_rollup,
            "assistant_communication_plan": review_plan,
        },
    }


def _list_recent_x_messages(
    store: Persistence,
    office_id: str,
    *,
    limit: int,
    inbound_only: bool = True,
) -> list[dict[str, Any]]:
    pool_size = max(limit * 4, 20)
    items = store.list_x_messages(office_id, reply_needed_only=inbound_only, limit=min(pool_size, 200))
    if not items and inbound_only:
        items = store.list_x_messages(office_id, limit=min(pool_size, 200))
    if inbound_only:
        items = [
            item
            for item in items
            if str(item.get("direction") or "").strip().lower() != "outbound"
        ]
    return items[:limit]


def _recent_x_message_party_label(item: dict[str, Any]) -> str:
    direction = str(item.get("direction") or "").strip().lower()
    sender = _compact_inline_text(str(item.get("sender") or ""))
    recipient = _compact_inline_text(str(item.get("recipient") or ""))
    conversation_ref = _compact_inline_text(str(item.get("conversation_ref") or "X DM"))
    if direction == "outbound":
        return recipient or sender or conversation_ref or "X DM"
    return sender or recipient or conversation_ref or "X DM"


def _format_recent_x_message_entry(message: dict[str, Any], index: int) -> str:
    lead = _recent_x_message_party_label(message)
    body = _compact_inline_text(str(message.get("body") or ""))
    sent_at = str(message.get("sent_at") or "").strip()
    timestamp = ""
    if sent_at:
        try:
            timestamp = _format_turkish_datetime(sent_at)
        except Exception:
            timestamp = ""
    if body and timestamp:
        return f"{index}. {lead}: {body} ({timestamp})"
    if body:
        return f"{index}. {lead}: {body}"
    if timestamp:
        return f"{index}. {lead} ({timestamp})"
    return f"{index}. {lead}"


def _format_recent_x_post_entry(post: dict[str, Any], index: int) -> str:
    author = _compact_inline_text(str(post.get("author_handle") or "X"))
    content = _compact_inline_text(str(post.get("content") or ""))
    posted_at = str(post.get("posted_at") or "").strip()
    timestamp = ""
    if posted_at:
        try:
            timestamp = _format_turkish_datetime(posted_at)
        except Exception:
            timestamp = ""
    lead = f"{index}. {author}"
    if content:
        lead += f": {content}"
    if timestamp:
        lead += f" ({timestamp})"
    return lead


def _compose_recent_x_snapshot_reply(
    *,
    query: str,
    settings,
    store: Persistence,
    recent_messages: list[dict] | None = None,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
    home: dict[str, Any] | None = None,
    review_plan: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    if not review_plan and not _wants_recent_x_snapshot(query, recent_messages):
        return None
    if review_plan and str(review_plan.get("channel") or "").strip().lower() != "x":
        return None

    snapshot_context = _recent_x_snapshot_context(recent_messages) or {}
    limit = int((review_plan or {}).get("limit") or _recent_x_limit(query) or 0) or 1
    messages_only = bool((review_plan or {}).get("messages_only")) or _recent_x_messages_requested(query)
    mentions_only = bool((review_plan or {}).get("mentions_only")) or (
        _recent_x_mentions_requested(query) and not messages_only
    )
    mixed_overview = not messages_only and not mentions_only

    x_status = _x_status_payload(settings, store)
    home_payload = home or build_assistant_home(store, settings.office_id, settings=settings)
    x_scopes = {str(item).strip() for item in list(x_status.get("scopes") or []) if str(item).strip()}
    can_read_dm = "dm.read" in x_scopes or bool(x_status.get("dm_count"))
    x_messages = _list_recent_x_messages(store, settings.office_id, limit=limit, inbound_only=True) if (messages_only or mixed_overview) else []
    x_mentions = store.list_x_posts(settings.office_id, post_type="mention", limit=limit) if (mentions_only or mixed_overview) else []
    x_posts = (
        []
        if messages_only
        else store.list_x_posts(settings.office_id, post_type="post", limit=limit)
    )

    lines: list[str] = []
    if messages_only:
        if x_messages:
            lines.append(f"X hesabındaki en son gelen {limit} mesaj şöyle:")
            for index, item in enumerate(x_messages, start=1):
                lines.append(_format_recent_x_message_entry(item, index))
            if len(x_messages) < limit:
                lines.append(f"Şu an yerel aynada {len(x_messages)} X mesajı var; daha fazlası henüz görünmüyor.")
        elif not x_status.get("configured"):
            lines.append("X hesabı bağlı görünmüyor. Önce hesabı bağladıktan sonra son mesajlara bakabilirim.")
        elif not can_read_dm:
            lines.append("X hesabın bağlı, ama direkt mesajları okuyabilmem için `dm.read` izni açık değil.")
            if x_status.get("mention_count") or x_status.get("post_count"):
                lines.append(
                    f"Şu an yerel aynada {int(x_status.get('mention_count') or 0)} mention ve {int(x_status.get('post_count') or 0)} gönderi kaydı var."
                )
            lines.append("DM görmek istersen hesabı `dm.read` kapsamıyla yeniden bağla; istersen mevcut mention akışını hemen özetleyeyim.")
        elif x_status.get("error"):
            lines.append(f"X senkronu şu anda hataya düşüyor: {_compact_inline_text(str(x_status.get('error') or ''))}")
        else:
            lines.append("Yerel aynada henüz uygun X direkt mesajı görünmüyor.")
            if x_status.get("last_sync_at"):
                lines.append(f"Son senkron: {_compact_inline_text(str(x_status.get('last_sync_at') or ''))}")
    elif mentions_only:
        if x_mentions:
            lines.append(f"X hesabındaki son {limit} mention şöyle:")
            for index, item in enumerate(x_mentions, start=1):
                lines.append(_format_recent_x_post_entry(item, index))
        elif not x_status.get("configured"):
            lines.append("X hesabı bağlı görünmüyor. Önce hesabı bağladıktan sonra mention akışına bakabilirim.")
        elif x_status.get("error"):
            lines.append(f"X senkronu şu anda hataya düşüyor: {_compact_inline_text(str(x_status.get('error') or ''))}")
        else:
            lines.append("Yerel aynada henüz mention görünmüyor.")
    else:
        if x_messages:
            lines.append("X hesabında son mesaj akışı şöyle:")
            for index, item in enumerate(x_messages, start=1):
                lines.append(_format_recent_x_message_entry(item, index))
        elif x_mentions or x_posts:
            lines.append("X hesabında son sosyal akış şöyle:")
            for index, item in enumerate((x_mentions + x_posts)[:limit], start=1):
                lines.append(_format_recent_x_post_entry(item, index))
        elif not x_status.get("configured"):
            lines.append("X hesabı bağlı görünmüyor. Önce hesabı bağladıktan sonra sosyal akışı inceleyebilirim.")
        elif x_status.get("error"):
            lines.append(f"X senkronu şu anda hataya düşüyor: {_compact_inline_text(str(x_status.get('error') or ''))}")
        else:
            lines.append("Yerel aynada henüz uygun X kaydı görünmüyor.")

    lines.append("")
    if messages_only and x_messages:
        lines.append("İstersen bu kişilerden biri için kısa bir yanıt taslağı hazırlayabilirim.")
    elif messages_only and x_status.get("configured") and not can_read_dm:
        lines.append("İstersen hesabı DM izniyle yeniden bağlayalım ya da mention akışına bakayım.")
    else:
        lines.append("İstersen bunun üstüne son mention'ları ya da son gönderileri de ayrı özetleyeyim.")

    return {
        "content": "\n".join(lines),
        "assistant_summary": home_payload.get("today_summary") or "",
        "tool_suggestions": _assistant_tool_suggestions("x", requires_setup=home_payload.get("requires_setup") or []),
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_x_snapshot",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "source_refs": source_refs or [],
            "x_status": x_status,
            "x_snapshot_messages": x_messages,
            "x_snapshot_mentions": x_mentions,
            "x_snapshot_posts": x_posts,
            "messages_only": messages_only,
            "mentions_only": mentions_only,
            "requested_limit": limit,
            "assistant_communication_plan": review_plan,
        },
    }


def _assistant_whatsapp_review_answer_prompt(
    *,
    query: str,
    review_plan: dict[str, Any],
    actor_conversation: dict[str, Any] | None,
    snapshot_items: list[dict[str, Any]] | None,
) -> str:
    lines = [
        "LawCopilot için WhatsApp konuşma inceleme cevabı üret.",
        "Kurallar:",
        "- Yalnız verilen konuşma kaydına dayan.",
        "- Uydurma bağlam, niyet veya eski konu ekleme.",
        "- Kullanıcı 'en son ne yazmış' diyorsa en son gelen mesajı açık söyle.",
        "- Kullanıcı yorum istiyorsa çok kısa yorum yap, ama bunu kayda dayandır.",
        "- Cevap Türkçe, kısa ve net olsun.",
        "",
        f"Kullanıcı sorusu: {query}",
        f"Plan: {json.dumps(review_plan, ensure_ascii=False)}",
    ]
    if actor_conversation:
        actor_label = _compact_inline_text(str(actor_conversation.get("actor_label") or "")) or "Karşı taraf"
        lines.append(f"Aktör: {actor_label}")
        lines.append("Yakın konuşma akışı:")
        for item in list(actor_conversation.get("recent_window") or [])[-6:]:
            body = _compact_inline_text(str(item.get("body") or ""))
            if not body:
                continue
            direction = str(item.get("direction") or "").strip().lower()
            speaker = "Sen" if direction == "outbound" else actor_label
            lines.append(f"- {speaker}: {body}")
    else:
        lines.append("Bulunan mesaj kayıtları:")
        for item in list(snapshot_items or [])[:6]:
            lines.append(f"- {_format_recent_whatsapp_entry(item, 1)}")
    return "\n".join(lines)


def _assistant_runtime_whatsapp_review_answer(
    *,
    query: str,
    review_plan: dict[str, Any],
    reply: dict[str, Any],
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> str | None:
    if not runtime:
        return None
    source_context = reply.get("source_context") if isinstance(reply.get("source_context"), dict) else {}
    actor_conversation = source_context.get("actor_conversation") if isinstance(source_context.get("actor_conversation"), dict) else None
    snapshot_items = source_context.get("whatsapp_snapshot") if isinstance(source_context.get("whatsapp_snapshot"), list) else []
    prompt = _assistant_whatsapp_review_answer_prompt(
        query=query,
        review_plan=review_plan,
        actor_conversation=actor_conversation,
        snapshot_items=snapshot_items,
    )
    completion = _maybe_runtime_completion(
        runtime,
        prompt,
        events,
        task="assistant_whatsapp_review_answer",
        subject=subject,
    )
    text = _compact_inline_text(str((completion or {}).get("text") or ""))
    return text or None


def _compose_assistant_communication_review_reply(
    *,
    query: str,
    settings,
    store: Persistence,
    recent_messages: list[dict] | None,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
    home: dict[str, Any] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    review_plan = _resolve_assistant_communication_plan(
        query=query,
        recent_messages=recent_messages,
        runtime=runtime,
        events=events,
        subject=subject,
    )
    if not review_plan and _generic_recent_message_overview_without_channel_requested(query):
        review_plan = _default_recent_message_review_plan(
            query=query,
            store=store,
            office_id=settings.office_id,
        )
    if not review_plan:
        return None
    reply: dict[str, Any] | None = None
    channel = str(review_plan.get("channel") or "").strip().lower()
    if channel == "email":
        reply = _compose_recent_email_snapshot_reply(
            query=query,
            settings=settings,
            store=store,
            recent_messages=recent_messages,
            linked_entities=linked_entities,
            source_refs=source_refs,
            home=home,
            review_plan=review_plan,
        )
    elif channel == "telegram":
        reply = _compose_recent_telegram_snapshot_reply(
            query=query,
            settings=settings,
            store=store,
            recent_messages=recent_messages,
            linked_entities=linked_entities,
            source_refs=source_refs,
            home=home,
            review_plan=review_plan,
        )
    elif channel == "whatsapp":
        reply = _compose_recent_whatsapp_snapshot_reply(
            query=query,
            settings=settings,
            store=store,
            recent_messages=recent_messages,
            linked_entities=linked_entities,
            source_refs=source_refs,
            home=home,
            review_plan=review_plan,
        )
    elif channel == "x":
        reply = _compose_recent_x_snapshot_reply(
            query=query,
            settings=settings,
            store=store,
            recent_messages=recent_messages,
            linked_entities=linked_entities,
            source_refs=source_refs,
            home=home,
            review_plan=review_plan,
        )
    if not reply:
        return None
    reply["source_context"] = {
        **(reply.get("source_context") or {}),
        "assistant_communication_plan": review_plan,
    }
    return reply


def _integration_capability_summary_lines(
    *,
    google_status: dict[str, Any],
    outlook_status: dict[str, Any],
    telegram_status: dict[str, Any],
    whatsapp_status: dict[str, Any],
    x_status: dict[str, Any],
    instagram_status: dict[str, Any],
    linkedin_status: dict[str, Any],
) -> list[str]:
    lines: list[str] = []
    google_caps: list[str] = []
    if google_status.get("gmail_connected"):
        google_caps.append("Gmail")
    if google_status.get("calendar_connected"):
        google_caps.append("Takvim")
    if google_status.get("drive_connected"):
        google_caps.append("Drive")
    if google_caps:
        lines.append(
            f"• Google ({google_status.get('account_label') or 'Google hesabı'}): bağlı. "
            f"Erişimler: {', '.join(google_caps)}."
        )
    elif google_status.get("configured"):
        lines.append(
            f"• Google ({google_status.get('account_label') or 'Google hesabı'}): kurulu ama etkin veri erişimi görünmüyor."
        )

    outlook_caps: list[str] = []
    if outlook_status.get("mail_connected"):
        outlook_caps.append("Outlook Mail")
    if outlook_status.get("calendar_connected"):
        outlook_caps.append("Outlook Takvim")
    if outlook_caps:
        lines.append(
            f"• Outlook ({outlook_status.get('account_label') or 'Outlook hesabı'}): bağlı. "
            f"Erişimler: {', '.join(outlook_caps)}."
        )
    elif outlook_status.get("configured"):
        lines.append(
            f"• Outlook ({outlook_status.get('account_label') or 'Outlook hesabı'}): kurulu ama etkin veri erişimi görünmüyor."
        )

    if telegram_status.get("configured"):
        lines.append(f"• Telegram: {telegram_status.get('account_label') or 'Telegram botu'} bağlı.")
    if whatsapp_status.get("configured"):
        lines.append(f"• WhatsApp: {whatsapp_status.get('account_label') or 'WhatsApp hesabı'} bağlı.")
    if x_status.get("configured"):
        dm_note = " DM erişimi açık." if x_status.get("dm_count") or "dm.read" in list(x_status.get("scopes") or []) else ""
        lines.append(f"• X: {x_status.get('account_label') or 'X hesabı'} bağlı.{dm_note}")
    if instagram_status.get("configured"):
        lines.append(
            f"• Instagram: {instagram_status.get('account_label') or instagram_status.get('username') or 'Instagram hesabı'} bağlı. "
            "Profesyonel hesap mesajları okunabilir ve onaylı yanıt akışı kullanılabilir."
        )
    if linkedin_status.get("configured"):
        comment_note = ""
        if linkedin_status.get("comment_count"):
            comment_note = f" {linkedin_status.get('comment_count')} yorum yerelde izleniyor."
        elif linkedin_status.get("post_count"):
            comment_note = f" {linkedin_status.get('post_count')} gönderi eşitlendi."
        lines.append(
            f"• LinkedIn: {linkedin_status.get('account_label') or 'LinkedIn hesabı'} bağlı. "
            f"Gönderi akışı ve paylaşım yetkisi hazır.{comment_note}"
        )
    return lines


def _redact_assistant_integration_user_content(
    content: str,
    active_setup: dict[str, Any] | None,
) -> str:
    if not active_setup:
        return content
    pending_field = dict(active_setup.get("pending_field") or {})
    if str(pending_field.get("target") or "") != "secret":
        return content
    label = str(pending_field.get("label") or pending_field.get("key") or "gizli alan")
    return f"[Gizli değer paylaşıldı: {label}]"


def _compose_assistant_integration_reply(
    *,
    query: str,
    thread_id: int,
    actor: str,
    settings,
    store: Persistence,
    integration_service,
    recent_messages: list[dict] | None,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    active_setup = integration_service.get_active_assistant_setup(thread_id)
    planner_hint = None
    if _runtime_semantic_available(runtime):
        if active_setup:
            planner_hint = _assistant_runtime_integration_followup_plan(
                query=query,
                recent_messages=recent_messages,
                active_setup=active_setup,
                runtime=runtime,
                events=events,
                subject=subject,
            )
        if not planner_hint:
            planner_hint = _assistant_runtime_integration_setup_plan(
                query=query,
                recent_messages=recent_messages,
                runtime=runtime,
                events=events,
                subject=subject,
            )
    orchestration = integration_service.orchestrate_assistant_chat(
        thread_id=thread_id,
        query=query,
        actor=actor,
        planner_hint=planner_hint,
    )
    if not orchestration:
        return None

    assistant_setup = orchestration.get("assistant_setup")
    source_context = {
        "source_refs": source_refs or [],
        "integration_setup": {
            **dict(assistant_setup or {}),
            "authorization_url": orchestration.get("authorization_url"),
            "deep_link_path": orchestration.get("deep_link_path"),
            "suggested_replies": list(orchestration.get("suggested_replies") or []),
        } if assistant_setup else None,
        "integration_connector": orchestration.get("connector"),
        "integration_connection": orchestration.get("connection"),
        "integration_generated_request": orchestration.get("generated_request"),
        "integration_setup_plan": planner_hint,
    }
    if orchestration.get("sync_result") is not None:
        source_context["integration_sync_result"] = orchestration.get("sync_result")
    return {
        "content": str(orchestration.get("content") or "").strip() or "Entegrasyon akisini hazirladim.",
        "assistant_summary": build_assistant_home(store, settings.office_id, settings=settings).get("today_summary") or "",
        "tool_suggestions": [],
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": str(orchestration.get("generated_from") or "assistant_integration_orchestration"),
        "ai_provider": None,
        "ai_model": None,
        "source_context": source_context,
    }


def _compose_integration_access_reply(
    *,
    query: str,
    settings,
    store: Persistence,
    integration_service,
    linked_entities: list[dict[str, Any]],
    source_refs: list[dict] | None,
) -> dict[str, Any] | None:
    if not _wants_integration_access_snapshot(query):
        return None

    normalized = _normalize_tr_text(query)
    status_map = _integration_access_provider_status_payloads(settings=settings, store=store)
    google_status = status_map["google"]
    outlook_status = status_map["outlook"]
    telegram_status = status_map["telegram"]
    whatsapp_status = status_map["whatsapp"]
    x_status = status_map["x"]
    instagram_status = status_map["instagram"]
    linkedin_status = status_map["linkedin"]

    provider_focus = list(dict.fromkeys(_integration_access_provider_focus(query)))
    if len(provider_focus) == 1:
        focused_provider = provider_focus[0]
        focused_status = status_map.get(focused_provider)
        if focused_status is not None:
            return _compose_provider_specific_integration_access_reply(
                query=query,
                provider=focused_provider,
                status=focused_status,
                linked_entities=linked_entities,
                source_refs=source_refs,
            )

    google_live = bool(
        google_status.get("gmail_connected")
        or google_status.get("calendar_connected")
        or google_status.get("drive_connected")
    )
    outlook_live = bool(
        outlook_status.get("mail_connected")
        or outlook_status.get("calendar_connected")
    )
    google_focus = any(token in normalized for token in ("google", "gmail"))
    outlook_focus = any(token in normalized for token in ("outlook", "hotmail"))

    if google_focus and outlook_live and google_live:
        intro = "Evet, Google hesabın şu an bağlı görünüyor. Outlook bağlantısı Google'ı kesmiş görünmüyor; ikisi de aktif."
    elif google_focus:
        intro = (
            "Evet, Google hesabın şu an bağlı görünüyor."
            if google_live
            else "Hayır, şu an Google tarafında etkin bir bağlantı görmüyorum."
        )
    elif outlook_focus:
        intro = (
            "Evet, Outlook hesabın şu an bağlı görünüyor."
            if outlook_live
            else "Hayır, şu an Outlook tarafında etkin bir bağlantı görmüyorum."
        )
    elif google_live and outlook_live:
        intro = "Şu an hem Google hem Outlook bağlı görünüyor."
    elif google_live:
        intro = "Şu an Google bağlı görünüyor; Outlook tarafı etkin görünmüyor."
    elif outlook_live:
        intro = "Şu an Outlook bağlı görünüyor; Google tarafı etkin görünmüyor."
    else:
        intro = "Şu an etkin Google veya Outlook bağlantısı görünmüyor."

    detail_lines = _integration_capability_summary_lines(
        google_status=google_status,
        outlook_status=outlook_status,
        telegram_status=telegram_status,
        whatsapp_status=whatsapp_status,
        x_status=x_status,
        instagram_status=instagram_status,
        linkedin_status=linkedin_status,
    )
    managed_lines: list[str] = []
    try:
        managed_items = list(integration_service.list_connections().get("items") or [])
    except Exception:
        managed_items = []
    for item in managed_items[:8]:
        connector = dict(item.get("connector") or {})
        connection = dict(item.get("connection") or {})
        if not connector or str(connector.get("management_mode") or "") == "legacy-desktop":
            continue
        label = str(connection.get("display_name") or connector.get("name") or connector.get("id") or "Connector")
        status = str(connection.get("status") or connection.get("auth_status") or "configured")
        managed_lines.append(f"• {label}: {status}.")
    detail_lines.extend(managed_lines)
    if not detail_lines:
        detail_lines.append("• Kayıtlı etkin hesap bulunamadı.")

    return {
        "content": "\n".join([intro, "", *detail_lines]),
        "assistant_summary": build_assistant_home(store, settings.office_id, settings=settings).get("today_summary") or "",
        "tool_suggestions": [
            {
                "tool": "settings",
                "label": "Ayarlar",
                "reason": "Bağlı hesapları ve izinleri buradan doğrulayabiliriz.",
            }
        ],
        "linked_entities": linked_entities,
        "draft_preview": None,
        "requires_approval": False,
        "generated_from": "assistant_integration_status",
        "ai_provider": None,
        "ai_model": None,
        "source_context": {
            "source_refs": source_refs or [],
            "google_status": google_status,
            "outlook_status": outlook_status,
            "telegram_status": telegram_status,
            "whatsapp_status": whatsapp_status,
            "x_status": x_status,
            "instagram_status": instagram_status,
            "linkedin_status": linkedin_status,
        },
    }


def _casual_assistant_checkin_reply(assistant_name: str) -> str:
    return (
        f"Buradayım, ben {assistant_name}. Her şey sakin gidiyor. "
        "İstersen kurulumda eksik kalanları söyleyeyim ya da günün kısa özetini paylaşayım?"
    )


def _is_low_signal_greeting_query(query: str) -> bool:
    normalized = re.sub(r"[^a-z0-9\\s]+", " ", _normalize_tr_text(query))
    tokens = [token for token in normalized.split() if token]
    if not tokens:
        return False
    allowed = {
        "merhaba",
        "selam",
        "hayat",
        "naber",
        "nabuyon",
        "napiyon",
        "napiyon",
        "nasil",
        "gidiyor",
        "nasilsin",
        "hazir",
        "misin",
        "orada",
        "ne",
        "haber",
    }
    joined = " ".join(tokens)
    known_phrases = {
        "merhaba",
        "selam",
        "naber",
        "ne haber",
        "nasilsin",
        "nasil gidiyor",
        "hayat nasil gidiyor",
        "hazir misin",
        "orada misin",
    }
    return joined in known_phrases or (len(tokens) <= 3 and all(token in allowed for token in tokens))


def _extract_last_question_paragraph(paragraphs: list[str]) -> str:
    for paragraph in reversed(paragraphs):
        stripped = paragraph.strip()
        if not stripped:
            continue
        if stripped.endswith("?"):
            return stripped
        match = re.search(r"([^?]+\?)\s*$", stripped)
        if match:
            return match.group(1).strip()
    return ""


def _polish_assistant_thread_content(
    content: str,
    *,
    is_casual_prompt: bool,
    wants_status_snapshot: bool,
    include_document_context: bool,
    assistant_name: str,
    fallback_text: str,
) -> str:
    text = str(content or "").strip()
    if not text:
        return fallback_text
    if is_casual_prompt:
        return _casual_assistant_checkin_reply(assistant_name)

    text = re.sub(r"(?m)^[ \t]*[*-]\s+", "• ", text)
    if wants_status_snapshot or include_document_context:
        return text

    normalized = _normalize_tr_text(text)
    noisy_markers = (
        "durum ozeti",
        "mevcut durum ozeti",
        "durum analizi",
        "su anki calisma durumunuz",
        "su anki durum",
        "kurulum notu",
        "eksik kurulum",
        "guncel veri",
        "guncel durum",
        "onerilen arac",
        "onerilen araclar",
    )
    status_line_markers = (
        "ajanda:",
        "iletisim:",
        "taslaklar:",
        "kurulum notu:",
        "guncel veri:",
        "guncel durum:",
    )
    if not any(marker in normalized for marker in noisy_markers) and not any(marker in normalized for marker in status_line_markers):
        return text

    paragraphs = [paragraph.strip() for paragraph in re.split(r"\n\s*\n", text) if paragraph.strip()]
    if not paragraphs:
        return fallback_text
    lead = paragraphs[0]
    followup = _extract_last_question_paragraph(paragraphs[1:])
    fallback = str(fallback_text or "").strip()
    if followup and followup != lead and _normalize_tr_text(followup) == _normalize_tr_text(fallback):
        return f"{lead}\n\n{followup}".strip()
    if fallback and _normalize_tr_text(fallback) != _normalize_tr_text(lead):
        return f"{lead}\n\n{fallback}".strip()
    return lead


def _compact_document_excerpt(value: str, *, limit: int = 220) -> str:
    excerpt = re.sub(r"\s+", " ", str(value or "").strip())
    if len(excerpt) <= limit:
        return excerpt
    return excerpt[: limit - 1].rstrip() + "…"


def _workspace_document_source_ref_id(source_refs: list[dict] | None) -> int:
    for ref in source_refs or []:
        if str(ref.get("type") or "").lower() not in {"workspace_document", "attachment", "file"}:
            continue
        candidate_id = int(ref.get("workspace_document_id") or ref.get("document_id") or 0)
        if candidate_id > 0:
            return candidate_id
    return 0


def _should_use_workspace_retrieval(
    *,
    query: str,
    matter_id: int | None,
    source_refs: list[dict] | None,
    recent_messages: list[dict] | None,
) -> bool:
    if _workspace_document_source_ref_id(source_refs) > 0:
        return True
    normalized = _normalize_tr_text(_assistant_recent_user_context(query, recent_messages))
    markers = (
        "belge",
        "belgeler",
        "dosya",
        "dosyalar",
        "dokuman",
        "doküman",
        "pdf",
        "dilekce",
        "dilekçe",
        "sozlesme",
        "sözleşme",
        "ihtar",
        "itiraz",
        "icra",
        "mahkeme",
        "dekont",
        "emsal",
        "ornek",
        "örnek",
        "benzer",
        "onceki",
        "önceki",
        "tahliye",
        "kira",
    )
    if any(token in normalized for token in markers):
        return True
    return bool(matter_id and any(token in normalized for token in ("olgu", "iddia", "dayanak", "taslak", "hazirla", "hazırla", "yaz")))


def _assistant_workspace_search_context(
    store: Persistence,
    office_id: str,
    *,
    query: str,
    recent_messages: list[dict] | None,
    matter_id: int | None,
    source_refs: list[dict] | None,
    limit: int = 4,
    include_similar: bool = False,
) -> dict[str, Any] | None:
    if not _should_use_workspace_retrieval(query=query, matter_id=matter_id, source_refs=source_refs, recent_messages=recent_messages):
        return None

    combined_query = _assistant_recent_user_context(query, recent_messages)
    root = store.get_active_workspace_root(office_id)
    direct_workspace_document_id = _workspace_document_source_ref_id(source_refs)
    scope = "workspace"
    rows: list[dict[str, Any]] = []

    if direct_workspace_document_id > 0 and root:
        rows = list(
            store.search_workspace_document_chunks(
                office_id,
                int(root["id"]),
                workspace_document_id=direct_workspace_document_id,
            )
            or []
        )
        scope = "workspace_document"
    elif matter_id is not None:
        rows = list(store.search_document_chunks(office_id, matter_id) or []) + list(store.search_linked_workspace_chunks(office_id, matter_id) or [])
        scope = "matter"
    elif root:
        rows = list(store.search_workspace_document_chunks(office_id, int(root["id"])) or [])
        scope = "workspace"

    citations = score_chunk_records(combined_query, rows, k=limit)
    if not citations and matter_id is not None and root:
        fallback_rows = list(store.search_workspace_document_chunks(office_id, int(root["id"])) or [])
        fallback_citations = score_chunk_records(combined_query, fallback_rows, k=limit)
        if fallback_citations:
            rows = fallback_rows
            citations = fallback_citations
            scope = "workspace_fallback"

    related_documents: list[dict[str, Any]] = []
    seen_documents: set[tuple[str, int]] = set()
    for citation in citations:
        source_type = str(citation.get("source_type") or "document")
        document_id = int(citation.get("document_id") or 0)
        dedupe_key = (source_type, document_id)
        if dedupe_key in seen_documents:
            continue
        seen_documents.add(dedupe_key)
        relative_path = str((citation.get("metadata") or {}).get("relative_path") or "").strip()
        related_documents.append(
            {
                "document_id": document_id,
                "label": str(citation.get("document_name") or relative_path or "Belge"),
                "source_type": source_type,
                "relative_path": relative_path or None,
                "max_score": float(citation.get("relevance_score") or 0.0),
            }
        )

    support_level = (
        "yuksek"
        if citations and max(float(item.get("relevance_score") or 0.0) for item in citations) >= 0.26
        else "orta"
        if citations
        else "dusuk"
    )

    source_workspace_document: dict[str, Any] | None = None
    if direct_workspace_document_id > 0:
        source_workspace_document = store.get_workspace_document(office_id, direct_workspace_document_id)
    elif root:
        for item in related_documents:
            if str(item.get("source_type") or "") != "workspace":
                continue
            source_workspace_document = store.get_workspace_document(office_id, int(item["document_id"]))
            if source_workspace_document:
                break

    similar_documents: list[dict[str, Any]] = []
    if include_similar and root and source_workspace_document:
        all_workspace_documents = store.list_workspace_documents(office_id, int(root["id"])) or []
        all_workspace_rows = store.search_workspace_document_chunks(office_id, int(root["id"])) or []
        similar_documents = list(
            (find_similar_documents(
                source_document=source_workspace_document,
                candidate_documents=all_workspace_documents,
                chunk_rows=all_workspace_rows,
                limit=3,
            ).get("items") or [])
        )[:3]

    return {
        "query": combined_query,
        "scope": scope,
        "support_level": support_level,
        "citations": citations,
        "related_documents": related_documents,
        "source_workspace_document": source_workspace_document,
        "similar_documents": similar_documents,
    }


def _assistant_workspace_prompt_lines(context: dict[str, Any] | None) -> list[str]:
    if not context:
        return ["- İlgili çalışma alanı dayanağı aranmadı."]
    citations = list(context.get("citations") or [])
    if not citations:
        return ["- Sorguya uyan belirgin bir çalışma alanı pasajı bulunamadı."]
    lines = [f"- Dayanak düzeyi: {context.get('support_level') or 'dusuk'}"]
    for citation in citations[:3]:
        label = str(citation.get("document_name") or (citation.get("metadata") or {}).get("relative_path") or "Belge")
        excerpt = _compact_document_excerpt(str(citation.get("excerpt") or ""), limit=220)
        score = int(round(float(citation.get("relevance_score") or 0.0) * 100))
        lines.append(f"- {label} [{score}/100]: {excerpt or 'Kısa alıntı çıkarılamadı.'}")
    similar_documents = list(context.get("similar_documents") or [])
    if similar_documents:
        lines.append("- Benzer eski belgeler:")
        for item in similar_documents[:2]:
            score = int(round(float(item.get("benzerlik_puani") or 0.0) * 100))
            reason = _compact_document_excerpt(str(item.get("neden_benzer") or ""), limit=150)
            lines.append(f"  - {item.get('belge_adi') or 'Belge'} [{score}/100]: {reason}")
    return lines


def _assistant_workspace_fallback_reply(context: dict[str, Any] | None) -> str | None:
    if not context:
        return None
    citations = list(context.get("citations") or [])
    if not citations:
        return "Çalışma alanında bu soruyu doğrudan destekleyen güçlü bir belge bulamadım. İstersen belge adını, klasörü veya daha belirgin birkaç anahtar kelimeyi söyle."
    lines = ["Çalışma alanında buna en yakın dayanakları buldum:"]
    for citation in citations[:3]:
        label = str(citation.get("document_name") or (citation.get("metadata") or {}).get("relative_path") or "Belge")
        excerpt = _compact_document_excerpt(str(citation.get("excerpt") or ""), limit=180)
        lines.append(f"• {label}: {excerpt or 'Kısa alıntı çıkarılamadı.'}")
    similar_documents = list(context.get("similar_documents") or [])
    if similar_documents:
        similar_labels = ", ".join(str(item.get("belge_adi") or "Belge") for item in similar_documents[:2])
        if similar_labels:
            lines.append(f"• Benzer önceki belgeler de var: {similar_labels}.")
    return "\n".join(lines)


def _assistant_document_summary_items(
    store: Persistence,
    office_id: str,
    matter_id: int | None,
    *,
    source_refs: list[dict[str, Any]] | None = None,
    limit: int = 6,
) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    seen_keys: set[tuple[str, str]] = set()

    for ref in (source_refs or [])[:limit]:
        ref_type = str(ref.get("type") or "attachment").strip() or "attachment"
        label = str(ref.get("label") or ref.get("display_name") or ref.get("name") or ref.get("relative_path") or "Belge")
        ref_id = ref.get("document_id") or ref.get("id") or label
        dedupe_key = (ref_type, str(ref_id))
        if dedupe_key in seen_keys:
            continue
        seen_keys.add(dedupe_key)

        raw_excerpt = str(ref.get("attachment_context") or ref.get("analysis_text") or "").strip()
        if raw_excerpt:
            assessment = assess_untrusted_text(raw_excerpt, max_chars=520)
            excerpt = _compact_document_excerpt(assessment.sanitized_text, limit=220)
        else:
            excerpt = _compact_document_excerpt(str(ref.get("analysis_error") or "").strip(), limit=220)

        items.append(
            {
                "label": label,
                "source_type": ref_type,
                "excerpt": excerpt,
            }
        )
        if len(items) >= limit:
            return items

    if matter_id:
        for document in (store.list_matter_documents(office_id, matter_id) or [])[:limit]:
            document_id = int(document.get("id") or 0)
            if not document_id or ("matter_document", str(document_id)) in seen_keys:
                continue
            seen_keys.add(("matter_document", str(document_id)))
            chunks = store.list_document_chunks(office_id, document_id) or []
            excerpt = " ".join(_compact_document_excerpt(str(chunk.get("text") or ""), limit=180) for chunk in chunks[:2] if str(chunk.get("text") or "").strip()).strip()
            items.append(
                {
                    "label": str(document.get("display_name") or document.get("filename") or "Belge"),
                    "source_type": "matter_document",
                    "excerpt": _compact_document_excerpt(excerpt, limit=220),
                }
            )
            if len(items) >= limit:
                return items
        for document in (store.list_matter_workspace_documents(office_id, matter_id) or [])[:limit]:
            document_id = int(document.get("id") or 0)
            if not document_id or ("workspace_document", str(document_id)) in seen_keys:
                continue
            seen_keys.add(("workspace_document", str(document_id)))
            chunks = store.list_workspace_document_chunks(office_id, document_id) or []
            excerpt = " ".join(_compact_document_excerpt(str(chunk.get("text") or ""), limit=180) for chunk in chunks[:2] if str(chunk.get("text") or "").strip()).strip()
            items.append(
                {
                    "label": str(document.get("display_name") or document.get("relative_path") or "Belge"),
                    "source_type": "workspace_document",
                    "excerpt": _compact_document_excerpt(excerpt, limit=220),
                }
            )
            if len(items) >= limit:
                return items
        return items

    root = store.get_active_workspace_root(office_id)
    if not root:
        return items
    for document in store.list_workspace_documents(office_id, int(root["id"]), limit=limit) or []:
        document_id = int(document.get("id") or 0)
        if not document_id or ("workspace_document", str(document_id)) in seen_keys:
            continue
        seen_keys.add(("workspace_document", str(document_id)))
        chunks = store.list_workspace_document_chunks(office_id, document_id) or []
        excerpt = " ".join(_compact_document_excerpt(str(chunk.get("text") or ""), limit=180) for chunk in chunks[:2] if str(chunk.get("text") or "").strip()).strip()
        items.append(
            {
                "label": str(document.get("display_name") or document.get("relative_path") or "Belge"),
                "source_type": "workspace_document",
                "excerpt": _compact_document_excerpt(excerpt, limit=220),
            }
        )
        if len(items) >= limit:
            break
    return items


def _build_document_summary_prompt(*, query: str, items: list[dict[str, Any]]) -> str:
    lines = [
        "LawCopilot için listedeki her belgeyi tek tek kısa Türkçe özetle.",
        "Kurallar:",
        "- Her belge için ayrı madde yaz.",
        "- Belge adını kalınlaştırmadan başta ver.",
        "- Yalnız verilen alıntıları kullan.",
        "- Her madde en fazla iki kısa cümle olsun.",
        "- Eğer bir belge için metin yetersizse bunu açıkça söyle.",
        "",
        f"Kullanıcı isteği: {query}",
        "",
        "Belge alıntıları:",
    ]
    for item in items:
        lines.append(f"- Belge: {item['label']}")
        lines.append(f"  Kaynak türü: {item['source_type']}")
        lines.append(f"  Metin özeti: {item['excerpt'] or 'Yeterli metin çıkarılamadı.'}")
    return "\n".join(lines)


def _assistant_document_summary_reply(*, query: str, items: list[dict[str, Any]], runtime, events: StructuredLogger, subject: str, matter_id: int | None) -> tuple[str, str | None, str | None]:
    if not items:
        return (
            "Şu an özetleyebileceğim metin çıkarılmış bir belge görünmüyor. İstersen önce çalışma alanını yeniden tarayayım ya da belirli bir dosyayı seçip onun üzerinden ilerleyelim.",
            None,
            None,
        )

    runtime_completion = _maybe_runtime_completion(
        runtime,
        _build_document_summary_prompt(query=query, items=items),
        events,
        task="assistant_document_summary",
        subject=subject,
        matter_id=matter_id,
    )
    if runtime_completion:
        return runtime_completion["text"], runtime_completion["provider"], runtime_completion["model"]

    lines = ["Elimizdeki belgeleri tek tek kısaca özetledim:"]
    for item in items:
        excerpt = str(item.get("excerpt") or "").strip() or "Henüz metin çıkarımı hazır değil."
        lines.append(f"- {item.get('label')}: {excerpt}")
    return "\n".join(lines), None, None


def _assistant_document_inventory_reply(document_inventory: dict[str, object], *, matter_id: int | None) -> str:
    workspace_documents = list(document_inventory.get("workspace_documents") or [])
    google_drive_files = list(document_inventory.get("google_drive_files") or [])
    matter_documents = list(document_inventory.get("matter_documents") or [])
    workspace_count = int(document_inventory.get("workspace_count") or 0)
    google_drive_count = int(document_inventory.get("google_drive_count") or 0)
    matter_count = int(document_inventory.get("matter_count") or 0)
    workspace_root_name = str(document_inventory.get("workspace_root_name") or "").strip()

    lines: list[str] = []
    if matter_id:
        if matter_count:
            labels = ", ".join(str(item.get("label") or "Belge") for item in matter_documents[:6])
            extra = max(0, matter_count - min(matter_count, 6))
            sentence = f"Etkin dosyada {matter_count} belge görüyorum: {labels}"
            lines.append(sentence + (f" ve {extra} belge daha." if extra else "."))
        else:
            lines.append("Etkin dosyada henüz kayıtlı belge görünmüyor.")

    if workspace_count:
        labels = ", ".join(str(item.get("label") or "Belge") for item in workspace_documents[:6])
        extra = max(0, workspace_count - min(workspace_count, 6))
        scope_label = workspace_root_name or "Çalışma alanında"
        sentence = f"{scope_label} toplam {workspace_count} belge var: {labels}"
        lines.append(sentence + (f" ve {extra} belge daha." if extra else "."))
    elif workspace_root_name:
        lines.append(f"{workspace_root_name} içinde henüz belge görünmüyor.")
    else:
        lines.append("Henüz seçili bir çalışma alanı görünmüyor, bu yüzden belge envanteri çıkaramıyorum.")

    if google_drive_count:
        labels = ", ".join(str(item.get("label") or "Drive dosyası") for item in google_drive_files[:6])
        extra = max(0, google_drive_count - min(google_drive_count, 6))
        sentence = f"Google Drive tarafında {google_drive_count} dosya görüyorum: {labels}"
        lines.append(sentence + (f" ve {extra} dosya daha." if extra else "."))

    if workspace_count or matter_count or google_drive_count:
        lines.append("İstersen bunları türüne, dosyasına veya son güncellenene göre de sıralayabilirim.")
    return " ".join(lines)


def _build_similarity_explanation_prompt(*, source_document_name: str, items: list[dict], fallback_explanation: str) -> str:
    item_lines = [
        (
            f"- Belge: {item.get('belge_adi')} | Skor: {item.get('benzerlik_puani')} | "
            f"Neden: {_truncate_for_prompt(item.get('neden_benzer') or '', 180)} | "
            f"Klasör: {item.get('klasor_baglami')}"
        )
        for item in items[:4]
    ]
    return "\n".join(
        [
            "LawCopilot için benzer belge sonuçlarını açıklayan kısa bir Türkçe özet yaz.",
            "Kurallar:",
            "- Yalnız verilen bağlamı kullan.",
            "- Benzerlik sonucunu kesin hüküm gibi sunma.",
            "- En fazla üç cümle yaz.",
            "",
            f"Kaynak belge: {source_document_name}",
            f"Mevcut fallback açıklaması: {fallback_explanation}",
            "",
            "Benzer belge adayları:",
            *(item_lines or ["- Benzer belge adayı yok."]),
        ]
    )


def _google_status_payload(settings, store: Persistence) -> dict:
    account = store.get_connected_account(settings.office_id, "google")
    portability_account = store.get_connected_account(settings.office_id, "google-portability")
    scopes = list(account.get("scopes") or settings.google_scopes) if account else list(settings.google_scopes)
    account_status = str(account.get("status") or "").strip().lower() if account else ""
    metadata = dict(account.get("metadata") or {}) if account else {}
    portability_scopes = list(portability_account.get("scopes") or []) if portability_account else []
    portability_status = str(portability_account.get("status") or "").strip().lower() if portability_account else ""
    portability_metadata = dict(portability_account.get("metadata") or {}) if portability_account else {}
    email_thread_count = len(store.list_email_threads(settings.office_id, provider="google"))
    calendar_event_count = len(store.list_calendar_events(settings.office_id, limit=200, provider="google"))
    drive_file_count = len(store.list_drive_files(settings.office_id, limit=200))
    youtube_playlist_count = len(
        store.list_external_events(
            settings.office_id,
            provider="youtube",
            event_type="playlist",
            limit=200,
        )
    )
    youtube_history_count = len(
        store.list_external_events(
            settings.office_id,
            provider="youtube",
            event_type="history",
            limit=200,
        )
    )
    chrome_history_count = len(
        store.list_external_events(
            settings.office_id,
            provider="chrome",
            event_type="history",
            limit=200,
        )
    )
    account_connected = account_status == "connected"
    portability_connected = portability_status == "connected"
    calendar_write_ready = any(
        scope in {
            "https://www.googleapis.com/auth/calendar.events",
            "https://www.googleapis.com/auth/calendar",
        }
        for scope in scopes
    )
    gmail_connected = bool(
        email_thread_count > 0
        or metadata.get("gmail_connected")
        or (account_connected and any("gmail" in str(scope) for scope in scopes))
    )
    calendar_connected = bool(
        calendar_event_count > 0
        or metadata.get("calendar_connected")
        or (account_connected and any("calendar" in str(scope) for scope in scopes))
    )
    drive_connected = bool(
        drive_file_count > 0
        or metadata.get("drive_connected")
        or (account_connected and any("drive" in str(scope) for scope in scopes))
    )
    youtube_connected = bool(
        youtube_playlist_count > 0
        or metadata.get("youtube_connected")
        or (account_connected and any("youtube" in str(scope) for scope in scopes))
    )
    configured = bool(settings.google_configured or account or scopes)
    return {
        "provider": "google",
        "configured": configured,
        "enabled": bool(settings.google_enabled or account),
        "account_label": (account.get("account_label") if account else None) or settings.google_account_label,
        "scopes": scopes,
        "gmail_connected": gmail_connected,
        "calendar_connected": calendar_connected,
        "drive_connected": drive_connected,
        "youtube_connected": youtube_connected,
        "youtube_playlist_count": youtube_playlist_count,
        "youtube_history_available": bool(
            youtube_history_count > 0
            or portability_metadata.get("youtube_history_available")
            or (portability_connected and any("dataportability.myactivity.youtube" in str(scope) for scope in portability_scopes))
        ),
        "youtube_history_count": youtube_history_count,
        "chrome_history_available": bool(
            chrome_history_count > 0
            or portability_metadata.get("chrome_history_available")
            or (portability_connected and any("dataportability.chrome.history" in str(scope) for scope in portability_scopes))
        ),
        "chrome_history_count": chrome_history_count,
        "portability_configured": bool(portability_account),
        "portability_account_label": portability_account.get("account_label") if portability_account else None,
        "portability_scopes": portability_scopes,
        "portability_status": portability_account.get("status") if portability_account else "missing",
        "portability_last_sync_at": portability_account.get("last_sync_at") if portability_account else None,
        "calendar_write_ready": calendar_write_ready,
        "status": account.get("status") if account else ("pending" if configured else "missing"),
        "email_thread_count": email_thread_count,
        "calendar_event_count": calendar_event_count,
        "drive_file_count": drive_file_count,
        "last_sync_at": account.get("last_sync_at") if account else None,
        "connected_account": account,
        "desktop_managed": True,
    }


