def _assistant_thread_context_bundle(
    *,
    query: str,
    recent_messages: list[dict] | None,
    source_refs: list[dict] | None,
    store: Persistence,
    office_id: str,
) -> dict[str, Any]:
    conversation_lines, conversation_meta = _assistant_thread_recent_history_lines(recent_messages)
    external_context_lines, external_meta = _assistant_thread_external_context_lines(
        query=query,
        recent_messages=recent_messages,
        source_refs=source_refs,
        store=store,
        office_id=office_id,
    )
    return {
        "conversation_lines": conversation_lines,
        "external_context_lines": external_context_lines,
        "meta": {
            **conversation_meta,
            **external_meta,
        },
    }


def _contains_any_phrase(value: str, phrases: tuple[str, ...]) -> bool:
    return any(phrase in value for phrase in phrases)


def _is_assistant_integration_setup_request(query: str) -> bool:
    normalized = " ".join(_normalize_tr_text(query).split())
    if not normalized:
        return False

    web_watch_markers = (
        "resmi gazete",
        "web sayfa",
        "web sayfasi",
        "website",
        "web sitesi",
        "site",
        "sayfa",
    )
    web_watch_actions = ("takip", "izle", "monitor", "watch")
    if any(marker in normalized for marker in web_watch_markers) and any(action in normalized for action in web_watch_actions):
        return True

    service_markers = (
        "slack",
        "notion",
        "google",
        "gmail",
        "drive",
        "calendar",
        "takvim",
        "outlook",
        "telegram",
        "whatsapp",
        "instagram",
        "linkedin",
        "twitter",
        "github",
        "jira",
        "trello",
        "hubspot",
        "discord",
        "tiktok",
        "dropbox",
        "crm",
        "api",
        "servis",
        "service",
        "database",
        "veritabani",
        "postgres",
        "elastic",
        "entegrasyon",
        "integration",
        "hesap",
        "account",
        "website",
        "web",
        "site",
        "sayfa",
    )
    if not any(marker in normalized for marker in service_markers):
        return False

    setup_patterns = (
        r"\bkur(?:alim(?:\s+mi)?|ulum(?:unu)?|maya|mak)?\b",
        r"\bbagla(?:yalim(?:\s+mi)?|mak)?\b",
        r"\bentegre(?:\s+et(?:mek)?|\s+edelim)?\b",
        r"\bentegrasyon\b",
        r"\b(?:hesabimi|hesabi|account)\s+bagla\b",
        r"\boauth\b",
        r"\bizin\s+ekran(?:i|ini)\b",
        r"\bsetup\b",
        r"\bbaglanti(?:yi)?\b",
    )
    return any(re.search(pattern, normalized) for pattern in setup_patterns)


def _is_action_behavior_complaint(normalized: str) -> bool:
    return _contains_any_phrase(
        normalized,
        (
            "neden",
            "niye",
            "nasil",
            "sorun",
            "problem",
            "hata",
            "yanlis",
            "alakasiz",
            "kendi kendine",
            "durduk yere",
            "olusturmamali",
            "olusturmasin",
            "yazmadan",
            "demem lazim",
            "demeden",
            "istemiyorum",
            "istemeden",
            "sikayet",
        ),
    )


def _has_explicit_action_verb(normalized: str) -> bool:
    return _contains_any_phrase(
        normalized,
        (
            "hazirla",
            "olustur",
            "yaz",
            "gonder",
            "at",
            "yolla",
            "yanitla",
            "cevapla",
            "cevap ver",
            "donus yap",
            "ekle",
            "ilet",
            "paylas",
        ),
    )


def _is_explicit_email_action_request(query: str, recent_messages: list[dict] | None) -> bool:
    normalized = _normalize_tr_text(query)
    if (
        _is_action_behavior_complaint(normalized)
        or _is_assistant_integration_setup_request(query)
        or not _has_explicit_action_verb(normalized)
    ):
        return False

    if _EMAIL_PATTERN.search(str(query or "")):
        return True

    direct_email_markers = (
        "mail",
        "e-posta",
        "eposta",
        "bu mail",
        "bu e-posta",
        "bu eposta",
        "maili",
        "e-postayi",
        "epostayi",
        "taslaga",
        "taslaga ekle",
        "taslaklara",
        "taslaklar kismina",
        "taslaklarda",
    )
    if _contains_any_phrase(normalized, direct_email_markers):
        return True

    email_context = _extract_recent_email_context(query, recent_messages)
    if not email_context:
        return False

    contextual_markers = (
        "bu kisiyi",
        "buna",
        "bunu",
        "ona",
        "karsi tarafa",
    )
    return _contains_any_phrase(normalized, contextual_markers)


def _is_explicit_channel_action_request(query: str, *, channel_markers: tuple[str, ...]) -> bool:
    normalized = _normalize_tr_text(query)
    if _is_action_behavior_complaint(normalized) or _is_assistant_integration_setup_request(query):
        return False
    return _contains_any_phrase(normalized, channel_markers) and _has_explicit_action_verb(normalized)


def _is_generic_message_action_request(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    if _is_action_behavior_complaint(normalized) or _is_assistant_integration_setup_request(query):
        return False
    if _contains_any_phrase(normalized, ("mail", "e-posta", "eposta", "whatsapp", "telegram", "tweet", "x'te", "x te")):
        return False
    if "mesaj" in normalized:
        return _has_explicit_action_verb(normalized)
    compact_query = re.sub(r"\s+", " ", str(query or "").strip())
    return bool(_extract_message_action_request_from_compact_query(compact_query))


def _should_handle_assistant_thread_locally(
    query: str,
    recent_messages: list[dict] | None,
    *,
    dispatch_kind: str | None = None,
) -> bool:
    if dispatch_kind:
        if dispatch_kind == "integration_setup":
            return False
        if dispatch_kind in {"recent_email_snapshot", "recent_whatsapp_snapshot", "recent_telegram_snapshot", "recent_x_snapshot", "action", "operation", "route"}:
            return True
        if dispatch_kind in {"general", "integration_access"}:
            return False
    if _is_assistant_integration_setup_request(query):
        return False
    return bool(
        _is_general_approval_confirmation(query)
        or _is_explicit_email_action_request(query, recent_messages)
        or _wants_recent_whatsapp_snapshot(query, recent_messages)
        or _wants_recent_x_snapshot(query, recent_messages)
        or _is_explicit_channel_action_request(query, channel_markers=("telegram",))
        or _is_explicit_channel_action_request(query, channel_markers=("whatsapp", "whatsapptan", "whatsapp'tan"))
        or _is_explicit_channel_action_request(query, channel_markers=("x'te", "x te", "tweet", "gonderi paylas", "post paylas"))
        or _is_explicit_channel_action_request(query, channel_markers=("linkedin", "linkedinde", "linkedin de", "linkedin'de"))
        or _is_generic_message_action_request(query)
        or is_travel_booking_query(query)
        or _should_attempt_semantic_action_plan(query, recent_messages)
        or _should_attempt_semantic_route_plan(query, recent_messages)
        or _should_attempt_semantic_operation_plan(query, recent_messages)
    )


def _clean_message_recipient(value: str) -> str:
    candidate = re.sub(r"\s+", " ", str(value or "").strip())
    candidate = candidate.strip("\"'“”‘’")
    if _normalize_tr_text(candidate) in {
        "bana",
        "beni",
        "bize",
        "bizim",
        "sana",
        "seni",
        "size",
        "siz",
        "ona",
        "onu",
        "kendime",
        "kendine",
        "kendisine",
        "buraya",
        "burayi",
        "oraya",
        "suraya",
        "şuraya",
    }:
        parts = [part[:1].upper() + part[1:] for part in candidate.split() if part]
        return " ".join(parts)
    for suffix in ("'ya", "'ye", "'a", "'e", "ya", "ye", "a", "e"):
        if len(candidate) > len(suffix) + 2 and candidate.lower().endswith(suffix):
            candidate = candidate[: -len(suffix)]
            break
    candidate = candidate.strip("\"'“”‘’ ")
    parts = [part[:1].upper() + part[1:] for part in candidate.split() if part]
    return " ".join(parts)


def _looks_like_contact_recipient(value: str) -> bool:
    raw = _compact_inline_text(value)
    if not raw:
        return False
    if _EMAIL_PATTERN.search(raw):
        return True
    if "@" in raw:
        return True
    digits = re.sub(r"\D+", "", raw)
    if len(digits) >= 8:
        return True
    normalized = _normalize_tr_text(raw)
    if not normalized:
        return False
    blocked = {
        "bana",
        "beni",
        "bize",
        "bizim",
        "sana",
        "seni",
        "size",
        "siz",
        "kendime",
        "kendine",
        "kendisine",
        "buraya",
        "burayi",
        "şuraya",
        "suraya",
        "oraya",
        "buradan",
        "maile",
        "maile",
        "epostaya",
        "e postaya",
        "taslaklara",
        "taslaga",
        "taslağa",
        "ajandaya",
        "ajandama",
        "takvime",
        "bugune",
        "bugüne",
        "yarina",
        "yarına",
    }
    if normalized in blocked:
        return False
    return len(normalized.split()) <= 4


def _is_placeholder_message_body(value: str) -> bool:
    normalized = re.sub(r"\s+", " ", _normalize_tr_text(value)).strip()
    if not normalized:
        return True
    placeholders = {
        "mesaj",
        "mesaji",
        "mesaji bir",
        "mesaj yaz",
        "mesaj gonder",
        "mesaj gönder",
        "mesaj at",
        "mesaj yolla",
        "not",
        "yazi",
        "whatsapp mesaj",
        "whatsapp mesaji",
        "whatsapp mesaji bir",
        "whatsapp notu",
    }
    if normalized in placeholders:
        return True
    return normalized.startswith("whatsapp mesaj")


def _extract_message_action_request_from_compact_query(compact_query: str) -> dict[str, Any] | None:
    if not compact_query:
        return None

    patterns = [
        re.compile(
            r"^\s*(?P<recipient>.+?)\s+(?:bir\s+)?mesaj\s+(?:gonderelim|gönderelim|hazirlayalim|hazırlayalım|yazalim|yazalım|olusturalim|oluşturalım)\s+(?P<body>.+?)\s+diye\s*$",
            re.IGNORECASE,
        ),
        re.compile(
            r"^\s*(?P<recipient>.+?)\s+(?P<body>.+?)\s+diye\s+(?:bir\s+)?mesaj\s+(?:hazırla|hazirla|oluştur|olustur|yaz|gönder|gonder|ilet|paylaş|paylas)\s*$",
            re.IGNORECASE,
        ),
        re.compile(
            r"^\s*(?P<recipient>.+?)\s+(?:için|icin)\s+[\"“'‘]?(?P<body>[^\"”'’]+?)[\"”'’]?\s+(?:mesaj|not)\s+(?:hazırla|hazirla|oluştur|olustur|yaz|gönder|gonder|ilet|paylaş|paylas)\s*$",
            re.IGNORECASE,
        ),
        re.compile(
            r"^\s*(?P<recipient>.+?)\s+(?P<body>.+?)\s+(?:yaz|gönder|gonder|ilet|paylaş|paylas|at|yolla)\s*$",
            re.IGNORECASE,
        ),
    ]
    for pattern in patterns:
        match = pattern.match(compact_query)
        if not match:
            continue
        recipient = _clean_message_recipient(match.group("recipient"))
        if not _looks_like_contact_recipient(recipient):
            continue
        body = re.sub(r"\s+", " ", str(match.group("body") or "").strip()).strip("\"'“”‘’ ")
        if not body or _is_placeholder_message_body(body):
            return {
                "needs_clarification": True,
                "channel": "whatsapp",
                "to_contact": recipient,
            }
        if recipient and body:
            return {
                "to_contact": recipient,
                "body": body,
                "title": f"{recipient} için mesaj",
                "channel": "whatsapp",
            }

    return None


def _extract_generic_message_action_request(query: str) -> dict[str, Any] | None:
    if not _is_generic_message_action_request(query):
        return None
    compact_query = re.sub(r"\s+", " ", str(query or "").strip())
    parsed = _extract_message_action_request_from_compact_query(compact_query)
    if parsed:
        return parsed
    return {
        "needs_clarification": True,
        "channel": "whatsapp",
    }


