def _normalize_planned_datetime(value: str) -> str:
    raw = _compact_inline_text(str(value or ""))
    if not raw:
        return ""
    normalized = raw[:-1] + "+00:00" if raw.endswith("Z") else raw
    try:
        dt = datetime.fromisoformat(normalized)
    except ValueError:
        return ""
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=_safe_local_timezone())
    return dt.isoformat()


def _normalize_planned_contact(value: str, *, channel: str) -> str:
    compact = _compact_inline_text(value)
    if not compact:
        return ""
    if channel == "email" or _EMAIL_PATTERN.search(compact):
        return compact
    if "@" in compact:
        return compact
    digits = re.sub(r"\D+", "", compact)
    if len(digits) >= 8:
        return digits
    return _clean_message_recipient(compact)


def _assistant_dispatch_prompt(
    *,
    query: str,
    recent_messages: list[dict] | None,
    source_refs: list[dict] | None,
) -> str:
    recent_lines: list[str] = []
    if recent_messages:
        for item in recent_messages[-4:]:
            role = str(item.get("role") or "unknown")
            content = _compact_inline_text(str(item.get("content") or ""))
            if content:
                recent_lines.append(f"- {role}: {content[:220]}")
    return "\n".join(
        [
            "LawCopilot için üst seviye sohbet yönlendirme kararı ver.",
            "Amaç: Kullanıcının ilk niyetini seçmek.",
            "Yalnız JSON döndür.",
            "Şema:",
            "{",
            '  "kind": "general|integration_setup|integration_access|recent_email_snapshot|recent_whatsapp_snapshot|recent_telegram_snapshot|recent_x_snapshot|action|operation|route",',
            '  "confidence": "low|medium|high",',
            '  "reason": "string"',
            "}",
            "Kurallar:",
            "- integration_setup: hesap bağlama, kurulum, OAuth, entegrasyon ekleme, servis bağlama isteği.",
            "- integration_access: hangi hesaplara/entegrasyonlara erişimin olduğunu sorma.",
            "- recent_email_snapshot / recent_whatsapp_snapshot / recent_telegram_snapshot / recent_x_snapshot: son mesajları listeleme/özetleme istemi.",
            "- action: dış dünyada gönderim, yanıt, paylaşım, rezervasyon gibi eylem istemi.",
            "- operation: görev, takvim, otomasyon kuralı gibi iç operasyon istemi.",
            "- route: web arama, site inceleme, video, belge, sosyal takip, hava, seyahat, yer arama gibi bilgi/araştırma yolu.",
            "- general: normal sohbet, açıklama, düşünme, tavsiye, proje değerlendirmesi.",
            "- Sadece kanal adının geçmesi action veya snapshot için yeterli değil; asıl niyet setup ise integration_setup seç.",
            "- X/Twitter hesabındaki son DM veya son sosyal mesajları istemek route değil, recent_x_snapshot'tır.",
            "- Emin değilsen general seç.",
            "",
            f"Kullanıcı sorgusu: {query}",
            f"Source ref sayısı: {len(source_refs or [])}",
            "Yakın konuşma özeti:",
            *(recent_lines or ["- Yakın konuşma yok."]),
        ]
    )


def _assistant_runtime_dispatch_plan(
    *,
    query: str,
    recent_messages: list[dict] | None,
    source_refs: list[dict] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    if not runtime:
        return None
    runtime_completion = _maybe_runtime_completion(
        runtime,
        _assistant_dispatch_prompt(
            query=query,
            recent_messages=recent_messages,
            source_refs=source_refs,
        ),
        events,
        task="assistant_dispatch_plan",
        subject=subject,
    )
    if not runtime_completion:
        return None
    payload = _parse_json_object_from_text(str(runtime_completion.get("text") or ""))
    if not payload:
        return None
    kind = str(payload.get("kind") or "").strip()
    confidence = str(payload.get("confidence") or "").strip().lower()
    if kind not in _ASSISTANT_DISPATCH_KINDS or confidence not in {"medium", "high"}:
        return None
    return {
        "kind": kind,
        "confidence": confidence,
        "reason": _compact_inline_text(str(payload.get("reason") or "")),
        "source": "semantic_runtime",
    }


def _assistant_fallback_dispatch_kind(
    query: str,
    recent_messages: list[dict] | None,
    *,
    allow_snapshot_heuristics: bool = True,
    allow_intent_heuristics: bool = True,
) -> str | None:
    if _is_assistant_integration_setup_request(query):
        return "integration_setup"
    if _wants_integration_access_snapshot(query):
        return "integration_access"
    if allow_snapshot_heuristics and _wants_recent_email_snapshot(query, recent_messages):
        return "recent_email_snapshot"
    if allow_snapshot_heuristics and _wants_recent_telegram_snapshot(query, recent_messages):
        return "recent_telegram_snapshot"
    if allow_snapshot_heuristics and _wants_recent_whatsapp_snapshot(query, recent_messages):
        return "recent_whatsapp_snapshot"
    if allow_snapshot_heuristics and _wants_recent_x_snapshot(query, recent_messages):
        return "recent_x_snapshot"
    if not allow_intent_heuristics:
        return None
    if _assistant_route_heuristic_plan(query, recent_messages):
        return "route"
    if _assistant_operation_heuristic_plan(query):
        return "operation"
    if _assistant_rule_based_action_plan(query=query, matter_id=None, recent_messages=recent_messages):
        return "action"
    return None


def _assistant_explicit_snapshot_dispatch_kind(
    query: str,
    recent_messages: list[dict] | None,
) -> str | None:
    if _wants_recent_email_snapshot(query, recent_messages):
        return "recent_email_snapshot"
    if _wants_recent_telegram_snapshot(query, recent_messages):
        return "recent_telegram_snapshot"
    if _wants_recent_whatsapp_snapshot(query, recent_messages):
        return "recent_whatsapp_snapshot"
    if _wants_recent_x_snapshot(query, recent_messages):
        return "recent_x_snapshot"
    return None


def _resolve_assistant_dispatch_kind(
    *,
    query: str,
    recent_messages: list[dict] | None,
    source_refs: list[dict] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    explicit_snapshot_kind = _assistant_explicit_snapshot_dispatch_kind(query, recent_messages)
    semantic_plan = _assistant_runtime_dispatch_plan(
        query=query,
        recent_messages=recent_messages,
        source_refs=source_refs,
        runtime=runtime,
        events=events,
        subject=subject,
    )
    if semantic_plan:
        semantic_kind = str(semantic_plan.get("kind") or "").strip()
        if explicit_snapshot_kind and semantic_kind in {"general", "route"}:
            return {
                "kind": explicit_snapshot_kind,
                "confidence": "high",
                "reason": _compact_inline_text(str(semantic_plan.get("reason") or "")),
                "source": "semantic_runtime+deterministic_guard",
            }
        return semantic_plan
    if explicit_snapshot_kind:
        return {
            "kind": explicit_snapshot_kind,
            "confidence": "high",
            "reason": "",
            "source": "heuristic_fallback",
        }
    fallback_kind = _assistant_fallback_dispatch_kind(
        query,
        recent_messages,
        allow_snapshot_heuristics=not _runtime_semantic_available(runtime),
        allow_intent_heuristics=not _runtime_semantic_available(runtime),
    )
    if not fallback_kind:
        return None
    return {
        "kind": fallback_kind,
        "confidence": "high",
        "reason": "",
        "source": "heuristic_fallback",
    }


