def _assistant_runtime_integration_followup_plan(
    *,
    query: str,
    recent_messages: list[dict] | None,
    active_setup: dict[str, Any],
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    if not runtime or not active_setup:
        return None
    runtime_completion = _maybe_runtime_completion(
        runtime,
        _assistant_integration_followup_prompt(
            query=query,
            recent_messages=recent_messages,
            active_setup=active_setup,
        ),
        events,
        task="assistant_integration_followup_plan",
        subject=subject,
    )
    if not runtime_completion:
        return None
    payload = _parse_json_object_from_text(str(runtime_completion.get("text") or ""))
    if not payload:
        return None
    intent = str(payload.get("intent") or "").strip().lower()
    confidence = str(payload.get("confidence") or "").strip().lower()
    if intent not in {"explain_current", "provide_value", "status_check", "execute_desktop_action", "switch_setup", "cancel", "none"}:
        return None
    if confidence not in {"medium", "high"}:
        return None
    connector_id = _normalize_assistant_integration_connector_id(str(payload.get("connector_id") or ""))
    field_key = str(payload.get("field_key") or "").strip().lower()
    if field_key not in {"client_id", "client_secret", "tenant_id", "bot_token", "allowed_user_id", "phone_number_id", "access_token", "business_label"}:
        field_key = ""
    return {
        "followup_intent": intent,
        "connector_id": connector_id,
        "field_key": field_key,
        "confidence": confidence,
        "reason": _compact_inline_text(str(payload.get("reason") or "")),
        "source": "semantic_runtime",
    }


