def _assistant_runtime_action_plan(
    *,
    query: str,
    matter_id: int | None,
    recent_messages: list[dict] | None,
    store: Persistence,
    office_id: str,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    if not runtime:
        return None
    runtime_completion = _maybe_runtime_completion(
        runtime,
        _assistant_action_intent_prompt(
            query=query,
            recent_messages=recent_messages,
            matter_id=matter_id,
            store=store,
            office_id=office_id,
        ),
        events,
        task="assistant_action_intent_plan",
        subject=subject,
        matter_id=matter_id,
    )
    if not runtime_completion:
        return None
    payload = _parse_json_object_from_text(str(runtime_completion.get("text") or ""))
    if not payload:
        return None

    intent = str(payload.get("intent") or "").strip()
    if intent not in _ASSISTANT_ACTION_INTENTS or intent == "none":
        return None

    target_channel = str(payload.get("target_channel") or _ASSISTANT_ACTION_CHANNELS.get(intent) or "").strip()
    if target_channel not in {"email", "whatsapp", "telegram", "instagram", "x", "linkedin", "travel"}:
        target_channel = _ASSISTANT_ACTION_CHANNELS.get(intent) or ""

    return {
        "intent": intent,
        "target_channel": target_channel,
        "to_contact": _normalize_planned_contact(str(payload.get("to_contact") or ""), channel=target_channel or "whatsapp"),
        "title": _compact_inline_text(str(payload.get("title") or "")),
        "instructions": _compact_inline_text(str(payload.get("instructions") or "")),
        "needs_clarification": bool(payload.get("needs_clarification")),
        "clarification_reason": _compact_inline_text(str(payload.get("clarification_reason") or "")),
        "confidence": str(payload.get("confidence") or "").strip().lower() or "medium",
        "source": "semantic_runtime",
    }


def _assistant_contextual_action_plan(
    *,
    query: str,
    recent_messages: list[dict] | None,
    store: Persistence,
    office_id: str,
) -> dict[str, Any] | None:
    if not _message_requests_reply_generation(query):
        return None
    recipient = _resolve_direct_reply_recipient(query, recent_messages)
    if not recipient:
        return None
    reply_context = _build_recent_whatsapp_reply_context(
        recipient=recipient,
        store=store,
        office_id=office_id,
    )
    return {
        "intent": "send_whatsapp_message",
        "target_channel": "whatsapp",
        "to_contact": recipient,
        "title": f"{recipient} için yanıt",
        "instructions": _compose_direct_reply_generation_instruction(
            query=query,
            recipient=recipient,
            reply_context=reply_context,
        ),
        "needs_clarification": reply_context is None,
        "clarification_reason": "" if reply_context else "recipient_context_missing",
        "confidence": "high" if reply_context else "medium",
        "source": "contextual_fallback",
        "reply_context": reply_context,
    }


def _merge_assistant_action_plans(
    *,
    query: str,
    semantic_plan: dict[str, Any] | None,
    contextual_plan: dict[str, Any] | None,
) -> dict[str, Any] | None:
    if semantic_plan and not contextual_plan:
        return semantic_plan
    if contextual_plan and not semantic_plan:
        return contextual_plan
    if not semantic_plan and not contextual_plan:
        return None
    merged = dict(semantic_plan or {})
    contextual = dict(contextual_plan or {})
    if not merged.get("to_contact") and contextual.get("to_contact"):
        merged["to_contact"] = contextual.get("to_contact")
    if not merged.get("title") and contextual.get("title"):
        merged["title"] = contextual.get("title")
    if (
        _message_instructions_need_generation(
            str(merged.get("instructions") or ""),
            query=query,
            recipient=str(merged.get("to_contact") or contextual.get("to_contact") or ""),
        )
        and contextual.get("instructions")
    ):
        merged["instructions"] = contextual.get("instructions")
    if contextual.get("reply_context"):
        merged["reply_context"] = contextual.get("reply_context")
        if merged.get("intent") in {"send_whatsapp_message", "send_telegram_message", "send_instagram_message", "send_linkedin_message"}:
            if merged.get("needs_clarification") and merged.get("to_contact"):
                merged["needs_clarification"] = False
                merged["clarification_reason"] = ""
        merged["source"] = "semantic_runtime+contextual" if semantic_plan else contextual.get("source")
    return merged


