def _assistant_runtime_operation_plan(
    *,
    query: str,
    matter_id: int | None,
    recent_messages: list[dict] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    if not runtime:
        return None
    runtime_completion = _maybe_runtime_completion(
        runtime,
        _assistant_operation_intent_prompt(
            query=query,
            recent_messages=recent_messages,
            matter_id=matter_id,
        ),
        events,
        task="assistant_operation_intent_plan",
        subject=subject,
        matter_id=matter_id,
    )
    if not runtime_completion:
        return None
    payload = _parse_json_object_from_text(str(runtime_completion.get("text") or ""))
    if not payload:
        return None
    intent = str(payload.get("intent") or "").strip()
    confidence = str(payload.get("confidence") or "").strip().lower() or "medium"
    if intent not in _ASSISTANT_OPERATION_INTENTS or intent == "none" or confidence not in {"medium", "high"}:
        return None
    return {
        "intent": intent,
        "title": _compact_inline_text(str(payload.get("title") or "")),
        "due_at": _normalize_planned_datetime(str(payload.get("due_at") or "")),
        "priority": str(payload.get("priority") or "").strip().lower() or "medium",
        "starts_at": _normalize_planned_datetime(str(payload.get("starts_at") or "")),
        "ends_at": _normalize_planned_datetime(str(payload.get("ends_at") or "")),
        "location": _compact_inline_text(str(payload.get("location") or "")),
        "needs_preparation": bool(payload.get("needs_preparation", True)),
        "mode": str(payload.get("mode") or "").strip().lower(),
        "reminder_at": _normalize_planned_datetime(str(payload.get("reminder_at") or "")),
        "channels": [str(item).strip().lower() for item in list(payload.get("channels") or []) if str(item).strip()],
        "targets": [_compact_inline_text(str(item)) for item in list(payload.get("targets") or []) if _compact_inline_text(str(item))],
        "match_terms": [_compact_inline_text(str(item)) for item in list(payload.get("match_terms") or []) if _compact_inline_text(str(item))],
        "reply_text": _compact_inline_text(str(payload.get("reply_text") or "")),
        "instructions": _compact_inline_text(str(payload.get("instructions") or "")),
        "needs_clarification": bool(payload.get("needs_clarification")),
        "clarification_reason": _compact_inline_text(str(payload.get("clarification_reason") or "")),
        "confidence": confidence,
        "source": "semantic_runtime",
    }


def _assistant_operation_heuristic_plan(query: str) -> dict[str, Any] | None:
    if automation_update := build_assistant_automation_update(query):
        return {
            "intent": "configure_automation",
            "automation_update": automation_update,
            "confidence": "high",
            "source": "heuristic",
        }
    if calendar_candidate := _extract_calendar_candidate(query):
        return {
            "intent": "create_calendar_event",
            "title": _compact_inline_text(str(calendar_candidate.get("title") or "")),
            "starts_at": str(calendar_candidate.get("starts_at") or ""),
            "ends_at": str(calendar_candidate.get("ends_at") or ""),
            "location": _compact_inline_text(str(calendar_candidate.get("location") or "")),
            "needs_preparation": bool(calendar_candidate.get("needs_preparation")),
            "confidence": "high",
            "source": "heuristic",
        }
    if task_candidate := _extract_task_candidate(query):
        return {
            "intent": "create_task",
            "title": _compact_inline_text(str(task_candidate.get("title") or "")),
            "due_at": str(task_candidate.get("due_at") or ""),
            "priority": str(task_candidate.get("priority") or "medium"),
            "instructions": _compact_inline_text(str(task_candidate.get("explanation") or query)),
            "confidence": "medium",
            "source": "heuristic",
        }
    return None


def _should_attempt_semantic_operation_plan(query: str, recent_messages: list[dict] | None) -> bool:
    normalized = _normalize_tr_text(_resolve_assistant_query(query, recent_messages))
    if _is_action_behavior_complaint(normalized):
        return False
    operation_markers = (
        "gorev",
        "görev",
        "task",
        "todo",
        "yapilacak",
        "yapılacak",
        "hatirlat",
        "hatırlat",
        "takvim",
        "ajanda",
        "listeme al",
        "listeme al",
        "takip listeme",
        "toplanti",
        "toplantı",
        "gorusme",
        "görüşme",
        "durusma",
        "duruşma",
        "randevu",
        "etkinlik",
        "planlayalim",
        "planlayalım",
        "otomasyon",
        "kural",
        "haber ver",
        "haber dus",
        "haber düş",
        "bildir",
        "bildirim",
        "otomatik",
    )
    if _contains_any_phrase(normalized, operation_markers):
        return True
    return bool(
        re.search(
            r"\b(20\d{2}-\d{2}-\d{2}|\d{1,2}[./]\d{1,2}[./]\d{2,4}|yarin|yarın|obur gun|öbür gün|pazartesi|sali|salı|carsamba|çarşamba|persembe|perşembe|cuma|cumartesi|pazar)\b",
            normalized,
        )
    )


def _resolve_assistant_operation_plan(
    *,
    query: str,
    matter_id: int | None,
    recent_messages: list[dict] | None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    runtime_plan = _assistant_runtime_operation_plan(
        query=query,
        matter_id=matter_id,
        recent_messages=recent_messages,
        runtime=runtime,
        events=events,
        subject=subject,
    )
    if runtime_plan:
        return runtime_plan
    if _runtime_semantic_available(runtime):
        return None
    return _assistant_operation_heuristic_plan(query)


def _assistant_route_heuristic_plan(query: str, recent_messages: list[dict] | None) -> dict[str, Any] | None:
    effective_query = _resolve_assistant_query(query, recent_messages)
    youtube_url = extract_youtube_url(effective_query)
    if youtube_url and is_video_summary_query(effective_query):
        return {"intent": "video_summary", "confidence": "high", "source": "heuristic", "url": youtube_url}
    if is_youtube_search_query(effective_query):
        return {"intent": "youtube_search", "confidence": "high", "source": "heuristic"}
    if _is_document_inventory_query(effective_query):
        return {"intent": "document_inventory", "confidence": "high", "source": "heuristic"}
    if _is_document_summary_query(effective_query):
        return {"intent": "document_summary", "confidence": "high", "source": "heuristic"}
    if _is_legal_draft_request(effective_query, recent_messages):
        return {"intent": "legal_draft", "confidence": "high", "source": "heuristic"}
    if is_social_monitoring_query(effective_query) and not _is_external_context_summary_query(effective_query):
        return {"intent": "social_monitoring", "confidence": "high", "source": "heuristic"}
    website_url = extract_query_url(effective_query)
    if website_url and is_website_crawl_query(effective_query) and not is_travel_query(effective_query):
        return {"intent": "website_crawl", "confidence": "high", "source": "heuristic", "url": website_url}
    if website_url and is_website_review_query(effective_query) and not is_travel_query(effective_query):
        return {"intent": "website_inspection", "confidence": "high", "source": "heuristic", "url": website_url}
    if is_weather_query(effective_query) and not is_travel_query(effective_query):
        return {"intent": "weather_search", "confidence": "high", "source": "heuristic"}
    if is_travel_query(effective_query) and not is_travel_booking_query(effective_query):
        return {"intent": "travel_search", "confidence": "high", "source": "heuristic"}
    if is_place_search_query(effective_query) and not is_travel_query(effective_query):
        return {"intent": "places_search", "confidence": "high", "source": "heuristic"}
    if is_web_search_query(effective_query) and not is_travel_query(effective_query):
        return {"intent": "web_search", "confidence": "high", "source": "heuristic"}
    return None


def _is_external_context_summary_query(query: str) -> bool:
    normalized = _normalize_tr_text(query)
    wants_summary = _contains_any_phrase(
        normalized,
        (
            "ozetle",
            "özetle",
            "kisaca ozetle",
            "kısaca özetle",
            "toparla",
            "ozetini ver",
            "özetini ver",
        ),
    )
    if not wants_summary:
        return False
    return _contains_any_phrase(
        normalized,
        (
            "telegram",
            "whatsapp",
            "x dm",
            "x dmi",
            "x mention",
            "mention",
            "dm",
            "direkt mesaj",
            "direct message",
            "e-posta",
            "eposta",
            "mail",
        ),
    )


