def _assistant_semantic_thread_title(
    *,
    query: str,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> str:
    fallback = _fallback_assistant_thread_title(query)
    normalized = _normalize_tr_text(query)
    # Thread title generation should never make lightweight chat turns feel slow.
    if len(query.strip()) <= 80:
        return fallback
    if any(
        token in normalized
        for token in (
            "merhaba",
            "selam",
            "naber",
            "nasilsin",
            "nasılsın",
            "hangi model",
            "hangi yapay zeka",
            "hangi saglayici",
            "hangi sağlayıcı",
            "hazir misin",
            "hazır mısın",
            "calisiyor musun",
            "çalışıyor musun",
        )
    ):
        return fallback
    runtime_completion = _maybe_runtime_completion(
        runtime,
        _assistant_thread_title_prompt(query=query),
        events,
        task="assistant_thread_title_plan",
        subject=subject,
    )
    if not runtime_completion:
        return fallback
    payload = _parse_json_object_from_text(str(runtime_completion.get("text") or ""))
    if not payload:
        return fallback
    confidence = str(payload.get("confidence") or "").strip().lower()
    candidate = _sanitize_assistant_thread_title(str(payload.get("title") or ""))
    if confidence not in {"medium", "high"}:
        return fallback
    if not candidate or candidate.lower() in _ASSISTANT_THREAD_DEFAULT_TITLES:
        return fallback
    if _looks_like_raw_thread_title(candidate, query):
        return fallback
    return candidate


def _assistant_video_summary_answer(
    *,
    query: str,
    video_url: str,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> tuple[dict[str, Any], str | None, str | None, str]:
    inspection = WebIntelService().extract(url=video_url, render_mode="cheap", include_screenshot=False)
    analysis = analyze_video_url(video_url, max_segments=24)
    analysis["title"] = str(inspection.get("title") or analysis.get("title") or "YouTube videosu").strip() or "YouTube videosu"
    analysis["page_summary"] = str(inspection.get("summary") or "").strip()
    transcript = str(analysis.get("transcript") or "").strip()
    provider = None
    model = None
    if transcript and runtime:
        transcript_chunks = []
        for item in list(analysis.get("segments") or [])[:12]:
            excerpt = _compact_inline_text(str(item.get("excerpt") or item.get("text") or ""))
            if excerpt:
                transcript_chunks.append(f"[{item.get('segment_index')}] {excerpt}")
        prompt = "\n".join(
            [
                "LawCopilot için YouTube videosunu Türkçe özetle.",
                "Kullanıcının sorusunu merkeze al.",
                "Kurallar:",
                "- Önce 1 kısa paragrafla videonun ana fikrini söyle.",
                "- Sonra en fazla 4 kısa maddeyle önemli noktaları ver.",
                "- Varsa kullanıcı için pratik sonuç veya aksiyon önerisini en sonda tek cümleyle ekle.",
                "- Metin kısa, net ve güvenli olsun.",
                "",
                f"Kullanıcı isteği: {query}",
                f"Video başlığı: {analysis['title']}",
                "",
                "Transkript parçaları:",
                *transcript_chunks,
            ]
        )
        completion = _maybe_runtime_completion(
            runtime,
            prompt,
            events,
            task="assistant_video_summary",
            subject=subject,
        )
        if completion:
            return analysis, completion.get("provider"), completion.get("model"), str(completion.get("text") or "")
    return analysis, provider, model, _assistant_video_summary_fallback(analysis)


def _assistant_video_summary_fallback(analysis: dict[str, Any]) -> str:
    title = _compact_inline_text(str(analysis.get("title") or "YouTube videosu"))
    transcript_available = bool(analysis.get("transcript_available"))
    if transcript_available:
        lines = [f"{title} için video özetini hazırladım."]
        segments = list(analysis.get("segments") or [])
        if segments:
            lines.append("Öne çıkan bölümler:")
            for index, item in enumerate(segments[:3], start=1):
                excerpt = _compact_inline_text(str(item.get("excerpt") or item.get("text") or ""))
                if excerpt:
                    lines.append(f"{index}. {excerpt}")
        return "\n".join(lines)
    page_summary = _compact_inline_text(str(analysis.get("page_summary") or ""))
    lines = [f"{title} için transcript alınamadı."]
    if page_summary:
        lines.append(page_summary)
    lines.append("Video linkine transcript erişimi açılırsa daha güçlü bir özet çıkarabilirim.")
    return "\n".join(lines)


def _assistant_website_crawl_answer(
    *,
    query: str,
    url: str,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> tuple[dict[str, Any], str | None, str | None, str]:
    crawl = WebIntelService().crawl(url=url, query=query, max_pages=4, render_mode="cheap", include_screenshot=False)
    provider = None
    model = None
    fallback_lines = [str(crawl.get("summary") or "Site taramasını tamamladım.")]
    pages = list(crawl.get("pages") or [])
    if pages:
        fallback_lines.append("Öne çıkan sayfalar:")
        for index, page in enumerate(pages[:4], start=1):
            row = f"{index}. {page.get('title') or page.get('url') or 'Sayfa'}"
            excerpt = _compact_inline_text(str(page.get("excerpt") or page.get("summary") or ""))
            if excerpt:
                row += f" — {excerpt}"
            fallback_lines.append(row)
    fallback = "\n".join(fallback_lines)
    if pages and runtime:
        prompt = "\n".join(
            [
                "LawCopilot için site taraması sonucunu Türkçe cevapla.",
                "Kullanıcının sorusunu, taranan sayfalarla sınırlı kalarak cevapla.",
                "Kurallar:",
                "- İlk cümlede net cevap ver.",
                "- Sonra en fazla 4 kısa madde kullan.",
                "- Emin olmadığın yerde bunu kısaça belirt.",
                "- Uydurma bilgi ekleme; yalnız taranan sayfaları kullan.",
                "",
                f"Kullanıcı sorusu: {query}",
                f"Ana URL: {url}",
                "",
                "Taranan sayfalar:",
                *[
                    "\n".join(
                        [
                            f"- Başlık: {page.get('title') or 'Sayfa'}",
                            f"  URL: {page.get('url') or ''}",
                            f"  Özet: {page.get('summary') or ''}",
                            f"  Metin: {page.get('excerpt') or ''}",
                        ]
                    )
                    for page in pages[:4]
                ],
            ]
        )
        completion = _maybe_runtime_completion(
            runtime,
            prompt,
            events,
            task="assistant_website_crawl",
            subject=subject,
        )
        if completion:
            provider = completion.get("provider")
            model = completion.get("model")
            return crawl, provider, model, str(completion.get("text") or fallback)
    return crawl, provider, model, fallback


def _resolve_assistant_route_plan(
    *,
    query: str,
    matter_id: int | None,
    recent_messages: list[dict] | None,
    source_refs: list[dict] | None,
    profile: dict[str, Any] | None = None,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    runtime_plan = _assistant_runtime_route_plan(
        query=query,
        matter_id=matter_id,
        recent_messages=recent_messages,
        source_refs=source_refs,
        runtime=runtime,
        events=events,
        subject=subject,
    )
    if runtime_plan:
        return runtime_plan
    if _runtime_semantic_available(runtime):
        return None
    route_plan = _assistant_route_heuristic_plan(query, recent_messages)
    if route_plan:
        return route_plan
    preference_context = resolve_source_preference_context(query, profile=profile)
    if preference_context.get("should_search"):
        task_kinds = set(preference_context.get("task_kinds") or [])
        if any(item in task_kinds for item in {"travel_booking", "travel"}):
            route_intent = "travel_search"
        else:
            route_intent = "places_search" if preference_context.get("needs_local_results") else "web_search"
        return {
            "intent": route_intent,
            "confidence": "medium",
            "source": "preference_goal_fallback",
        }
    return None


def _assistant_rule_based_action_plan(
    *,
    query: str,
    matter_id: int | None,
    recent_messages: list[dict] | None,
) -> dict[str, Any] | None:
    normalized_query = _normalize_tr_text(query)
    generic_message_request = _extract_generic_message_action_request(query)
    if generic_message_request:
        if _is_explicit_channel_action_request(query, channel_markers=("linkedin", "linkedinde", "linkedin de", "linkedin'de")):
            linkedin_message_request = _extract_message_action_request_from_compact_query(
                _strip_channel_markers_for_message_action(
                    query,
                    (
                        "linkedin'den",
                        "linkedin'da",
                        "linkedin'de",
                        "linkedinden",
                        "linkedin den",
                        "linkedin dan",
                        "linkedinde",
                        "linkedin de",
                        "linkedin",
                    ),
                )
            ) or generic_message_request
            return {
                "intent": "send_linkedin_message",
                "target_channel": "linkedin",
                "to_contact": _normalize_planned_contact(str(linkedin_message_request.get("to_contact") or ""), channel="linkedin"),
                "title": _compact_inline_text(str(linkedin_message_request.get("title") or "")),
                "instructions": _compact_inline_text(str(linkedin_message_request.get("body") or query)),
                "needs_clarification": bool(linkedin_message_request.get("needs_clarification")),
                "clarification_kind": "direct_message",
                "confidence": "high",
                "source": "heuristic",
            }
        if _is_explicit_channel_action_request(query, channel_markers=("telegram",)):
            return {
                "intent": "send_telegram_message",
                "target_channel": "telegram",
                "to_contact": _normalize_planned_contact(str(generic_message_request.get("to_contact") or ""), channel="telegram"),
                "title": _compact_inline_text(str(generic_message_request.get("title") or "")),
                "instructions": _compact_inline_text(str(generic_message_request.get("body") or query)),
                "needs_clarification": bool(generic_message_request.get("needs_clarification")),
                "clarification_kind": "direct_message",
                "confidence": "high",
                "source": "heuristic",
            }
        if _is_explicit_channel_action_request(query, channel_markers=("instagram", "insta", "instagramdan", "instagram'dan", "dm")):
            return {
                "intent": "send_instagram_message",
                "target_channel": "instagram",
                "to_contact": _normalize_planned_contact(str(generic_message_request.get("to_contact") or ""), channel="instagram"),
                "title": _compact_inline_text(str(generic_message_request.get("title") or "")),
                "instructions": _compact_inline_text(str(generic_message_request.get("body") or query)),
                "needs_clarification": bool(generic_message_request.get("needs_clarification")),
                "clarification_kind": "direct_message",
                "confidence": "high",
                "source": "heuristic",
            }
        if _is_explicit_channel_action_request(query, channel_markers=("whatsapp", "whatsapptan", "whatsapp'tan")):
            return {
                "intent": "send_whatsapp_message",
                "target_channel": "whatsapp",
                "to_contact": _normalize_planned_contact(str(generic_message_request.get("to_contact") or ""), channel="whatsapp"),
                "title": _compact_inline_text(str(generic_message_request.get("title") or "")),
                "instructions": _compact_inline_text(str(generic_message_request.get("body") or "")),
                "needs_clarification": bool(generic_message_request.get("needs_clarification")),
                "clarification_kind": "direct_message",
                "confidence": "high",
                "source": "heuristic",
            }
        return {
            "intent": "send_whatsapp_message",
            "target_channel": "whatsapp",
            "to_contact": _normalize_planned_contact(str(generic_message_request.get("to_contact") or ""), channel="whatsapp"),
            "title": _compact_inline_text(str(generic_message_request.get("title") or "")),
            "instructions": _compact_inline_text(str(generic_message_request.get("body") or "")),
            "needs_clarification": bool(generic_message_request.get("needs_clarification")),
            "clarification_kind": "direct_message",
            "confidence": "high",
            "source": "heuristic",
        }

    if _is_explicit_email_action_request(query, recent_messages):
        email_context = _extract_recent_email_context(query, recent_messages)
        reply_requested = _contains_any_phrase(_normalize_tr_text(query), ("yanit", "cevap"))
        return {
            "intent": "reply_email" if reply_requested else "send_email",
            "target_channel": "email",
            "to_contact": _normalize_planned_contact(str((email_context or {}).get("to_contact") or ""), channel="email"),
            "title": _compact_inline_text(str((email_context or {}).get("subject") or "")),
            "instructions": _compact_inline_text(str((email_context or {}).get("body") or query)),
            "needs_clarification": False,
            "confidence": "high",
            "source": "heuristic",
            "prefer_matter_update": bool(matter_id and not email_context and not reply_requested),
        }

    if _is_explicit_channel_action_request(query, channel_markers=("telegram",)):
        return {
            "intent": "send_telegram_message",
            "target_channel": "telegram",
            "to_contact": "",
            "title": "",
            "instructions": _compact_inline_text(query),
            "needs_clarification": False,
            "confidence": "high",
            "source": "heuristic",
        }

    if _is_explicit_channel_action_request(query, channel_markers=("whatsapp", "whatsapptan", "whatsapp'tan")):
        whatsapp_message_request = _extract_explicit_whatsapp_message_action_request(query)
        return {
            "intent": "send_whatsapp_message",
            "target_channel": "whatsapp",
            "to_contact": _normalize_planned_contact(str((whatsapp_message_request or {}).get("to_contact") or ""), channel="whatsapp"),
            "title": _compact_inline_text(str((whatsapp_message_request or {}).get("title") or "")),
            "instructions": _compact_inline_text(str((whatsapp_message_request or {}).get("body") or "")),
            "needs_clarification": bool((whatsapp_message_request or {}).get("needs_clarification")),
            "clarification_kind": "direct_message",
            "confidence": "high",
            "source": "heuristic",
        }

    if _is_explicit_channel_action_request(query, channel_markers=("instagram", "insta", "instagramdan", "instagram'dan", "dm")):
        return {
            "intent": "send_instagram_message",
            "target_channel": "instagram",
            "to_contact": "",
            "title": "",
            "instructions": _compact_inline_text(query),
            "needs_clarification": False,
            "clarification_kind": "direct_message",
            "confidence": "high",
            "source": "heuristic",
        }

    if _is_explicit_channel_action_request(query, channel_markers=("x'te", "x te", "tweet", "gonderi paylas", "post paylas")):
        return {
            "intent": "post_x_update",
            "target_channel": "x",
            "to_contact": "",
            "title": "",
            "instructions": _compact_inline_text(query),
            "needs_clarification": False,
            "confidence": "high",
            "source": "heuristic",
        }

    if _is_explicit_channel_action_request(query, channel_markers=("linkedin", "linkedinde", "linkedin de", "linkedin'de")):
        if _contains_any_phrase(normalized_query, ("mesaj", "dm", "direkt mesaj", "inbox", "gelen kutusu", "yanitla", "yanıtla", "yaz")):
            linkedin_message_request = _extract_message_action_request_from_compact_query(
                _strip_channel_markers_for_message_action(
                    query,
                    (
                        "linkedin'den",
                        "linkedin'da",
                        "linkedin'de",
                        "linkedinden",
                        "linkedin den",
                        "linkedin dan",
                        "linkedinde",
                        "linkedin de",
                        "linkedin",
                    ),
                )
            ) or _extract_generic_message_action_request(query) or {}
            return {
                "intent": "send_linkedin_message",
                "target_channel": "linkedin",
                "to_contact": _normalize_planned_contact(str(linkedin_message_request.get("to_contact") or ""), channel="linkedin"),
                "title": _compact_inline_text(str(linkedin_message_request.get("title") or "")),
                "instructions": _compact_inline_text(str(linkedin_message_request.get("body") or query)),
                "needs_clarification": bool(linkedin_message_request.get("needs_clarification")),
                "clarification_kind": "direct_message",
                "confidence": "high",
                "source": "heuristic",
            }
        return {
            "intent": "post_linkedin_update",
            "target_channel": "linkedin",
            "to_contact": "",
            "title": "",
            "instructions": _compact_inline_text(query),
            "needs_clarification": False,
            "confidence": "high",
            "source": "heuristic",
        }

    if is_travel_booking_query(query):
        return {
            "intent": "reserve_travel_ticket",
            "target_channel": "travel",
            "to_contact": "",
            "title": "",
            "instructions": _compact_inline_text(query),
            "needs_clarification": False,
            "confidence": "high",
            "source": "heuristic",
        }

    return None


def _should_attempt_semantic_action_plan(query: str, recent_messages: list[dict] | None) -> bool:
    normalized = _normalize_tr_text(query)
    if _is_action_behavior_complaint(normalized) or _is_assistant_integration_setup_request(query):
        return False
    if (
        is_web_search_query(query)
        or is_travel_query(query)
        or is_weather_query(query)
        or is_place_search_query(query)
        or is_youtube_search_query(query)
        or is_video_summary_query(query)
        or is_website_crawl_query(query)
    ):
        return False
    if _extract_recent_email_context(query, recent_messages) or _recent_email_thread_context(recent_messages):
        return True
    semantic_markers = (
        "bildir",
        "bilgilendir",
        "haber ver",
        "soyle",
        "ilet",
        "ulas",
        "ulasir misin",
        "temasa gec",
        "don",
        "geri don",
        "yanit gec",
        "yanit ver",
        "cevap ver",
        "cevap yaz",
        "cevap olustur",
        "cevap oluştur",
        "cevap hazirla",
        "cevap hazırla",
        "yanit olustur",
        "yanıt oluştur",
        "yanit hazirla",
        "yanıt hazırla",
        "mesaj olustur",
        "mesaj oluştur",
        "mesaj hazirla",
        "mesaj hazırla",
        "kibarca cevap",
        "yazili olarak",
        "not dus",
        "duyur",
        "satın al",
        "satin al",
        "rezervasyon",
        "bilet al",
        "bileti al",
        "yer ayirt",
    )
    has_action_marker = _contains_any_phrase(normalized, semantic_markers)
    if not has_action_marker:
        return False

    has_channel_hint = _contains_any_phrase(
        normalized,
        ("mail", "e-posta", "eposta", "whatsapp", "telegram", "linkedin", "x te", "x'te", "tweet"),
    )
    has_recipient_hint = bool(
        _EMAIL_PATTERN.search(str(query or ""))
        or re.search(r"\b[\wçğıöşü]+(?:'ya|'ye|'a|'e)\b", str(query or ""), re.IGNORECASE)
    ) or _contains_any_phrase(
        normalized,
        ("ona", "onlara", "karsi tarafa", "muvekkile", "musteriye"),
    )
    return bool(has_channel_hint or has_recipient_hint)


def _resolve_assistant_action_plan(
    *,
    query: str,
    matter_id: int | None,
    recent_messages: list[dict] | None,
    settings,
    store: Persistence,
    runtime,
    events: StructuredLogger | None,
    subject: str,
) -> dict[str, Any] | None:
    heuristic_plan = _assistant_rule_based_action_plan(
        query=query,
        matter_id=matter_id,
        recent_messages=recent_messages,
    )
    if heuristic_plan and str(heuristic_plan.get("intent") or "") == "reserve_travel_ticket":
        return heuristic_plan

    contextual_plan = _assistant_contextual_action_plan(
        query=query,
        recent_messages=recent_messages,
        store=store,
        office_id=settings.office_id,
    )
    runtime_plan = _assistant_runtime_action_plan(
        query=query,
        matter_id=matter_id,
        recent_messages=recent_messages,
        store=store,
        office_id=settings.office_id,
        runtime=runtime,
        events=events,
        subject=subject,
    )
    merged_plan = _merge_assistant_action_plans(
        query=query,
        semantic_plan=runtime_plan,
        contextual_plan=contextual_plan,
    )
    if merged_plan and str(merged_plan.get("confidence") or "").strip().lower() in {"medium", "high"}:
        return merged_plan
    if contextual_plan and str(contextual_plan.get("confidence") or "").strip().lower() in {"medium", "high"}:
        return contextual_plan
    if _runtime_semantic_available(runtime):
        return contextual_plan if contextual_plan and contextual_plan.get("needs_clarification") else None
    return _merge_assistant_action_plans(
        query=query,
        semantic_plan=heuristic_plan,
        contextual_plan=contextual_plan,
    )


