    def _build_kb_explainability(
        *,
        why_this: str,
        confidence: float,
        source_basis: list[dict[str, Any] | str],
        kb_context: dict[str, Any],
        risk_level: str = "A",
        requires_confirmation: bool = False,
    ) -> dict[str, Any]:
        supporting_records = list(kb_context.get("supporting_records") or [])
        meaningful_supporting_records: list[dict[str, Any]] = []
        for record in supporting_records:
            metadata = record.get("metadata") if isinstance(record.get("metadata"), dict) else {}
            nested_metadata = metadata.get("metadata") if isinstance(metadata.get("metadata"), dict) else {}
            source_type = str(metadata.get("source_type") or "").strip().lower()
            file_back_kind = str(nested_metadata.get("file_back_kind") or "").strip().lower()
            if source_type == "assistant_file_back" and file_back_kind in {"query_answer", "assistant_reply"}:
                continue
            meaningful_supporting_records.append(record)

        grounded_source_count = 0
        rag_source_count = 0
        for item in list(source_basis or []):
            if not isinstance(item, dict):
                continue
            item_type = str(item.get("type") or "").strip()
            if item_type == "rag_source":
                rag_source_count += 1
                grounded_source_count += 1
            elif item_type == "knowledge_record" and meaningful_supporting_records:
                grounded_source_count += 1
        has_meaningful_grounding = bool(
            meaningful_supporting_records
            or list(kb_context.get("recent_related_feedback") or [])
            or rag_source_count > 0
            or grounded_source_count > 0
        )
        return {
            "why_this": why_this,
            "confidence": round(float(confidence), 2) if has_meaningful_grounding else None,
            "source_basis": source_basis,
            "risk_level": risk_level,
            "requires_confirmation": requires_confirmation,
            "memory_scope": kb_context.get("scopes") or ["global"],
            "claim_summary_lines": kb_context.get("claim_summary_lines") or [],
            "resolved_claims": kb_context.get("resolved_claims") or [],
            "supporting_pages_or_records": kb_context.get("supporting_records") or [],
            "supporting_relations": kb_context.get("supporting_relations") or [],
            "recent_related_feedback": kb_context.get("recent_related_feedback") or [],
            "record_type_counts": kb_context.get("record_type_counts") or {},
            "context_selection_reasons": kb_context.get("context_selection_reasons") or [],
            "available_memory_actions": [
                "correct",
                "forget",
                "change_scope",
                "reduce_confidence",
                "suppress_recommendation",
                "boost_proactivity",
            ],
        }

    def _maybe_file_back_answer(
        *,
        kind: str,
        title: str,
        content: str,
        query: str | None = None,
        matter_id: int | None = None,
        source_refs: list[dict[str, Any] | str] | None = None,
        generated_from: str | None = None,
    ) -> dict[str, Any] | None:
        if not knowledge_base.enabled:
            return None
        if kind in {"query_answer", "assistant_reply"} and _is_project_repo_query(query or title):
            return None
        try:
            return knowledge_base.maybe_file_back_response(
                kind=kind,
                title=title,
                content=content,
                source_refs=source_refs,
                metadata={
                    "matter_id": matter_id,
                    "generated_from": generated_from,
                    "page_key": "legal" if matter_id else "projects",
                    "record_type": "legal_matter" if matter_id else "source",
                },
                scope=f"project:matter-{matter_id}" if matter_id else "professional",
                sensitivity="restricted" if matter_id else "medium",
            )
        except Exception as exc:  # noqa: BLE001
            events.log("personal_kb_file_back_failed", level="warning", kind=kind, error=str(exc))
            return None

    def _kb_connector_sync_after_provider_push(
        *,
        provider: str,
        synced_at: str | None,
        stats: dict[str, Any],
        checkpoint: dict[str, Any] | None = None,
        cursor: str | None = None,
        reason: str,
    ) -> dict[str, Any] | None:
        if not knowledge_base.enabled:
            return None
        try:
            knowledge_base.register_connector_push_checkpoint(
                provider=provider,
                synced_at=synced_at,
                stats=stats,
                checkpoint=checkpoint,
                cursor=cursor,
                reason=reason,
                trigger="integration_sync",
            )
            connector_names = _provider_connector_names(provider)
            if not connector_names:
                return {
                    "provider": provider,
                    "registered": True,
                    "connector_names": [],
                }
            return knowledge_base.run_connector_sync(
                store=store,
                reason=reason,
                connector_names=connector_names,
                trigger="integration_sync",
            )
        except Exception as exc:  # noqa: BLE001
            events.log("personal_kb_connector_sync_failed", level="warning", provider=provider, error=str(exc))
            return None

    def _kb_source_basis(
        *,
        kb_context: dict[str, Any] | None = None,
        source_refs: list[dict[str, Any] | str] | None = None,
        rag_sources: list[dict[str, Any]] | None = None,
        action: dict[str, Any] | None = None,
        draft: dict[str, Any] | None = None,
    ) -> list[dict[str, Any] | str]:
        items: list[dict[str, Any] | str] = []
        for record in list((kb_context or {}).get("supporting_records") or [])[:4]:
            items.append(
                {
                    "type": "knowledge_record",
                    "page_key": record.get("page_key"),
                    "record_id": record.get("record_id"),
                    "title": record.get("title"),
                    "scope": record.get("scope"),
                    "record_type": record.get("record_type"),
                }
            )
        for source in list(rag_sources or [])[:3]:
            items.append(
                {
                    "type": "rag_source",
                    "document": source.get("document"),
                    "line_start": source.get("line_start"),
                    "line_end": source.get("line_end"),
                    "chunk_id": source.get("chunk_id"),
                }
            )
        if action:
            items.append(
                {
                    "type": "assistant_action",
                    "id": action.get("id"),
                    "action_type": action.get("action_type"),
                    "status": action.get("status"),
                }
            )
        if draft:
            items.append(
                {
                    "type": "outbound_draft",
                    "id": draft.get("id"),
                    "channel": draft.get("channel"),
                    "approval_status": draft.get("approval_status"),
                }
            )
        items.extend(list(source_refs or []))
        deduped: list[dict[str, Any] | str] = []
        seen: set[str] = set()
        for item in items:
            marker = json.dumps(item, ensure_ascii=False, sort_keys=True) if isinstance(item, dict) else str(item)
            if marker in seen:
                continue
            seen.add(marker)
            deduped.append(item)
        return deduped[:8]

    def _assistant_action_ladder(
        *,
        action: dict[str, Any] | None,
        policy: dict[str, Any],
        event_type: str | None = None,
    ) -> dict[str, Any]:
        status = str((action or {}).get("status") or "").strip()
        stage = "suggest"
        if event_type == "generated":
            stage = "draft"
        elif event_type in {"approved"}:
            stage = "one_click_approve"
        elif event_type in {"dispatch_requested"}:
            stage = "preview"
        elif event_type in {"dispatch_completed"}:
            stage = "execute"
        elif event_type in {"dismissed", "draft_removed"}:
            stage = "suggest"
        elif event_type in {"dispatch_failed"}:
            stage = "preview"
        elif status == "pending_review":
            stage = "preview"
        elif status == "approved":
            stage = "one_click_approve"
        elif status == "completed":
            stage = "execute"
        elif status == "dismissed":
            stage = "suggest"

        target_channel = str((action or {}).get("target_channel") or "").strip().lower()
        low_risk_action = str((action or {}).get("action_type") or "").strip().lower() in {"create_task", "calendar_suggestion"} or target_channel in {"calendar", "task", "tasks", "navigation"}
        execution = evaluate_execution_gateway(
            action_kind=_assistant_action_kind((action or {}).get("action_type")),
            risk_level=policy.get("level"),
            policy_label=str(policy.get("label") or ""),
            requires_confirmation=bool(policy.get("requires_confirmation") or (action or {}).get("manual_review_required")),
            auto_allowed=bool(policy.get("auto_allowed")),
            scope="professional" if (action or {}).get("matter_id") else "personal",
            suggest_only=True,
            reversible=bool(low_risk_action or target_channel in {"calendar", "tasks"}),
            current_stage=stage,
            preview_summary=str((action or {}).get("description") or (action or {}).get("title") or "").strip() or "Aksiyon preview halinde gösterilir.",
            audit_label=f"{str((action or {}).get('action_type') or 'action').strip() or 'action'}:{stage}",
        )
        policy_decision = execution.policy_decision
        ladder = dict(execution.action_ladder)
        ladder["current_stage"] = "one_click_approve" if stage == "one_click_approve" else ladder.get("current_stage")
        return ladder

    def _run_query_with_kb(
        payload: QueryIn,
        *,
        role: str,
        subject: str,
        sid: str,
    ) -> dict[str, Any]:
        low_signal_greeting = _is_low_signal_greeting_query(payload.query) and not _runtime_semantic_available(runtime)
        if low_signal_greeting:
            kb_context = {
                "query": payload.query,
                "summary_lines": [],
                "claim_summary_lines": [],
                "supporting_pages": [],
                "supporting_records": [],
                "decision_records": [],
                "reflections": [],
                "recent_related_feedback": [],
                "scopes": [],
                "record_type_counts": {},
                "supporting_relations": [],
                "resolved_claims": [],
                "backend": None,
                "context_selection_reasons": [],
            }
            personal_model_context = {
                "query": payload.query,
                "intent": {"name": "general", "categories": []},
                "selected_categories": [],
                "facts": [],
                "claim_summary_lines": [],
                "summary_lines": [],
                "usage_note": "Düşük sinyalli selamlaşma mesajlarında kişisel model bağlamı kullanılmaz.",
            }
        else:
            kb_context = _resolve_kb_context(
                payload.query,
                include_personal=True,
                page_keys=["persona", "preferences", "projects", "legal", "decisions", "reflections"],
            )
            personal_model_context = _resolve_personal_model_context(
                payload.query,
                include_personal=True,
            )
        profile = store.get_user_profile(settings.office_id)
        result = _query_result(
            payload,
            role,
            subject,
            sid,
            router,
            rag,
            rag_meta,
            audit,
            events,
            runtime,
            profile,
            knowledge_context=kb_context,
            personal_model_context=personal_model_context,
        )
        rag_sources = list(result.get("sources") or [])
        supporting_records = list(kb_context.get("supporting_records") or [])
        meaningful_supporting_records = []
        for record in supporting_records:
            metadata = record.get("metadata") if isinstance(record.get("metadata"), dict) else {}
            nested_metadata = metadata.get("metadata") if isinstance(metadata.get("metadata"), dict) else {}
            source_type = str(metadata.get("source_type") or "").strip().lower()
            file_back_kind = str(nested_metadata.get("file_back_kind") or "").strip().lower()
            if source_type == "assistant_file_back" and file_back_kind in {"query_answer", "assistant_reply"}:
                continue
            meaningful_supporting_records.append(record)
        if rag_sources and meaningful_supporting_records:
            why_this = "Yanıt belge dayanakları ile ilgili wiki ve decision kayıtları birlikte kullanılarak üretildi."
        elif rag_sources:
            why_this = "Yanıt arama dayanakları ve profil bağlamı kullanılarak üretildi."
        elif meaningful_supporting_records:
            why_this = "Yanıt derlenmiş wiki kayıtları ve profil bağlamı kullanılarak üretildi."
        else:
            why_this = "Yanıt bu isteğin içeriği ve mevcut sohbet akışı üzerinden üretildi."
        confidence = max(
            float(((result.get("citation_quality") or {}).get("score")) or 0.0),
            min(0.9, 0.58 + len(supporting_records[:4]) * 0.06),
        )
        explainability = _build_kb_explainability(
            why_this=why_this,
            confidence=confidence,
            source_basis=_kb_source_basis(kb_context=kb_context, rag_sources=rag_sources),
            kb_context=kb_context,
        )
        assistant_context_pack = assistant_context_packer.build_combined_pack(
            query=payload.query,
            profile=profile,
            personal_model_context=personal_model_context,
            knowledge_context=kb_context,
            inbox=[],
            calendar=[],
            limit=12,
        )
        file_back = None
        if payload.allow_writeback:
            file_back = _maybe_file_back_answer(
                kind="query_answer",
                title=_safe_excerpt(payload.query, max_len=96) or "Query answer",
                content=str(result.get("answer") or ""),
                query=payload.query,
                source_refs=explainability["source_basis"],
                generated_from=str(result.get("generated_from") or ""),
            )
        return {
            **result,
            "knowledge_context": kb_context,
            "personal_model_context": personal_model_context,
            "assistant_context_pack": assistant_context_pack,
            "explainability": explainability,
            "file_back": file_back,
            "writeback_allowed": payload.allow_writeback,
        }

    def _execute_queued_query_job(job_payload: dict[str, Any]) -> dict[str, Any]:
        return _run_query_with_kb(
            QueryIn(
                query=str(job_payload.get("query") or ""),
                model_profile=job_payload.get("model_profile"),
                allow_writeback=bool(job_payload.get("allow_writeback")),
            ),
            role=str(job_payload.get("role") or "intern"),
            subject=str(job_payload.get("owner") or ""),
            sid=str(job_payload.get("sid") or "runtime-query-job"),
        )

    runtime_job_processor.set_query_executor(_execute_queued_query_job)

    def _enrich_thread_reply_with_kb(
        *,
        reply: dict[str, Any],
        query: str,
        matter_id: int | None,
        source_refs: list[dict[str, Any]] | None,
    ) -> dict[str, Any]:
        source_context = dict(reply.get("source_context") or {})
        kb_context = dict(source_context.get("knowledge_context") or {})
        if not kb_context:
            kb_context = _resolve_kb_context(
                query,
                matter_id=matter_id,
                include_personal=matter_id is None,
            )
        action = source_context.get("assistant_action") if isinstance(source_context.get("assistant_action"), dict) else None
        policy = knowledge_base.safety_policy.classify(_assistant_action_kind((action or {}).get("action_type")))
        supporting_records = list(kb_context.get("supporting_records") or [])
        meaningful_supporting_records = []
        for record in supporting_records:
            metadata = record.get("metadata") if isinstance(record.get("metadata"), dict) else {}
            nested_metadata = metadata.get("metadata") if isinstance(metadata.get("metadata"), dict) else {}
            source_type = str(metadata.get("source_type") or "").strip().lower()
            file_back_kind = str(nested_metadata.get("file_back_kind") or "").strip().lower()
            if source_type == "assistant_file_back" and file_back_kind in {"query_answer", "assistant_reply"}:
                continue
            meaningful_supporting_records.append(record)
        if action or reply.get("requires_approval"):
            why_this = "Yanıt konuşma bağlamı, ilgili wiki kayıtları ve aksiyon merdiveni durumu kullanılarak üretildi."
        elif meaningful_supporting_records:
            why_this = "Yanıt konuşma akışı ile ilgili wiki, decision ve reflection kayıtları sentezlenerek üretildi."
        else:
            why_this = "Yanıt bu sohbet akışı ve mevcut mesajın içeriği temel alınarak üretildi."
        confidence = min(0.88, 0.62 + len(list(kb_context.get("supporting_records") or [])[:4]) * 0.05)
        explainability = _build_kb_explainability(
            why_this=why_this,
            confidence=confidence,
            source_basis=_kb_source_basis(kb_context=kb_context, source_refs=source_refs, action=action, draft=reply.get("draft_preview")),
            kb_context=kb_context,
            risk_level=policy.get("level", "A"),
            requires_confirmation=bool(reply.get("requires_approval")),
        )
        source_context["knowledge_context"] = kb_context
        source_context["explainability"] = explainability
        source_context["explainability_drawer"] = explainability
        reply["source_context"] = source_context
        reply["knowledge_context"] = kb_context
        reply["explainability"] = explainability
        file_back = _maybe_file_back_answer(
            kind="assistant_reply",
            title=_safe_excerpt(str((action or {}).get("title") or query), max_len=96) or "Assistant reply",
            content=str(reply.get("content") or ""),
            query=query,
            matter_id=matter_id,
            source_refs=explainability["source_basis"],
            generated_from=str(reply.get("generated_from") or ""),
        )
        return {
            "knowledge_context": kb_context,
            "explainability": explainability,
            "file_back": file_back,
        }

    def _assistant_action_kind(action_type: str | None) -> str:
        mapping = {
            "prepare_client_update": "draft_message",
            "prepare_internal_summary": "draft_message",
            "send_email": "send_email",
            "reply_email": "send_email",
            "send_whatsapp_message": "send_message",
            "send_telegram_message": "send_message",
            "send_linkedin_message": "send_message",
            "post_x_update": "send_message",
            "post_linkedin_update": "send_message",
            "reserve_travel_ticket": "reserve_travel",
            "create_task": "create_task_draft",
        }
        return mapping.get(str(action_type or "").strip(), "read_summary")

    def _assistant_action_possible_risks(action_kind: str, *, action_type: str | None = None) -> list[str]:
        risk_map = {
            "draft_message": ["Taslak yanlış bağlam veya tonla hazırlanmış olabilir."],
            "send_email": ["Yanlış alıcıya gönderim riski var.", "Hukuki veya profesyonel ton manuel inceleme gerektirir."],
            "send_message": ["Yanlış kişi veya yanlış kanal seçilmiş olabilir.", "Mesaj içeriği bağlama göre fazla iddialı olabilir."],
            "reserve_travel": ["Yanlış rota veya zaman seçimi masraf yaratabilir.", "Rezervasyon öncesi kullanıcı teyidi gerekir."],
            "create_task_draft": ["Taslak görev önceliği gerçek bağlamı tam yansıtmayabilir."],
            "read_summary": ["Özet bağlamı eksik yakalamış olabilir."],
        }
        risks = list(risk_map.get(action_kind, risk_map["read_summary"]))
        if str(action_type or "").strip() in {"post_x_update", "post_linkedin_update"}:
            risks.append("Dış paylaşımlar itibari veya hukuki etki doğurabilir.")
        return risks

    def _assistant_action_source_refs(
        action: dict[str, Any],
        draft: dict[str, Any] | None = None,
        approval_event: dict[str, Any] | None = None,
    ) -> list[dict[str, Any] | str]:
        refs: list[dict[str, Any] | str] = list(action.get("source_refs") or [])
        refs.append(
            {
                "type": "assistant_action",
                "id": action.get("id"),
                "action_type": action.get("action_type"),
                "status": action.get("status"),
            }
        )
        if draft:
            refs.append(
                {
                    "type": "outbound_draft",
                    "id": draft.get("id"),
                    "channel": draft.get("channel"),
                    "approval_status": draft.get("approval_status"),
                    "delivery_status": draft.get("delivery_status"),
                }
            )
        if approval_event:
            refs.append(
                {
                    "type": "approval_event",
                    "id": approval_event.get("id"),
                    "event_type": approval_event.get("event_type"),
                }
            )
        deduped: list[dict[str, Any] | str] = []
        seen: set[str] = set()
        for item in refs:
            marker = json.dumps(item, ensure_ascii=False, sort_keys=True) if isinstance(item, dict) else str(item)
            if marker in seen:
                continue
            seen.add(marker)
            deduped.append(item)
        return deduped

    def _record_assistant_action_decision(
        *,
        event_type: str,
        action: dict[str, Any] | None,
        draft: dict[str, Any] | None = None,
        approval_event: dict[str, Any] | None = None,
        note: str | None = None,
        error: str | None = None,
    ) -> dict[str, Any] | None:
        if not knowledge_base.enabled or not action:
            return None
        try:
            action_kind = _assistant_action_kind(action.get("action_type"))
            policy = knowledge_base.safety_policy.classify(action_kind)
            execution = evaluate_execution_gateway(
                action_kind=action_kind,
                risk_level=policy.get("level"),
                policy_label=str(policy.get("label") or ""),
                requires_confirmation=bool(policy.get("requires_confirmation") or action.get("manual_review_required")),
                auto_allowed=bool(policy.get("auto_allowed")),
                scope="professional" if action.get("matter_id") else "personal",
                suggest_only=True,
                reversible=str(action.get("target_channel") or "").strip().lower() in {"calendar", "task", "tasks", "navigation"}
                or str(action.get("action_type") or "").strip().lower() in {"create_task", "calendar_suggestion"},
                current_stage="suggest",
                preview_summary=str(action.get("description") or action.get("title") or action.get("action_type") or "Assistant action").strip(),
                audit_label=f"assistant_action_record:{str(action.get('action_type') or 'action').strip() or 'action'}",
            )
            policy_decision = execution.policy_decision
            kb_context = _resolve_kb_context(
                " ".join(
                    part
                    for part in [
                        str(action.get("title") or "").strip(),
                        str(action.get("description") or "").strip(),
                        str(action.get("rationale") or "").strip(),
                    ]
                    if part
                )
                or str(action.get("action_type") or "assistant action"),
                matter_id=int(action["matter_id"]) if action.get("matter_id") else None,
                include_personal=not bool(action.get("matter_id")),
                page_keys=["persona", "preferences", "projects", "legal", "decisions", "recommendations", "reflections"],
            )
            title_base = str(
                action.get("title")
                or (draft.get("subject") if draft else None)
                or action.get("action_type")
                or "Assistant action"
            ).strip()
            event_titles = {
                "generated": "Assistant action suggested",
                "approved": "Assistant action approved",
                "dismissed": "Assistant action dismissed",
                "dispatch_requested": "Assistant draft dispatch requested",
                "dispatch_completed": "Assistant dispatch completed",
                "dispatch_failed": "Assistant dispatch failed",
                "draft_removed": "Assistant draft removed",
            }
            summary_text = {
                "generated": str(
                    action.get("description")
                    or (draft.get("body") if draft else None)
                    or action.get("rationale")
                    or ""
                ).strip(),
                "approved": note or "Kullanıcı taslağı gönderim veya paylaşım için onayladı.",
                "dismissed": note or "Kullanıcı aksiyonu kapatmayı tercih etti.",
                "dispatch_requested": note or "Taslak dış sisteme gönderim için hazırlandı.",
                "dispatch_completed": note or "Dış sistem gönderimi başarıyla tamamlandı.",
                "dispatch_failed": error or note or "Dış sistem gönderimi başarısız oldu.",
                "draft_removed": note or "Taslak çalışma alanından kaldırıldı.",
            }
            reasoning_summary = {
                "generated": f"{str(action.get('rationale') or 'Asistan komutu veya mevcut bağlam taslağa dönüştürüldü.').strip()} Manuel inceleme zorunlu bırakıldı.",
                "approved": "Bu kayıt explicit user confirmation sonrası tutuldu. Taslak insan onayıyla ilerletildi.",
                "dismissed": "Bu kayıt explicit user rejection sonrası tutuldu. Aksiyon otomatik yürütülmedi.",
                "dispatch_requested": "Taslak approval sonrası dış gönderim kuyruğuna hazırlandı; son sistem adımı ayrıca izlenir.",
                "dispatch_completed": "Dış kanal teslimi tamamlandı ve provenance kaydına işlendi.",
                "dispatch_failed": "Dış kanal gönderimi hata verdi; tekrar veya düzeltme ihtiyacı doğabilir.",
                "draft_removed": "Taslak kullanıcı kararıyla çalışma panelinden çıkarıldı.",
            }
            confidence = 0.78 if event_type == "generated" else 1.0
            user_confirmation_required = bool(policy_decision.requires_confirmation) if event_type == "generated" else False
            possible_risks = _assistant_action_possible_risks(action_kind, action_type=action.get("action_type"))
            if error:
                possible_risks.append(_safe_excerpt(error, max_len=180))
            decision_record = knowledge_base.create_decision_record(
                title=f"{event_titles.get(event_type, 'Assistant action update')}: {title_base}",
                summary=summary_text.get(event_type) or title_base,
                intent=str(action.get("action_type") or event_type),
                source_refs=_assistant_action_source_refs(action, draft=draft, approval_event=approval_event),
                reasoning_summary=reasoning_summary.get(event_type) or "Assistant action lifecycle kaydı oluşturuldu.",
                confidence=confidence,
                user_confirmation_required=user_confirmation_required,
                possible_risks=possible_risks,
                action_kind=action_kind,
                alternatives=[
                    "Taslağı farklı tonla yeniden üret.",
                    "Kaynak bağlamı genişlet.",
                    "Aksiyonu yürütmeden önce kullanıcıdan ek netlik iste.",
                ]
                if event_type == "generated"
                else [],
            )
            explainability = _build_kb_explainability(
                why_this=reasoning_summary.get(event_type) or "Assistant action lifecycle kaydı oluşturuldu.",
                confidence=confidence,
                source_basis=_kb_source_basis(
                    kb_context=kb_context,
                    source_refs=_assistant_action_source_refs(action, draft=draft, approval_event=approval_event),
                    action=action,
                    draft=draft,
                ),
                kb_context=kb_context,
                risk_level=policy_decision.risk_level,
                requires_confirmation=user_confirmation_required,
            )
            action_ladder = _assistant_action_ladder(action=action, policy=policy, event_type=event_type)
            _sync_personal_kb_safely(f"assistant_action_{event_type}")
            return {
                "decision_record": decision_record,
                "policy": policy,
                "policy_decision": policy_decision.as_dict(),
                "explainability": explainability,
                "knowledge_context": kb_context,
                "action_ladder": action_ladder,
            }
        except Exception as exc:  # noqa: BLE001
            events.log(
                "personal_kb_action_record_failed",
                level="warning",
                event_type=event_type,
                action_id=action.get("id") if action else None,
                error=str(exc),
            )
            return None

    def _assistant_home_payload_with_kb() -> dict[str, Any]:
        home = _assistant_home_payload(settings, store)
        if not knowledge_base.enabled:
            return home
        try:
            _sync_personal_kb_safely("assistant_home", min_interval_seconds=12.0)
            recommendation_payload = knowledge_base.recommend(
                store=store,
                settings=settings,
                limit=3,
                persist=True,
            )
            trigger_payload = knowledge_base.evaluate_triggers(
                store=store,
                settings=settings,
                persist=True,
                limit=4,
                include_suppressed=False,
            )
            kb_state = knowledge_base._load_state()
            existing_ids = {str(item.get("id") or "") for item in home.get("proactive_suggestions") or []}
            for card in _knowledge_recommendations_as_home_cards(recommendation_payload):
                if card["id"] in existing_ids:
                    continue
                home.setdefault("proactive_suggestions", []).append(card)
                existing_ids.add(card["id"])
            for card in _knowledge_triggers_as_home_cards(trigger_payload):
                if card["id"] in existing_ids:
                    continue
                home.setdefault("proactive_suggestions", []).append(card)
                existing_ids.add(card["id"])
            for card in _web_watch_events_as_home_cards(integration_service.list_events(limit=20)):
                if card["id"] in existing_ids:
                    continue
                home.setdefault("proactive_suggestions", []).append(card)
                existing_ids.add(card["id"])
            home["explainable_recommendations"] = recommendation_payload.get("items") or []
            home["proactive_triggers"] = trigger_payload.get("items") or []
            home["knowledge_base"] = knowledge_base.status(ensure=False, previews=False)
            report_path = knowledge_base.base_dir / "system" / "reports" / "knowledge-health-latest.json"
            if report_path.exists():
                try:
                    report = json.loads(report_path.read_text(encoding="utf-8"))
                except (json.JSONDecodeError, UnicodeDecodeError):
                    report = {}
                home["knowledge_health_summary"] = report.get("summary") or {}
            else:
                home["knowledge_health_summary"] = {}
            memory_overview = knowledge_base.memory_overview()
            home["decision_timeline"] = list(reversed(list(kb_state.get("decision_records") or [])))[:5]
            home["connector_sync_status"] = knowledge_base.connector_sync_status(store=store)
            home["location_context"] = knowledge_base.get_location_context(store=store)
            home["orchestration_status"] = knowledge_base.orchestration_status()
            home["reflection_status"] = knowledge_base.reflection_status()
            home["autonomy_status"] = knowledge_base.autonomy_status(store=store, settings=settings)
            home["memory_overview"] = memory_overview
            assistant_core = knowledge_base.assistant_core_status(store=store)
            coaching_dashboard = knowledge_base.coaching_status(store=store)
            home["assistant_core"] = assistant_core
            home["assistant_system_status"] = _assistant_system_status(sync=False)
            if assistant_core.get("supports_coaching") or int((coaching_dashboard.get("summary") or {}).get("active_goals") or 0) > 0:
                home["coaching_dashboard"] = coaching_dashboard
            home["wiki_brain"] = knowledge_base.wiki_brain_status(ensure=False, previews=False)
            home["proactive_control_state"] = {
                "suppressed_topics": memory_overview.get("suppressed_topics") or [],
                "boosted_topics": memory_overview.get("boosted_topics") or [],
            }
            home["recommendation_history_summary"] = list(reversed(list(kb_state.get("recommendation_history") or [])))[:8]
            home["assistant_known_profile"] = {
                page_key: [
                    {
                        "id": item.get("id"),
                        "title": item.get("title"),
                        "summary": item.get("summary"),
                        "updated_at": item.get("updated_at"),
                        "scope": ((item.get("metadata") or {}).get("scope") or "global"),
                        "record_type": ((item.get("metadata") or {}).get("record_type") or page_key),
                        "sensitivity": ((item.get("metadata") or {}).get("sensitivity") or "medium"),
                        "shareability": ((item.get("metadata") or {}).get("shareability") or "shareable"),
                        "confidence": item.get("confidence"),
                        "source_basis": list(item.get("source_refs") or [])[:4],
                    }
                    for item in list(((kb_state.get("pages") or {}).get(page_key) or {}).get("records") or [])
                    if str(item.get("status") or "active") == "active"
                ][:4]
                for page_key in ("persona", "preferences", "routines", "projects", "contacts")
            }
        except Exception as exc:  # noqa: BLE001
            events.log("personal_kb_home_failed", level="warning", error=str(exc))
            home["knowledge_base"] = knowledge_base.status(ensure=False, previews=False)
        return home

    def _run_personal_kb_scheduler_loop() -> None:
        while not kb_scheduler_stop.wait(max(5, int(settings.personal_kb_scheduler_poll_seconds or 60))):
            try:
                knowledge_base.run_orchestration(
                    store=store,
                    settings=settings,
                    reason="scheduler_loop",
                    force=False,
                )
            except Exception as exc:  # noqa: BLE001
                events.log("personal_kb_scheduler_failed", level="warning", error=str(exc))

    def _run_runtime_job_processor_loop() -> None:
        while not kb_scheduler_stop.wait(5):
            try:
                runtime_job_processor.process_pending_jobs(
                    lease_owner="backend-runtime-loop",
                    limit=4,
                )
            except Exception as exc:  # noqa: BLE001
                events.log("runtime_job_processor_failed", level="warning", error=str(exc))

    def _request_runtime_job_processing_async(*, reason: str, delay_seconds: float = 0.05, limit: int = 4) -> bool:
        thread = runtime_jobs_nudge_thread_holder[0]
        if thread and thread.is_alive():
            return False

        def _runner() -> None:
            if delay_seconds > 0:
                time.sleep(delay_seconds)
            try:
                runtime_job_processor.process_pending_jobs(
                    lease_owner=f"backend-runtime-nudge:{reason}",
                    limit=limit,
                )
            except Exception as exc:  # noqa: BLE001
                events.log("runtime_job_nudge_failed", level="warning", reason=reason, error=str(exc))

        thread = threading.Thread(
            target=_runner,
            name=f"lawcopilot-runtime-job-nudge-{reason}",
            daemon=True,
        )
        thread.start()
        runtime_jobs_nudge_thread_holder[0] = thread
        return True

    def _openclaw_workspace_status(*, sync: bool = False, include_previews: bool = False, force_sync: bool = False) -> dict:
        nonlocal openclaw_last_sync_at
        if not openclaw_workspace.enabled:
            return openclaw_workspace.status(include_previews=include_previews)
        try:
            if sync:
                now = time.monotonic()
                if force_sync or now - openclaw_last_sync_at >= openclaw_sync_interval_seconds:
                    openclaw_workspace.sync()
                    openclaw_last_sync_at = now
            return openclaw_workspace.status(include_previews=include_previews)
        except Exception as exc:  # noqa: BLE001
            events.log("openclaw_workspace_sync_failed", level="warning", error=str(exc))
            status = openclaw_workspace.status(include_previews=include_previews)
            status["workspace_ready"] = False
            return status

    def _request_openclaw_workspace_sync_async(*, force_sync: bool = False) -> bool:
        if not settings.openclaw_async_sync_enabled or not openclaw_workspace.enabled:
            return False
        thread = openclaw_async_sync_thread_holder[0]
        if thread and thread.is_alive():
            return False

        def _runner() -> None:
            _openclaw_workspace_status(sync=True, force_sync=force_sync)

        thread = threading.Thread(
            target=_runner,
            name="lawcopilot-openclaw-sync",
            daemon=True,
        )
        thread.start()
        openclaw_async_sync_thread_holder[0] = thread
        return True

    if openclaw_workspace.enabled:
        _openclaw_workspace_status(sync=True)

