    @app.post("/memory/edit")
    def edit_memory_explorer_record(
        payload: KnowledgeMemoryCorrectionRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        if payload.action not in {"correct", "reduce_confidence", "suppress_recommendation", "boost_proactivity"}:
            raise HTTPException(status_code=400, detail="unsupported_memory_edit_action")
        try:
            result = knowledge_base.apply_memory_correction(
                action=payload.action,
                page_key=payload.page_key,
                target_record_id=payload.target_record_id,
                key=payload.key,
                corrected_summary=payload.corrected_summary,
                scope=payload.scope,
                note=payload.note,
                recommendation_kind=payload.recommendation_kind,
                topic=payload.topic,
                source_refs=list(payload.source_refs or []),
            )
        except ValueError as exc:
            raise HTTPException(status_code=400, detail=str(exc)) from exc
        audit.log(
            "memory_explorer_edit",
            subject=subject,
            role=role,
            session_id=sid,
            action=payload.action,
            page_key=result.get("page_key") or payload.page_key,
            record_id=result.get("record_id"),
        )
        _pilot_event(
            "pilot_memory_correction",
            action=payload.action,
            page_key=result.get("page_key") or payload.page_key,
            scope=payload.scope or result.get("scope"),
            source="memory_explorer",
        )
        page_payload = None
        try:
            page_payload = knowledge_base.memory_explorer_page(f"page:{result.get('page_key') or payload.page_key or 'preferences'}")
        except ValueError:
            page_payload = None
        return {
            **result,
            "page": page_payload,
            "memory_overview": knowledge_base.memory_overview(),
            "health": knowledge_base.memory_explorer_health(),
        }

