    @app.post("/assistant/memory/corrections")
    def apply_assistant_memory_correction(
        payload: KnowledgeMemoryCorrectionRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        try:
            result = knowledge_base.apply_memory_correction(
                action=payload.action,
                page_key=payload.page_key,
                target_record_id=payload.target_record_id,
                key=payload.key,
                corrected_summary=payload.corrected_summary,
                scope=payload.scope,
                note=payload.note,
                recommendation_kind=payload.recommendation_kind,
                topic=payload.topic,
                source_refs=list(payload.source_refs or []),
            )
        except ValueError as exc:
            raise HTTPException(status_code=400, detail=str(exc)) from exc
        correction_query = payload.corrected_summary or payload.note or payload.topic or payload.recommendation_kind or payload.key or payload.page_key or "memory correction"
        if result.get("record_id"):
            kb_state = knowledge_base._load_state()
            for item in (((kb_state.get("pages") or {}).get(result.get("page_key") or "") or {}).get("records") or []):
                if str(item.get("id") or "") != str(result.get("record_id") or ""):
                    continue
                correction_query = str(item.get("summary") or item.get("title") or correction_query)
                break
        file_back = knowledge_base.maybe_file_back_response(
            kind="preference_correction",
            title=f"Memory correction: {payload.action}",
            content=payload.corrected_summary or payload.note or f"{payload.action} uygulandı",
            source_refs=list(payload.source_refs or []),
            metadata={
                "page_key": payload.page_key or result.get("page_key") or "preferences",
                "record_type": "preference" if payload.action in {"suppress_recommendation", "boost_proactivity", "correct"} else "source",
                "scope": payload.scope or result.get("scope") or "personal",
            },
            scope=payload.scope or result.get("scope") or "personal",
            sensitivity="high",
        )
        audit.log(
            "personal_kb_memory_corrected",
            subject=subject,
            role=role,
            session_id=sid,
            action=payload.action,
            page_key=payload.page_key,
            target_record_id=payload.target_record_id,
        )
        _pilot_event(
            "pilot_memory_correction",
            action=payload.action,
            page_key=payload.page_key or result.get("page_key"),
            scope=payload.scope or result.get("scope"),
            source="assistant_memory_endpoint",
        )
        return {
            **result,
            "file_back": file_back,
            "knowledge_context": knowledge_base.resolve_relevant_context(
                correction_query,
                scopes=[payload.scope] if payload.scope else ["personal", "professional", "global"],
                page_keys=[payload.page_key] if payload.page_key else None,
            ),
            "memory_overview": knowledge_base.memory_overview(),
            "connector_sync_status": knowledge_base.connector_sync_status(store=store),
        }

