    @app.put("/profile")
    def save_user_profile(
        payload: UserProfileRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        profile = store.upsert_user_profile(
            settings.office_id,
            display_name=payload.display_name,
            favorite_color=payload.favorite_color,
            food_preferences=payload.food_preferences,
            transport_preference=payload.transport_preference,
            weather_preference=payload.weather_preference,
            travel_preferences=payload.travel_preferences,
            home_base=payload.home_base,
            current_location=payload.current_location,
            location_preferences=payload.location_preferences,
            maps_preference=payload.maps_preference,
            prayer_notifications_enabled=payload.prayer_notifications_enabled,
            prayer_habit_notes=payload.prayer_habit_notes,
            communication_style=payload.communication_style,
            assistant_notes=re.sub(r"\s+", " ", str(payload.assistant_notes or "").strip())[:2400],
            important_dates=[item.model_dump() for item in payload.important_dates],
            related_profiles=[item.model_dump() for item in payload.related_profiles],
            contact_profile_overrides=[item.model_dump() for item in payload.contact_profile_overrides],
            inbox_watch_rules=[item.model_dump() for item in payload.inbox_watch_rules],
            inbox_keyword_rules=[item.model_dump() for item in payload.inbox_keyword_rules],
            inbox_block_rules=[item.model_dump() for item in payload.inbox_block_rules],
            source_preference_rules=[item.model_dump() for item in payload.source_preference_rules],
        )
        profile_reconciliation = memory_mutations.reconcile_user_profile(
            profile=profile,
            authority="profile",
            reason="user_profile_update",
        )
        _sync_personal_kb_safely("user_profile_update")
        _openclaw_workspace_status(sync=True, force_sync=True)
        audit.log(
            "user_profile_updated",
            subject=subject,
            role=role,
            session_id=sid,
            important_date_count=len(payload.important_dates),
            related_profile_count=len(payload.related_profiles),
            contact_profile_override_count=len(payload.contact_profile_overrides),
            inbox_watch_rule_count=len(payload.inbox_watch_rules),
            inbox_keyword_rule_count=len(payload.inbox_keyword_rules),
            inbox_block_rule_count=len(payload.inbox_block_rules),
        )
        return {
            "profile": profile,
            "profile_reconciliation": profile_reconciliation,
            "message": "Kişisel profil kaydedildi.",
        }

