    def _sync_personal_profile_learning_after_connector_push(provider: str) -> dict[str, Any] | None:
        try:
            result = personal_model.sync_external_profile_learning(force=True)
        except Exception as exc:  # noqa: BLE001
            events.log("personal_model_external_profile_learning_failed", level="warning", provider=provider, error=str(exc))
            return None
        events.log(
            "personal_model_external_profile_learning_completed",
            provider=provider,
            fact_count=int(result.get("fact_count") or 0),
            source_count=int(result.get("source_count") or 0),
        )
        return result

    @app.post("/integrations/google/sync")
    def sync_google_data(
        payload: GoogleSyncRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        sync_connected_accounts_from_settings(settings, store)
        synced_at = payload.synced_at.isoformat() if payload.synced_at else datetime.now(timezone.utc).isoformat()
        store.upsert_connected_account(
            settings.office_id,
            "google",
            account_label=payload.account_label or settings.google_account_label or "Google hesabı",
            status="connected" if settings.google_configured else "pending",
            scopes=payload.scopes or list(settings.google_scopes),
            connected_at=synced_at if settings.google_configured else None,
            last_sync_at=synced_at,
            manual_review_required=True,
            metadata={
                "gmail_connected": settings.gmail_connected,
                "calendar_connected": settings.calendar_connected,
                "drive_connected": settings.drive_connected,
                "youtube_connected": bool(payload.youtube_playlists),
                "email_thread_count": len(payload.email_threads),
                "calendar_event_count": len(payload.calendar_events),
                "drive_file_count": len(payload.drive_files),
                "youtube_playlist_count": len(payload.youtube_playlists),
            },
        )
        for thread in payload.email_threads:
            thread_metadata = dict(thread.metadata or {})
            if thread.sender:
                thread_metadata["sender"] = thread.sender
            store.upsert_email_thread(
                settings.office_id,
                provider=thread.provider,
                thread_ref=thread.thread_ref,
                subject=thread.subject,
                snippet=thread.snippet,
                participants=[thread.sender] if thread.sender else None,
                received_at=thread.received_at.isoformat() if thread.received_at else None,
                unread_count=int(thread.unread_count),
                reply_needed=bool(thread.reply_needed),
                matter_id=thread.matter_id,
                metadata=thread_metadata,
            )
        for event in payload.calendar_events:
            store.upsert_calendar_event(
                settings.office_id,
                provider=event.provider,
                external_id=event.external_id,
                title=event.title,
                starts_at=event.starts_at.isoformat(),
                ends_at=event.ends_at.isoformat() if event.ends_at else None,
                location=event.location,
                matter_id=event.matter_id,
                metadata=event.metadata or {},
            )
        for drive_file in payload.drive_files:
            store.upsert_drive_file(
                settings.office_id,
                provider=drive_file.provider,
                external_id=drive_file.external_id,
                name=drive_file.name,
                mime_type=drive_file.mime_type,
                web_view_link=drive_file.web_view_link,
                modified_at=drive_file.modified_at.isoformat() if drive_file.modified_at else None,
            )
        store.delete_external_events(settings.office_id, provider="youtube", event_type="playlist")
        for playlist in payload.youtube_playlists:
            item_titles = [
                _compact_inline_text(str(item.get("title") or ""))
                for item in list(playlist.items or [])[:8]
                if _compact_inline_text(str(item.get("title") or ""))
            ]
            summary_parts = []
            if str(playlist.description or "").strip():
                summary_parts.append(str(playlist.description).strip())
            if item_titles:
                summary_parts.append(f"Örnek videolar: {', '.join(item_titles[:5])}")
            if not summary_parts:
                summary_parts.append(f"{int(playlist.item_count or 0)} videoluk YouTube oynatma listesi.")
            store.add_external_event(
                settings.office_id,
                provider="youtube",
                event_type="playlist",
                external_ref=playlist.external_id,
                title=playlist.title,
                actor_label=playlist.channel_title,
                summary=" ".join(part for part in summary_parts if part).strip(),
                importance="normal",
                metadata={
                    "url": playlist.web_view_link,
                    "source_url": playlist.web_view_link,
                    "playlist_id": playlist.external_id,
                    "playlist_title": playlist.title,
                    "item_count": int(playlist.item_count or 0),
                    "privacy_status": playlist.privacy_status,
                    "channel_title": playlist.channel_title,
                    "items": list(playlist.items or [])[:8],
                    "item_titles": item_titles,
                    "category": "youtube_playlist",
                    "scope": "personal",
                },
                source_created_at=playlist.published_at.isoformat() if playlist.published_at else None,
            )
        audit.log(
            "google_sync_completed",
            subject=subject,
            role=role,
            session_id=sid,
            email_thread_count=len(payload.email_threads),
            calendar_event_count=len(payload.calendar_events),
            youtube_playlist_count=len(payload.youtube_playlists),
        )
        _openclaw_workspace_status(sync=True)
        kb_sync = _kb_connector_sync_after_provider_push(
            provider="google",
            synced_at=synced_at,
            stats={
                "email_threads": len(payload.email_threads),
                "calendar_events": len(payload.calendar_events),
                "drive_files": len(payload.drive_files),
                "youtube_playlists": len(payload.youtube_playlists),
            },
            checkpoint=payload.checkpoint,
            cursor=payload.cursor,
            reason="google_mirror_sync",
        )
        personal_profile_sync = _sync_personal_profile_learning_after_connector_push("google")
        return {
            "ok": True,
            "message": "Google verileri yerel ajandaya işlendi.",
            "status": _google_status_payload(settings, store),
            "synced": {
                "email_threads": len(payload.email_threads),
                "calendar_events": len(payload.calendar_events),
                "drive_files": len(payload.drive_files),
                "youtube_playlists": len(payload.youtube_playlists),
                "synced_at": synced_at,
            },
            "knowledge_base_sync": kb_sync,
            "personal_profile_sync": personal_profile_sync,
        }

    @app.post("/integrations/google/portability/sync")
    def sync_google_portability_data(
        payload: GooglePortabilitySyncRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        sync_connected_accounts_from_settings(settings, store)
        synced_at = payload.synced_at.isoformat() if payload.synced_at else datetime.now(timezone.utc).isoformat()
        store.upsert_connected_account(
            settings.office_id,
            "google-portability",
            account_label=payload.account_label or "Google geçmiş aktarımı",
            status="connected",
            scopes=payload.scopes or [],
            connected_at=synced_at,
            last_sync_at=synced_at,
            manual_review_required=False,
            metadata={
                "youtube_history_available": bool(payload.youtube_history_entries),
                "chrome_history_available": bool(payload.chrome_history_entries),
                "youtube_history_count": len(payload.youtube_history_entries),
                "chrome_history_count": len(payload.chrome_history_entries),
            },
        )
        store.delete_external_events(settings.office_id, provider="youtube", event_type="history")
        store.delete_external_events(settings.office_id, provider="chrome", event_type="history")
        for entry in payload.youtube_history_entries:
            store.add_external_event(
                settings.office_id,
                provider="youtube",
                event_type="history",
                external_ref=entry.external_id,
                title=entry.title,
                actor_label=entry.channel_title,
                summary=(entry.title or "YouTube geçmişi kaydı").strip(),
                importance="normal",
                metadata={
                    "url": entry.url,
                    "source_url": entry.url,
                    "channel_title": entry.channel_title,
                    **dict(entry.metadata or {}),
                },
                source_created_at=entry.viewed_at.isoformat() if entry.viewed_at else None,
            )
        for entry in payload.chrome_history_entries:
            summary = entry.title or entry.url
            store.add_external_event(
                settings.office_id,
                provider="chrome",
                event_type="history",
                external_ref=entry.external_id,
                title=entry.title,
                summary=summary.strip(),
                importance="low",
                metadata={
                    "url": entry.url,
                    "source_url": entry.url,
                    **dict(entry.metadata or {}),
                },
                source_created_at=entry.visited_at.isoformat() if entry.visited_at else None,
            )
        audit.log(
            "google_portability_sync_completed",
            subject=subject,
            role=role,
            session_id=sid,
            youtube_history_count=len(payload.youtube_history_entries),
            chrome_history_count=len(payload.chrome_history_entries),
        )
        kb_sync = _kb_connector_sync_after_provider_push(
            provider="google_portability",
            synced_at=synced_at,
            stats={
                "youtube_history_entries": len(payload.youtube_history_entries),
                "chrome_history_entries": len(payload.chrome_history_entries),
            },
            checkpoint=payload.checkpoint,
            cursor=payload.cursor,
            reason="google_portability_sync",
        )
        return {
            "ok": True,
            "message": "Google geçmiş verileri yerel ajandaya işlendi.",
            "status": _google_status_payload(settings, store),
            "synced": {
                "youtube_history_entries": len(payload.youtube_history_entries),
                "chrome_history_entries": len(payload.chrome_history_entries),
                "synced_at": synced_at,
            },
            "knowledge_base_sync": kb_sync,
        }

