        for contact in payload.contacts:
            store.upsert_whatsapp_contact_snapshot(
                settings.office_id,
                provider=contact.provider,
                conversation_ref=contact.conversation_ref,
                display_name=contact.display_name,
                profile_name=contact.profile_name,
                phone_number=contact.phone_number,
                is_group=bool(contact.is_group),
                group_name=contact.group_name,
                last_seen_at=contact.last_seen_at.isoformat() if contact.last_seen_at else None,
                metadata=contact.metadata or {},
            )
        audit.log(
            "whatsapp_sync_completed",
            subject=subject,
            role=role,
            session_id=sid,
            message_count=len(payload.messages),
            contact_count=len(payload.contacts),
        )
        kb_sync = _kb_connector_sync_after_provider_push(
            provider="whatsapp",
            synced_at=synced_at,
            stats={"messages": len(payload.messages)},
            checkpoint=payload.checkpoint,
            cursor=payload.cursor,
            reason="whatsapp_mirror_sync",
        )
        personal_profile_sync = _sync_personal_profile_learning_after_connector_push("whatsapp")
        return {
            "ok": True,
            "message": "WhatsApp verileri yerel kayıtlarla eşitlendi.",
            "status": _whatsapp_status_payload(settings, store),
            "synced": {
                "messages": len(payload.messages),
                "contacts": len(payload.contacts),
                "synced_at": synced_at,
                "note": payload.note or "",
            },
            "knowledge_base_sync": kb_sync,
            "personal_profile_sync": personal_profile_sync,
        }

