    @app.post("/integrations/linkedin/sync")
    def sync_linkedin_data(
        payload: LinkedInSyncRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        synced_at = payload.synced_at.isoformat() if payload.synced_at else datetime.now(timezone.utc).isoformat()
        store.upsert_connected_account(
            settings.office_id,
            "linkedin",
            account_label=payload.account_label or "LinkedIn hesabı",
            status="connected",
            scopes=payload.scopes or list(settings.linkedin_scopes),
            connected_at=synced_at,
            last_sync_at=synced_at,
            manual_review_required=True,
            metadata={
                "user_id": payload.user_id or "",
                "person_urn": payload.person_urn or "",
                "post_count": len(payload.posts),
                "comment_count": len(payload.comments),
                "message_count": len(payload.messages),
                "mode": "web" if any(str(scope or "").strip().lower() == "personal_account:web_session" for scope in (payload.scopes or [])) else settings.linkedin_mode,
            },
        )
        for post in payload.posts:
            signal = classify_social_content(post.provider, post.author_handle or "", post.content, post.metadata or {})
            post_metadata = dict(post.metadata or {})
            post_metadata["social_signal"] = signal
            store.upsert_linkedin_post(
                settings.office_id,
                provider=post.provider,
                external_id=post.external_id,
                author_handle=post.author_handle,
                content=post.content,
                posted_at=post.posted_at.isoformat() if post.posted_at else None,
                reply_needed=bool(post.reply_needed or signal.get("reply_needed")),
                metadata=post_metadata,
            )
        for comment in payload.comments:
            signal = classify_social_content(comment.provider, comment.author_handle or "", comment.content, comment.metadata or {})
            comment_metadata = dict(comment.metadata or {})
            comment_metadata["social_signal"] = signal
            store.upsert_linkedin_comment(
                settings.office_id,
                provider=comment.provider,
                external_id=comment.external_id,
                object_urn=comment.object_urn,
                parent_external_id=comment.parent_external_id,
                author_handle=comment.author_handle,
                content=comment.content,
                posted_at=comment.posted_at.isoformat() if comment.posted_at else None,
                reply_needed=bool(comment.reply_needed or signal.get("reply_needed") or signal.get("notify_user")),
                metadata=comment_metadata,
            )
        for message in payload.messages:
            store.upsert_linkedin_message(
                settings.office_id,
                provider=message.provider,
                conversation_ref=message.conversation_ref,
                message_ref=message.message_ref,
                sender=message.sender,
                recipient=message.recipient,
                body=message.body,
                direction=message.direction,
                sent_at=message.sent_at.isoformat() if message.sent_at else None,
                reply_needed=bool(message.reply_needed),
                metadata=message.metadata or {},
            )
        audit.log(
            "linkedin_sync_completed",
            subject=subject,
            role=role,
            session_id=sid,
            post_count=len(payload.posts),
            comment_count=len(payload.comments),
            message_count=len(payload.messages),
            account_label=payload.account_label or "LinkedIn hesabı",
        )
        kb_sync = _kb_connector_sync_after_provider_push(
            provider="linkedin",
            synced_at=synced_at,
            stats={"posts": len(payload.posts), "comments": len(payload.comments), "messages": len(payload.messages)},
            checkpoint=payload.checkpoint,
            cursor=payload.cursor,
            reason="linkedin_mirror_sync",
        )
        personal_profile_sync = _sync_personal_profile_learning_after_connector_push("linkedin")
        return {
            "ok": True,
            "message": "LinkedIn verileri yerel kayıtlarla eşitlendi.",
            "status": _linkedin_status_payload(settings, store),
            "synced": {
                "posts": len(payload.posts),
                "comments": len(payload.comments),
                "messages": len(payload.messages),
                "synced_at": synced_at,
            },
            "knowledge_base_sync": kb_sync,
            "personal_profile_sync": personal_profile_sync,
        }

    @app.post("/assistant/calendar/events")
    def create_assistant_calendar_event(
        payload: AssistantCalendarEventCreateRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        if payload.ends_at and payload.ends_at < payload.starts_at:
            raise HTTPException(status_code=400, detail="Bitiş saati başlangıçtan önce olamaz.")
        provider = str(payload.provider or "lawcopilot-planner").strip() or "lawcopilot-planner"
        external_id = str(payload.external_id or f"{provider}-{int(time.time() * 1000)}").strip()
        metadata = dict(payload.metadata or {})
        if payload.notes:
            metadata["notes"] = payload.notes.strip()
        event = store.upsert_calendar_event(
            settings.office_id,
            provider=provider,
            external_id=external_id,
            title=payload.title.strip(),
            starts_at=payload.starts_at.isoformat(),
            ends_at=payload.ends_at.isoformat() if payload.ends_at else None,
            attendees=[str(item).strip() for item in payload.attendees if str(item).strip()],
            location=payload.location.strip() if payload.location else None,
            matter_id=payload.matter_id,
            status=payload.status,
            needs_preparation=bool(payload.needs_preparation),
            metadata=metadata,
        )
        audit.log(
            "assistant_calendar_event_created",
            subject=subject,
            role=role,
            session_id=sid,
            provider=provider,
            external_id=external_id,
            matter_id=payload.matter_id,
        )
        _openclaw_workspace_status(sync=True)
        return {
            "event": event,
            "message": "Takvim planı kaydedildi.",
        }

