    @app.get("/integrations/assistant-capabilities")
    def get_assistant_capabilities(
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        _, role, _ = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        sync_connected_accounts_from_settings(settings, store)
        telegram_status = _telegram_status_payload(settings, store)
        whatsapp_status = _whatsapp_status_payload(settings, store)
        x_status = _x_status_payload(settings, store)
        instagram_status = _instagram_status_payload(settings, store)
        linkedin_status = _linkedin_status_payload(settings, store)
        telegram_mode = str(telegram_status.get("mode") or "bot").strip().lower() or "bot"
        linkedin_mode = str(linkedin_status.get("mode") or "official").strip().lower() or "official"
        x_scopes = {str(item).strip() for item in x_status.get("scopes") or [] if str(item).strip()}
        x_dm_read = "dm.read" in x_scopes
        x_dm_write = "dm.write" in x_scopes
        instagram_scopes = {str(item).strip() for item in instagram_status.get("scopes") or [] if str(item).strip()}
        linkedin_scopes = {str(item).strip() for item in linkedin_status.get("scopes") or [] if str(item).strip()}
        linkedin_social_read = "r_member_social" in linkedin_scopes or bool(linkedin_status.get("post_count") or linkedin_status.get("comment_count"))
        linkedin_web_messaging = linkedin_mode == "web" and bool(linkedin_status.get("configured"))
        return {
            "agenda": True,
            "suggested_actions": True,
            "draft_first": True,
            "approval_required": True,
            "integration_skills": integration_service.assistant_skill_inventory(),
            "google_status": _google_status_payload(settings, store),
            "telegram_status": telegram_status,
            "whatsapp_status": whatsapp_status,
            "x_status": x_status,
            "instagram_status": instagram_status,
            "linkedin_status": linkedin_status,
            "channel_capabilities": {
                "telegram": {
                    "can_read_messages": bool(telegram_status.get("configured")),
                    "can_send_messages": bool(telegram_status.get("configured")),
                    "requires_bot": telegram_mode != "web",
                    "requires_allowed_user_id": telegram_mode != "web",
                    "supports_personal_web_session": True,
                },
                "whatsapp": {
                    "can_read_messages": bool(whatsapp_status.get("message_count")),
                    "can_send_messages": bool(whatsapp_status.get("configured")),
                    "can_read_full_history": False,
                    "requires_webhook_for_live_incoming": True,
                },
                "x": {
                    "can_read_mentions": bool(x_status.get("configured")),
                    "can_read_own_posts": bool(x_status.get("configured")),
                    "can_post_updates": bool(x_status.get("configured")),
                    "can_read_dm": bool(x_status.get("configured") and x_dm_read),
                    "can_send_dm": bool(x_status.get("configured") and x_dm_write),
                },
                "instagram": {
                    "can_read_messages": bool(instagram_status.get("configured")),
                    "can_send_messages": bool(instagram_status.get("configured") and "instagram_manage_messages" in instagram_scopes),
                    "can_read_full_history": False,
                    "requires_professional_account": True,
                },
                "linkedin": {
                    "can_post_updates": bool(linkedin_status.get("configured") and "w_member_social" in linkedin_scopes),
                    "can_read_posts": bool(linkedin_status.get("configured") and linkedin_social_read),
                    "can_read_comments": bool(linkedin_status.get("configured") and linkedin_social_read),
                    "can_read_messages": bool(linkedin_web_messaging and linkedin_status.get("message_count")),
                    "can_send_messages": linkedin_web_messaging,
                    "can_send_comments": False,
                    "supports_personal_web_session": True,
                },
            },
            "access_plan": {
                "telegram": {
                    "official_mode": "bot_api",
                    "selected_mode": telegram_mode,
                    "assistant_can_read": bool(telegram_status.get("configured")),
                    "assistant_can_send": bool(telegram_status.get("configured")),
                    "supports_personal_full_account": telegram_mode == "web",
                    "notes": (
                        "Telegram Web oturumu açıksa mevcut kişisel konuşmalar okunur ve mevcut sohbetlere yanıt verilir."
                        if telegram_mode == "web"
                        else "Yalnız bota ulaşan sohbetler okunur ve bot adına mesaj gönderilir."
                    ),
                },
                "whatsapp": {
                    "official_mode": "business_cloud_api",
                    "assistant_can_read": bool(whatsapp_status.get("message_count")),
                    "assistant_can_send": bool(whatsapp_status.get("configured")),
                    "supports_personal_full_account": False,
                    "notes": "Gönderim Business Cloud API üzerinden yapılır. Yeni gelen mesajlar için webhook gerekir; kişisel hesap ve tam geçmiş desteklenmez.",
                },
                "x": {
                    "official_mode": "oauth_api_v2",
                    "assistant_can_read_posts": bool(x_status.get("configured")),
                    "assistant_can_read_dm": bool(x_status.get("configured") and x_dm_read),
                    "assistant_can_send_dm": bool(x_status.get("configured") and x_dm_write),
                    "supports_personal_full_account": True,
                    "notes": "OAuth ile gönderi, mention ve izin verilirse DM erişimi sağlanır.",
                },
                "instagram": {
                    "official_mode": "instagram_professional_messaging",
                    "assistant_can_read_messages": bool(instagram_status.get("configured")),
                    "assistant_can_send_messages": bool(instagram_status.get("configured") and "instagram_manage_messages" in instagram_scopes),
                    "supports_personal_full_account": False,
                    "notes": "Resmi Meta erişimiyle yalnız Instagram Professional hesapların mesajları okunur ve yanıtlanır. Kişisel inbox ve tam geçmiş desteklenmez.",
                },
                "linkedin": {
                    "official_mode": "oauth_social_api",
                    "selected_mode": linkedin_mode,
                    "assistant_can_post_updates": bool(linkedin_status.get("configured") and "w_member_social" in linkedin_scopes),
                    "assistant_can_read_posts": bool(linkedin_status.get("configured") and linkedin_social_read),
                    "assistant_can_read_comments": bool(linkedin_status.get("configured") and linkedin_social_read),
                    "assistant_can_read_messages": bool(linkedin_web_messaging and linkedin_status.get("message_count")),
                    "assistant_can_send_messages": linkedin_web_messaging,
                    "supports_personal_full_account": linkedin_mode == "web",
                    "notes": (
                        "Web oturumu modunda mevcut LinkedIn DM konuşmaları eşitlenebilir ve yanıt gönderilebilir."
                        if linkedin_mode == "web"
                        else "Resmi erişimle gönderiler ve yorumlar eşitlenebilir, paylaşım yapılabilir. DM için web oturumu modu ayrıca seçilmelidir."
                    ),
                },
            },
            "runtime_enabled": llm_service.enabled,
            "assistant_runtime_mode": llm_service.runtime_mode,
        }

