    @app.delete("/assistant/threads/{thread_id}")
    def delete_assistant_thread(
        thread_id: int,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        deleted = store.delete_assistant_thread(settings.office_id, thread_id=thread_id)
        if not deleted:
            raise HTTPException(status_code=404, detail="assistant_thread_not_found")
        remaining_threads = store.list_assistant_threads(settings.office_id, limit=100)
        selected_thread_id: int | None = int(remaining_threads[0]["id"]) if remaining_threads else None
        if selected_thread_id is None:
            replacement = store.create_assistant_thread(settings.office_id, created_by=subject)
            selected_thread_id = int(replacement["id"])
            remaining_threads = store.list_assistant_threads(settings.office_id, limit=100)
        audit.log("assistant_thread_deleted", subject=subject, role=role, session_id=sid, thread_id=thread_id)
        return {
            "deleted_thread_id": thread_id,
            "selected_thread_id": selected_thread_id,
            "items": remaining_threads,
            "generated_from": "assistant_thread_memory",
        }

    @app.get("/assistant/thread")
    def get_assistant_thread(
        limit: int = 30,
        before_id: int | None = None,
        thread_id: int | None = None,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        if thread_id is not None:
            thread = store.get_assistant_thread(settings.office_id, thread_id)
            if not thread:
                raise HTTPException(status_code=404, detail="assistant_thread_not_found")
        else:
            thread = store.get_or_create_assistant_thread(settings.office_id, created_by=subject)
        thread_id = int(thread["id"])
        messages = store.list_assistant_messages(
            settings.office_id,
            thread_id=thread_id,
            limit=limit,
            before_id=before_id,
        )
        total_count = store.count_assistant_messages(settings.office_id, thread_id=thread_id)
        has_more = bool(messages) and (messages[0]["id"] > 1)
        if has_more:
            first_msg_id = messages[0]["id"]
            with store._conn() as conn:
                earlier = conn.execute(
                    "SELECT COUNT(*) AS cnt FROM assistant_messages WHERE office_id=? AND thread_id=? AND id < ?",
                    (settings.office_id, thread_id, first_msg_id),
                ).fetchone()
                has_more = bool(earlier and int(earlier["cnt"]) > 0)
        audit.log("assistant_thread_viewed", subject=subject, role=role, session_id=sid, message_count=len(messages))
        return {
            "thread": thread,
            "messages": messages,
            "has_more": has_more,
            "total_count": total_count,
            "assistant_summary": build_assistant_home(store, settings.office_id, settings=settings).get("today_summary"),
            "onboarding": _assistant_onboarding_state(settings, store),
            "generated_from": "assistant_thread_memory",
        }

