    @app.patch("/assistant/thread/messages/{message_id}/feedback")
    def update_assistant_thread_message_feedback(
        message_id: int,
        payload: AssistantThreadMessageFeedbackRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        feedback_value = str(payload.feedback_value or "").strip().lower()
        stored_feedback = None if feedback_value == "none" else feedback_value
        message = store.set_assistant_message_feedback(
            settings.office_id,
            message_id=message_id,
            feedback_value=stored_feedback,
            note=payload.note,
        )
        if not message:
            raise HTTPException(status_code=404, detail="assistant_thread_message_not_found")
        learning: dict[str, Any] | None = None
        if stored_feedback:
            try:
                learning = knowledge_base.record_assistant_message_feedback(
                    store=store,
                    message_id=message_id,
                    feedback_value=stored_feedback,
                    note=payload.note,
                )
            except ValueError as exc:
                raise HTTPException(status_code=400, detail=str(exc)) from exc
        refresh_learning = knowledge_base.refresh_assistant_feedback_learning(
            store=store,
            changed_message_id=message_id,
        )
        current_learning = refresh_learning.get("current_learning")
        if current_learning:
            learning = {**(learning or {}), **current_learning, "refresh": refresh_learning}
        elif refresh_learning:
            learning = {**(learning or {}), "refresh": refresh_learning}
        audit.log(
            "assistant_thread_message_feedback_updated",
            subject=subject,
            role=role,
            session_id=sid,
            message_id=message_id,
            thread_id=message.get("thread_id"),
            feedback_value=stored_feedback or "none",
        )
        return {
            "message": message,
            "learning": learning,
            "assistant_runtime_profile": store.get_assistant_runtime_profile(settings.office_id),
            "memory_overview": knowledge_base.memory_overview(),
            "connector_sync_status": knowledge_base.connector_sync_status(store=store),
            "generated_from": "assistant_thread_memory",
        }

    @app.post("/assistant/thread/messages")
    def post_assistant_thread_message(
        payload: AssistantThreadMessageRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        route_started_at = time.time()
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        _debug_route_timing("assistant_thread.auth", route_started_at)
        require_role("intern", role)
        turn = _prepare_assistant_thread_turn(
            payload=payload,
            subject=subject,
            settings=settings,
            store=store,
            integration_service=integration_service,
            runtime=runtime,
            events=events,
        )
        _debug_route_timing("assistant_thread.turn_prepared", route_started_at)
        if turn.fast_reply and not _should_bypass_fast_assistant_reply(turn.raw_content):
            onboarding_after = _assistant_onboarding_state(settings, store)
            response_extensions = build_thread_response_extensions(
                reply=turn.fast_reply,
                generated_from=str(turn.fast_reply.get("generated_from") or ""),
                memory_updates=[],
            )
            turn.fast_reply["source_context"] = {
                **(turn.fast_reply.get("source_context") or {}),
                "onboarding": onboarding_after,
                **response_extensions,
            }
            audit.log("assistant_thread_message_posted", subject=subject, role=role, session_id=sid, thread_id=turn.thread["id"])
            return _finalize_assistant_thread_response(
                thread=turn.thread,
                reply=turn.fast_reply,
                onboarding_after=onboarding_after,
                response_extensions=response_extensions,
            )
        execution_state = _build_assistant_thread_execution_state(
            payload=payload,
            turn=turn,
            subject=subject,
            settings=settings,
            store=store,
            runtime=runtime,
            events=events,
            memory_service=memory_service,
            personal_model=personal_model,
            sync_reason="assistant_thread_message",
        )
        _debug_route_timing("assistant_thread.context_ready", route_started_at)
        reply = _resolve_prebuilt_assistant_thread_reply(
            payload=payload,
            turn=turn,
            state=execution_state,
            subject=subject,
            role=role,
            sid=sid,
            settings=settings,
            store=store,
            runtime=runtime,
            events=events,
            integration_service=integration_service,
            knowledge_base=knowledge_base,
        )
        if reply is None:
            reply = _compose_assistant_thread_reply(
                query=execution_state.normalized_query,
                matter_id=payload.matter_id,
                source_refs=turn.source_refs,
                recent_messages=turn.prior_messages,
                subject=subject,
                settings=settings,
                store=store,
                runtime=runtime,
                events=events,
                knowledge_context=execution_state.kb_context,
                personal_model_context=execution_state.personal_model_context,
                knowledge_base=knowledge_base,
            )
        _debug_route_timing("assistant_thread.reply_composed", route_started_at)
        reply, response_extensions = _enrich_assistant_thread_reply_for_delivery(
            reply=reply,
            payload=payload,
            turn=turn,
            state=execution_state,
            personal_model=personal_model,
            settings=settings,
            store=store,
        )
        _debug_route_timing("assistant_thread.finalize_prep", route_started_at)
        audit.log("assistant_thread_message_posted", subject=subject, role=role, session_id=sid, thread_id=turn.thread["id"])
        response_payload = _finalize_assistant_thread_response(
            thread=turn.thread,
            reply=reply,
            onboarding_after=execution_state.onboarding_after,
            response_extensions=response_extensions,
        )
        _debug_route_timing("assistant_thread.finalized", route_started_at)
        return response_payload

