    @app.post("/assistant/thread/messages/stream")
    def post_assistant_thread_message_stream(
        payload: AssistantThreadMessageRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        def event_stream():
            try:
                turn = _prepare_assistant_thread_turn(
                    payload=payload,
                    subject=subject,
                    settings=settings,
                    store=store,
                    integration_service=integration_service,
                    runtime=runtime,
                    events=events,
                )
                yield _ndjson_line({"type": "thread_ready", "thread": turn.thread, "user_message": turn.user_message})
                if turn.fast_reply and not _should_bypass_fast_assistant_reply(turn.raw_content):
                    onboarding_after = _assistant_onboarding_state(settings, store)
                    response_extensions = build_thread_response_extensions(
                        reply=turn.fast_reply,
                        generated_from=str(turn.fast_reply.get("generated_from") or ""),
                        memory_updates=[],
                    )
                    turn.fast_reply["source_context"] = {
                        **(turn.fast_reply.get("source_context") or {}),
                        "onboarding": onboarding_after,
                        **response_extensions,
                    }
                    yield _ndjson_line({"type": "assistant_start"})
                    assembled = ""
                    for delta in _iter_text_deltas(str(turn.fast_reply.get("content") or "")):
                        assembled += delta
                        yield _ndjson_line({"type": "assistant_chunk", "delta": delta, "content": assembled})
                    turn.fast_reply["content"] = assembled or str(turn.fast_reply.get("content") or "")
                    response_payload = _finalize_assistant_thread_response(
                        thread=turn.thread,
                        reply=turn.fast_reply,
                        onboarding_after=onboarding_after,
                        response_extensions=response_extensions,
                    )
                    yield _ndjson_line({"type": "assistant_complete", "response": response_payload})
                    return
                execution_state = _build_assistant_thread_execution_state(
                    payload=payload,
                    turn=turn,
                    subject=subject,
                    settings=settings,
                    store=store,
                    runtime=runtime,
                    events=events,
                    memory_service=memory_service,
                    personal_model=personal_model,
                    sync_reason="assistant_thread_stream",
                )
                used_live_stream = False
                reply = _resolve_prebuilt_assistant_thread_reply(
                    payload=payload,
                    turn=turn,
                    state=execution_state,
                    subject=subject,
                    role=role,
                    sid=sid,
                    settings=settings,
                    store=store,
                    runtime=runtime,
                    events=events,
                    integration_service=integration_service,
                    knowledge_base=knowledge_base,
                )
                if reply is None:
                    stream_request = _build_assistant_thread_stream_request(
                        query=execution_state.normalized_query,
                        matter_id=payload.matter_id,
                        source_refs=turn.source_refs,
                        recent_messages=turn.prior_messages,
                        subject=subject,
                        settings=settings,
                        store=store,
                        runtime=runtime,
                        events=events,
                        knowledge_context=execution_state.kb_context,
                        personal_model_context=execution_state.personal_model_context,
                        knowledge_base=knowledge_base,
                    )
                    live_stream, stream_meta = _maybe_runtime_stream(
                        runtime,
                        str(stream_request.get("runtime_prompt") or ""),
                        events,
                        task="assistant_thread_reply",
                        subject=subject,
                        matter_id=payload.matter_id,
                    )
                    if live_stream:
                        used_live_stream = True
                        yield _ndjson_line({"type": "assistant_start"})
                        assembled = ""
                        for delta in live_stream:
                            piece = str(delta or "")
                            if not piece:
                                continue
                            assembled += piece
                            yield _ndjson_line({"type": "assistant_chunk", "delta": piece, "content": assembled})
                        reply = _materialize_assistant_thread_stream_reply(
                            request=stream_request,
                            generated_text=assembled,
                            runtime_completion=stream_meta,
                        )
                    else:
                        reply = _compose_assistant_thread_reply(
                            query=execution_state.normalized_query,
                            matter_id=payload.matter_id,
                            source_refs=turn.source_refs,
                            recent_messages=turn.prior_messages,
                            subject=subject,
                            settings=settings,
                            store=store,
                            runtime=runtime,
                            events=events,
                            knowledge_context=execution_state.kb_context,
                            personal_model_context=execution_state.personal_model_context,
                            knowledge_base=knowledge_base,
                        )
                reply, response_extensions = _enrich_assistant_thread_reply_for_delivery(
                    reply=reply,
                    payload=payload,
                    turn=turn,
                    state=execution_state,
                    personal_model=personal_model,
                    settings=settings,
                    store=store,
                )

                if not used_live_stream:
                    yield _ndjson_line({"type": "assistant_start"})
                    assembled = ""
                    for delta in _iter_text_deltas(str(reply.get("content") or "")):
                        assembled += delta
                        yield _ndjson_line({"type": "assistant_chunk", "delta": delta, "content": assembled})
                    reply["content"] = assembled or str(reply.get("content") or "")
                else:
                    reply["content"] = str(reply.get("content") or "")

                audit.log("assistant_thread_message_posted", subject=subject, role=role, session_id=sid, thread_id=turn.thread["id"], streamed=True)
                response_payload = _finalize_assistant_thread_response(
                    thread=turn.thread,
                    reply=reply,
                    onboarding_after=execution_state.onboarding_after,
                    response_extensions=response_extensions,
                )
                yield _ndjson_line({"type": "assistant_complete", "response": response_payload})
            except HTTPException as exc:
                yield _ndjson_line({"type": "error", "detail": str(exc.detail), "status": exc.status_code})
            except Exception as exc:
                yield _ndjson_line({"type": "error", "detail": str(exc) or "Asistan akışı tamamlanamadı.", "status": 500})

        return StreamingResponse(
            event_stream(),
            media_type="application/x-ndjson",
            headers={
                "Cache-Control": "no-cache, no-transform",
                "X-Accel-Buffering": "no",
            },
        )

