    @app.get("/assistant/contact-profiles")
    def get_assistant_contact_profiles(
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        sync_connected_accounts_from_settings(settings, store)
        items = build_assistant_contact_profiles(store, settings.office_id)
        relationship_profiles = build_assistant_relationship_profiles(store, settings.office_id)
        channel_counts: dict[str, int] = {}
        for item in items:
            for channel in item.get("channels") or []:
                normalized = str(channel or "").strip().lower()
                if not normalized:
                    continue
                channel_counts[normalized] = channel_counts.get(normalized, 0) + 1
        audit.log(
            "assistant_contact_profiles_viewed",
            subject=subject,
            role=role,
            session_id=sid,
            item_count=len(items),
            relationship_profile_count=len(relationship_profiles),
        )
        return {
            "items": items,
            "relationship_profiles": relationship_profiles,
            "directory_summary": {
                "total_accounts": len(items),
                "priority_profiles": len(relationship_profiles),
                "blocked_accounts": len([item for item in items if item.get("blocked")]),
                "watch_enabled_accounts": len([item for item in items if item.get("watch_enabled")]),
                "channels": channel_counts,
            },
            "generated_from": "assistant_contact_profiles",
        }

