    @app.post("/assistant/actions/generate")
    def generate_assistant_action(
        payload: AssistantActionGenerateRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        route_started_at = time.time()
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        _debug_route_timing("assistant_action_generate.auth", route_started_at)
        require_role("lawyer", role)
        result = _generate_assistant_action_output(
            payload=payload,
            subject=subject,
            settings=settings,
            store=store,
            runtime=runtime,
            events=events,
        )
        _debug_route_timing("assistant_action_generate.generated", route_started_at)
        action = result["action"]
        draft = result["draft"]
        action_case = _sync_assistant_action_case(
            store=store,
            office_id=settings.office_id,
            action=action,
            draft=draft,
            created_by=subject,
            actor=subject,
            status="awaiting_approval" if result["manual_review_required"] else "draft_ready",
            current_step="draft_ready",
            note=result["message"],
            metadata={"generated_from": result["generated_from"], "manual_review_required": result["manual_review_required"]},
        )
        kb_result = _record_assistant_action_decision(event_type="generated", action=action, draft=draft)
        _debug_route_timing("assistant_action_generate.kb_recorded", route_started_at)
        audit.log("assistant_action_generated", subject=subject, role=role, session_id=sid, action_id=action["id"], draft_id=draft["id"])
        _debug_route_timing("assistant_action_generate.finalized", route_started_at)
        return {
            "action": action,
            "draft": draft,
            "generated_from": result["generated_from"],
            "manual_review_required": result["manual_review_required"],
            "message": result["message"],
            "action_case": action_case,
            "decision_record": (kb_result or {}).get("decision_record"),
            "policy_guardrails": (kb_result or {}).get("policy"),
            "explainability": (kb_result or {}).get("explainability"),
            "knowledge_context": (kb_result or {}).get("knowledge_context"),
            "action_ladder": (kb_result or {}).get("action_ladder"),
        }

    @app.post("/assistant/actions/{action_id}/approve")
    def approve_assistant_action(
        action_id: int,
        payload: AssistantActionDecisionRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        action = store.get_assistant_action(settings.office_id, action_id)
        if not action:
            raise HTTPException(status_code=404, detail="Aksiyon bulunamadı.")
        draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
        action = store.update_assistant_action_status(settings.office_id, action_id, "approved")
        if draft:
            draft = store.update_outbound_draft(
                settings.office_id,
                int(draft["id"]),
                approval_status="approved",
                delivery_status="ready_to_send" if not settings.connector_dry_run else "manual_review_only",
                approved_by=subject,
                dispatch_state="ready" if not settings.connector_dry_run else "idle",
                dispatch_error=None,
            )
            action = store.update_assistant_action_status(
                settings.office_id,
                action_id,
                "approved",
                draft_id=int(draft["id"]),
                dispatch_state="ready" if not settings.connector_dry_run else "idle",
                dispatch_error=None,
            )
        action_case = _sync_assistant_action_case(
            store=store,
            office_id=settings.office_id,
            action=action,
            draft=draft,
            created_by=str(action.get("created_by") or subject),
            actor=subject,
            status="approved",
            current_step="dispatch_ready" if draft and not settings.connector_dry_run else "approved",
            note=payload.note or "Taslak onaylandı.",
            metadata={"dispatch_mode": "manual_review_only" if settings.connector_dry_run else "ready_to_send"},
        )
        approval_event = store.add_approval_event(
            settings.office_id,
            actor=subject,
            event_type="approved",
            action_id=action_id,
            outbound_draft_id=int(draft["id"]) if draft else None,
            note=payload.note or "Taslak onaylandı.",
        )
        kb_result = _record_assistant_action_decision(
            event_type="approved",
            action=action,
            draft=draft,
            approval_event=approval_event,
            note=payload.note or "Taslak onaylandı.",
        )
        audit.log("assistant_action_approved", subject=subject, role=role, session_id=sid, action_id=action_id)
        return {
            "action": action,
            "draft": draft,
            "dispatch_mode": "manual_review_only" if settings.connector_dry_run else "ready_to_send",
            "message": "Taslak onaylandı. Son gönderim kararı hâlâ insandadır.",
            "action_case": action_case,
            "decision_record": (kb_result or {}).get("decision_record"),
            "policy_guardrails": (kb_result or {}).get("policy"),
            "explainability": (kb_result or {}).get("explainability"),
            "knowledge_context": (kb_result or {}).get("knowledge_context"),
            "action_ladder": (kb_result or {}).get("action_ladder"),
        }

