    @app.get("/assistant/actions/{action_id}/case")
    def get_assistant_action_case(
        action_id: int,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        _, role, _ = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        action = store.get_assistant_action(settings.office_id, action_id)
        if not action:
            raise HTTPException(status_code=404, detail="Aksiyon bulunamadı.")
        action_case = store.get_action_case_by_action_id(settings.office_id, action_id)
        draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
        events_payload = store.list_action_case_events(settings.office_id, int(action_case["id"])) if action_case else []
        dispatch_attempts = store.list_dispatch_attempts(
            settings.office_id,
            action_id=action_id,
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
        )
        external_receipts = store.list_external_receipts(
            settings.office_id,
            action_id=action_id,
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
        )
        compensation_plan = _build_action_case_compensation_plan(
            action_case=action_case,
            action=action,
            draft=draft,
            dispatch_attempts=dispatch_attempts,
            external_receipts=external_receipts,
        )
        return {
            "action": action,
            "draft": draft,
            "action_case": action_case,
            "events": events_payload,
            "dispatch_attempts": dispatch_attempts,
            "external_receipts": external_receipts,
            "compensation_plan": compensation_plan,
            "case_steps": _build_action_case_steps(
                action_case=action_case,
                action=action,
                draft=draft,
                dispatch_attempts=dispatch_attempts,
                external_receipts=external_receipts,
            ),
            "available_controls": _build_action_case_available_controls(
                action_case=action_case,
                action=action,
                draft=draft,
                dispatch_attempts=dispatch_attempts,
                compensation_plan=compensation_plan,
            ),
            "generated_from": "assistant_action_case_registry",
        }

    @app.post("/assistant/actions/{action_id}/pause")
    def pause_assistant_action_case(
        action_id: int,
        payload: AssistantActionDecisionRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        action = store.get_assistant_action(settings.office_id, action_id)
        if not action:
            raise HTTPException(status_code=404, detail="Aksiyon bulunamadı.")
        draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
        action_case = store.get_action_case_by_action_id(settings.office_id, action_id)
        if _action_case_is_paused(action_case):
            return {"action": action, "draft": draft, "action_case": action_case, "message": "Aksiyon zaten duraklatılmış."}
        if str((action_case or {}).get("status") or "").lower() == "awaiting_external_confirmation":
            raise HTTPException(status_code=409, detail="Dış sistem süreci başladıktan sonra duraklatma desteklenmiyor.")
        if str(action.get("status") or "").lower() in {"completed", "dismissed"}:
            raise HTTPException(status_code=409, detail="Tamamlanmış veya kapatılmış aksiyon duraklatılamaz.")
        if action_case is None:
            action_case = _sync_assistant_action_case(
                store=store,
                office_id=settings.office_id,
                action=action,
                draft=draft,
                created_by=str(action.get("created_by") or subject),
                actor=subject,
                status="approved" if str(action.get("status") or "").lower() == "approved" else "awaiting_approval",
                current_step="dispatch_ready" if str(action.get("dispatch_state") or "").lower() == "ready" else "draft_ready",
                note="Aksiyon kontrol yüzeyine alındı.",
            )
        paused_metadata = {
            "paused_from_status": action_case.get("status"),
            "paused_from_step": action_case.get("current_step"),
            "paused_from_action_status": action.get("status"),
            "paused_from_action_dispatch_state": action.get("dispatch_state"),
            "paused_from_draft_dispatch_state": (draft or {}).get("dispatch_state"),
            "paused_at": datetime.now(timezone.utc).isoformat(),
            "pause_note": payload.note,
        }
        action_case = store.update_action_case(
            settings.office_id,
            int(action_case["id"]),
            status="paused",
            current_step="paused",
            last_actor=subject,
            metadata=paused_metadata,
        ) or action_case
        store.add_action_case_event(
            settings.office_id,
            case_id=int(action_case["id"]),
            step_key="paused",
            event_type="paused",
            actor=subject,
            note=payload.note or "Aksiyon duraklatıldı.",
            payload={"action_status": action.get("status"), "dispatch_state": action.get("dispatch_state")},
        )
        if str(action.get("status") or "").lower() not in {"completed", "dismissed"}:
            action = store.update_assistant_action_status(
                settings.office_id,
                action_id,
                str(action.get("status") or "approved"),
                draft_id=int(draft["id"]) if draft and draft.get("id") else None,
                dispatch_state="paused",
                dispatch_error=action.get("dispatch_error"),
                external_message_id=action.get("external_message_id"),
                last_dispatch_at=action.get("last_dispatch_at"),
            ) or action
        if draft and str(draft.get("dispatch_state") or "").lower() not in {"completed"}:
            draft = store.update_outbound_draft(
                settings.office_id,
                int(draft["id"]),
                dispatch_state="paused",
                dispatch_error=draft.get("dispatch_error"),
                external_message_id=draft.get("external_message_id"),
                last_dispatch_at=draft.get("last_dispatch_at"),
            ) or draft
        audit.log("assistant_action_paused", subject=subject, role=role, session_id=sid, action_id=action_id)
        return {"action": action, "draft": draft, "action_case": action_case, "message": "Aksiyon duraklatıldı."}

    @app.post("/assistant/actions/{action_id}/resume")
    def resume_assistant_action_case(
        action_id: int,
        payload: AssistantActionDecisionRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        action = store.get_assistant_action(settings.office_id, action_id)
        if not action:
            raise HTTPException(status_code=404, detail="Aksiyon bulunamadı.")
        draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
        action_case = store.get_action_case_by_action_id(settings.office_id, action_id)
        if not _action_case_is_paused(action_case):
            raise HTTPException(status_code=409, detail="Yalnız duraklatılmış aksiyonlar yeniden başlatılabilir.")
        case_metadata = dict((action_case or {}).get("metadata") or {})
        restored_status = str(case_metadata.get("paused_from_status") or "approved")
        restored_step = str(case_metadata.get("paused_from_step") or "approved")
        restored_action_dispatch = case_metadata.get("paused_from_action_dispatch_state")
        restored_draft_dispatch = case_metadata.get("paused_from_draft_dispatch_state")
        action_case = store.update_action_case(
            settings.office_id,
            int(action_case["id"]),
            status=restored_status,
            current_step=restored_step,
            last_actor=subject,
            metadata={
                "paused_from_status": None,
                "paused_from_step": None,
                "paused_from_action_status": None,
                "paused_from_action_dispatch_state": None,
                "paused_from_draft_dispatch_state": None,
                "last_resumed_at": datetime.now(timezone.utc).isoformat(),
                "last_resume_note": payload.note,
            },
        ) or action_case
        store.add_action_case_event(
            settings.office_id,
            case_id=int(action_case["id"]),
            step_key=restored_step,
            event_type="resumed",
            actor=subject,
            note=payload.note or "Aksiyon yeniden başlatıldı.",
            payload={"restored_status": restored_status, "restored_step": restored_step},
        )
        action = store.update_assistant_action_status(
            settings.office_id,
            action_id,
            str(action.get("status") or "approved"),
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
            dispatch_state=str(restored_action_dispatch or "idle"),
            dispatch_error=action.get("dispatch_error"),
            external_message_id=action.get("external_message_id"),
            last_dispatch_at=action.get("last_dispatch_at"),
        ) or action
        if draft:
            draft = store.update_outbound_draft(
                settings.office_id,
                int(draft["id"]),
                dispatch_state=str(restored_draft_dispatch or "idle"),
                dispatch_error=draft.get("dispatch_error"),
                external_message_id=draft.get("external_message_id"),
                last_dispatch_at=draft.get("last_dispatch_at"),
            ) or draft
        audit.log("assistant_action_resumed", subject=subject, role=role, session_id=sid, action_id=action_id)
        return {"action": action, "draft": draft, "action_case": action_case, "message": "Aksiyon yeniden başlatıldı."}

    @app.post("/assistant/actions/{action_id}/retry-dispatch")
    def retry_assistant_action_dispatch(
        action_id: int,
        payload: AssistantActionDecisionRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        action = store.get_assistant_action(settings.office_id, action_id)
        if not action:
            raise HTTPException(status_code=404, detail="Aksiyon bulunamadı.")
        draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
        action_case = store.get_action_case_by_action_id(settings.office_id, action_id)
        _require_action_case_not_paused(action_case)
        if str(action.get("status") or "").lower() in {"completed", "dismissed"}:
            raise HTTPException(status_code=409, detail="Tamamlanmış veya kapatılmış aksiyon yeniden gönderime alınamaz.")
        attempts = store.list_dispatch_attempts(
            settings.office_id,
            action_id=action_id,
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
            limit=20,
        )
        last_failed_attempt = next((item for item in attempts if str(item.get("status") or "").lower() == "failed"), None)
        if not last_failed_attempt and str(action.get("dispatch_state") or "").lower() != "failed" and str((draft or {}).get("dispatch_state") or "").lower() != "failed":
            raise HTTPException(status_code=409, detail="Yeniden gönderim için başarısız bir deneme bulunamadı.")
        next_retry_count = _dispatch_retry_count(last_failed_attempt) + 1
        backoff_seconds = _dispatch_retry_backoff_seconds(next_retry_count)
        retry_ready_at = (datetime.now(timezone.utc) + timedelta(seconds=backoff_seconds)).isoformat() if backoff_seconds > 0 else None
        if draft:
            draft = store.update_outbound_draft(
                settings.office_id,
                int(draft["id"]),
                delivery_status="ready_to_send" if str(draft.get("approval_status") or "").lower() == "approved" else draft.get("delivery_status"),
                dispatch_state="ready",
                dispatch_error=None,
            ) or draft
        action = store.update_assistant_action_status(
            settings.office_id,
            action_id,
            "approved",
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
            dispatch_state="ready",
            dispatch_error=None,
            external_message_id=action.get("external_message_id"),
            last_dispatch_at=action.get("last_dispatch_at"),
        ) or action
        retry_attempt = store.create_dispatch_attempt(
            settings.office_id,
            actor=subject,
            action_id=action_id,
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
            dispatch_target=str((draft or {}).get("channel") or action.get("target_channel") or ""),
            status="retry_scheduled",
            note=payload.note or "Gönderim yeniden planlandı.",
            metadata={
                "retry_of_attempt_id": (last_failed_attempt or {}).get("id"),
                "origin": "retry_dispatch",
                "retry_count": next_retry_count,
                "backoff_seconds": backoff_seconds,
                "retry_ready_at": retry_ready_at,
            },
        )
        if action_case is None:
            action_case = _sync_assistant_action_case(
                store=store,
                office_id=settings.office_id,
                action=action,
                draft=draft,
                created_by=str(action.get("created_by") or subject),
                actor=subject,
                status="approved",
                current_step="dispatch_ready",
                note=payload.note or "Gönderim yeniden planlandı.",
            )
        else:
            action_case = store.update_action_case(
                settings.office_id,
                int(action_case["id"]),
                status="approved",
                current_step="dispatch_ready",
                last_actor=subject,
                metadata={
                    "retry_scheduled_attempt_id": retry_attempt.get("id"),
                    "last_retry_note": payload.note,
                    "retry_count": next_retry_count,
                    "retry_backoff_seconds": backoff_seconds,
                    "retry_ready_at": retry_ready_at,
                },
                last_error=None,
            ) or action_case
            store.add_action_case_event(
                settings.office_id,
                case_id=int(action_case["id"]),
                step_key="dispatch_ready",
                event_type="retry_scheduled",
                actor=subject,
                note=payload.note or "Gönderim yeniden planlandı.",
                payload={
                    "retry_attempt_id": retry_attempt.get("id"),
                    "retry_of_attempt_id": (last_failed_attempt or {}).get("id"),
                    "retry_count": next_retry_count,
                    "backoff_seconds": backoff_seconds,
                    "retry_ready_at": retry_ready_at,
                },
            )
        approval_event = store.add_approval_event(
            settings.office_id,
            actor=subject,
            event_type="dispatch_retry_scheduled",
            action_id=action_id,
            outbound_draft_id=int(draft["id"]) if draft and draft.get("id") else None,
            note=payload.note or "Gönderim yeniden planlandı.",
        )
        audit.log("assistant_action_dispatch_retry_scheduled", subject=subject, role=role, session_id=sid, action_id=action_id)
        return {
            "action": action,
            "draft": draft,
            "action_case": action_case,
            "dispatch_attempt": retry_attempt,
            "approval_event": approval_event,
            "message": (
                f"Gönderim yeniden planlandı. Yeni deneme {datetime.fromisoformat(retry_ready_at).astimezone().strftime('%d.%m.%Y %H:%M')} sonrasında başlatılabilir."
                if retry_ready_at
                else "Gönderim yeniden planlandı. Başlatma adımında bu deneme kaydını kullanabilirsiniz."
            ),
        }

    @app.get("/assistant/approvals")
    def list_assistant_approvals(
        limit: int = 20,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        _, role, _ = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        actions = store.list_assistant_actions(settings.office_id, status="pending_review", limit=limit)
        items = []
        for action in actions:
            draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
            action_payload = _decorate_assistant_action_for_surface(
                store=store,
                office_id=settings.office_id,
                action=action,
                draft=draft,
            )
            items.append(
                {
                    "id": f"assistant-action-{action['id']}",
                    "action_id": action["id"],
                    "draft_id": draft.get("id") if draft else None,
                    "status": action.get("status"),
                    "title": action.get("title"),
                    "action_type": action.get("action_type"),
                    "target_channel": action.get("target_channel"),
                    "manual_review_required": bool(action.get("manual_review_required")),
                    "approval_required": True,
                    "draft": draft,
                    "action": action_payload,
                    "action_case": (action_payload or {}).get("action_case"),
                    "available_controls": (action_payload or {}).get("available_controls"),
                }
            )
        return {"items": items, "generated_from": "approval_registry"}

