    @app.get("/assistant/drafts")
    def list_assistant_drafts(
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        assistant_drafts = [
            item
            for item in store.list_outbound_drafts(settings.office_id)
            if str(item.get("approval_status") or "").lower() != "dismissed"
            and str(item.get("delivery_status") or "").lower() not in {"cancelled", "canceled"}
        ]
        assistant_drafts = [
            item
            for item in (
                _decorate_assistant_draft_for_surface(store=store, office_id=settings.office_id, draft=draft)
                for draft in assistant_drafts
            )
            if item is not None
        ]
        matter_drafts = store.list_all_matter_drafts(settings.office_id)
        audit.log("assistant_drafts_viewed", subject=subject, role=role, session_id=sid, assistant_draft_count=len(assistant_drafts))
        return {
            "items": assistant_drafts,
            "matter_drafts": matter_drafts,
            "generated_from": "assistant_agenda_engine",
        }

    @app.post("/assistant/share-drafts")
    def create_assistant_share_draft(
        payload: AssistantShareDraftCreateRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)

        channel = str(payload.channel or "").strip().lower()
        share_body = str(payload.content or "").strip()
        if not share_body:
            raise HTTPException(status_code=400, detail="Paylaşım içeriği boş olamaz.")

        share_message = store.get_assistant_message(settings.office_id, message_id=int(payload.message_id)) if payload.message_id else None
        if payload.message_id and not share_message:
            raise HTTPException(status_code=404, detail="Paylaşılacak mesaj bulunamadı.")
        if payload.thread_id and share_message and int(share_message.get("thread_id") or 0) != int(payload.thread_id):
            raise HTTPException(status_code=409, detail="Mesaj bu sohbet kaydıyla eşleşmiyor.")

        resolved_contact = _compact_inline_text(str(payload.to_contact or ""))
        if payload.contact_profile_id and not resolved_contact:
            profiles = build_assistant_contact_profiles(store, settings.office_id)
            matched_profile = next((item for item in profiles if str(item.get("id") or "") == str(payload.contact_profile_id or "")), None)
            if not matched_profile:
                raise HTTPException(status_code=404, detail="Paylaşım hedefi bulunamadı.")
            resolved_contact = _assistant_share_contact_value(matched_profile, channel=channel)

        if channel == "email":
            email_candidate = _compact_inline_text(resolved_contact)
            if not email_candidate:
                raise HTTPException(status_code=400, detail="E-posta için geçerli bir alıcı adresi girin.")
            if not _EMAIL_PATTERN.search(email_candidate):
                raise HTTPException(status_code=400, detail="E-posta paylaşımı için geçerli bir adres gerekli.")
            resolved_contact = email_candidate
        elif channel in {"whatsapp", "telegram"} and not resolved_contact:
            raise HTTPException(status_code=400, detail="Bu kanal için kişi veya grup seçin.")

        draft_source_context: dict[str, Any] = {
            "share_origin": "assistant_message",
            "message_id": int(payload.message_id) if payload.message_id else None,
            "thread_id": int(payload.thread_id) if payload.thread_id else int(share_message.get("thread_id") or 0) if share_message else None,
            "contact_profile_id": str(payload.contact_profile_id or "").strip() or None,
            "source_refs": [
                {
                    "type": "assistant_message",
                    "message_id": int(payload.message_id) if payload.message_id else None,
                    "thread_id": int(payload.thread_id) if payload.thread_id else int(share_message.get("thread_id") or 0) if share_message else None,
                }
            ],
            "message_excerpt": _safe_excerpt(share_body, max_len=220),
        }
        if share_message:
            draft_source_context["shared_message_role"] = share_message.get("role")
            draft_source_context["shared_message_generated_from"] = share_message.get("generated_from")

        if channel == "whatsapp":
            resolved_target = _resolve_whatsapp_dispatch_target(store, settings.office_id, resolved_contact)
            if resolved_target:
                draft_source_context.update(
                    {
                        "recipient": resolved_target.get("recipient"),
                        "conversation_ref": resolved_target.get("conversation_ref"),
                        "recipient_label": resolved_target.get("label") or resolved_contact,
                    }
                )

        draft_subject = _compact_inline_text(str(payload.subject or "")) or _assistant_share_subject(share_body)
        execution = evaluate_execution_gateway(
            action_kind=_assistant_share_draft_type(channel),
            risk_level="B",
            requires_confirmation=True,
            tool_class="write",
            scope="personal",
            suggest_only=True,
            reversible=True,
            current_stage="draft",
            preview_summary=draft_subject,
            audit_label="assistant_share_draft",
        )
        draft = store.create_outbound_draft(
            settings.office_id,
            matter_id=None,
            draft_type=_assistant_share_draft_type(channel),
            channel=channel,
            to_contact=resolved_contact or None,
            subject=draft_subject,
            body=share_body,
            source_context=draft_source_context,
            generated_from="assistant_message_share",
            created_by=subject,
            approval_status="pending_review" if execution.policy_decision.preview_required else "approved",
            delivery_status="not_sent",
        )
        action = store.create_assistant_action(
            settings.office_id,
            matter_id=None,
            action_type=_assistant_share_draft_type(channel),
            title=f"{_assistant_share_channel_label(channel)} paylaşımı hazırla" if channel else "Paylaşımı hazırla",
            description=_safe_excerpt(share_body, max_len=240),
            rationale=(
                "Sohbet mesajı paylaşım panelinden dış iletişim taslağı hazırlandı. "
                f"{execution.policy_decision.reason_summary}"
            ),
            source_refs=[item for item in draft_source_context.get("source_refs") or [] if isinstance(item, dict)],
            target_channel=channel,
            draft_id=int(draft["id"]),
            status="pending_review" if execution.policy_decision.preview_required else "suggested",
            manual_review_required=execution.policy_decision.manual_review_required,
            created_by=subject,
        )
        approval_event = store.add_approval_event(
            settings.office_id,
            actor=subject,
            event_type="draft_generated",
            action_id=int(action["id"]),
            outbound_draft_id=int(draft["id"]),
            note="Mesaj paylaşım panelinden dış iletişim taslağı hazırlandı.",
        )
        kb_result = _record_assistant_action_decision(
            event_type="generated",
            action=action,
            draft=draft,
            approval_event=approval_event,
            note="Mesaj paylaşım panelinden dış iletişim taslağı hazırlandı.",
        )
        action_case = _sync_assistant_action_case(
            store=store,
            office_id=settings.office_id,
            action=action,
            draft=draft,
            created_by=subject,
            actor=subject,
            status="awaiting_approval" if execution.policy_decision.manual_review_required else "draft_ready",
            current_step="draft_ready",
            note="Mesaj paylaşım panelinden dış iletişim taslağı hazırlandı.",
            metadata={"generated_from": "assistant_message_share", "manual_review_required": execution.policy_decision.manual_review_required},
        )
        audit.log(
            "assistant_share_draft_created",
            subject=subject,
            role=role,
            session_id=sid,
            draft_id=draft["id"],
            channel=channel,
            message_id=payload.message_id,
        )
        return {
            "draft": draft,
            "action": action,
            "action_case": action_case,
            "generated_from": "assistant_message_share",
            "message": "Paylaşım taslağı hazırlandı.",
            "decision_record": (kb_result or {}).get("decision_record"),
            "policy_guardrails": (kb_result or {}).get("policy"),
            "explainability": (kb_result or {}).get("explainability"),
            "knowledge_context": (kb_result or {}).get("knowledge_context"),
            "action_ladder": (kb_result or {}).get("action_ladder"),
        }

    @app.post("/assistant/actions/{action_id}/schedule-compensation")
    def schedule_assistant_action_compensation(
        action_id: int,
        payload: AssistantActionDecisionRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        action = store.get_assistant_action(settings.office_id, action_id)
        if not action:
            raise HTTPException(status_code=404, detail="Aksiyon bulunamadı.")
        draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
        action_case = store.get_action_case_by_action_id(settings.office_id, action_id)
        _require_action_case_not_paused(action_case)
        dispatch_attempts = store.list_dispatch_attempts(
            settings.office_id,
            action_id=action_id,
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
            limit=20,
        )
        external_receipts = store.list_external_receipts(
            settings.office_id,
            action_id=action_id,
            draft_id=int(draft["id"]) if draft and draft.get("id") else None,
            limit=20,
        )
        compensation_plan = _build_action_case_compensation_plan(
            action_case=action_case,
            action=action,
            draft=draft,
            dispatch_attempts=dispatch_attempts,
            external_receipts=external_receipts,
        )
        if not compensation_plan or not compensation_plan.get("can_schedule"):
            raise HTTPException(status_code=409, detail=str((compensation_plan or {}).get("reason") or "Bu aksiyon için telafi planı başlatılamıyor."))

        compensation_action = None
        compensation_draft = None
        compensation_case = None
        recommended_action_type = str(compensation_plan.get("recommended_action_type") or "").strip()
        recommended_target_channel = str(compensation_plan.get("recommended_target_channel") or "").strip() or None
        suggested_instruction = str(compensation_plan.get("suggested_instruction") or "").strip() or (payload.note or "")
        if recommended_action_type:
            generated = _generate_assistant_action_output(
                payload=AssistantActionGenerateRequest(
                    action_type=recommended_action_type,
                    matter_id=int(action["matter_id"]) if action.get("matter_id") else None,
                    to_contact=str((draft or {}).get("to_contact") or "") or None,
                    title=f"Telafi: {str(action.get('title') or 'Asistan aksiyonu')}",
                    instructions=suggested_instruction,
                    source_refs=list((action or {}).get("source_refs") or []),
                    target_channel=recommended_target_channel,
                ),
                subject=subject,
                settings=settings,
                store=store,
                runtime=runtime,
                events=events,
            )
            compensation_action = generated["action"]
            compensation_draft = generated["draft"]
            compensation_case = _sync_assistant_action_case(
                store=store,
                office_id=settings.office_id,
                action=compensation_action,
                draft=compensation_draft,
                created_by=str((compensation_action or {}).get("created_by") or subject),
                actor=subject,
                status="awaiting_approval" if generated["manual_review_required"] else "draft_ready",
                current_step="draft_ready",
                note=payload.note or "Telafi taslağı oluşturuldu.",
                metadata={
                    "generated_from": generated.get("generated_from"),
                    "manual_review_required": generated.get("manual_review_required"),
                    "compensation_for_action_id": action_id,
                },
            )

        if action_case is None:
            action_case = _sync_assistant_action_case(
                store=store,
                office_id=settings.office_id,
                action=action,
                draft=draft,
                created_by=str(action.get("created_by") or subject),
                actor=subject,
                status=str(action.get("status") or "approved"),
                current_step=str((action_case or {}).get("current_step") or "completed"),
                note=payload.note or "Telafi akışı planlandı.",
            )
        action_case = store.update_action_case(
            settings.office_id,
            int(action_case["id"]),
            last_actor=subject,
            metadata={
                "compensation_status": "scheduled",
                "compensation_strategy": compensation_plan.get("strategy"),
                "compensation_reason": compensation_plan.get("reason"),
                "compensation_action_type": recommended_action_type or None,
                "compensation_target_channel": recommended_target_channel,
                "compensation_instruction": suggested_instruction,
                "compensation_action_id": int(compensation_action["id"]) if compensation_action and compensation_action.get("id") else None,
                "compensation_case_id": int(compensation_case["id"]) if compensation_case and compensation_case.get("id") else None,
                "compensation_scheduled_at": datetime.now(timezone.utc).isoformat(),
                "compensation_note": payload.note,
            },
        ) or action_case
        store.add_action_case_event(
            settings.office_id,
            case_id=int(action_case["id"]),
            step_key="completion",
            event_type="compensation_scheduled",
            actor=subject,
            note=payload.note or "Telafi akışı planlandı.",
            payload={
                "strategy": compensation_plan.get("strategy"),
                "compensation_action_id": int(compensation_action["id"]) if compensation_action and compensation_action.get("id") else None,
                "compensation_case_id": int(compensation_case["id"]) if compensation_case and compensation_case.get("id") else None,
            },
        )
        updated_plan = _build_action_case_compensation_plan(
            action_case=action_case,
            action=action,
            draft=draft,
            dispatch_attempts=dispatch_attempts,
            external_receipts=external_receipts,
        )
        audit.log("assistant_action_compensation_scheduled", subject=subject, role=role, session_id=sid, action_id=action_id)
        return {
            "action": action,
            "draft": draft,
            "action_case": action_case,
            "compensation_plan": updated_plan,
            "compensation_action": compensation_action,
            "compensation_draft": compensation_draft,
            "compensation_case": compensation_case,
            "message": "Telafi akışı planlandı.",
        }

    @app.post("/assistant/drafts/{draft_id}/remove")
    def remove_assistant_draft(
        draft_id: int,
        payload: AssistantDraftSendRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        draft = store.get_outbound_draft(settings.office_id, draft_id)
        if not draft:
            raise HTTPException(status_code=404, detail="Taslak bulunamadı.")
        linked_action = store.get_assistant_action_by_draft_id(settings.office_id, draft_id)
        action_id = int(linked_action["id"]) if linked_action and linked_action.get("id") else None
        updated = store.update_outbound_draft(
            settings.office_id,
            draft_id,
            approval_status="dismissed",
            delivery_status="cancelled",
            dispatch_state="idle",
            dispatch_error=None,
        )
        if linked_action and action_id:
            linked_action = store.update_assistant_action_status(
                settings.office_id,
                action_id,
                "dismissed",
                draft_id=draft_id,
                dispatch_state="idle",
                dispatch_error=None,
            )
        approval_event = store.add_approval_event(
            settings.office_id,
            actor=subject,
            event_type="dismissed",
            action_id=action_id,
            outbound_draft_id=draft_id,
            note=payload.note or "Taslak çalışma panelinden kaldırıldı.",
        )
        kb_result = _record_assistant_action_decision(
            event_type="draft_removed",
            action=linked_action,
            draft=updated,
            approval_event=approval_event,
            note=payload.note or "Taslak çalışma panelinden kaldırıldı.",
        )
        action_case = _sync_assistant_action_case(
            store=store,
            office_id=settings.office_id,
            action=linked_action,
            draft=updated,
            created_by=str((linked_action or {}).get("created_by") or subject),
            actor=subject,
            status="cancelled",
            current_step="dismissed",
            note=payload.note or "Taslak çalışma panelinden kaldırıldı.",
        )
        audit.log("assistant_draft_removed", subject=subject, role=role, session_id=sid, draft_id=draft_id)
        return {
            "draft": updated,
            "action": linked_action,
            "action_case": action_case,
            "message": "Taslak kaldırıldı.",
            "decision_record": (kb_result or {}).get("decision_record"),
            "policy_guardrails": (kb_result or {}).get("policy"),
            "explainability": (kb_result or {}).get("explainability"),
            "knowledge_context": (kb_result or {}).get("knowledge_context"),
            "action_ladder": (kb_result or {}).get("action_ladder"),
        }

    @app.post("/assistant/drafts/{draft_id}/send")
    def send_assistant_draft(
        draft_id: int,
        payload: AssistantDraftSendRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        draft = store.get_outbound_draft(settings.office_id, draft_id)
        if not draft:
            raise HTTPException(status_code=404, detail="Taslak bulunamadı.")
        if str(draft.get("channel") or "").lower() == "whatsapp":
            source_context = dict(draft.get("source_context") or {})
            resolved_target = _resolve_whatsapp_dispatch_target(
                store,
                settings.office_id,
                str(source_context.get("recipient") or draft.get("to_contact") or ""),
            )
            if not resolved_target:
                raise HTTPException(
                    status_code=409,
                    detail="WhatsApp hedefi çözümlenemedi. Önce tam kişi, grup adı veya numarayı netleştirin.",
                )
        if str(draft.get("delivery_status")) == "sent" or str(draft.get("dispatch_state")) == "completed":
            raise HTTPException(status_code=409, detail="Taslak zaten gönderildi.")
        linked_action = store.get_assistant_action_by_draft_id(settings.office_id, draft_id)
        linked_case = store.get_action_case_by_action_id(settings.office_id, int(linked_action["id"])) if linked_action and linked_action.get("id") else None
        _require_action_case_not_paused(linked_case)
        action_id = int(linked_action["id"]) if linked_action and linked_action.get("id") else None
        if str(draft.get("approval_status")) != "approved":
            draft = store.update_outbound_draft(
                settings.office_id,
                draft_id,
                approval_status="approved",
                delivery_status="ready_to_send" if not settings.connector_dry_run else "manual_review_only",
                approved_by=subject,
                dispatch_state="ready" if not settings.connector_dry_run else "idle",
                dispatch_error=None,
            )
            if linked_action and action_id:
                linked_action = store.update_assistant_action_status(
                    settings.office_id,
                    action_id,
                    "approved",
                    draft_id=draft_id,
                    dispatch_state="ready" if not settings.connector_dry_run else "idle",
                    dispatch_error=None,
                )
            approval_event = store.add_approval_event(
                settings.office_id,
                actor=subject,
                event_type="approved",
                action_id=action_id,
                outbound_draft_id=draft_id,
                note=payload.note or "Taslak panelinden onaylandı.",
            )
        else:
            approval_event = None
        if settings.connector_dry_run:
            updated = store.update_outbound_draft(
                settings.office_id,
                draft_id,
                delivery_status="manual_review_only",
                approved_by=subject,
                dispatch_state="idle",
            )
            dispatch_event = store.add_approval_event(
                settings.office_id,
                actor=subject,
                event_type="dispatch_skipped",
                action_id=action_id,
                outbound_draft_id=draft_id,
                note=payload.note or "Güvenlik nedeniyle taslak modunda bırakıldı.",
            )
            kb_result = _record_assistant_action_decision(
                event_type="approved",
                action=linked_action,
                draft=updated,
                approval_event=approval_event or dispatch_event,
                note=payload.note or "Güvenlik nedeniyle taslak modunda bırakıldı.",
            )
            action_case = _sync_assistant_action_case(
                store=store,
                office_id=settings.office_id,
                action=linked_action,
                draft=updated,
                created_by=str((linked_action or {}).get("created_by") or subject),
                actor=subject,
                status="approved",
                current_step="approved",
                note=payload.note or "Güvenlik nedeniyle taslak modunda bırakıldı.",
                metadata={"dispatch_mode": "manual_review_only"},
            )
            return {
                "draft": updated,
                "action": linked_action,
                "action_case": action_case,
                "message": "Gönderim güvenlik ayarı nedeniyle taslak modunda bırakıldı.",
                "dispatch_mode": "manual_review_only",
                "decision_record": (kb_result or {}).get("decision_record"),
                "policy_guardrails": (kb_result or {}).get("policy"),
                "explainability": (kb_result or {}).get("explainability"),
                "knowledge_context": (kb_result or {}).get("knowledge_context"),
                "action_ladder": (kb_result or {}).get("action_ladder"),
            }
        updated = store.update_outbound_draft(
            settings.office_id,
            draft_id,
            delivery_status="ready_to_send",
            approved_by=subject,
            dispatch_state="ready",
            dispatch_error=None,
        )
        if linked_action and action_id:
            linked_action = store.update_assistant_action_status(
                settings.office_id,
                action_id,
                "approved",
                draft_id=draft_id,
                dispatch_state="ready",
                dispatch_error=None,
            )
        dispatch_event = store.add_approval_event(
            settings.office_id,
            actor=subject,
            event_type="dispatch_ready",
            action_id=action_id,
            outbound_draft_id=draft_id,
            note=payload.note or "Taslak dış gönderime hazırlandı.",
        )
        kb_result = _record_assistant_action_decision(
            event_type="dispatch_requested",
            action=linked_action,
            draft=updated,
            approval_event=approval_event or dispatch_event,
            note=payload.note or "Taslak dış gönderime hazırlandı.",
        )
        action_case = _sync_assistant_action_case(
            store=store,
            office_id=settings.office_id,
            action=linked_action,
            draft=updated,
            created_by=str((linked_action or {}).get("created_by") or subject),
            actor=subject,
            status="approved",
            current_step="dispatch_ready",
            note=payload.note or "Taslak dış gönderime hazırlandı.",
            metadata={"dispatch_mode": "ready_to_send"},
        )
        audit.log("assistant_draft_send_requested", subject=subject, role=role, session_id=sid, draft_id=draft_id)
        return {
            "draft": updated,
            "action": linked_action,
            "action_case": action_case,
            "message": "Taslak gönderime hazırlandı. Otomatik gönderim kapalıysa son adımı manuel doğrulayın.",
            "dispatch_mode": "ready_to_send",
            "decision_record": (kb_result or {}).get("decision_record"),
            "policy_guardrails": (kb_result or {}).get("policy"),
            "explainability": (kb_result or {}).get("explainability"),
            "knowledge_context": (kb_result or {}).get("knowledge_context"),
            "action_ladder": (kb_result or {}).get("action_ladder"),
        }

    @app.post("/assistant/drafts/{draft_id}/dispatch-started")
    def start_assistant_draft_dispatch(
        draft_id: int,
        payload: AssistantDispatchReportRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        existing_draft = store.get_outbound_draft(settings.office_id, draft_id)
        if not existing_draft:
            raise HTTPException(status_code=404, detail="Taslak bulunamadı.")
        linked_action = store.get_assistant_action(settings.office_id, payload.action_id) if payload.action_id else store.get_assistant_action_by_draft_id(settings.office_id, draft_id)
        linked_case = store.get_action_case_by_action_id(settings.office_id, int(linked_action["id"])) if linked_action and linked_action.get("id") else None
        _require_action_case_not_paused(linked_case)
        draft = store.update_outbound_draft(
            settings.office_id,
            draft_id,
            delivery_status="payment_pending",
            dispatch_state="awaiting_external_confirmation",
            dispatch_error=None,
            external_message_id=payload.external_message_id,
            last_dispatch_at=datetime.now(timezone.utc).isoformat(),
        )
        if payload.action_id:
            store.update_assistant_action_status(
                settings.office_id,
                payload.action_id,
                "approved",
                dispatch_state="awaiting_external_confirmation",
                dispatch_error=None,
                external_message_id=payload.external_message_id,
                last_dispatch_at=datetime.now(timezone.utc).isoformat(),
            )
        approval_event = store.add_approval_event(
            settings.office_id,
            actor=subject,
            event_type="dispatch_started",
            action_id=payload.action_id,
            outbound_draft_id=draft_id,
            note=payload.note or "Dış işlem başlatıldı; son onay veya ödeme sağlayıcı tarafında tamamlanacak.",
        )
        dispatch_attempt = _start_dispatch_attempt(
            store=store,
            office_id=settings.office_id,
            actor=subject,
            action=linked_action,
            draft=draft,
            note=payload.note or "Dış işlem başlatıldı; son onay veya ödeme sağlayıcı tarafında tamamlanacak.",
            external_message_id=payload.external_message_id,
            metadata={"origin": "draft_dispatch_started"},
        )
        kb_result = _record_assistant_action_decision(
            event_type="dispatch_requested",
            action=linked_action,
            draft=draft,
            approval_event=approval_event,
            note=payload.note or "Dış işlem başlatıldı; son onay veya ödeme sağlayıcı tarafında tamamlanacak.",
        )
        action_case = _sync_assistant_action_case(
            store=store,
            office_id=settings.office_id,
            action=linked_action,
            draft=draft,
            created_by=str((linked_action or {}).get("created_by") or subject),
            actor=subject,
            status="awaiting_external_confirmation",
            current_step="dispatching",
            note=payload.note or "Dış işlem başlatıldı; son onay veya ödeme sağlayıcı tarafında tamamlanacak.",
        )
        external_receipt = _record_dispatch_external_receipt(
            store=store,
            office_id=settings.office_id,
            actor=subject,
            action=linked_action,
            draft=draft,
            dispatch_attempt=dispatch_attempt,
            payload=payload,
            receipt_type="dispatch_started",
            default_status="accepted",
            note=payload.note or "Dış işlem başlatıldı; sağlayıcı kabul kaydı işlendi.",
        )
        if external_receipt and action_case:
            store.add_action_case_event(
                settings.office_id,
                case_id=int(action_case["id"]),
                step_key="dispatch_receipt",
                event_type="external_receipt_recorded",
                actor=subject,
                note=payload.note or "Dış işlem receipt kaydı işlendi.",
                payload={
                    "receipt_id": int(external_receipt["id"]),
                    "dispatch_attempt_id": int(dispatch_attempt["id"]) if dispatch_attempt else None,
                    "receipt_type": external_receipt.get("receipt_type"),
                    "receipt_status": external_receipt.get("receipt_status"),
                },
            )
        audit.log("assistant_draft_dispatch_started", subject=subject, role=role, session_id=sid, draft_id=draft_id)
        return {
            "draft": draft,
            "action_case": action_case,
            "dispatch_attempt": dispatch_attempt,
            "external_receipt": external_receipt,
            "message": payload.note or "Dış işlem başlatıldı; son onay veya ödeme sağlayıcı tarafında tamamlanacak.",
            "decision_record": (kb_result or {}).get("decision_record"),
            "policy_guardrails": (kb_result or {}).get("policy"),
            "explainability": (kb_result or {}).get("explainability"),
            "knowledge_context": (kb_result or {}).get("knowledge_context"),
            "action_ladder": (kb_result or {}).get("action_ladder"),
        }

