    @app.post("/assistant/actions/{action_id}/dispatch-complete")
    def complete_assistant_action_dispatch(
        action_id: int,
        payload: AssistantDispatchReportRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("lawyer", role)
        action = store.update_assistant_action_status(
            settings.office_id,
            action_id,
            "completed",
            dispatch_state="completed",
            dispatch_error=None,
            external_message_id=payload.external_message_id,
            last_dispatch_at=datetime.now(timezone.utc).isoformat(),
        )
        if not action:
            raise HTTPException(status_code=404, detail="Aksiyon bulunamadı.")
        approval_event = store.add_approval_event(
            settings.office_id,
            actor=subject,
            event_type="dispatch_completed",
            action_id=action_id,
            outbound_draft_id=int(action["draft_id"]) if action.get("draft_id") else None,
            note=payload.note or "Aksiyon gönderimi tamamlandı.",
        )
        draft = store.get_outbound_draft(settings.office_id, int(action["draft_id"])) if action.get("draft_id") else None
        dispatch_attempt = _finalize_dispatch_attempt(
            store=store,
            office_id=settings.office_id,
            actor=subject,
            action=action,
            draft=draft,
            payload=payload,
            status="completed",
            note=payload.note or "Aksiyon gönderimi tamamlandı.",
            metadata={"origin": "action_dispatch_completed"},
        )
        kb_result = _record_assistant_action_decision(
            event_type="dispatch_completed",
            action=action,
            draft=draft,
            approval_event=approval_event,
            note=payload.note or "Aksiyon gönderimi tamamlandı.",
        )
        action_case = _sync_assistant_action_case(
            store=store,
            office_id=settings.office_id,
            action=action,
            draft=draft,
            created_by=str(action.get("created_by") or subject),
            actor=subject,
            status="completed",
            current_step="completed",
            note=payload.note or "Aksiyon gönderimi tamamlandı.",
            completed=True,
        )
        external_receipt = _record_dispatch_external_receipt(
            store=store,
            office_id=settings.office_id,
            actor=subject,
            action=action,
            draft=draft,
            dispatch_attempt=dispatch_attempt,
            payload=payload,
            receipt_type="dispatch_completed",
            default_status="completed",
            note=payload.note or "Aksiyon gönderimi tamamlandı.",
        )
        if external_receipt and action_case:
            store.add_action_case_event(
                settings.office_id,
                case_id=int(action_case["id"]),
                step_key="dispatch_receipt",
                event_type="external_receipt_recorded",
                actor=subject,
                note=payload.note or "Aksiyon receipt kaydı işlendi.",
                payload={
                    "receipt_id": int(external_receipt["id"]),
                    "dispatch_attempt_id": int(dispatch_attempt["id"]) if dispatch_attempt else None,
                    "receipt_type": external_receipt.get("receipt_type"),
                    "receipt_status": external_receipt.get("receipt_status"),
                },
            )
        _sync_parent_action_case_from_compensation(
            store=store,
            office_id=settings.office_id,
            actor=subject,
            compensation_action_case=action_case,
            compensation_action=action,
            compensation_draft=draft,
            outcome="completed",
            note=payload.note or "Telafi aksiyonu tamamlandı.",
            dispatch_attempt=dispatch_attempt,
            external_receipt=external_receipt,
        )
        audit.log("assistant_action_dispatch_completed", subject=subject, role=role, session_id=sid, action_id=action_id)
        return {
            "action": action,
            "action_case": action_case,
            "dispatch_attempt": dispatch_attempt,
            "external_receipt": external_receipt,
            "message": payload.note or "Aksiyon gönderimi tamamlandı.",
            "decision_record": (kb_result or {}).get("decision_record"),
            "policy_guardrails": (kb_result or {}).get("policy"),
            "explainability": (kb_result or {}).get("explainability"),
            "knowledge_context": (kb_result or {}).get("knowledge_context"),
            "action_ladder": (kb_result or {}).get("action_ladder"),
        }

