    @app.post("/auth/token")
    def token(req: TokenRequest):
        bootstrap_key = str(req.bootstrap_key or "")
        if req.role == "admin":
            if not settings.bootstrap_admin_key or bootstrap_key != settings.bootstrap_admin_key:
                raise HTTPException(status_code=403, detail="admin_bootstrap_key_required")
        elif settings.bootstrap_admin_key and not settings.allow_local_token_bootstrap:
            if bootstrap_key != settings.bootstrap_admin_key:
                raise HTTPException(status_code=403, detail="runtime_bootstrap_key_required")
        elif not settings.allow_local_token_bootstrap:
            raise HTTPException(status_code=403, detail="token_bootstrap_disabled")
        jwt, exp, sid = issue_token(settings.jwt_secret, req.subject, req.role, settings.token_ttl_seconds)
        store.store_session(sid, req.subject, req.role, datetime.fromtimestamp(exp, tz=timezone.utc).isoformat())
        audit.log("token_issued", subject=req.subject, role=req.role, session_id=sid)
        return {
            "access_token": jwt,
            "token_type": "bearer",
            "expires_in": settings.token_ttl_seconds,
            "session_id": sid,
        }

