    @app.post("/query/jobs")
    def create_query_job(
        payload: QueryJobCreateRequest,
        x_role: str | None = Header(default=None),
        authorization: str | None = Header(default=None),
    ):
        subject, role, sid = _extract_context(x_role, authorization, settings.jwt_secret, store, settings.allow_header_auth)
        require_role("intern", role)
        job = store.create_query_job(subject, payload.query, payload.model_profile, payload.continue_in_background)
        runtime_job = runtime_job_processor.enqueue_query_job(
            requested_by=subject,
            payload={
                "query_job_id": int(job["id"]),
                "query": payload.query,
                "model_profile": payload.model_profile,
                "allow_writeback": bool(payload.allow_writeback),
                "owner": subject,
                "role": role,
                "sid": sid,
            },
            priority=30,
        )
        store.set_query_job_runtime_job(int(job["id"]), subject, int(runtime_job["id"]))
        _request_runtime_job_processing_async(reason=f"query-{job['id']}", delay_seconds=0.05, limit=2)
        return {
            "job_id": job["id"],
            "status": "running",
            "runtime_job_id": runtime_job["id"],
            "execution_backend": "runtime_job_queue",
            "ui": {
                "message": "Yanıt hazırlanıyor. İstersen beklemeyi bırakıp arkaplanda devam ettirebilirsin.",
                "cancel_label": "İptal Et",
                "background_label": "Arkaplanda Devam Et",
            },
        }

